INSERT INTO road_sign_category_translations VALUES(9,11,102,'Նախազգուշացնող','Նախազգուշացնող նշաններըտեղեկացնում են ճանապարհի այն վտանգավոր տեղամասին մոտենալու մասին, որով երթևեկելիս (տեղաշարժվելիս) անհրաժեշտ է ձեռնարկել իրադրությանը համապատասխան միջոցներ','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(10,12,102,'Առավելության','Առավելության նշանները սահմանում են խաչմերուկներով, երթևեկելի մասերի փոխհատումներով կամ ճանապարհների նեղ հատվածներով անցման հերթականությունը','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(11,13,102,'Արգելող','Արգելող նշանները մտցնում կամ վերացնում են երթևեկության որոշակի սահմանափակումներ','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(12,14,102,'Թելադրող','Թելադրող նշանները ցույց են տալիս երթևեկության թույլատրելի ուղղությունները, նվազագույն արագությունը, ինչպես նաև հետիոտների և որոշ տրանսպորտային միջոցների վարորդների համար նախատեսում են երթևեկության ուղղությունները','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(13,15,102,'Հատուկ թելադրանքի','Հատուկ թելադրանքի նշանները մտցնում կամ վերացնում են երթևեկության որոշակի ռեժիմներ','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(14,16,102,'Տեղեկատվության','Տեղեկատվության նշանները տեղեկացնում են բնակավայրերի և այլ օբյեկտների տեղակայման, ինչպես նաև սահմանված կամ առաջարկվող երթևեկության ռեժիմների մասին','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(15,17,102,'Սպասարկման','Սպասարկման նշանները տեղեկացնում են համապատասխան օբյեկտների գտնվելու վայրի մասին','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(16,18,102,'Lրացուցիչ տեղեկատվության','Լրացուցիչ տեղեկատվության նշանները (ցուցանակները) ճշտում կամ սահմանափակում են այն նշանների ազդեցությունը, որոնց հետ կիրառվում են:','2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(17,19,102,unistr('Տրանսպորտային միջոցների ճանաչման նշաններ\u000d\u000a'),unistr('Տրանսպորտային միջոցների վրա անհրաժեշտության դեպքում պետք է տեղադրվեն կամ պատկերվեն տրանսպորտային միջոցի ճանաչման նշաններ: Բացի «Բժիշկ» և «Հաշմանդամ» ճանաչման նշաններից, որոնք տեղադրվում են վարորդի ցանկությամբ, մյուս բոլոր ճանաչման նշանների տեղադրումը պարտադիր է, եթե առկա է դրանցով նշվող հանգամանքը:\u000d\u000a\u000d\u000a'),'2025-05-04 00:23:04','2025-05-04 00:23:04');
INSERT INTO road_sign_category_translations VALUES(18,11,100,'Warning','The warning signs inform about the approach to the dangerous part of the road, where it is necessary to take appropriate measures when driving (moving)','2025-11-06 21:13:30','2025-11-06 21:13:30');
INSERT INTO road_sign_category_translations VALUES(19,11,101,'Предупреждение','Предупреждающие знаки информируют о приближении к опасному участку дороги, где необходимо принять соответствующие меры при движении (движении).','2025-11-06 21:13:30','2025-11-06 21:13:30');
INSERT INTO road_sign_category_translations VALUES(20,12,100,'Advantage','Right-of-way signs determine the order of passage at intersections, intersections, or narrow road sections','2025-11-06 21:13:31','2025-11-06 21:13:31');
INSERT INTO road_sign_category_translations VALUES(21,12,101,'Преимущество','Знаки полосы движения определяют порядок проезда на перекрестках, перекрестках или узких участках дороги.','2025-11-06 21:13:31','2025-11-06 21:13:31');
INSERT INTO road_sign_category_translations VALUES(22,13,100,'Forbidding','Prohibition signs introduce or remove certain traffic restrictions','2025-11-06 21:13:32','2025-11-06 21:13:32');
INSERT INTO road_sign_category_translations VALUES(23,13,101,'Запрещающий','Запрещающие знаки вводят или снимают определенные ограничения движения.','2025-11-06 21:13:32','2025-11-06 21:13:32');
INSERT INTO road_sign_category_translations VALUES(24,14,100,'Dictator','Indicative signs indicate permitted traffic directions, minimum speed limits, and provide directions for pedestrians and drivers of some vehicles.','2025-11-06 21:13:35','2025-11-06 21:13:35');
INSERT INTO road_sign_category_translations VALUES(25,14,101,'Диктатор','Указательные знаки указывают разрешенные направления движения, минимальные ограничения скорости, а также указывают направления для пешеходов и водителей некоторых транспортных средств.','2025-11-06 21:13:35','2025-11-06 21:13:35');
INSERT INTO road_sign_category_translations VALUES(26,15,100,'Special instructions','Special dictation signs introduce or eliminate certain traffic patterns','2025-11-06 21:13:36','2025-11-06 21:13:36');
INSERT INTO road_sign_category_translations VALUES(27,15,101,'Особые инструкции','Специальные знаки диктовки вводят или исключают определенные схемы дорожного движения.','2025-11-06 21:13:36','2025-11-06 21:13:36');
INSERT INTO road_sign_category_translations VALUES(28,16,100,'Information:','Information signs inform about the location of residences and other facilities, as well as established or proposed traffic patterns','2025-11-06 21:13:39','2025-11-06 21:13:39');
INSERT INTO road_sign_category_translations VALUES(29,16,101,'Информация:','Информационные знаки информируют о местонахождении жилых домов и других объектов, а также установленных или предполагаемых схемах движения.','2025-11-06 21:13:39','2025-11-06 21:13:39');
INSERT INTO road_sign_category_translations VALUES(30,17,100,'Maintenance','Service signs inform about the location of the relevant facilities','2025-11-06 21:13:42','2025-11-06 21:13:42');
INSERT INTO road_sign_category_translations VALUES(31,17,101,'Обслуживание','Служебные знаки информируют о местонахождении соответствующих объектов','2025-11-06 21:13:42','2025-11-06 21:13:42');
INSERT INTO road_sign_category_translations VALUES(32,18,100,'Additional information','Additional information signs (signs) specify or limit the effect of the signs with which they are applied.','2025-11-06 21:13:44','2025-11-06 21:13:44');
INSERT INTO road_sign_category_translations VALUES(33,18,101,'Дополнительная информация','Дополнительные информационные знаки (знаки) уточняют или ограничивают действие знаков, с которыми они применяются.','2025-11-06 21:13:44','2025-11-06 21:13:44');
INSERT INTO road_sign_category_translations VALUES(34,19,100,'Identification signs of vehicles','Vehicle identification signs must be affixed or depicted on vehicles as appropriate. In addition to the "Doctor" and "Disabled" recognition signs, which are placed at the driver''s request, the installation of all other recognition signs is mandatory, if the circumstance indicated by them exists.','2025-11-06 21:13:47','2025-11-06 21:13:47');
INSERT INTO road_sign_category_translations VALUES(35,19,101,'Опознавательные знаки транспортных средств','Опознавательные знаки транспортных средств должны быть прикреплены или изображены на транспортных средствах в зависимости от обстоятельств. Помимо опознавательных знаков «Врач» и «Инвалид», которые размещаются по требованию водителя, установка всех остальных опознавательных знаков обязательна при наличии указанного ими обстоятельства.','2025-11-06 21:13:47','2025-11-06 21:13:47');
