INSERT INTO answer_translations VALUES(17796,17796,102,'Տրանսպորտային միջոցից դուրս` ճանապարհի  վրա  գտնվող անձը` բացառությամբ ճանապարհի վրա աշխատանքներ իրականացնելու իրավասություն  ունեցող  և  օրենսդրությամբ սահմանված կարգով այդ աշխատանքներն իրականացնող անձը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
