INSERT INTO answer_translations VALUES(17798,17798,102,'Բնակավայրերից դուրս` ճանապարհներին` հաշվի առնելով տրանսպորտային միջոցների երթևեկության ինտենսիվությունը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
