INSERT INTO answer_translations VALUES(17812,17812,102,'Ոչ ավել 50 սմ խորանարդ  բանվորական ծավալի  շարժիչով  և ոչ ավել  50 կմ/ժ  առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17813,17813,102,'Ոչ ավել 60 սմ խորանարդ բանվորական ծավալի շարժիչով և ոչ ավել  60 կմ/ժ  առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17814,17814,102,'Ոչ ավել 70 սմ խորանարդ բանվորական ծավալի շարժիչով և ոչ ավել  70 կմ/ժ  առավելագույն արագությամբ երկանիվ կամ եռանիվ տրանսպորտային միջոցը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17815,17815,102,'Երթևեկության  ընդհատումը՝  կապված  լուսացույցի  արգելող ազդանշանի անսպասելի միացման հետ։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17816,17816,102,'Երթևեկության ընդհատումը՝ կապված ճանապարհին գոյացած խցանման հետ։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17817,17817,102,'Տրանսպորտային միջոցի անսարքության, վարորդի (ուղևորի) ֆիզիկական  և  (կամ)  հոգեկան վիճակով և  (կամ)  բեռի փոխադրմամբ պայմանավորված՝ վտանգի կամ  ճանապարհին ի հայտ եկած այլ խոչընդոտի պատճառով տրանսպորտային միջոցն անշարժ վիճակի բերելը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17818,17818,102,'Թվարկած բոլոր դեպքերը։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO answer_translations VALUES(17819,17819,102,'Ճանապարհի տեսանելիության հեռավորությունը՝ օրվա մութ ժամանակ։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO answer_translations VALUES(17820,17820,102,'Ճանապարհի տեսանելիության հեռավորությունը բնակավայրերում՝ երթևեկելի մասի արհեստական լուսավորվածության բացակայության պայմաններում։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17821,17821,102,'Մառախուղի, անձրևի, ձյունաթափի և (կամ)  ճանապարհային երթևեկության անվտանգության ապահովման համար այլ անբարենպաստ  եղանակի  պայմաններում,  ճանապարհի տեսանելիություն և (կամ)  մինչև  300  մետր տեսանելիության հեռավորություն։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17822,17822,102,'Մինչև 5 րոպե կամ ուղևորի նստելու, իջնելու և (կամ) տրանսպորտային  միջոցը  բեռնելու,  բեռնաթափելու  համար անհրաժեշտ ժամանակով տրանսպորտային միջոցն կանխամտածված անշարժ վիճակի բերելը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17823,17823,102,'5  րոպեից  ավելի  տրանսպորտային  միջոցն  անշարժ  վիճակի բերելը,  եթե դա  կապված չէ  ուղևորների  նստեցման, իջեցման կամ  տրանսպորտային միջոցի  բեռնման, բեռնաթափման հետ։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17824,17824,102,'Կանգառի  կետեր  (կանգառներ)  ունեցող,  երթուղիներով շարժվող,  ուղևորներ  և  (կամ)  ուղեբեռներ  տեղափոխող տրանսպորտային  միջոցը  (տրամվայ,  տրոլեյբուս,  ավտոբուս)։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17825,17825,102,'Կանգառի  կետեր  (կանգառներ)  ունեցող,  երթուղիներով շարժվող,  ուղևորներ  և  (կամ)  ուղեբեռներ  տեղափոխող տրանսպորտային  միջոցը  (տրամվայ,  տրոլեյբուս,  ավտոբուս), ինչպես  նաև  թեթև  մարդատար  տաքսի  ավտոմոբիլը։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17826,17826,102,'Առանց  շարժիչի  հաշմանդամային  սայլակներով տեղաշարժվող  հաշմանդամները։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO answer_translations VALUES(17827,17827,102,'Բեռնասայլակ,  սահնակ,  մանկասայլակ  կամ  հաշմանդամային սայլակ  քաշող  (հրող)  անձինք։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO answer_translations VALUES(17828,17828,102,'Թվարկած  բոլոր  անձինք։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO answer_translations VALUES(17829,17829,102,'Կոշտ կցիչով քարշակվող ցանկացած  մեխանիկական տրանսպորտային միջոցը։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO answer_translations VALUES(17830,17830,102,'Շարժիչով  չկահավորված  տրանսպորտային  միջոցը,  որը նախատեսված  է  մեխանիկական տրանսպորտային միջոցով շարժման  մեջ  դրվելու  և   դրա   կազմում  որպես  մեկ ամբողջություն երթևեկելու համար (ներառյալ՝ հատուկ կցորդը)։','2025-05-18 20:17:13','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17831,17831,102,'Աջակողմյան  երթևեկություն։','2025-05-18 20:17:13','2025-05-19 18:25:41');
