INSERT INTO answer_translations VALUES(17900,17900,102,'5  րոպեից  ավելի ժամանակով տրանսպորտային  միջոցը կանխամտածված անշարժ  վիճակի բերելը,  եթե դա  կապված չէ ուղևորների  նստեցման, իջեցման կամ  տրանսպորտային միջոց ի բեռնման, բեռնաթափման հետ։','2025-05-18 20:17:14','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17901,17901,102,'Մինչև 5 րոպե կամ ուղևորի նստելու, իջնելու և (կամ) տրանսպորտային  միջոցը  բեռնելու,  բեռնաթափելու  համար անհրաժեշտ ժամանակով տրանսպորտային միջոցը կանխամտածված անշարժ վիճակի բերելը։','2025-05-18 20:17:14','2025-05-19 18:25:41');
