INSERT INTO answer_translations VALUES(17903,17903,102,'Կանգառի  կետեր  (կանգառներ)  ունեցող,  երթուղիներով շարժվող,  ուղևորներ  և  (կամ)  ուղեբեռներ  տեղափոխող տրանսպորտային  միջոցը  (տրամվայ,  տրոլեյբուս,  ավտոբուս)։','2025-05-18 20:17:14','2025-05-19 18:25:41');
