INSERT INTO answer_translations VALUES(17959,17959,102,'տրանսպորտային միջոցի գծանշված երթևեկության գոտու սահմաններում զբաղեցրած շարքից, երթևեկության սկզբնական ուղղությունը պահպանելով, դուրս գալը','2025-05-18 20:17:14','2025-05-18 20:17:14');
