INSERT INTO answer_translations VALUES(17961,17961,102,'տրանսպորտային միջոցի` այլ ճանապարհ դուրս գալու նպատակով իրականացվող մանևրը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17962,17962,102,'տրանսպորտային միջոցի` այլ ճանապարհ կամ ճանապարհից մերձակա տարածք դուրս գալու նպատակով իրականացվող մանևրը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17963,17963,102,'տրանսպորտային միջոցը հանդիպակաց ուղղությամբ վարելը.','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17964,17964,102,'տրանսպորտային միջոցի շարժման ուղղությունը հանդիպակաց ուղղությամբ փոխելու նպատակով իրականացվող մանևր:','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17965,17965,102,'շարժման մեջ գտնվող մեկ կամ մի քանի տրանսպորտային միջոցներից առաջ անցնելը` առանց զբաղեցրած գոտուց դուրս գալու','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17966,17966,102,'շարժման մեջ գտնվող մեկ կամ մի քանի տրանսպորտային միջոցներից առաջ անցնելը` կապված զբաղեցրած գոտուց դուրս գալու հետ','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17967,17967,102,'կանգառի կամ կայանման վայրից տրանսպորտային միջոցի շարժումն սկսելու պահը` կապված հարևան երթևեկության գոտի վերադասավորման հետ կամ առանց դրա','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17968,17968,102,'կանգառի կամ կայանման վայրից տրանսպորտային միջոցի շարժումն սկսելու պահը` կապված հարևան երթևեկության գոտի վերադասավորման հետ:','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17969,17969,102,'տրանսպորտային միջոցի երթևեկության սկիզբ (կապված հարևան երթևեկության գոտի դուրս գալու հետ), վերադասավորում, երթևեկության ուղղության փոփոխություն, կանգառ (վերադասավորվելով) և հետընթաց կատարելը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17970,17970,102,'տրանսպորտային միջոցի երթևեկության սկիզբ, վերադասավորում, երթևեկության ուղղության փոփոխություն, կանգառ և հետընթաց կատարելը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17971,17971,102,'ճանապարհի հարակից երթևեկելի մասերը բաժանող, կառուցվածքորեն առանձնացված տարր, որը նախատեսված չէ տրանսպորտային միջոցների և հետիոտների երթևեկության կամ կանգառի համար','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17972,17972,102,'ճանապարհի հարակից երթևեկելի մասերը բաժանող, կառուցվածքորեն և (կամ) համապատասխան գծանշումով առանձնացված տարր, որը նախատեսված չէ տրանսպորտային միջոցների և հետիոտների երթևեկության կամ կան գառի համար','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17973,17973,102,'ճանապարհով բեռնակիր և (կամ) հեծկան կենդանիներ կամ անասուններ քշող անձը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17974,17974,102,'բեռնակիր և (կամ) հեծկան կենդանիներ կամ անասուններ քշող անձը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17975,17975,102,'օրենսդրությամբ սահմանված կարգով հետիոտնի տեղաշարժվելու համար նախատեսված երթևեկելի մասին հարող ճանապարհի տարրը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17976,17976,102,'օրենսդրությամբ սահմանված կարգով հետիոտնի տեղաշարժվելու համար նախատեսված երթևեկելի մասից որևէ եղանակով առանձնացված ճանապարհի տարրը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17977,17977,102,'Նշված երկու դեպքերը','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17978,17978,102,'Թեթև  մարդատար ավտոմոբիլների  դողերի  պահպանաշերտի մնացորդային  բարձրությունը կազմում է 1.8 մմ։','2025-05-18 20:17:14','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17979,17979,102,'Խախտված է հիդրավլիկ արգելակային հաղորդակի հերմետիկությունը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17980,17980,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17981,17981,102,'Բեռնատար ավտոմոբիլի դողերի պահպանաշերտի մնացորդային  բարձրությունը կազմում է 1.6 մմ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17982,17982,102,'Չի գործում պնևմատիկ արգելակային հաղորդակի ճնշաչափը։','2025-05-18 20:17:14','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17983,17983,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17984,17984,102,'Առկա են ղեկային կառավարման մանրամասերի (դետալների) ու հանգույցների` կառուցվածքով չնախատեսված տեղաշարժեր կամ պարուրակային միացումները  ձգված չեն։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17985,17985,102,'Բեռնատար ավտոմոբիլում  բացակայում է կրակմարիչը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17986,17986,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17987,17987,102,'Սահմանված ռեժիմով   չեն  աշխատում արտաքին  լուսային սարքերը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17988,17988,102,'Մոտոցիկլի դողերի պահպանաշերտի  մնացորդային բարձրությունը կազմում է 0.6 մմ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17989,17989,102,'Երկու դեպքում  էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17990,17990,102,'Հետին հակամառախուղային լապտերիկները միացված են տրանսպորտային միջոցի արգելակումն ազդարարող լուսային սարքերին։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17991,17991,102,'Չի աշխատում շարժիչը հովացնող հեղուկի ջերմաստիճանի ցուցիչը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17992,17992,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17993,17993,102,'Շարժիչն աշխատում է ընդհատումներով։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17994,17994,102,'Դողերն ունեն անվադողի հենքը (կորդը) մերկացնող տեղային վնասվածքներ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17995,17995,102,'Չեն աշխատում թեթև  մարդատար  ավտոմոբիլի  սրահի ներքին լուսավորության սարքերը։','2025-05-18 20:17:14','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(17996,17996,102,'Թվարկած բոլոր դեպքերում։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17997,17997,102,'Առանց կողային կցորդի մոտոցիկլում բացակայում է «Վթարային կանգառ» նշանը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17998,17998,102,'Դողերը չափերով կամ թույլատրելի բեռնվածությամբ չեն համապատասխանում տրանսպորտային միջոցի տվյալ մոդելին։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(17999,17999,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18000,18000,102,'Բացակայում  է  դողի  անվահեցի  ամրացման  հեղյուսներից թեկուզ  մեկը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18001,18001,102,'Նույն  սռնու  վրա  տեղադրված  են  պահպանաշերտի  տարբեր նախշանկարներով դողեր։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18002,18002,102,'Երկու  դեպքում  էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18003,18003,102,'Բացակայում  են  կառուցվածքով  նախատեսված  նստատեղերի գլխակալները։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18004,18004,102,'Նույն  սռնու  վրա  տեղադրված  են  նոր  և  վերականգնված դողեր։','2025-05-18 20:17:14','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(18005,18005,102,'Երկու  դեպքում  էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18006,18006,102,'Արտածվող  գազերում  վնասակար  նյութերի պարունակությունը  գերազանցում է  ՀՀ  օրենսդրությամբ սահմանված նորմերը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18007,18007,102,'Մոտոցիկլի վրա բացակայում են կառուցվածքով նախատեսված ոտնատեղերը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18008,18008,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18009,18009,102,'Խախտված  է  շարժիչի  հենատուփի  օդափոխության համակարգի  հերմետիկությունը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18010,18010,102,'Խախտված է շարժիչի սնման համակարգի հերմետիկությունը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18011,18011,102,'Երկու դեպքում էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18012,18012,102,'Խախտված է շարժիչի հենատուփի օդափոխության համակարգի հերմետիկությունը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18013,18013,102,'Նույն  սռնու  վրա՝  տեղադրված  են  ցրտադիմացկուն  և  ոչ ցրտադիմացկուն  դողեր։','2025-05-18 20:17:14','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(18014,18014,102,'Երկու  դեպքում  էլ։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18015,18015,102,'Չեն  աշխատում  կառուցվածքով  նախատեսված ապակեողողիչները։','2025-05-18 20:17:14','2025-05-18 20:17:14');
INSERT INTO answer_translations VALUES(18016,18016,102,'Շարժիչի  արտաքին  աղմուկի  թույլատրելի  մակարդակը գերազանցում  է  ստանդարտով սահմանված  նորմերը։','2025-05-18 20:17:14','2025-05-18 20:17:14');
