INSERT INTO answer_translations VALUES(20054,20054,102,'Տրանսպորտային միջոցի լիարժեք կառավարումը ապահովող','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20055,20055,102,'Ազատ է ընտրելու ցանկացած արագություն, որը չի գերազանցի առավելագույն թույլատրելին','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20056,20056,102,'գերազանցել տվյալ տրանսպորտային միջոցի տեխնիկական բնութագրով սահմանված առավելագույն արագությունը.','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20057,20057,102,'գերազանցել տրանսպորտային միջոցի վրա տեղադրված «Արագության սահմանափակում» ճանաչման նշանով նախատեսված արագությունը.','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20058,20058,102,'առանց անհրաժեշտության ընթանալ շատ ցածր արագությամբ` խոչընդոտելով մյուս տրանսպորտային միջոցների երթևեկությանը.','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20059,20059,102,'կտրուկ արգելակել, եթե դա անհրաժեշտ չէ ճանապարհատրանսպորտային պատահար կանխելու համար','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20060,20060,102,'Բոլոր նշված գործողությունները','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20061,20061,102,'1 և 3','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20062,20062,102,'1 և 4','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20063,20063,102,'միայն 2-ը','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20064,20064,102,'2 և 3','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20065,20065,102,'Երկաթուղային գծանցը հատել ավելի քան 30 կմ/ժ արագությամբ','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20066,20066,102,'Երկաթուղային գծանցը հատել պակաս 30 կմ/ժ արագությունից','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20067,20067,102,'Առանց երկաթգծի ուղեմասի պետի թույլտվության գծանցով երթևեկել դանդաղընթաց մեքենաներով` 8 կմ/ժ ցածր արագությամբ և տափանների հետ կցված տրակտորներով','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20068,20068,102,'Չգերազանցի տվյալ հատվածում սահմանված առավելագույն թույլատրելին:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20069,20069,102,'Հնարավորություն ունենա կանգնելու և բաց թողնելու անցման առաջնահերթության իրավունք ունեցող փոխադրամիջոցները','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20070,20070,102,'Դա կխոչընդոտի իրեն վազանցող տրանսպորտային միջոցի վարորդի վազանց կատարելուն:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20071,20071,102,'Դա անհրաժեշտ է իրեն ճանապարհը զիջելու նպատակով կանգ առած վարորդի ճանապարհը ազատելու համար:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20072,20072,102,'Դա կատարվում է խաչմերուկն ազատելու նպատակով','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20073,20073,102,'«Երեխաների փոխադրում» ճանաչման նշանով կահավորված տրանսպորտային միջոցներ երեխաների նստեցման և իջեցման ժամանակ այդ տրանսպորտային միջոցներին մոտենալիս:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20074,20074,102,'Շլանալու դեպքում','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20075,20075,102,'Երթևեկության համար խոչընդոտ կամ վտանգ առաջանալու դեպքում:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20076,20076,102,'Կապույտ և կարմիր գույների առկայծող փարոսիկներ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոց մոտենալու դեպքում, ինչպես նաև կապույտ կամ կապույտ և կարմիր գույների առկայծող փարոսիկներ միացրած, կանգնած վիճակում գտնվող տրանսպորտային միջոցին մոտենալիս:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20077,20077,102,'Բոլոր նշված դեպքերում','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20078,20078,102,'Այո','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20079,20079,102,'Ոչ','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20080,20080,102,'8 ուղևոր','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20081,20081,102,'9 ուղևոր','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20082,20082,102,'4 ուղևոր','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20083,20083,102,'Կողավոր թափքով բեռնատար ավտոմոբիլի թափքում:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20084,20084,102,'Փուրգոն թափքով բեռնատար ավտոմոբիլի թափքում','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20085,20085,102,'Այո','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20086,20086,102,'Ոչ','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20087,20087,102,'սահմանափակում է վարորդի տեսադաշտը.','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20088,20088,102,'դժվարացնում է տրանսպորտային միջոցի ղեկավարումը և թուլացնում կայունությունը','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20089,20089,102,'ծածկում է արտաքին լուսային սարքերն ու լուսանդրադարձիչները, համարանիշերը կամ ճանաչման նշանները, ինչպես նաև խանգարում ձեռքով տրվող ազդանշանների ընկալմանը','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20090,20090,102,'նշված բոլոր դեպքերում:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20091,20091,102,'Բեռը բարեհաջող հասցնի մինչև մոտակա բեռնաթափման վայրը:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20092,20092,102,'Վերացնի խախտումները կամ դադարեցնի հետագա երթևեկությունը','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20093,20093,102,'Այո','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20094,20094,102,'Ոչ','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20095,20095,102,'Այո','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20096,20096,102,'Ոչ','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO answer_translations VALUES(20097,20097,102,'Կանգ առնեն և շարունակեն երթևեկությունը  միայն թույլտվություն ստանալուց հետո։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20098,20098,102,'Իջեցնեն արագությունը, որպեսզի անհրաժեշտության դեպքում հնարավորություն ունենան անմիջապես կանգ առնել։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20099,20099,102,'Շարունակեն երթևեկությունը, քանի որ երթևեկում են սահմանված երթուղով։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20100,20100,102,'Շարունակեն երթևեկությունը, քանի որ երթևեկում են սահմանված  երթուղով։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20101,20101,102,'Զիջեն ճանապարհը՝ նշված տրանսպորտային միջոցի անխոչընդոտ անցումն ապահովելու համար։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20102,20102,102,'Իջեցնեն արագությունը  և  զիջեն ճանապարհը՝ նշված տրանսպորտային  միջոցի   անխոչընդոտ   անցումն ապահովելու համար։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20103,20103,102,'Երթևեկության մյուս մասնակիցների նկատմամբ առավելություն ստանալու համար։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20104,20104,102,'Բնակավայրերում՝ վազանց կատարելու մտադրության մասին մյուս վարորդներին նախազգուշացնելու համար։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20105,20105,102,'Երբ դա անհրաժեշտ է ճանապարհատրանսպորտային պատահարը կանխելու համար։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20106,20106,102,'Բոլոր դեպքերում էլ։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20107,20107,102,'Լապտերների միայն  մոտակա լույսը։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20108,20108,102,'Լապտերների միայն հեռահար լույսը։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20109,20109,102,'Լապտերների հեռահար կամ մոտակա լույսը։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20110,20110,102,'Պարտադիր է։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20111,20111,102,'Պարտադիր չէ։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20112,20112,102,'Երթևեկելի  մասի եզրին կանգառ կատարելիս։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20113,20113,102,'«Վտանգավոր շրջադարձ» նշանի ազդեցության ճանապարհի կորացումից առաջ։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20114,20114,102,'Երթևեկության հարևան գոտի վերադասավորվելուց առաջ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20115,20115,102,'Անմիջապես  մանևրն  սկսելուց  առաջ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20116,20116,102,'Անմիջապես  մանևրն  սկսելուց  հետո։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20117,20117,102,'Նախօրոք՝  մինչև  մանևրն  սկսելը։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20118,20118,102,'Մանևրն սկսելուց անմիջապես առաջ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20119,20119,102,'Մանևրն սկսելու հետ միաժամանակ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20120,20120,102,'Նախօրոք՝ մինչև մանևրն սկսելը։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20121,20121,102,'Մանևրն սկսելուց  անմիջապես  առաջ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20122,20122,102,'Մանևրն ավարտելուց անմիջապես  հետո։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20123,20123,102,'Մանևրը  կատարելու  ժամանակ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20124,20124,102,'Եթե նրա հետևից երթևեկում է այլ տրանսպորտային միջոց։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20125,20125,102,'Միայն բնակավայրերում։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20126,20126,102,'Բոլոր դեպքերում։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO answer_translations VALUES(20127,20127,102,'Երեք  երկար  և  մեկ  կարճ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20128,20128,102,'Մեկ  երկար  և  երեք  կարճ։','2025-05-18 20:17:54','2025-05-19 18:25:41');
