INSERT INTO answer_translations VALUES(20569,20569,102,'Պառկեցնել գլուխը բարձր դիրքով։','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO answer_translations VALUES(20570,20570,102,'Ստորին վերջույթի և գլխի վնասվածք։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20571,20571,102,'Կոնքի և կրծքավանդակի վնասվածք։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20572,20572,102,'Ստորին վերջույթի և գլխի վնասվածք։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20573,20573,102,'Կոնքի և կրծքավանդակի վնասվածք։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20574,20574,102,'Օգնել մեքենայում գտնվող անձանց շտապ դուրս գալ մեքենայից։','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20575,20575,102,'Մեքենայում գտնվող անձանց խնդրել մնալ մեքենայի մեջ մինչև էլեկտրական հոսանքը չանջատեն։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20576,20576,102,'Լվանալ վերքը օճառով և մաքուր ջրով, այնուհետև վիրակապել։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20577,20577,102,'Մշակել վերքը սպիրտային հիմքով նյութերով (յոդ, օղի, օծանելիք և այլն)։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20578,20578,102,'Լվանալ վերքը օճառով և մաքուր ջրով։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20579,20579,102,'Մշակել վերքը սպիրտային հիմքով նյութերով (յոդ, օղի, օծանելիք և այլն)։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20580,20580,102,'Դադարեցնել  արյունահոսությունը և վիրակապել վերքը։','2025-05-18 20:17:57','2025-05-19 18:25:41');
INSERT INTO answer_translations VALUES(20581,20581,102,'Նշել վթարի վայրին ամենամոտ գտնվող կողմնորոշիչը: Հաղորդել տուժածների թիվը, նշել նրանց սեռը և տարիքը.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20582,20582,102,'Նշել վթարի վայրին ամենամոտ գտնվող փողոցը և տան համարը: Տեղեկացնել, թե ով է տուժել վթարի հետևանքով (հետիոտն, մեքենայի վարորդ կամ ուղևոր) և նկարագրել ստացված վնասվածքները:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20583,20583,102,'Նշել վթարի վայրը (փողոցը, տան համարը և դեպքի վայրին ամենամոտ կողմնորոշիչները): Տեղեկացնել տուժածների թիվը, նրանց սեռը, մոտավոր տարիքը, գիտակցության,  շնչառության, արյան շրջանառության, ինչպես նաև ուժեղ արյունահոսության, կոտրվածքների և այլ վնասվածքների առկայության մասին: Սպասել մինչև օպերատորը նշի, որ կանչն ընդունված է:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20584,20584,102,'Տուժածին պառկեցնել կողքի:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20585,20585,102,'Տուժածին պառկեցնել մեջքի վրա`  կոշտ, հարթ մակերեսի վրա, առանց  անհրաժեշտության չտեղաշարժել, դիրքը չփոխել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20586,20586,102,'Տուժածին պառկեցնել մեջքի վրա, պարանոցի տակ տեղադրել շորերից պատրաստված գլանակ և բարձրացնել ոտքերը:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20587,20587,102,'Մարմնի ախտահարված հատվածները շփել ձյունով կամ բրդյա կտորով, ապա տաքացնել, տալ ալկոհոլային խմիչք, տեղափոխել տաք տարածք:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20588,20588,102,'Տաքացնել մարմնի ախտահարված հատվածները և անշարժացնել դրանք, տուժածին ծածկել տաք շորերով կամ ծածկոցով, տալ տաք ըմպելիք,  տեղափոխել տաք տարածք:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20589,20589,102,'Մարմնի ախտահարված հատվածները  քսուքով պատել, տաքացնող կոմպրես և ջեռակ դնել, տեղափոխել տաք տարածք, տալ տաք ըմպելիք:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20590,20590,102,'Դադարեցնել արյունահոսությունը վերքի վրա ուղղակի ճնշման միջոցով, վերքի վրա դնել սեղմող վիրակապ: Գիտակցության կորստի դեպքում տուժածին տալ կայուն կողքի շրջված դիրք: Հնարավորության դեպքում գլխի վնասվածքի շրջանում սառը դնել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20591,20591,102,'Անշարժացնել ողնաշարի պարանոցային հատվածը `օգտագործելով ինքնաշեն շինա (օձիք): վերքի վրա դնել ստերիլ բամբակե խծուծ, տուժածին պառկեցնել մեջքի վրա` ոտքերը բարձրացրած դիրքում: Հնարավորության դեպքում գլխին սառը դնել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20592,20592,102,'Արգելվում է պարանոցային շինա դնել: Անհրաժեշտ է վերքը ծածկել բժշկական կպչուն սպեղանիով, տուժածին պառկեցնել կողքի վրա:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20593,20593,102,'Մեջքի վրա` գլխի տակ դնելով գլանակ','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20594,20594,102,'Մեջքի վրա` ոտքերը տարածած վիճակում','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20595,20595,102,'Տուժածին տալ կայուն կողքի շրջված դիրք այնպես, որ ծալված ծնկները հպվեն գետնին, իսկ վերևում գտնվող ձեռքը գտնվի այտի տակ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20596,20596,102,'Տաք եղանակին ոչ ավելի, քան կես ժամ, իսկ ցուրտ եղանակին `ոչ ավելի, քան մեկ ժամ','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20597,20597,102,'Տաք եղանակին ոչ ավելի, քան 1 ժամ, իսկ ցուրտ եղանակին` ոչ ավելի, քան կես ժամ','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20598,20598,102,'Լարանի կապված մնալու ժամանակը սահմանափակ չէ','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20599,20599,102,'Բռնել տուժածի կզակից, հետ թեքել գլուխը և հետևել կրծքավանդակի շարժմանը 10 վայրկյան տևողությամբ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20600,20600,102,'Մի ձեռքը դնել տուժածի ճակատին, մյուս ձեռքի երկու մատով կզակը բարձրացնելով և գլուխը հետ թեքելով անհրաժեշտ է 10 վայրկյան տևողությամբ հետևել  շնչառությանը, փորձելով արտաշնչած օդը զգալ Ձեր այտին և հետևել կրծքավանդակի շարժմանը','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20601,20601,102,'Առանց տուժածի գլուխը թեքելու, անհրաժեշտ է խոնարհվել նրա դեմքին և 10 վայրկյան տևողությամբ հետևել նրա շնչառությունը, փորձելով արտաշնչած օդը զգալ Ձեր այտնի և հետևել կրծքավանդակի շարժմանը:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20602,20602,102,'Վերքից դանդաղորեն դուրս է հոսում մուգ գույնի արյուն: Վերքի վրա  դրվում է սեղմող վիրակապ, որի վրա գրառում կա վերքի վրա պահելու ժամանակի վերաբերյալ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20603,20603,102,'Վերքից վառ  կարմիր գույնի արյուն է հոսում`  ուժեղ ցայտելով, ընդհատվող շիթով կամ շատրվանի նման: Վնասված զարկերակն անհրաժեշտ է սեղմել մատներով, այնուհետև վերքից վերև, որքան հնարավոր է վերքին մոտ դրվում է արյունահոսությունը կանգնեցնող լարան, որի վրա գրառում կա պահելու ժամանակի վերաբերյալ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20604,20604,102,'Արյունը դանդաղորեն դուրս է հոսում վերքից: Վնասվածքից ցած դրվում է արյունահոսությունը կանգնեցնող լարան, որի վրա գրառում կա պահելու ժամանակի վերաբերյալ','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20605,20605,102,'Թույլատրվում է','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20606,20606,102,'Թույլատրվում է ծայրահեղ անհրաժեշտության դեպքում','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20607,20607,102,'Արգելվում է','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20608,20608,102,'Դնել ճնշող վիրակապ վնասվածքի տեղում:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20609,20609,102,'Վերքից վերև հատվածում ճնշող վիրակապ դնել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20610,20610,102,'Վերքից ներքև հատվածում ճնշող վիրակապ դնել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20611,20611,102,'Վերքը լվանալ ջրով, վերքից հեռացնել  օտար մարմինները, վերքի վրա դնել ստերիլ բամբակ` ամրացնելով բինտային վիրակապով:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20612,20612,102,'Հագնել բժշկական ձեռնոցներ, վերքը մաքրել յոդի ալկոհոլային լուծույթով, դեղաքսուք դնել և ծածկել կպչուն սպեղանիով:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20613,20613,102,'Հագնել բժշկական ձեռնոցներ, վերքն առանց մաքրելու ծածկել ստերիլ թանզիֆե անձեռոցիկով` եզրերին ամրացնելով կպչուն սպեղանի կամ բինտով վիրակապել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20614,20614,102,'Վերին վերջույթը`  իրանի երկայնքով տարածած, կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց՝ փափուկ կտոր դնելով դրանց միջև:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20615,20615,102,'Վերին վերջույթը` արմնկային հոդում ծալված, գլխաշորի վրա հենած`կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց` փափուկ կտոր դնելով դրանց միջև:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20616,20616,102,'Վերին վերջույթը, արմնկային հոդում ծալված, գլխաշորի վրա հենած`կապվում է իրանին: Ստորին վերջույթները կապվում են միմյանց','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20617,20617,102,'Ավտոմեքենայի շրջվելու, բռնկվելու, պայթյունի մեծ հավանականության կամ տուժածի գիտակցության կորստի դեպքում:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20618,20618,102,'Ավտոմեքենայի շրջվելու, բռնկվելու, պայթյունի մեծ հավանականության կամ տուժածի գերսառեցման, գիտակցության և շնչառության կորստի դեպքում, ինչպես նաև անմիջականորեն խցիկում առաջին օգնություն ցուցաբերելու անհնարինության դեպքում:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20619,20619,102,'Ավտոմեքենայի շրջվելու, բռնկվելու, պայթյունի մեծ հավանականության դեպքում կամ տուժածի մոտ ծանր արյունահոսության, գանգուղեղային վնասվածքի առկայության դեպքում','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20620,20620,102,'Այրված մակերեսի վրա սառը ջուր լցնել, ծածկել ստերիլ անձեռոցիկով և ամուր վիրակապել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20621,20621,102,'Բացել բշտիկները, մաքրել այրվածքի մակերեսը հագուստի մնացորդներից, ծածկել  ստերիլ անձեռոցիկով (չվիրակապել), հնարավորության դեպքում սառը դնել, և տուժածին ջուր խմեցնել','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20622,20622,102,'20 րոպե տևողությամբ այրվածքի մակերեսը սառեցնել ջրով: Առանց բշտիկները բացելու և հագուստի մնացորդները հեռացնելու այրվածքի մակերեսը ծածկել ստերիլ  անձեռոցիկով (չվիրակապել), հնարավորության դեպքում սառը դնել և տուժածին ջուր խմեցնել:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO answer_translations VALUES(20623,20623,102,'Առաջինը՝  կարմիրի հետ միաժամանակ։','2025-05-24 07:15:23','2025-05-24 07:15:23');
