INSERT INTO answer_translations VALUES(21014,17761,101,'Грузового автомобиля','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21015,17762,101,'Легкового автомобиля','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21016,17763,101,'Да','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21017,17764,101,'Нет','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21018,17765,101,'Только пешеходам','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21019,17766,101,'Только велосипедисту','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21020,17767,101,'Никому','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21021,17768,101,'Велосипедисту и пешеходам ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21022,17769,101,'Возможно будет выполнить его одним действием','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21023,17770,101,'Обеспечена видимость в 100 метров с обеих сторон','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21024,17771,101,'Запрещается','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21025,17772,101,'Водитель автобуса','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21026,17773,101,'Водитель легкового автомобиля ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21027,17774,101,'Разрешается в условиях видимости в 100 м с обеих сторон','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21028,17775,101,'Запрещается','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21029,17776,101,'Да','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21030,17777,101,'Нет','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21031,17778,101,'Лицо, находящееся в салоне (кабине) транспортного средства или на транспортном средстве, кроме водителя и обучающего вождению лица. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21032,17779,101,'Лицо, находящееся в салоне (кабине) транспортного средства или на транспортном средстве, а также лицо, которое садится (поднимается) в транспортное средство и выходит из (сходит с) него, кроме водителя и обучающего вождению лица','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21033,17780,101,'Лицам от 16 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21034,17781,101,'Лицам от 17 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21035,17782,101,'Лицам от 18 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21036,17783,101,'Лицам от 17 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21037,17784,101,'Лцам от 18 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21038,17785,101,'Лицам от 19 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21039,17786,101,'Элемент дороги, предназначенный для движения транспортных средств.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21040,17787,101,'Элемент дороги, предназначенный для движения безрельсовых транспортных средств. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21041,17788,101,'Должен','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21042,17789,101,'Не должен. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21043,17790,101,'Не должен, если это затрудняет управление автомобиля','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21044,17791,101,'Не должен, если обучающий разрешает вести.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21045,17792,101,'Лицам от 18 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21046,17793,101,'Лицам от 19 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21047,17794,101,'Лицам от 20 лет','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21048,17795,101,'Лицам от 21 года.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21049,17796,101,'Лицо, находящееся вне транспортного средства на дороге, за исключением лица, имеющего полномочие на произведение работ на дороге и в порядке, установленном законодательством, осуществляющего данные работы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21050,17797,101,'Лицо, находящееся вне транспортного средства на дороге, в том числе лица, имеющего полномочие на произведение работ на дороге и в порядке, установленном законодательством, осуществляющего данные работы. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21051,17798,101,'Вне населённых пунктов, на дорогах, учитывая интенсивность движения транспортных средств. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21052,17799,101,'На закрытой площадке или автодроме. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21053,17800,101,'На любой дороге (кроме автомагистралей), учитывая интенсивность движения транспортных средств. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21054,17801,101,'Не считается. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21055,17802,101,'Считается. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21056,17803,101,'750 килограмм. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21057,17804,101,'800 килограмм','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21058,17805,101,'1000 килограмм. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21059,17806,101,'Без защитных очков.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21060,17807,101,'Без шлема.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21061,17808,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21062,17809,101,'Лицам от 16 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21063,17810,101,'Лицам от 17 лет','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21064,17811,101,'Лицам от 18 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21065,17812,101,'Двух- или трехколесное транспортное средство с двигателем рабочим объемом до 50 куб. см и максимальной скоростью до 50 км/ч.','2025-11-06 21:40:30','2026-03-11 00:34:29');
INSERT INTO answer_translations VALUES(21066,17813,101,'Двух- или трехколесное транспортное средство с двигателем рабочим объемом до 60 куб. см и максимальной скоростью до 60 км/ч.','2025-11-06 21:40:30','2026-03-11 00:34:29');
INSERT INTO answer_translations VALUES(21067,17814,101,'Двух- или трехколесное транспортное средство с двигателем рабочим объемом до 70 куб. см и максимальной скоростью до 70 км/ч.','2025-11-06 21:40:30','2026-03-11 00:34:29');
INSERT INTO answer_translations VALUES(21068,17815,101,'Прекращение движения в связи с неожиданным включением запрещающего сигнала светофора. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21069,17816,101,'Прекращение движения в связи с образовавшейся на дороге пробке.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21070,17817,101,'Прекращение движения транспортного средства из-за его неисправности, опасности, создаваемой физическим и (или) душевным состоянием водителя (пассажира) и (или) перевозимым грузом, появления препятствия на дороге.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21071,17818,101,'Все перечисленные случаи. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21072,17819,101,'Расстояние видимости дороги в темное время суток. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21073,17820,101,'Расстояние видимости дороги в населенных пунктах, в условиях отсутствия искусственного освещения проезжей части. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21074,17821,101,'Видимость дороги и (или) расстояние видимости до 300 метров, в условиях тумана, дождя, снегопада и (или) в других неблагоприятных погодных условиях для обеспечения безопасности дорожного движения. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21075,17822,101,'Преднамеренное приведение транспортного средства в неподвижное состояние на время до 5 минут или на необходимое время для посадки или высадки пассажиров и (или) загрузки, разгрузки транспортного средства. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21076,17823,101,'Приведение транспортного средства в неподвижное состояние на время более 5 минут, если это не связано с посадкой, высадкой пассажиров или загрузкой, разгрузкой транспортного средства. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21077,17824,101,'Транспортное средство (трамвай, тролейбус, автобус), имеющее места остановки (остановки), движущееся по маршрутам, перевозящее пассажиров и (или) багажи.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21078,17825,101,'Транспортное средство (трамвай, тролейбус, автобус), имеющее места остановки (остановки), движущееся по маршрутам, перевозящее пассажиров и (или) багажи, а также легковой автомобиль такси. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21079,17826,101,'Инвалиды, передвигающиеся в инвалидной коляске без двигателя. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21080,17827,101,'Лица, везущие (толкающие) тележку, санки, детскую или инвалидную коляску.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21081,17828,101,'Все перечисленные лица.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21082,17829,101,'Любое механическое транспортное средство, буксируемое жестким прицепом.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21083,17830,101,'Не оборудованное двигателем транспортное средство, которое предназначено для приведения в движение посредством механического транспортного средства и движения в его составе в качестве единого целого (включая специальный прицеп).  ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21084,17831,101,'Правостороннее движение. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21085,17832,101,'Левостороннее движение.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21086,17833,101,'Преднамеренное приведение транспортного средства в неподвижное состояние на время более 5 минут, если это не связано с посадкой, высадкой пассажиров или загрузкой, разгрузкой транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21087,17834,101,'Преднамеренное приведение транспортного средства в неподвижное состояние на время более 5 минут, за исключением случаев предупреждения столкновения с другим участником дорожного движения или каким-либо препятствием, посадки, высадки пассажира и (или) загрузки, разгрузки транспортного средства, а также других случаев, предусмотренных законодательством. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21088,17835,101,'Лицам от 18 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21089,17836,101,'Лицам от 19 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21090,17837,101,'Лицам от 20 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21091,17838,101,'Лицам от 21 года.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21092,17839,101,'В течение 15 дней.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21093,17840,101,'В течение 10 дней. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21094,17841,101,'В течение 20 дней. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21095,17842,101,'Собственник или пользователь транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21096,17843,101,'Организация, которая продала транспортное средство.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21097,17844,101,'Организация, которая провела последний годовой технический осмотр транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21098,17845,101,'Все перечисленные лица и организации.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21099,17846,101,'Исправность тормозной системы и рулевого управления.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21100,17847,101,'Соответствие остаточной высоты рисунка протектора шин установленным нормам.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21101,17848,101,'Все перечисленное.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21102,17849,101,'Служащим Полиции для перемещения в медицинское учреждение лиц, нуждающихся в срочной медицинской помощи,','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21103,17850,101,'Медицинским работникам, которые в целях оказания медицинской помощи следуют в том же направлении (с согласия водителя),','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21104,17851,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21105,17852,101,'Немедленно остановить транспортное средство. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21106,17853,101,'Включить аварийную световую сигнализацию.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21107,17854,101,'Не перемещать связанные с аварией предметы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21108,17855,101,'Выполнить все перечисленные действия.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21109,17856,101,'Удостоверение на право управления транспортным средством данной категории и регистрационные документы транспортного средства. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21110,17857,101,'Доверенность, в случае управления транспортного средства, принадлежащего другому лицу.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21111,17858,101,'Все перечисленные документы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21112,17859,101,'Обозначенная разметкой продольная полоса проезжей части, ширина которой достаточна для движения транспортных средств в один ряд.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21113,17860,101,'Обозначенная или не обозначенная разметкой продольная полоса проезжей части, ширина которой достаточна для движения транспортных средств в один ряд.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21114,17861,101,'Масса снаряженного и заправленного транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21115,17862,101,'Масса нагруженного, снаряженного и заправленного транспортного средства с водителем, пассажирами и грузом. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21116,17863,101,'Лицо, имеющее полномочия на регулирование дорожного движения и осуществляющее это регулирование в установленном законодательством порядке. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21117,17864,101,'Любой участник дорожного движения (водитель, пассажир или пешеход), который выполняет регулирующие действия в случае необходимости. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21118,17865,101,'Все перечисленные лица. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21119,17866,101,'Приравнивается к водителю. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21120,17867,101,'Не приравнивается к водителю.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21121,17868,101,'Ситуация, возникшая вследствие действия и (или) бездействия участника движения, при которой создается реальная угроза дорожно-транспортного происшествия.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21122,17869,101,'Ситуация, возникшая вследствие действия и (или) бездействия участника движения и (или) регулировщика, при которой создается реальная угроза дорожно-транспортного происшествия.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21123,17870,101,'Период времени осенью и зимой — с 20:00 вечера до 8:00 утра, весной и летом — с 22:00 вечера до 6:00 утра.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21124,17871,101,'Период времени между концом вечерних сумерек и началом утренних сумерек.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21125,17872,101,'Время отсутствия солнечного освещения.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21126,17873,101,'Автомобиль, своей структурой и обустроенностью предназначенный для безопасной и удобной перевозки пассажиров и груза, имеющий более 8-и мест для сидения пассажиров','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21127,17874,101,'Автомобиль, своей структурой и обустроенностью предназначенный для безопасной и удобной перевозки пассажиров и груза, имеющий 8 и более мест для сидения пассажиров.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21128,17875,101,'Автомобиль, своей структурой и обустроенностью предназначенный для безопасной и удобной перевозки пассажиров и груза, имеющий не более 8-и мест для сидения пассажиров. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21129,17876,101,'Автомобиль, своей структурой и обустроенностью предназначенный для безопасной и удобной перевозки пассажиров и груза, имеющий не более 4-х мест для сидения пассажиров (за исключением детей до 12 лет).','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21130,17877,101,'Инвалиды, передвигающиеся со скоростью пешехода в инвалидной коляске с двигателем. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21131,17878,101,'Лица, ведущие велосипед, мопед или мотоцикл','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21132,17879,101,'Все перечисленные лица.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21133,17880,101,'С момента положительной сдачи практических экзаменов по вождению транспортных средств в подразделениях Дорожной полиции.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21134,17881,101,'С момента получения удостоверения на право вождения.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21135,17882,101,'Лицам от 16 лет.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21136,17883,101,'Лицам от 17 лет','2025-11-06 21:40:30','2025-11-06 21:40:30');
