INSERT INTO answer_translations VALUES(21151,17898,101,'17 лет','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21152,17899,101,'Приведение транспортного средства в неподвижное состояние в связи с требованием пассажира','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21153,17900,101,'Приведение транспортного средства в преднамеренное неподвижное состояние на время более 5 минут, если это не связано с посадкой, высадкой пассажиров или загрузкой, разгрузкой транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21154,17901,101,'Приведение транспортного средства в преднамеренное неподвижное состояние на время до 5 минут или на время, необходимое для посадки или высадки пассажира и (или) загрузки, разгрузки транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21155,17902,101,'Транспортное средство (трамвай, тролейбус, автобус), имеющее места остановки (остановки), движущееся по маршрутам, перевозящее пассажиров и (или) багажи, а также легковой автомобиль такси. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21156,17903,101,'Транспортное средство (трамвай, троллейбус, автобус), имеющее места остановки (остановки), движущееся по маршрутам, перевозящее пассажиров и (или) багажи. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21157,17904,101,'Транспортное средство, движущееся по туристическому маршруту, перевозящее пассажиров и (или) багажи. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21158,17905,101,'Максимальная масса снаряженного и заправленного транспортного средства.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21159,17906,101,'Масса нагруженного, снаряженного и заправленного транспортного средства с водителем, пассажирами и грузом, которую предприятие-изготовитель установило в качестве максимально допустимой.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21160,17907,101,'Масса нагруженноготранспортного средства с водителем, пассажирами и грузом, которую предприятие-изготовитель установило в качестве максимально допустимой.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21161,17908,101,'950 килограмм.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21162,17909,101,'850 килограмм.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21163,17910,101,'750 килограмм.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21164,17911,101,'Место на определенном отрезке маршрута транспортного средства общего пользования, предусмотренное для посадки и высадки пассажиров и оборудованное соответствующими дорожными знаками.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21165,17912,101,'Место на определенном отрезке маршрута транспортного средства общего пользования, предусмотренное для посадкивысадки пассажиров. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21166,17913,101,'Удостоверение на управление транспортных средств категории \"B\" или \"C\" или подкатегории \"C1\" и им исполнился 21 год. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21167,17914,101,'Удостоверение на управление транспортных средств категории \"B\" или \"C\" или подкатегории \"B1\" и им исполнилось 18 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21168,17915,101,'Удостоверение на управление транспортных средств категорий \"AB\" или подкатегорий \"A1B1\" и им исполнилось 18 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21169,17916,101,'Удостоверение на управление транспортных средств категории \"B\" или \"C\" или подкатегории \"C1\" и им исполнилось 20 лет. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
