INSERT INTO answer_translations VALUES(21202,17949,101,'Водитель не должен продолжать или возобновлять движение или осуществлять какой-либо маневр, если это может вынудить водителей других транспортных средств изменить направление движения или скорость','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21203,17950,101,'Водитель не должен продолжать или возобновлять движение или осуществлять какой-либо маневр, если это может вынудить водителей других транспортных средств внезапно изменить направление движения или скорость.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21204,17951,101,'Безоговорочно остановить транспортное средство.','2025-11-06 21:40:30','2025-11-06 21:40:30');
