INSERT INTO answer_translations VALUES(21209,17956,101,'Двух','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21210,17957,101,'Четырех','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21211,17958,101,'Выезд транспортного средства из занимаемой полосы движения, с сохранением первоначального направления движения. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21212,17959,101,'Выезд транспортного средства из занимаемого ряда обозначенной разметкой полосы движения, с сохранением первоначального направления движения. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
