INSERT INTO answer_translations VALUES(21215,17962,101,'Маневр транспортного средства, осуществляемый с целью выезда на другую дорогу или прилегающую территорию.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21216,17963,101,'Управление транспортным средством по встречному направлению','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21217,17964,101,'маневр, осуществляемый с целью изменения направления движения транспортного средства на противоположное','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21218,17965,101,'Обгон одного или нескольких транспортных средств, находящихся в движении, без выезда с занимаемой полосы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21219,17966,101,'Обгон одного или нескольких транспортных средств, находящихся в движении, в связи с выездом с занимаемой полосы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21220,17967,101,'Момент начала движения транспортного средства с места стоянки или остановки в связи с перестроением на соседнюю полосу движения или без него. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21221,17968,101,'Момент начала движения транспортного средства с места стоянки или остановки в связи с перестроением на соседнюю полосу движения.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21222,17969,101,'Начало движения транспортного средства (связанное с выездом на соседнюю полосу движения), выполнение перестроения, изменения направления движения, остановки (с перестроением) и разворота.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21223,17970,101,'Начало движения транспортного средства, выполнение перестроения, изменения направления движения, остановки и разворота.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21224,17971,101,'конструктивно выделенный элемент дороги, разделяющий смежные проезжие части дороги, не предназначенный для движения и остановки транспортных средств и пешеходов. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21225,17972,101,'Элемент дороги, выделенный конструктивно и (или) соответствующей разметкой, разделяющий смежные проезжие части, не предназначенный для движения и остановки транспортных средств и пешеходов.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21226,17973,101,'погонщик, ведущий по дороге вьючных и (или) верховых животных или скот','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21227,17974,101,'погонщик, ведущий вьючных и (или) верховых животных или скот ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21228,17975,101,'Элемент дороги, примыкающий к проезжей части, предназначенный для движения пешеходов в установленном законодательством порядке.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21229,17976,101,'Элемент дороги, каким-либо образом отделенный от проезжей части, предназначенный для движения пешеходов в установленном законодательством порядке.','2025-11-06 21:40:30','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21230,17977,101,'Оба указанных случая.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21231,17978,101,'Остаточная высота протектора шин легкового автомобиля составляет 1.8 мм. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21232,17979,101,'Нарушена герметичность гидравлического тормозного привода. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21233,17980,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21234,17981,101,'Остаточная высота протектора шин грузового автомобиля составляет 1.6 мм.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21235,17982,101,'Не действует манометр пневматического тормозного привода','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21236,17983,101,'В обоих случаях. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21237,17984,101,'В рулевом управлении имеются не предусмотренные конструкцией перемещения деталей и узлов или резьбовые соединения не затянуты.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21238,17985,101,'В грузовом автомобиле отсутствует огнетушитель. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21239,17986,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21240,17987,101,'Не работают в установленном режиме внешние световые приборы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21241,17988,101,'Остаточная высота протектора шин мотоцикла составляет 0.6 мм','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21242,17989,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21243,17990,101,'Задние противотуманные фонари подключены к светодиодным стоп-сигналам транспортного средства. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21244,17991,101,'Не работает указатель температуры охлаждающей жидкости двигателя.','2025-11-06 21:40:30','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(21245,17992,101,'В обоих случаях. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21246,17993,101,'Двигатель работает с перебоями. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21247,17994,101,'Шины имеют обнажающие корд местные повреждения.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21248,17995,101,'Не работают приборы внутреннего освещения салона легкового автомобиля.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21249,17996,101,'Во всех перечисленных случаях','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21250,17997,101,'На мотоцикле без бокового прицепа отсутствует знак \"Аварийная остановка\". ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21251,17998,101,'Шины по размеру или допустимой нагрузке не соответствуют модели транспортного средства','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21252,17999,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21253,18000,101,'Отсутствует хотя бы один болт крепления обода колеса','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21254,18001,101,'На одну ось установлены шины с различными рисунками протектора. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21255,18002,101,'В обоих случаях. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21256,18003,101,'Отсутствуют предусмотренные конструкцией подголовники сидений. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21257,18004,101,'На одну ось установлены новые и восстановленные шины.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21258,18005,101,'В обоих случаях. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21259,18006,101,'Содержание вредных веществ в отработавших газах превышает нормы, установленные законодательством РА.','2025-11-06 21:40:30','2026-03-11 00:17:55');
INSERT INTO answer_translations VALUES(21260,18007,101,'На мотоцикле отсутствуют предусмотренные конструкцией подножки. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21261,18008,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21262,18009,101,'Нарушена герметичность системы вентиляции картера двигателя.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21263,18010,101,'Нарушена герметичность системы питания двигателя.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21264,18011,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21265,18012,101,'Нарушена герметичность системы вентиляции картера двигателя. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21266,18013,101,'На одну ось установлены новые морозостойкие и неморозостойкие шины. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21267,18014,101,'В обоих случаях','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21268,18015,101,'Не работают предусмотренные конструкцией стеклоомыватели.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21269,18016,101,'Допустимый уровень внешнего шума двигателя превышает установленные стандартом нормы.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21270,18017,101,'В обоих случаях','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21271,18018,101,'Двигатель работает с перебоями. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21272,18019,101,'Задние противотуманные фонари не подключены к светодиодным стоп-сигналам.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21273,18020,101,'Не работают предусмотренные конструкцией стеклоомыватели.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21274,18021,101,'Во всех перечисленных случаях','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21275,18022,101,'Установлены предметы или объекты, создающие опасность причинения вреда участникам дорожного движения.','2025-11-06 21:40:30','2026-03-11 00:16:54');
