INSERT INTO answer_translations VALUES(21278,18025,101,'Имеется люфт в соединениях рамы мотоцикла с рамой бокового прицепа.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21279,18026,101,'В передней части установлены противотуманные фары с огнями желтого цвета.','2025-11-06 21:40:30','2025-11-06 21:40:30');
