INSERT INTO answer_translations VALUES(21281,18028,101,'В грузовом автомобиле отсутствует медицинская аптечка. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21282,18029,101,'В передней части установлены светоотражающие приспособления белого цвета.','2025-11-06 21:40:30','2025-11-06 21:40:30');
