INSERT INTO answer_translations VALUES(21296,18043,101,'Отсутствуют предусмотренные конструкцией дуги безопасности. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21297,18044,101,'Остаточная высота протектора шин составляет 1.6 мм. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21298,18045,101,'В обоих случаях. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21299,18046,101,'В передней части установлены указатели поворота с огнями желтого цвета. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21300,18047,101,'Отсутствует хотя бы один болт крепления обода колеса. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21301,18048,101,'В обоих случаях. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
