INSERT INTO answer_translations VALUES(21332,18079,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21333,18080,101,'В автобусе отсутствует знак \"Аварийная остановка\". ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21334,18081,101,'В задней части установлены фонари освещения учетного номерного знака с огнями белого цвета. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21335,18082,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21336,18083,101,'Остаточная высота рисунка протектора шин прицепа легкового автомобиля менее 1,6 мм.','2025-11-06 21:40:30','2026-03-11 00:18:22');
INSERT INTO answer_translations VALUES(21337,18084,101,'В задней части установлены указатели поворота с огнями оранжевого цвета.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21338,18085,101,'В обоих случаях.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21339,18086,101,'Нарушена герметичность гидравлического тормозного привода. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21340,18087,101,'В задней части установлены указатели поворота с огнями белого цвета.','2025-11-06 21:40:30','2025-11-06 21:40:30');
