INSERT INTO answer_translations VALUES(21610,18357,101,'Разрешается, если эта полоса расположена у правого края проезжей части, и не отделена от остальной проезжей части сплошной линией разметки.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21611,18358,101,'Запрещается','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21612,18359,101,'Разрешается. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21613,18360,101,'Запрещается обгон всеми видами транспортных средств, за исключением тихоходных транспортных средств, гужевых повозок, мотоциклов без бокового прицепа, мопедов и велосипедов.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21614,18361,101,'Разрешается обгон грузовыми автомобилями с разрешенной максимальной массой не более 3.5 т. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21615,18362,101,'Обгон разрешен, если скорость обгоняемого транспортного средства не превышает 30 км/ч. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21616,18363,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21617,18364,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21618,18365,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21619,18366,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21620,18367,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21621,18368,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21622,18369,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21623,18370,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21624,18371,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21625,18372,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21626,18373,101,'Дорога, не имеющая сквозного проезда. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21627,18374,101,'Направление движения к объекту, расположенному в населенном пункте.','2025-11-06 21:40:30','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(21628,18375,101,'Конец дополнительной полосы на подъеме или полосе разгона.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21629,18376,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21630,18377,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21631,18378,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21632,18379,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21633,18380,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21634,18381,101,'Механическим транспортным средствам..','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21635,18382,101,'Всем транспортным средствам. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21636,18383,101,'Автомобилям и мотоциклам. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21637,18384,101,'Тем транспортным средствам, максимальная скорость которых превышает 40 км/ч. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21638,18385,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21639,18386,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21640,18387,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21641,18388,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21642,18389,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21643,18390,101,'Вререди участок дороги, имеющий неровность на проезжей части. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21644,18391,101,'Впереди участок дороги с тремя полосами для движения в данном направлении.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21645,18392,101,'На механиеском транспортном средстве установлены шины с шипами. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21646,18393,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21647,18394,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
