INSERT INTO answer_translations VALUES(21650,18397,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21651,18398,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21652,18399,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21653,18400,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21654,18401,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21655,18402,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21656,18403,101,'Место стоянки через 30 м для автомобилей с опознавательым знаком \"Инвалид\". ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21657,18404,101,'Место стоянки в зоне 30 м для транспортных средств, за исключением мотоколясок.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21658,18405,101,'Место стоянки в зоне 30 м для мотоколясок и автомобилей с опознавательым знаком \"Инвалид\". ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21659,18406,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21660,18407,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21661,18408,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21662,18409,101,'Механических транспортных средств. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21663,18410,101,'Только автомобилей.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21664,18411,101,'Только легковых автомобилей. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21665,18412,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21666,18413,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21667,18414,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21668,18415,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21669,18416,101,'5','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21670,18417,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21671,18418,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21672,18419,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21673,18420,101,'4','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21674,18421,101,'Главная дорога продолжается от перекрестка налево. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21675,18422,101,'Главная дорога продолжается прямо через перекресток и налево. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21676,18423,101,'В зоне действия таблички водители должны передвигаться с большей скоростью, чем указано на знаке. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21677,18424,101,'В зоне действия таблички водителям рекомендуется передвигаться с указанной на знаке скоростью. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21678,18425,101,'Только A и C','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21679,18426,101,'Только B.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21680,18427,101,'Только C.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21681,18428,101,'Все. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21682,18429,101,'Продолжить движение прямо','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21683,18430,101,'Перестроиться на полосу встречного движения.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21684,18431,101,'Через 150-300 метров после знака начинается сужение дороги с правой стороны протяженностью 100 м. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21685,18432,101,'Через 100 метров после знака начинается сужение дороги с правой стороны.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21686,18433,101,'Только направо и налево.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21687,18434,101,'Только прямо. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21688,18435,101,'Прямо и в обратном направлении.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21689,18436,101,'Остановка запрещена по субботам. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21690,18437,101,'Остановка запрещена по воскресеньям. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21691,18438,101,'Остановка запрещена по субботам-воскресеньям и по праздничным дням.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21692,18439,101,'Остановка запрещена во время снегопада.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21693,18440,101,'1','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21694,18441,101,'2','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21695,18442,101,'3','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21696,18443,101,'Из-за ремонтных работ выезд на обочину опасен.','2025-11-06 21:40:30','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(21697,18444,101,'На дороге ведутся ремонтные работы. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21698,18445,101,'Проехать перекресток, соблюдая правила безопасности.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21699,18446,101,'Уступил дорогу транспортным средствам, движущимся по пересекаемой дороге.','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21700,18447,101,'Остановиться перед знаком и уступил дорогу транспортным средствам, движущимся по пересекаемой дороге. ','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO answer_translations VALUES(21701,18448,101,'Ни одного из знаков. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21702,18449,101,'Только первого.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21703,18450,101,'Только четвертого. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21704,18451,101,'На перекрестке следует двигаться налево или направо. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21705,18452,101,'На пересекаемой дороге организовано реверсивное движение. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21706,18453,101,'На пересекаемой дороге организовано одностороннее движение. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21707,18454,101,'Обязан. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21708,18455,101,'Не обязан. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21709,18456,101,'При гололедице следует передвигаться со скоростью 40 км/ч.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21710,18457,101,'При мокром покрытии дороги следует передвигаться со скоростью не более 40 км/ч. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21711,18458,101,'Остановка запрещена по субботам. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21712,18459,101,'Остановка запрещена по воскресеньям. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21713,18460,101,'Остановка запрещена в рабочие дни.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21714,18461,101,'На данном участке дороги разрешается передвигаться со скоростью не более 50 км/ч. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21715,18462,101,'На данном участке дороги рекомендуется передвигаться со скоростью 50 км/ч. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21716,18463,101,'Движение разрешено только с указанной на знаке скоростью или более.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21717,18464,101,'1','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21718,18465,101,'2','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21719,18466,101,'3','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21720,18467,101,'При мокром покрытии дороги рекомендуется передвигаться со скоростью 40 км/ч. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21721,18468,101,'При мокром покрытии дороги разрешается передвигаться со скоростью не более 40 км/ч.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21722,18469,101,'На левую сторону дороги.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21723,18470,101,'На правую сторону дороги.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21724,18471,101,'На ту сторону дороги, где они установлены.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21725,18472,101,'Только \"a\"','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21726,18473,101,'Только \"b\". ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21727,18474,101,'\"a\" и \"b\".','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21728,18475,101,'Необходимо остановиться около первого знака. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21729,18476,101,'Необходимо остановиться перед вторым знаком. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21730,18477,101,'Необходимо остановиться на расстоянии не менее 5 метров от первой железнодорожной линии. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21731,18478,101,'Может перестроиться на правую полосу движения и после этого совершить правый поворот.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21732,18479,101,'Может приблизиться к перекрестку, затем совершить правый поворот.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21733,18480,101,'Оба ответа верны.','2025-11-06 21:40:31','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(21734,18481,101,'Имеет право. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21735,18482,101,'Не имеет право.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21736,18483,101,'Не обязан, поскольку знак запрещает остановку. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21737,18484,101,'Обязан.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21738,18485,101,'Проехать железнодорожный переезд, соблюдая меры безопасности.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21739,18486,101,'Проехать железнодорожный переезд, не останавливаясь. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21740,18487,101,'Остановиться перед знаком и, соблюдая меры безопасности, проехать многорельсовый железнодорожный переезд.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21741,18488,101,'Границы полос, выделенных для попутно двигающихся транспортных средств.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(21742,18489,101,'Границу полосы проезжей части с реверсивным движением. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
