INSERT INTO answer_translations VALUES(22316,19063,101,'Правила в данном случае не регулируются. Водители проедут, проявляя взаимное уважение ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22317,19064,101,'Только при выполнении поворота налево','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22318,19065,101,'Только при выполнении поворота направо','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22319,19066,101,'В обоих случаях аналогично','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22320,19067,101,'Пешеходам и велосипедистам','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22321,19068,101,'Только пешеходам','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22322,19069,101,'Только водителю легкового автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22323,19070,101,'Водителям легкового автомобиля и автобуса','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22324,19071,101,'Никому','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22325,19072,101,'Он должен считать, что находитесь на второстепенной дороге','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22326,19073,101,'Он должен руководствоваться правилами проезда перекрестка равнозначных дорог','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22327,19074,101,'Всем водителям','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22328,19075,101,'Только водителю грузового автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22329,19076,101,'Только водителю легкового автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22330,19077,101,'Водителю легкового автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22331,19078,101,'Водителям легкового автомобиля и автобуса','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22332,19079,101,'Всем водителям','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22333,19080,101,'Первым выполните маневр ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22334,19081,101,'Должны уступить другим водителям','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22335,19082,101,'Остановиться и подождать, пока не загорится зелёный разрешающий сигнал','2025-11-06 21:40:31','2025-11-06 21:40:31');
