INSERT INTO answer_translations VALUES(22337,19084,101,'Уступить водителю трамвая','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22338,19085,101,'Мы можем проехать перекресток первыми','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22339,19086,101,'Должны уступить дорогу','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22340,19087,101,'Водителю грузового автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22341,19088,101,'Водителю легкового автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22342,19089,101,'Обоим водителям','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22343,19090,101,'Обязаны','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22344,19091,101,'Не обязаны','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22345,19092,101,'Обязаны, поскольку он приблизился к нам с правой стороны','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22346,19093,101,'Не обязаны, поскольку дорога с твердым покрытием является главной по отношению к дороге без покрытия','2025-11-06 21:40:31','2025-11-06 21:40:31');
