INSERT INTO answer_translations VALUES(22411,19158,101,'Дорога с твердым покрытием (асфальтобетон, цементобетонным, каменные материалы и т. д.) по отношению к грунтовой ','2025-11-06 21:40:31','2025-11-06 21:40:31');
