INSERT INTO answer_translations VALUES(22415,19162,101,'Синему, зеленому и белому автомобилям. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22416,19163,101,'Белому, синему и желтому автомобилям. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
