INSERT INTO answer_translations VALUES(22419,19166,101,'Водитель легкового автомобиля.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22420,19167,101,'Водитель автомобиля','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22421,19168,101,'Водитель трамвая.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22422,19169,101,'Со стороны левого бока - налево и в обратном направлении. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22423,19170,101,'Со стороны правого бока - только направо. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22424,19171,101,'Со стороны левого бока - во всех направлениях.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22425,19172,101,'Со спины - только направо.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22426,19173,101,'Мотоцикл','2025-11-06 21:40:31','2025-11-06 21:40:31');
