INSERT INTO answer_translations VALUES(22432,19179,101,'Водитель автомобиля.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22433,19180,101,'Синему и зеленому автомобилям. Запрещено красному, желтому и белому. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22434,19181,101,'Синему, красному и зеленому автомобилям. Запрещено желтому и белому. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22435,19182,101,'Только красному автомобилю. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22436,19183,101,'Всем транспортным средствам.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22437,19184,101,'Красному и зеленому автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
