INSERT INTO answer_translations VALUES(22439,19186,101,'Направо, в первый проезд. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22440,19187,101,'Направо, во второй проезд. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
