INSERT INTO answer_translations VALUES(22443,19190,101,'Прямо и направо, в первый проезд.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22444,19191,101,'Только налево.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22445,19192,101,'Прямо и налево. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22446,19193,101,'Прямо и направо','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22447,19194,101,'Только направо. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22448,19195,101,'Со стороны груди и спины - только направо.','2025-11-06 21:40:31','2025-11-06 21:40:31');
