INSERT INTO answer_translations VALUES(22451,19198,101,'Должен уступить дорогу. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22452,19199,101,'Имеет право на первоочередное движение. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22453,19200,101,'Желтому и красному автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22454,19201,101,'Зеленому, красному и белому автомобилям. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22455,19202,101,'Белому и зеленому автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22456,19203,101,'Красном','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22457,19204,101,'Зеленом','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22458,19205,101,'Любом','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22459,19206,101,'Разрешает начинать движение. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22460,19207,101,'Запрещает движение и предупреждает, что вскоре будет включен зеленый сигнал.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22461,19208,101,'К перекрестку приближается транспортное средство, подающее специальные звуковые или проблесковые световые сигналы. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22462,19209,101,'На левом рисунке.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22463,19210,101,'На правом рисунке.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22464,19211,101,'Обязан','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22465,19212,101,'Не обязан. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22466,19213,101,'По всей ширине проезжей части. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22467,19214,101,'По полосам проезжей части, направление движения по которым может изменяться на противоположное. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22468,19215,101,'Только по полосам, предназначенным для движения транспортных средств общего пользования. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22469,19216,101,'Во всех направлениях. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22470,19217,101,'Только налево.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22471,19218,101,'Трамваю, желтому и красному автомобилям. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22472,19219,101,'Желтому и красному автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22473,19220,101,'Всем транспортным средствам.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22474,19221,101,'Всем транспортным средствам.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22475,19222,101,'Мотоциклу','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22476,19223,101,'Автомобилю и мотоциклу. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22477,19224,101,'Прямо и направо.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22478,19225,101,'Только прямо.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22479,19226,101,'Водитель автобуса.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22480,19227,101,'Водитель трамвая. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22481,19228,101,'Зеленому и белому автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22482,19229,101,'Белому, синему и зеленому автомобилям. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22483,19230,101,'Белому и желтому автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22484,19231,101,'Зеленому и желтому автомобилям.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22485,19232,101,'По всей ширине проезжей части. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22486,19233,101,'Со скоростью не более 50 км/ч. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22487,19234,101,'По полосе, над которой он расположен.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22488,19235,101,'Информирует, что въезд на перекресток запрещен.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22489,19236,101,'Разрешает движение и информирует, что время его действие истекает и вскоре будет включен запрещающий сигнал.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22490,19237,101,'Трамвай, красный автомобиль, зеленый автомобиль. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22491,19238,101,'Красный автомобиль, трамвай одновременно с зеленым автомобилем. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22492,19239,101,'Трамвай одновременно с зеленым автомобилем, красный автомобиль. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22493,19240,101,'Автомобили и мотоцикл','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22494,19241,101,'Все транспортные средства. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22495,19242,101,'Автомобили и трамвай.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22496,19243,101,'Прямо и налево. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22497,19244,101,'Во всех направлениях. ','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22498,19245,101,'Сине-желтому автомобилю - налево','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22499,19246,101,'Сине-желтому автомобилю - прямо, красному автомобилю - прямо и направо.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22500,19247,101,'Красному автомобилю.','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22501,19248,101,'Прямо и направо, в первый проезд','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO answer_translations VALUES(22502,19249,101,'Направо, в первый проезд.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22503,19250,101,'Направо, во второй проезд. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22504,19251,101,'Направо, в первый и второй проезды.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22505,19252,101,'Красный автомобиль. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22506,19253,101,'Синий автомобиль. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22507,19254,101,'Зеленый автомобиль. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22508,19255,101,'На левом рисунке. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22509,19256,101,'На правом рисунке.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22510,19257,101,'На обоих рисунках. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22511,19258,101,'Первым','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22512,19259,101,'Вторым','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22513,19260,101,'Третьим','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22514,19261,101,'Последним','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22515,19262,101,'Для регулирования движения трамваев и троллейбусов.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22516,19263,101,'Для регулирования движения только трамваев. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22517,19264,101,'Для регулирования движения трамваев, а также других транспортных средств общего пользования, движущихся по обособленной полосе. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22518,19265,101,'Первым','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22519,19266,101,'Вторым','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22520,19267,101,'Сине-желтому автомобилю - прямо, красному - направо.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22521,19268,101,'Красному автомобилю - прямо и направо, сине-желтому - прямо','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22522,19269,101,'Обоим автомобилям - только прямо','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22523,19270,101,'Красному автомобилю.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22524,19271,101,'Мотоциклу','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22525,19272,101,'Трамваю и красному автомобилю.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22526,19273,101,'Трамваю','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22527,19274,101,'Синему автомобилю.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22528,19275,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22529,19276,101,'Разрешается с целью обгона.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22530,19277,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22531,19278,101,'Разрешается при отсутствии встречных транспортных средств.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22532,19279,101,'Легковой автомобиль — прямо, патрульный автомобиль — во всех направлениях, автобус — только направо.','2025-11-06 21:40:32','2026-03-11 00:18:22');
INSERT INTO answer_translations VALUES(22533,19280,101,'Только патрульный автомобиль - во всех направлениях.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22534,19281,101,'Патрульный автомобиль — во всех направлениях, автобус — только направо.','2025-11-06 21:40:32','2026-03-11 00:18:22');
INSERT INTO answer_translations VALUES(22535,19282,101,'Светофор неисправен. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22536,19283,101,'При проезде перекрестка водители должны руководствоваться требованиями дорожного знака. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22537,19284,101,'Водители должны дождаться разрешающего сигнала светофора. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22538,19285,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22539,19286,101,'Разрешается, если автобус движется со скоростью 30 км/ч. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22540,19287,101,'Разрешается, если нет транспортных средств, двигающихся навстречу. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22541,19288,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22542,19289,101,'Автобус','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22543,19290,101,'Мотоцикл и легковой автомобиль.','2025-11-06 21:40:32','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(22544,19291,101,'Водитель грузового автомобиля.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22545,19292,101,'Водители автобуса и грузового автомобиля. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22546,19293,101,'Водители легкового автомобиля и автобуса.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22547,19294,101,'Водитель автобуса. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22548,19295,101,'Трамвай, легковой автомобиль, автобус.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22549,19296,101,'Легковой автомобиль, трамвай, автобус. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22550,19297,101,'Легковой автомобиль, автобус, трамвай.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22551,19298,101,'Да','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22552,19299,101,'Нет','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22553,19300,101,'Да, если он движется по обозначенному маршруту. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22554,19301,101,'Направо, в первый проезд. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22555,19302,101,'Направо, в первый и второй проезд.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22556,19303,101,'Налево, в первый проезд.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22557,19304,101,'Только велосипедисту. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22558,19305,101,'Только пешеходам. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22559,19306,101,'Пешеходам и велосипедисту. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22560,19307,101,'Может продолжать движение без остановки. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22561,19308,101,'Трамвай, автобус, грузовой автомобиль, мотоцикл. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22562,19309,101,'Автобус, грузовой автомобиль, трамвай, мотоцикл. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22563,19310,101,'Автобус, трамвай и мотоцикл, грузовой автомобиль.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22564,19311,101,'Никого','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22565,19312,101,'Два трамвая','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22566,19313,101,'Только А','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22567,19314,101,'Водитель автобуса','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22568,19315,101,'Водитель легкового автомобиля','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22569,19316,101,'Уступите дорогу трамваю','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22570,19317,101,'Проедете перекресток первыми','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22571,19318,101,'Въехать на перекресток и, уступив дорогу легковому автомобилю, проехать перекресток ','2025-11-06 21:40:32','2025-11-06 21:40:32');
