INSERT INTO answer_translations VALUES(22575,19322,101,'Мотоцикла','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22576,19323,101,'Оба водителя','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22577,19324,101,'Никто','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22578,19325,101,'Обязаны','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22579,19326,101,'Не обязаны','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22580,19327,101,'Да, не препятствуя пешеходам','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22581,19328,101,'Нет','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22582,19329,101,'Не обязаны','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22583,19330,101,'Обязаны.','2025-11-06 21:40:32','2026-03-11 00:16:54');
