INSERT INTO answer_translations VALUES(22724,19471,101,'Две или три полосы.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22725,19472,101,'Три полосы.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22726,19473,101,'Четыре или более полос. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22727,19474,101,'Предупреждают водителя о приближении к опасному участку дороги.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22728,19475,101,'Предупреждают о приближении к концу полосы движения. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22729,19476,101,'Указывают направление опасного поворота дороги. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22730,19477,101,'1-ая линия.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22731,19478,101,'2-ая линия','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22732,19479,101,'3-я линия. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22733,19480,101,'2-ая и 3-я линии.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22734,19481,101,'3-я и 4-ая линии.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22735,19482,101,'На проезжей части. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22736,19483,101,'У края проезжей части. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22737,19484,101,'У края проезжей части или по верху бордюров.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22738,19485,101,'Только по верху бордюров.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22739,19486,101,'\"Остановка запрещена\". ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22740,19487,101,'\"Стоянка запрещена\". ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22741,19488,101,'\"Стоянка запрещена по нечетным числам месяца\".','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22742,19489,101,'Всем механическим транспортным средствам.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22743,19490,101,'Транспортным средствам общего пользования и такси.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22744,19491,101,'Только велосипедам.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22745,19492,101,'Только транспортным средствам общего пользования. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22746,19493,101,'Показывает места, где указаны способы постановки механических транспортных средств на околотротуарной стоянке.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22747,19494,101,'Показывает места, где запрещена остановка механических транспортных средств.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22748,19495,101,'Показывает пункты остановок транспортных средств общего пользования и места стоянки такси.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22749,19496,101,'Сужение проезжей части, где уменьшается количество полос движения в данном направлении.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22750,19497,101,'Место, где водитель должен остановиться в случае необходимости, чтобы уступить дорогу транспортным средствам, движущимся по пересекаемой дороге. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22751,19498,101,'Приближение к месту, где запрещена остановка.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22752,19499,101,'Разрешается только для остановки. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22753,19500,101,'Разрешается при движении задним ходом','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22754,19501,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22755,19502,101,'Остановиться у \"Стоп-линии\" а затем возобновить движение.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22756,19503,101,'Продолжить движение через перекресток без остановки.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22757,19504,101,'Пешеходный переход. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22758,19505,101,'Место, где велосипедная дорожка пересекает проезжую часть. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22759,19506,101,'Место перегона скота. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22760,19507,101,'У разметки','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22761,19508,101,'На разметке.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22762,19509,101,'На расстоянии не меньше 5 м от разметки.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22763,19510,101,'Полосу для движения транспортных средств общего пользования. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22764,19511,101,'Полосу для движения специальных автомобилей.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22765,19512,101,'Показывает границы полос, на которых осуществляется реверсивное регулирование.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22766,19513,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22767,19514,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22768,19515,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22769,19516,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22770,19517,101,'Границу между проезжей частью и обочиной.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22771,19518,101,'Границу между полосой разгона и основной полосой проезжей части. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22772,19519,101,'Границу между полосой торможения и основной полосой проезжей части.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22773,19520,101,'Красному','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22774,19521,101,'Обоим автомобилям. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22775,19522,101,'Ни одному. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22776,19523,101,'Желтому, обозначенному опознавательным знаком \"Инвалид\"','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22777,19524,101,'На левом рисунке.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22778,19525,101,'На обоих рисунках.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22779,19526,101,'На правом рисунке. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22780,19527,101,'Круговые движения руки (днем - с лоскутом яркого цвета или каким-либо хорошо видимым предметом, ночью - с факелом или фонарем). ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22781,19528,101,'Поднятая над головой рука с жезлом или красным флагом.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22782,19529,101,'Вытянутая вперед рука.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22783,19530,101,'Покачивание вверх и вниз вытянутой вперед рукой. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22784,19531,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22785,19532,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22786,19533,101,'1,5 м.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22787,19534,101,'2,5 м. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22788,19535,101,'5 м.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22789,19536,101,'10 м. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22790,19537,101,'Непосредственно у \"Стоп-линии\" и (или) знака. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22791,19538,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22792,19539,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22793,19540,101,'Запрещается, так как расстояние между прерывистой линией разметки и остановившимся автомобилем менее 3 м. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22794,19541,101,'Запрещается по четным числам месяца. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22795,19542,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22796,19543,101,'Водитель синего автомобиля','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22797,19544,101,'Водитель красного автомобиля.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22798,19545,101,'Оба водителя нарушили. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22799,19546,101,'Оба водителя не нарушили.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22800,19547,101,'На обочинах дороги. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22801,19548,101,'На площадках для стоянки или за пределами дороги. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22802,19549,101,'На правой стороне проезжей части дороги, не препятствуя движению других транспортных средств.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22803,19550,101,'На левой стороне дороги, соблюдая меры безопасности движения.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22804,19551,101,'6 м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22805,19552,101,'5,5 м.','2025-11-06 21:40:32','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(22806,19553,101,'4м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22807,19554,101,'3.5 м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22808,19555,101,'2,5 м.','2025-11-06 21:40:32','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(22809,19556,101,'Не ближе 5 м от ближайшего рельса.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22810,19557,101,'Не ближе 7 м от ближайшего рельса. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22811,19558,101,'Не ближе 10 м от ближайшего рельса. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22812,19559,101,'15 м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22813,19560,101,'50 м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22814,19561,101,'100 м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22815,19562,101,'150 м','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22816,19563,101,'Водители красного автомобиля и мотоцикла.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22817,19564,101,'Водитель синего автомобиля','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22818,19565,101,'Водитель мотоцикла. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22819,19566,101,'Водители всех транспортных средств. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22820,19567,101,'Водитель легкового автомобиля.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22821,19568,101,'Водитель мотоцикла. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22822,19569,101,'Водитель автобуса.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22823,19570,101,'Водители мотоцикла и автобуса. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22824,19571,101,'Все водители.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22825,19572,101,'Не ближе 5 м от шлагбаума. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22826,19573,101,'Не ближе 3 м от шлагбаума. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22827,19574,101,'Непосредственно перед шлагбаумом. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22828,19575,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22829,19576,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22830,19577,101,'Номер дороги (маршрута). ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22831,19578,101,'Специальную полосу, предназначенную для движения транспортных средств общего пользования. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22832,19579,101,'Специальную полосу, предназначенную для движения транспортных средств категории \"А\". ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22833,19580,101,'Разрешается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22834,19581,101,'Запрещается','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22835,19582,101,'Разрешается, но поднявшись на тротуар. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22836,19583,101,'Запрещается. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22837,19584,101,'Разрешается во всех случаях. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22838,19585,101,'Разрешается для остановки с целью высадки пассажиров. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22839,19586,101,'Разрешается с целью обгона грузового автомобиля. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22840,19587,101,'Нижние края моста, тоннеля. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22841,19588,101,'Въезд в неосвещенные тоннели. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22842,19589,101,'Любой элемент дорожных сооружений, который создает опасность для движения.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22843,19590,101,'Продолжить движение','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22844,19591,101,'Замедлить движение, а, в случае необходимости, остановиться и продолжить движение, убедившись, что на переходе нет пешеходов. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22845,19592,101,'Остановиться и продолжить движение только в том случае, когда автобус возобновит движение.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22846,19593,101,'Никто','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22847,19594,101,'Водитель автобуса.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22848,19595,101,'Водитель легкового автомобиля','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22849,19596,101,'Оба водителя. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22850,19597,101,'С целью обгона или объезда. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22851,19598,101,'С целью поворота налево или разворота.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22852,19599,101,'В обоих вышеуказанных случаях. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22853,19600,101,'Ни один ответ не является правильным.','2025-11-06 21:40:32','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(22854,19601,101,'Останавливаться не обязательно. ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22855,19602,101,'Перед светофором.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22856,19603,101,'Перед разметкой \"Стоп-линия\". ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22857,19604,101,'Перед пересечением полос движения.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(22858,19605,101,'Нарушает','2025-11-06 21:40:32','2025-11-06 21:40:32');
