INSERT INTO answer_translations VALUES(23304,20051,101,'Состояние покрытия дороги','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23305,20052,101,'Видимость по направлению движения','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23306,20053,101,'Оба указанных условия','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23307,20054,101,'Обеспечивающую полный контроль над автомобилем','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23308,20055,101,'Может выбрать любую скорость, не превышающую максимально допустимую','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23309,20056,101,'Превышать максимальную скорость, установленную технической характеристикой данного транспортного средства ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23310,20057,101,'Превышать скорость, предусмотренную установленным на транспортном средстве опознавательным знаком \"Ограничение скорости\" ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23311,20058,101,'Без необходимости двигаться с очень низкой скоростью, препятствуя движению других транспортных средств','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23312,20059,101,'Резко тормозить, если это не необходимо для предотвращения дорожно-транспортного происшествия.','2025-11-06 21:40:32','2026-03-11 00:30:26');
INSERT INTO answer_translations VALUES(23313,20060,101,'Все указанные действия ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23314,20061,101,'1 и 3','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23315,20062,101,'1 и 4','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23316,20063,101,'Только 2','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23317,20064,101,'2 и 3','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23318,20065,101,'Проезжать железнодорожный переезд со скоростью более 30 км / ч','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23319,20066,101,'Проезжать железнодорожный переезд со скоростью менее 30 км / ч ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23320,20067,101,'Без разрешения начальника железнодорожного участка запрещается проезжать через переезд на тихоходных машинах со скоростью менее 8 км/ч и на тракторах, сцепленных с волокушами.','2025-11-06 21:40:32','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(23321,20068,101,'Не превышать максимально допустимую на данном участке','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23322,20069,101,'Иметь возможность остановиться и пропустить транспортные средства, имеющие право первоочередного проезда','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23323,20070,101,'Это создаст препятствие для водителя обгоняющего его транспортного средства выполнить обгон ','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23324,20071,101,'Это необходимо для освобождения дороги для водителя, остановившегося, чтобы уступить ему дорогу','2025-11-06 21:40:32','2025-11-06 21:40:32');
