INSERT INTO answer_translations VALUES(23327,20074,101,'При ослеплении','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23328,20075,101,'В случае возникновения препятствия или опасности для движения','2025-11-06 21:40:32','2025-11-06 21:40:32');
