INSERT INTO answer_translations VALUES(23330,20077,101,'Во всех указанных случаях','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO answer_translations VALUES(23331,20078,101,'Да','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23332,20079,101,'Нет','2025-11-06 21:40:33','2025-11-06 21:40:33');
