INSERT INTO answer_translations VALUES(23338,20085,101,'Да','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23339,20086,101,'Нет','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23340,20087,101,'Ограничивает поле зрения водителя','2025-11-06 21:40:33','2025-11-06 21:40:33');
