INSERT INTO answer_translations VALUES(23346,20093,101,'Да','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23347,20094,101,'Нет','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23348,20095,101,'Да','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23349,20096,101,'Нет','2025-11-06 21:40:33','2025-11-06 21:40:33');
