INSERT INTO answer_translations VALUES(23352,20099,101,'Продолжить движение, так как движутся по определенному маршруту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23353,20100,101,'Продолжить движение, так как движутся по определенному маршруту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
