INSERT INTO answer_translations VALUES(23428,20175,101,'Разрешается, если скорость мотоцикла не превышает 30 км/ч. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23429,20176,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23430,20177,101,'На перекрестке. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23431,20178,101,'Ближе, чем за 150 м до железнодорожного переезда.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23432,20179,101,'В обоих случаях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23433,20180,101,'На регулируемых перекрестках','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23434,20181,101,'На нерегулируемых перекрестках.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23435,20182,101,'В обоих случаях. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23436,20183,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23437,20184,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23438,20185,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23439,20186,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23440,20187,101,'Разрешается, если красный автомобиль движется со скоростью менее 30 км/ч.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23441,20188,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23442,20189,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23443,20190,101,'Разрешается, если скорость обгоняемого автомобиля не превышает 30 км/ч.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23444,20191,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23445,20192,101,'Запрещается.','2025-11-06 21:40:33','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(23446,20193,101,'Опережение находящегося в движении одного или нескольких транспортных средств, связанное с выездом на полосу встречного движения.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23447,20194,101,'Опережение находящегося в движении одного или нескольких транспортных средств, связанное с выездом с занимаемой полосы. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23448,20195,101,'Дальний свет фар. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23449,20196,101,'Ближний свет фар.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23450,20197,101,'Дальний или ближний свет фар.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23451,20198,101,'При движении в условиях недостаточной видимости. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23452,20199,101,'На имеющем неисправности мотоцикле, следующем к месту стоянки.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23453,20200,101,'В любом случае, при нахождении в движении. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23454,20201,101,'При перевозке больного пассажира.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23455,20202,101,'Дальний свет фар (если включен) переключить на ближний.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23456,20203,101,'Включить аварийную световую сигнализацию.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23457,20204,101,'Подать звуковой сигнал: один длинный и три коротких','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23458,20205,101,'Подать звуковой сигнал: один короткий и три длинных.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23459,20206,101,'В населенных пунктах, для предупреждения других водителей о намерении выполнить обгон. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23460,20207,101,'Когда это необходимо для предотвращения дорожно-транспортного происшествия.','2025-11-06 21:40:33','2026-03-11 00:18:22');
INSERT INTO answer_translations VALUES(23461,20208,101,'В обоих случаях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23462,20209,101,'Ближний или дальний свет фар.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23463,20210,101,'Только ближний свет фар','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23464,20211,101,'Только дальний свет фар.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23465,20212,101,'При движении в колонне в темное время суток. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23466,20213,101,'При движении в тоннелях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23467,20214,101,'Только в условиях недостаточной видимости. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23468,20215,101,'В темное время суток при разгрузке транспортного средства.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23469,20216,101,'Во всех перечисленных случаях. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23470,20217,101,'Не менее 100 м','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23471,20218,101,'Не менее 150 м','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23472,20219,101,'Не менее 300 м.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23473,20220,101,'Только вне населенных пунктов при отсутствии встречных и попутных транспортных средств. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23474,20221,101,'Только в условиях недостаточной видимости. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23475,20222,101,'В любых местах, если в этом есть необходимость.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23476,20223,101,'В темное время суток на всех участках дороги.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23477,20224,101,'25 - 50 м','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23478,20225,101,'50 - 100 м.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23479,20226,101,'100 - 150 м.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23480,20227,101,'Разрешается, если переезд не оборудован шлагбаумом.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23481,20228,101,'Разрешается, если они находятся в нетранспортном положении. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23482,20229,101,'Разрешается, если они находятся в транспортном положении.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23483,20230,101,'Там, где видимость с обоих сторон составляет не менее 1000 м. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23484,20231,101,'По усмотрению водителя в удобных для этого местах.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23485,20232,101,'В предусмотренных для этого местах.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23486,20233,101,'На расстоянии не менее 1000 м. От железнодорожных вокзалов.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23487,20234,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23488,20235,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23489,20236,101,'Разрешается по усмотрению водителя, если вблизи нет приближающегося поезда. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23490,20237,101,'Разрешается при отсутствии дежурного по переезду. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23491,20238,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23492,20239,101,'Разрешается, если они находятся в транспортном положении.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23493,20240,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23494,20241,101,'Положением шлагбаума и сигналами светофора.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23495,20242,101,'Требованиями дорожных знаков и разметок.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23496,20243,101,'Указаниями дежурного по переезду','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23497,20244,101,'Всеми перечисленными требованиями','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23498,20245,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23499,20246,101,'Разрешается, вне населенных пунктов — навстречу движению транспортных средств.','2025-11-06 21:40:33','2026-03-11 00:18:22');
INSERT INTO answer_translations VALUES(23500,20247,101,'Разрешается, вне населенных пунктов - по ходу движения транспортных средств','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23501,20248,101,'Разрешается только по крайней правой полосе. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23502,20249,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23503,20250,101,'Разрешается только при отсутствии знака \"Ограничение минимальной скорости\".','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23504,20251,101,'При дорожно-транспортном происшествии. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23505,20252,101,'При вынужденной остановке в местах, где остановка запрещена. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23506,20253,101,'В обоих случаях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23507,20254,101,'При дорожно-транспортном происшествии.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23508,20255,101,'При буксировке (на буксируемом механическом транспортном средстве).','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23509,20256,101,'При вынужденной остановке в местах, где остановка запрещена','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23510,20257,101,'Во всех перечисленных случаях. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23511,20258,101,'В населенных пунктах - не менее чем за 15 м, вне населенных пунктов - 30 м.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23512,20259,101,'В населенных пунктах - не менее чем за 10 м, вне населенных пунктов - 20 м','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23513,20260,101,'В населенных пунктах - не менее чем за 5 м, вне населенных пунктов - 10 м.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23514,20261,101,'При ослеплении водителя светом фар.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23515,20262,101,'При буксировке (на буксируемом механическом транспортном средстве).','2025-11-06 21:40:33','2026-03-11 00:16:54');
INSERT INTO answer_translations VALUES(23516,20263,101,'В обоих случаях.','2025-11-06 21:40:33','2026-03-11 00:17:55');
INSERT INTO answer_translations VALUES(23517,20264,101,'При дорожно-транспортном происшествии. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23518,20265,101,'При буксировке (на буксируемом механическом транспортном средстве).','2025-11-06 21:40:33','2026-03-11 00:17:55');
INSERT INTO answer_translations VALUES(23519,20266,101,'В обоих случаях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23520,20267,101,'Перемещение пешеходов по проезжей части дороги. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23521,20268,101,'Сквозное движение транспортных средств. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23522,20269,101,'Учебная езда. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23523,20270,101,'Только сигналами светофора. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23524,20271,101,'Только сигналами регулировщика. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23525,20272,101,'В обоих случаях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23526,20273,101,'Нет','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23527,20274,101,'Да','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23528,20275,101,'На левом рисунке. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23529,20276,101,'На среднем рисунке. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23530,20277,101,'На правом рисунке','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23531,20278,101,'На среднем и правом рисунках.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23532,20279,101,'Требованиями знаков.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23533,20280,101,'Сигналами светофора.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23534,20281,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23535,20282,101,'Разрешается, если водитель не может остановиться, не прибегая к резкому торможению. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23536,20283,101,'Только в том случае, когда требует остановить транспортное средство. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
