INSERT INTO answer_translations VALUES(23538,20285,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23539,20286,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23540,20287,101,'При остановке у края проезжей части. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23541,20288,101,'Перед закруглением участка дороги, обозначенной знаком \"Опасный поворот\".','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23542,20289,101,'Перед перестроением на соседнюю полосу движения.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23543,20290,101,'При движении по установленному маршруту.','2025-11-06 21:40:33','2026-03-11 00:34:29');
INSERT INTO answer_translations VALUES(23544,20291,101,'Непосредственно перед выполнением маневра.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23545,20292,101,'Сразу после выполнения маневра. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23546,20293,101,'Заранее - до выполнения маневра','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23547,20294,101,'Не обязан, если автобус движется по установленному маршруту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23548,20295,101,'Три длинных и один короткий. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23549,20296,101,'Один длинный и три коротких','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23550,20297,101,'Один длинный и два коротких. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23551,20298,101,'Два длинных и два коротких. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23552,20299,101,'Не имеет право. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23553,20300,101,'Имеет право.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23554,20301,101,'Можно, если неисправен указатель поворота. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23555,20302,101,'Можно, если неисправен указатель поворота в светлое врем суток.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23556,20303,101,'Можно во всех случаях.','2025-11-06 21:40:33','2025-11-06 21:40:33');
