INSERT INTO answer_translations VALUES(23695,20442,101,'Водителю автомобиля с включенными специальными световыми и звуковыми сигналами ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23696,20443,101,'Обоим водителям','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23697,20444,101,'Обоим водителям','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23698,20445,101,'Водителю грузового автомобиля с проблесковым маячком желтого цвета','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23699,20446,101,'Только водителю автобуса','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23700,20447,101,'Вы проедете перекресток первыми','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23701,20448,101,'Должны уступить дорогу водителю, приближающемуся слева.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23702,20449,101,'Всем','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23703,20450,101,'Водителю полицейской машины','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23704,20451,101,'Никому','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23705,20452,101,'Вы проедете перекресток первыми','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23706,20453,101,'Уступите только водителю полицейской машины','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23707,20454,101,'Уступите всем водителям','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23708,20455,101,'Уложить его, проподняв ноги.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23709,20456,101,'Уложить его, приподняв голову и туловище, обеспечив полулежащее положение. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23710,20457,101,'Уложить его в горизонтальном положении.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23711,20458,101,'Испуганной беременной женщине. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23712,20459,101,'Ребенку с царапинами. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23713,20460,101,'Мужчине со сломанной рукой','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23714,20461,101,'Мужчине без сознания','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23715,20462,101,'Запрокинуть голову пострадавшего назад. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23716,20463,101,'Наклонить голову пострадавшего и сдавить верхнюю часть носа.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23717,20464,101,'Ввести ватный тампон в нос пострадавшего. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23718,20465,101,'Подождать пока кровотечение само остановится.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23719,20466,101,'Предложить ему обратиться в близжайшую больницу. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23720,20467,101,'Дать ему стакан воды, 2 таблетки валерианы. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23721,20468,101,'Незамедлительно остановить машину и включить аварийную сигнализацию.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23722,20469,101,'Посоветовать ему немного пройтись и подышать свежим воздухом. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23723,20470,101,'Удерживать пострадавшего, стараясь ослабить судороги. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23724,20471,101,'Попытаться раскрыть рот, удержать язык и положить какойлибо предмет между зубами.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23725,20472,101,'Попытаться раскрыть дыхательные пути, откинув назад голову пострадавшего. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23726,20473,101,'Не трогать, подождать, пока судороги прекратятся.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23727,20474,101,'Оставить ожог открытым.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23728,20475,101,'Вскрыть волдыри с жидкостью, после чего туго перевязать.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23729,20476,101,'Смазать ожог растительным маслом. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23730,20477,101,'Охладить ожог водой, после чего накрыть стерильной перевязочной материей или чистыми тканями. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23731,20478,101,'Промыть рану водой.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23732,20479,101,'Приподнять руку пострадавшего и наложить тугую повязку.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23733,20480,101,'Рану смазать спиртовым раствором йода.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23734,20481,101,'Наложить на рану теплую примочку','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23735,20482,101,'Наложить на рану холодную примочку и приподнять. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23736,20483,101,'Наложить на рану холодную примочку и удерживать ниже уровня сердца.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23737,20484,101,'Наложить на рану спиртовую примочку. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23738,20485,101,'Попытаться посадить его. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23739,20486,101,'Приподнять его ноги','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23740,20487,101,'Обрызгать лицо холодной водой.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23741,20488,101,'Ударить по лицу. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23742,20489,101,'Оказать помощь всем, но быть осторожным.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23743,20490,101,'Оказать помощь пострадавшему, находящемуся к вам ближе всех.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23744,20491,101,'Не подходить, немедленно сообщить о случившемся и не разрешать посторонним лицам подходить к месту происшествия. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23745,20492,101,'Не подходить, попросить кого-либо другого оказать помощь.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23746,20493,101,'Вызвать скорую помощь','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23747,20494,101,'Проверить сознание и дыхание.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23748,20495,101,'Обездвижить ногу. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23749,20496,101,'Немедленно приподнять конечность пострадавшего. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23750,20497,101,'Накрыть рану стерильной салфеткой и обездвижить травмированную конечность.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23751,20498,101,'Надавив, остановить кровотечение.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23752,20499,101,'Наложить на рану холодные примочки.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23753,20500,101,'Уложить пострадавшего в горизонтальном положении. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23754,20501,101,'Посадить, прислонив на травмированную сторону. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23755,20502,101,'Посадить, прислонив на здоровую сторону. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23756,20503,101,'Промыть и попытаться осторожно вложить выпавшие органы обратно. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23757,20504,101,'Накрыть выпавшие органы чистой влажной тканью и полиэтиленовой пленкой. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23758,20505,101,'Перерезать выпавшие органы и перевязать рану. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23759,20506,101,'Не трогать, в этом состоянии перевезти в больницу. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23760,20507,101,'Уложить на спину. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23761,20508,101,'Отрыть рот и вытянуть язык.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23762,20509,101,'Повернуть на бок и откинуть голову назад. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23763,20510,101,'Только перевязать рану.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23764,20511,101,'Наложить тугую повязку на поврежденный участок и надавить на точку савливания артерии.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23765,20512,101,'Посыпать рану пеплом.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23766,20513,101,'Устроить пострадавшего в удобном положении. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23767,20514,101,'Обследовать место происшествия и обеспечить безопасность','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23768,20515,101,'Проверить наличие сильного кровотечения у пострадавшего.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23769,20516,101,'Вынести пострадавшего из автомобиля. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23770,20517,101,'Удалить из раны инородный предмет.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23771,20518,101,'Не препятствовать кровотечению поврежденного участка. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23772,20519,101,'Обеспечить неподвижное состояние инородного предмета.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23773,20520,101,'Обработать спиртом участок раны. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23774,20521,101,'40-60 ударов в минуту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23775,20522,101,'60-80 ударов в минуту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23776,20523,101,'80-100 ударов в минуту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23777,20524,101,'12-18 дыхательных движений в минуту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23778,20525,101,'20-30 дыхательных движений в минуту.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23779,20526,101,'40-60 дыхательных движений в минуту','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23780,20527,101,'У пострадавшего наблюдаются серьезные травмы. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23781,20528,101,'Место происшествия небезопасно, например, есть опасность взрыва. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23782,20529,101,'На автомобиль упал электрический провод. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23783,20530,101,'Уложить пострадавшего и наложить на травму холодную примочку. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23784,20531,101,'Положить на живот горячую грелку. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23785,20532,101,'Наложить на живот тугую повязку.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23786,20533,101,'Дать пострадавшему обильное питье.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23787,20534,101,'Распахнуть двери и выключить двигатель, при возможности, вынести пострадавшего с места происшествия. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23788,20535,101,'Тщательно обследовать пострадавшего с целью обнаружения травм. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23789,20536,101,'Повернуть пострадавшего на бок, в безопасное положение. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23790,20537,101,'Помочь пострадавшему принять положение полусидя.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23791,20538,101,'Напоить его холодной водой. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23792,20539,101,'Повернуть его на бок, в безопасное положение. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23793,20540,101,'Обеспечить нормальную температуру тела.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23794,20541,101,'Открыть дыхательные пути и проверить дыхание.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23795,20542,101,'Пострадавший чувствует боль','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23796,20543,101,'Пострадавший чувствует беспокойство.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23797,20544,101,'При нажатии ноготь белеет с трудом','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23798,20545,101,'Ноготь с трудом возвращается в прежний розовый цвет.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23799,20546,101,'Дать ему сахар или сладкую жидкость. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23800,20547,101,'Предложить ему отдохнуть несколько часов','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23801,20548,101,'Посоветовать сделать инъекцию инсулина.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23802,20549,101,'Кровь свертывается в течение 10 минут. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23803,20550,101,'Кровь бьет из раны струей.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23804,20551,101,'Кровь темно-красного цвета. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23805,20552,101,'Кровь из раны вытекает непрерывно. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23806,20553,101,'Отдалить пострадавшего от источника тока. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23807,20554,101,'Провести первичное обследование. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23808,20555,101,'С помощью какого-либо изолирующего предмета удалить провод с пострадавшего. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23809,20556,101,'Искать места входа и выхода электрического тока (места ожога) на теле. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23810,20557,101,'Избегать прямого контакта с раной и помощь оказывать только в стерильных перчатках.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23811,20558,101,'Не оказывать помощь тем пострадавшим, у которых наблюдается кровотечение. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23812,20559,101,'Помочь принять положение полусидя.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23813,20560,101,'Уложить и приподнять ноги','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23814,20561,101,'Уложить, согнув ноги в коленных суставах. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23815,20562,101,'Уложить, приподняв голову.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23816,20563,101,'Уложить, приподняв голову.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23817,20564,101,'Уложить и приподнять ноги. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23818,20565,101,'Уложить, согнув ноги в коленных суставах. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23819,20566,101,'Помочь принять положение полусидя. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23820,20567,101,'Уложить и приподнять ноги.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23821,20568,101,'Уложить, согнув ноги в коленных суставах. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23822,20569,101,'Уложить, приподняв голову. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23823,20570,101,'Травмы нижней конечности и головы.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23824,20571,101,'Травмы таза и грудной клетки. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23825,20572,101,'Травмы нижней конечности и головы.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23826,20573,101,'Травмы таза и грудной клетки. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23827,20574,101,'Помочь находящимся в автомобиле людям срочно покинуть автомобиль','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23828,20575,101,'Попросить находящихся в автомобиле людей не выходить из автомобиля, пока не будет выключен электрический ток. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23829,20576,101,'Промыть рану чистой водой с мылом, после чего перевязать.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23830,20577,101,'Обработать рану веществом на спиртовой основе (йод, водка, духи и т.д)','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23831,20578,101,'Промыть рану чистой водой с мылом. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23832,20579,101,'Обработать рану веществом на спиртовой основе (йод, водка, духи и т.д)','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23833,20580,101,'Остановить кровотечение и перевязать рану. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23834,20581,101,'Указать ориентир, ближайший к месту аварии. Сообщить количество пострадавших, указать их пол и возраст. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23835,20582,101,'Указать улицу и номер дома, ближайшие к месту аварии. Сообщить, кто пострадал в результате аварии (пешеход, водитель автомобиля или пассажир), и описать полученные травмы.','2025-11-06 21:40:33','2026-03-11 00:34:29');
INSERT INTO answer_translations VALUES(23836,20583,101,'Указать место аварии (улицу, номер дома и ориентир, ближайший к месту аварии). Сообщить количество пострадавших, их пол и приблизительный возраст, о наличии сознания, дыхания, кровообращения, а также сильного кровотечения, переломов и других травм. Подождать, пока оператор укажет, что вызов принят.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23837,20584,101,'Уложить пострадавшего на бок. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23838,20585,101,'Уложить пострадавшего на спину на твердую, гладкую поверхность, не передвигать, не менять положение без необходимости','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23839,20586,101,'Уложить пострадавшего на спину, под шею подложить валик из одежды и поднять ноги','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23840,20587,101,'Растереть пораженные участки тела снегом или шерстью, затем их утеплить, дать алкоголь, переместить в теплое помещение. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23841,20588,101,'Утеплить пораженные участки тела и обездвижить их, укутать пострадавшего теплой одеждой или пледом, дать теплое питье, переместить в теплое помещение.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23842,20589,101,'Смазать пораженные участки тела кремом, наложить согревающий компресс и грелку, переместить в теплое помещение, дать теплое питье.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23843,20590,101,'Остановить кровотечение прямым давлением на рану и наложить давящую повязку. При потере сознания придать устойчивое боковое положение. По возможности, приложить к месту травмы головы холод. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23844,20591,101,'Фиксировать шейный отдел позвоночника с помощью импровизированной шейной шины (воротника). На рану наложить стерильный ватный тампон, пострадавшего уложить на спину, приподняв ноги. По возможности, к голове приложить холод. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23845,20592,101,'Шейную шину накладывать запрещается, рану необходимо заклеить медицинским пластырем, пострадавшего уложить на бок.  ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23846,20593,101,'На спину с подложенным под голову валиком.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23847,20594,101,'На спину с вытянутыми ногами.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23848,20595,101,'Придать пострадавшему устойчивое боковое положение, чтобы согнутые колени опирались о землю, а верхняя рука находилась под щекой. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23849,20596,101,'Не более получаса в теплое время года и не более одного часа в холодное время года ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23850,20597,101,'Не более одного часа в теплое время года и не более получаса в холодное время года','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23851,20598,101,'Время наложения жгута не ограничено','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23852,20599,101,'Взять пострадавшего за подбородок, запрокинуть голову и в течение 10 секунд проследить за движением его грудной клетки. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23853,20600,101,'Положить одну руку на лоб пострадавшего, двумя пальцами другой поднять подбородок и, запрокинув голову, наклониться к его лицу и в течение 10 секунд прислушаться к дыханию, постараться ощутить выдыхаемый воздух своей щекой, проследить за движением грудной клетки. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23854,20601,101,'Не запрокидывая головы пострадавшего, необходимо наклониться к его лицу и в течение 10 секунд прислушаться к дыханию, попробовав почувствовать его своей щекой, проследить за движением его грудной клетки.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23855,20602,101,'Кровь темного цвета вытекает из раны медленно. На рану накладывается давящая повязка, с указанием в записке времени наложения повязки. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23856,20603,101,'Кровь ярко-алого цвета вытекает из раны пульсирующей или фонтанирующей струей. Артерия прижимается пальцами, затем в точках прижатия выше раны, максимально близко к ней, накладывается кровоостанавливающий жгут с указанием в записке времени наложения жгута. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23857,20604,101,'Кровь вытекает из раны медленно. Накладывается кровоостанавливающий жгут ниже места ранения, с указанием в записке времени наложения жгута. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23858,20605,101,'Разрешается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23859,20606,101,'Разрешается в случае крайней необходимости','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23860,20607,101,'Запрещается','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23861,20608,101,'Наложить давящую повязку на место ранения.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23862,20609,101,'Наложить жгут выше места ранения.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23863,20610,101,'Наложить жгут ниже места ранения','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23864,20611,101,'Промыть рану водой, удалить инородные тела, внедрившиеся в рану, приложить стерильную вату, закрепив ее бинтовой повязкой. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23865,20612,101,'Надеть медицинские перчатки, рану промыть спиртовым раствором йода, смазать лечебной мазью и заклеить лейкопластырем.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23866,20613,101,'Надеть медицинские перчатки, рану не промывать, наложить на нее марлевую стерильную салфетку, закрепив ее лейкопластырем по краям или бинтовой повязкой.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23867,20614,101,'Верхнюю конечность, вытянутую вдоль тела, прибинтовывают к туловищу. Нижние конечности прибинтовывают друг к другу, проложив между ними мягкую ткань.','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23868,20615,101,'Верхнюю конечность, согнутую в локте, подвешивают на косынке и прибинтовывают к туловищу. Нижние конечности прибинтовывают друг к другу, проложив между ними мягкую ткань','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23869,20616,101,'Верхнюю конечность, согнутую в локте, подвешивают на косынке и прибинтовывают к туловищу. Нижние конечности прибинтовывают друг к другу. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23870,20617,101,'При высокой вероятности опрокидывания автомобиля, пожара, взрыва или при потере потерпевшим сознания. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23871,20618,101,'При высокой вероятности опрокидывания автомобиля, пожара, взрыва, переохлаждения потерпевшего, при отсутствии у него сознания и дыхания, а также невозможности оказания первой помощи непосредственно в салоне автомобиля. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23872,20619,101,'При высокой вероятности опрокидывания автомобиля, пожара, взрыва или при обильном кровотечении либо черепно-мозговой травме.  ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23873,20620,101,'Полить ожоговую поверхность холодной водой, накрыть стерильной салфеткой и туго забинтовать. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23874,20621,101,'Вскрыть ожоговые пузыри, очистить ожоговую поверхность от остатков одежды, накрыть стерильной салфеткой (не бинтовать), по возможности приложить холод, поить пострадавшего водой. ','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO answer_translations VALUES(23875,20622,101,'Охладить ожоговую поверхность водой в течение 20 минут. Ожоговые пузыри не вскрывать, остатки одежды с обожженной поверхности не удалять, место ожога накрыть стерильной салфеткой (не бинтовать), по возможности приложить холод и поить пострадавшего водой.','2025-11-06 21:40:33','2025-11-06 21:40:33');
