INSERT INTO answer_translations VALUES(24621,21258,101,'Номер 8 красный.','2025-11-12 19:51:07','2025-11-12 19:51:07');
INSERT INTO answer_translations VALUES(24622,21259,102,'9 թվանշանը դեղին գույնի է','2025-11-12 19:51:07','2025-11-12 19:51:07');
INSERT INTO answer_translations VALUES(24623,21259,101,'Номер 9 желтый.','2025-11-12 19:51:07','2025-11-12 19:51:07');
