INSERT INTO pdd_rule_translations VALUES(1021,1021,102,'1.Հայաստանի Հանրապետության ճանապարհային երթևեկության կանոններով (այսուհետ` կանոններ) սահմանվում է ճանապարհային երթևեկության միասնական կարգ` Հայաստանի Հանրապետության տարածքում` կարգավորելով ճանապարհային երթևեկության ընթացքում օգտագործվող լուսացույցի, կարգավորողի ազդանշանների, վթարային, հատուկ ազդանշանների, տրանսպորտային միջոցների արտաքին լուսային սարքերի և ձայնային ազդանշանների կիրառման, տարբեր պայմաններում երթևեկության, երթևեկության արագությունը կանոնակարգելու, վազանց, կանգառ և կայանում, խաչմերուկների անցում, հետիոտնային անցումների հատում, տրանսպորտային միջոցների քարշակում, ուսումնական վարում, մարդկանց և բեռների փոխադրում իրականացնելու հետ կապված հարաբերությունները, ինչպես նաև երթևեկությունը կարգավորող նշանները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1022,1022,102,' 2. Հայաստանի Հանրապետության ճանապարհներին սահմանված է տրանսպորտային միջոցների աջակողմյան երթևեկություն:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1023,1023,102,' 3. Կանոններում օգտագործվում են հետևյալ հասկացությունները` ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1024,1024,102,' 1) գլխավոր ճանապարհ`2.1` «Գլխավոր ճանապարհ», 2.3.1` «Հատում երկրորդական ճանապարհի հետ», 2.3.2 – 2.3.7` «Երկրորդական ճանապարհի հարում», կամ 5.1` «Ավտոմայրուղի» նշաններով նշված ճանապարհ հատողի (հարողի) նկատմամբ կամ կոշտ ծածկույթով (ասֆալտբետոն, ցեմենտբետոն, քարե նյութեր և այլն) ճանապարհ հողային ծածկույթ ունեցողի նկատմամբ, կամ էլ ցանկացած ճանապարհ մերձակա տարածքներից դուրս եկող ճանապարհի նկատմամբ: Առանց ծածկույթի հողային ճանապարհի վրա, անմիջապես խաչմերուկից առաջ, ծածկույթով հատվածի առկայությունն այդ ճանապարհը հատվող ծածկույթով ճանապարհին հավասարազոր չի դարձնում. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1025,1025,102,' 2 )երթևեկության առավելություն`երթևեկության այլ մասնակիցների նկատմամբ` նախընտրած ուղղությամբ առաջնահերթ երթևեկելու իրավունք. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1026,1026,102,' 3) չստեղծել խոչընդոտ`երթևեկության մասնակիցներին ուղղված պահանջ, որի համաձայն նրանք չպետք է որևէ ձևով խոչընդոտեն. ուղևորներն ու հետիոտները` տրանսպորտային միջոցների, իսկ վարորդները` հետիոտների և այլ տրանսպորտային միջոցների երթևեկությունը. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1027,1027,102,' 4) կազմակերպված տրանսպորտային շարասյուն`մշտապես միացված լապտերներով, միևնույն երթևեկության գոտիով անմիջապես իրար հետևից ընթացող առնվազն 3 մեխանիկական տրանսպորտային միջոցների խումբ, որն առջևից ուղեկցվում է կապույտ և կարմիր առկայծող փարոսիկները միացրած տրանսպորտային միջոցով. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1028,1028,102,' 5) երթևեկության սկիզբ`կանգառի կամ կայանման վայրից տրանսպորտային միջոցի շարժումն սկսելու պահը` կապված հարևան երթևեկության գոտի վերադասավորման հետ կամ առանց դրա. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1029,1029,102,' 6) մանևրում`տրանսպորտային միջոցի երթևեկության սկիզբ (կապված հարևան երթևեկության գոտի դուրս գալու հետ), վերադասավորում, երթևեկության ուղղության փոփոխություն, կանգառ (վերադասավորվելով) և հետընթաց կատարելը. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1030,1030,102,' 7) վերադասավորում`տրանսպորտային միջոցի զբաղեցրած երթևեկության գոտուց կամ գծանշված երթևեկության գոտու սահմաններում զբաղեցրած շարքից, երթևեկության սկզբնական ուղղությունը պահպանելով, դուրս գալը. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1031,1031,102,' 8 )երթևեկության ուղղության փոփոխություն`նախկինում ընտրած երթևեկության ուղղության փոփոխություն (բացառությամբ հետընթացի)` կատարվող շրջադարձի կամ հետադարձի միջոցով. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1032,1032,102,' 9) շրջադարձ`տրանսպորտային միջոցի` այլ ճանապարհ կամ ճանապարհից մերձակա տարածք դուրս գալու նպատակով իրականացվող մանևր. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1033,1033,102,' 10) հետադարձ`տրանսպորտային միջոցի շարժման ուղղությունը հանդիպակաց ուղղությամբ փոխելու նպատակով իրականացվող մանևր. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1034,1034,102,' 11) վազանց՝շարժման մեջ գտնվող մեկ կամ մի քանի տրանսպորտային միջոցից առաջ անցնելը՝ կապված զբաղեցրած գոտուց դուրս գալու հետ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1035,1035,102,' 12) արգելք`երթևեկելի մասի որևէ գոտու վրա գտնվող անշարժ օբյեկտ (վնասված կամ անսարք տրանսպորտային միջոց, կողմնակի առարկա, ճանապարհի ծածկույթի վնասվածք և այլն), որը վարորդներին զրկում է նույն գոտիով երթևեկությունը շարունակելու հնարավորությունից: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1036,1036,102,' 13) երթևեկության համար վտանգ`երթևեկության ժամանակ ստեղծված իրադրություն, երբ նույն ուղղությամբ և (կամ) նույն արագությամբ երթևեկությունը շարունակելու դեպքում կստեղծվի ճանապարհատրանսպորտային պատահարի առաջացման իրական վտանգ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1037,1037,102,' 14) կողանցում`շարժման մեջ գտնվող մեկ կամ մի քանի տրանսպորտային միջոցներից առաջ անցնելը` առանց զբաղեցրած գոտուց դուրս գալու: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1038,1038,102,' 15) վտանգավոր բեռ`վտանգավոր նյութ, հումք, վտանգավոր թափոններ, որոնք փոխադրման ընթացքում իրենց յուրահատկությունների հետևանքով կարող են վնաս պատճառել մարդկանց կյանքին և առողջությանը, առաջացնել շրջակա միջավայրի աղտոտում և վնասել տրանսպորտային միջոցները կամ շենքերն ու շինությունները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1039,1039,102,' 16) երեխաների կազմակերպված խմբերի փոխադրում`մեխանիկական տրանսպորտային միջոցով (բացառությամբ ընդհանուր օգտագործման տրանսպորտային միջոցների) նախադպրոցական և դպրոցական տարիքի երկու և ավելի երեխաների կազմակերպված փոխադրում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1040,1040,102,' 17) սահմանափակ տեսանելիություն`երթևեկության մասնակցի տեղից շարժման ուղղությամբ ճանապարհի տեսանելիություն` սահմանափակված տրանսպորտային միջոցներով, ճանապարհի երկրաչափական չափանիշներով, տեղանքի ռելիեֆով, ճանապարհին հարակից բուսականությամբ, շինություններով և այլ օբյեկտներով. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1041,1041,102,' 18) հետիոտնային և հեծանվային արահետ (հեծանվահետիոտնային արահետ)՝երթևեկելի մասից կառուցվածքով առանձնացված ճանապարհի տարր (կամ առանձին ճանապարհ)՝ նախատեսված հետիոտներից առանձին կամ նրանց հետ համատեղ հեծանվորդների երթևեկության համար և նշված 4.5.2-4.5.7 նշաններով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1042,1042,102,' 19) հեծանվորդների համար գոտի՝երթևեկելի մասի մյուս հատվածից հորիզոնական գծանշումով առանձնացված և 5.14.2 նշանով նշված երթևեկելի մասի գոտի՝ նախատեսված հեծանիվներով և մոպեդներով երթևեկելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1043,1043,102,' 20) հիբրիդային ավտոմոբիլ՝էներգիայի 2-ից ոչ պակաս տարբեր փոխակերպիչներ (շարժիչներ) ունեցող և տրանսպորտային միջոցը շարժման մեջ դնելու նպատակների համար էներգիայի կուտակման 2 տարբեր համակարգեր ունեցող տրանսպորտային միջոց:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1044,1044,102,'4. Լուսացույցներում կիրառվում են կանաչ, դեղին, կարմիր և լուսնասպիտակ գույների լուսային ազդանշաններ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1045,1045,102,' 5. Կախված գործածման նպատակից` լուսացույցները լինում են տրանսպորտային, հետիոտնային և հեծանվորդների երթևեկությունը կարգավորող, իսկ դրանց ազդանշանները` կլոր (առանց պատկերի), ինչպես նաև պատկերներով` սլաքի (սլաքների), հետիոտնի կամ հեծանիվի ուրվապատկերի տեսքով և «X»-աձև: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1046,1046,102,' 6. Կլոր ազդանշաններով լուսացույցները կարող են ունենալ մեկ կամ երկու կանաչ սլաքի (սլաքների) տեսքով ազդանշաններով լրացուցիչ մասեր (սեկցիաներ), որոնք տեղադրվում են կանաչ ազդանշանի մակարդակի վրա: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1047,1047,102,' 7. Լուսացույցի կլոր ազդանշաններն ունեն հետևյալ նշանակությունները`1) կանաչ ազդանշանը թույլատրում է երթևեկությունը (կանաչ ազդանշանի գործողության ավարտին մնացած ժամանակի մասին (վայրկյաններով) վարորդներին և հետիոտներին տեղեկացնելու համար կարող են կիրառվել թվատախտակներ).2) կանաչ թարթող ազդանշանը թույլատրում է երթևեկությունը և տեղեկացնում, որ դրա գործողության ժամկետը լրանում է, և շուտով կմիանա արգելող ազդանշանը.3) դեղին ազդանշանն արգելում է երթևեկությունը (բացառությամբ կանոնների 19-րդ կետով նախատեսված դեպքի) և նախազգուշացնում ազդանշանի առաջիկա փոփոխման մասին.4) դեղին թարթող ազդանշանը թույլատրում է երթևեկությունը և տեղեկացնում չկարգավորվող խաչմերուկի կամ հետիոտնային անցման առկայության, ինչպես նաև նախազգուշացնում որևէ վտանգի մասին.5) կարմիր ազդանշանը, այդ թվում նաև՝ թարթող, արգելում է երթևեկությունը (կարմիր ազդանշանի գործողության ավարտին մնացած ժամանակի մասին (վայրկյաններով) վարորդներին և հետիոտներին տեղեկացնելու համար կարող են կիրառվել թվատախտակներ).6) կարմիր և դեղին ազդանշանների զուգակցումն արգելում է երթևեկությունը և տեղեկացնում կանաչ ազդանշանի առաջիկա միանալու մասին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1048,1048,102,' 8. Լուսացույցի կարմիր, դեղին և կանաչ գույների սլաքների տեսքով ազդանշաններն ունեն նույն նշանակությունը, ինչ համապատասխան գույնի կլոր ազդանշանները, սակայն դրանց գործողությունը տարածվում է միայն սլաքներով նշված ուղղության (ուղղությունների) վրա: Այդ դեպքում ձախ շրջադարձ թույլատրող սլաքը թույլատրում է նաև հետադարձը, եթե դա արգելված չէ համապատասխան ճանապարհային նշանով: Նույն նշանակությունն ունի լրացուցիչ սեկցիայի կանաչ սլաքը: Լրացուցիչ սեկցիայի անջատված ազդանշանն արգելում է երթևեկությունն այդ սեկցիայով կարգավորվող ուղղությամբ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1049,1049,102,' 9. Կարմիր և դեղին գույների սլաքների փոխարեն կարող են օգտագործվել սև ուրվագծային սլաքներով նույն նշանակությունն ունեցող կարմիր և դեղին կլոր ազդանշաններ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1050,1050,102,' 10. Լուսացույցի հիմնական կանաչ ազդանշանի սև ուրվագծային սլաքը (սլաքները) վարորդներին տեղեկացնում է լրացուցիչ սեկցիայի առկայության մասին և ցույց տալիս թույլատրված երթևեկության այնպիսի ուղղություններ, որոնք նախատեսված չեն լրացուցիչ սեկցիայի ազդանշանով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1051,1051,102,' 11. Հեծանվորդների երթևեկությունը կարգավորելու համար կիրառվում են հեծանիվի, իսկ հետիոտների տեղաշարժը` հետիոտնի ուրվապատկերների տեսքով լուսացույցի ազդանշաններ: Հեծանվորդների երթևեկությունը կարգավորելու համար կարող է կիրառվել նաև փոքրացրած չափերի կլոր ազդանշաններով լուսացույց` հեծանիվի ուրվապատկերով ցուցանակի հետ միասին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1052,1052,102,' 12. Ճանապարհների վրա կույր հետիոտների հաճախակի հայտնվելու վայրերում, երթևեկելի մասը հատելու հնարավորության մասին նրանց տեղեկացնելու համար լուսացույցի կանաչ լուսային ազդանշանը կարող է ուղեկցվել տրանսպորտային միջոցների ձայնային (հատուկ) ազդանշաններից տարբերվող ձայնային ազդանշանով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1053,1053,102,' 13. Տրանսպորտային միջոցների երթևեկությունը երթևեկելի մասի առանձին գոտիներով կարգավորելու համար, մասնավորապես, այն գոտիների, որոնցով երթևեկության ուղղությունը կարող է փոխվել հանդիպակացի, կիրառվում են դարձափոխային լուսացույցներ` «X»-աձև կարմիր և դեպի ներքև ուղղված սլաքի տեսքով` կանաչ ազդանշաններով, որոնք համապատասխանաբար արգելում կամ թույլատրում են երթևեկությունն այն գոտիով, որի վերևում տեղակայված են: Դարձափոխային լուսացույցների հիմնական ազդանշանները կարող են լրացվել անկյունագծով դեպի ներքև` աջ կամ ձախ ուղղված սլաքի տեսքով` դեղին ազդանշանով, որի միացումը տեղեկացնում է ազդանշանի փոխվելու և դեպի սլաքով նշված գոտի վերադասավորվելու անհրաժեշտության մասին: Եթե երկու կողմից 1.9 գծանշմամբ նշված գոտու վերևում տեղակայված դարձափոխային լուսացույցի ազդանշաններն անջատված են, ապա մուտքն այդ գոտի արգելված է: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1054,1054,102,' 14. Տրամվայների, ինչպես նաև առանձնացված գոտիով երթևեկող ընդհանուր օգտագործման այլ տրանսպորտային միջոցների երթևեկությունը կարգավորելու համար կարող են կիրառվել «T»-աձև դասավորված միագույն, լուսնասպիտակ չորս կլոր ազդանշաններ ունեցող լուսացույցներ: Երթևեկությունը թույլատրվում է միայն ներքևի և վերևի ազդանշաններից մեկի կամ մի քանիսի միաժամանակ միացված լինելու դեպքում, ընդ որում, ձախը թույլատրում է երթևեկությունը դեպի ձախ, միջինը` ուղիղ, իսկ աջը` դեպի աջ: Եթե լուսացույցի վերևի մեկ կամ մի քանի ազդանշաններ միացված են առանց ներքևի ազդանշանի, ապա երթևեկությունն արգելված է: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1055,1055,102,' 15. Երկաթուղային գծանցի վրա տեղակայված կլոր լուսնասպիտակ թարթող ազդանշանը թույլատրում է, իսկ կարմիրը` արգելում տրանսպորտային միջոցների երթևեկությունը գծանցով: Եթե թարթող լուսնասպիտակ և կարմիր ազդանշաններն անջատված են, ապա երթևեկությունը թույլատրվում է տեսանելիության սահմաններում` մոտեցող գնացքի (լոկոմոտիվի, երկաթուղային սայլակի) բացակայության դեպքում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1056,1056,102,' 16. Կարգավորողի ազդանշաններն ունեն հետևյալ նշանակությունները` ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1057,1057,102,' ձեռքը բարձրացված է դեպի վեր`Տրանսպորտային միջոցների երթևեկությունը և հետիոտների տեղաշարժն արգելված է` բացառությամբ կանոնների 19-րդ կետով նախատեսված դեպքերի. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1058,1058,102,' ձեռքերը պարզված են կողմ կամ իջեցված են`ա. ձախ և աջ կողմերից ոչ ռելսագնաց տրանսպորտային միջոցների երթևեկությունը թույլատրված է ուղիղ և դեպի աջ, տրամվայինը` ուղիղ: Հետիոտներին թույլատրվում է հատել երթևեկելի մասը կարգավորողի աջ և ձախ կողմերից․բ. թիկունքի և կրծքի կողմից բոլոր տրանսպորտային միջոցների երթևեկությունը և հետիոտների տեղաշարժն արգելված են. ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1059,1059,102,' աջ ձեռքը պարզված է առաջ`ա. ձախ կողմից ոչ ռելսագնաց տրանսպորտային միջոցների երթևեկությունը թույլատրված է բոլոր ուղղություններով, տրամվայինը` դեպի ձախ.բ. կրծքի կողմից բոլոր տրանսպորտային միջոցների երթևեկությունը թույլատրված է դեպի աջ.գ. թիկունքից և աջ կողմից բոլոր տրանսպորտային միջոցների երթևեկությունն արգելված է.դ. հետիոտներին թույլատրվում է երթևեկելի մասը հատել կարգավորողի թիկունքի կողմով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1060,1060,102,' 17. Ազդանշանների լավ տեսանելիության համար կարգավորողը կարող է օգտագործել ցուցաձող, այդ թվում` կարմիր ազդանշանով կամ լուսանդրադարձիչ սկավառակով, իսկ երթևեկության մասնակիցների ուշադրությունն իր վրա հրավիրելու համար` ազդանշան տալ նաև սուլիչով: Կարգավորողը կարող է ձեռքով տալ վարորդների ու հետիոտների համար հասկանալի նաև այլ ազդանշաններ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1061,1061,102,' 18. Լուսացույցի (բացի դարձափոխայինից) կամ կարգավորողի արգելող ազդանշանի դեպքում վարորդը պետք է կանգ առնի «Կանգ-գիծ» գծանշման (կամ 6.16` «Կանգ-գիծ» նշանի) առջև, իսկ դրա բացակայության դեպքում`1) հատվող երթևեկելի մասի առջև` հաշվի առնելով կանոնների 93-րդ կետը, խոչընդոտ չստեղծելով հետիոտների համար.2) երկաթուղային գծանցից առաջ` կանոնների 111-րդ կետի պահանջներին համապատասխան.3) այլ վայրերում` լուսացույցի կամ կարգավորողի առջև` խոչընդոտ չստեղծելով թույլատրելի ուղղություններով երթևեկող տրանսպորտային միջոցների և հետիոտների համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1062,1062,102,' 19. Դեղին ազդանշանը միանալու կամ կարգավորողը ձեռքը բարձրացնելու դեպքում այն վարորդները, որոնք հնարավորություն չունեն առանց կտրուկ արգելակելու կանգնել կանոնների 18-րդ կետում նշված տեղերում, կարող են շարունակել երթևեկությունը: Այդ ազդանշանի դեպքում երթևեկելի մասի վրա գտնվող հետիոտները պետք է ազատեն այն, իսկ եթե դա հնարավոր չէ, կանգ առնեն հանդիպակաց ուղղությունների տրանսպորտային հոսքերը բաժանող գծի վրա: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1063,1063,102,' 20. Վարորդներն ու հետիոտները պետք է կատարեն կարգավորողի կարգադրությունների և ազդանշանների պահանջները, նույնիսկ այն դեպքերում, եթե դրանք հակասում են լուսացույցի ազդանշաններին ու ճանապարհային նշանների կամ գծանշումների պահանջներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1064,1064,102,' 21. Երկաթուղային գծանցներում լուսացույցի կարմիր թարթող ազդանշանի հետ միաժամանակ կարող է տրվել նաև ձայնային ազդանշան, որը երթևեկության մասնակիցներին լրացուցիչ տեղեկացնում է գծանցով երթևեկությունն արգելելու մասին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1065,1065,102,'22. Վթարային լուսային ազդանշանը պետք է միացված լինի`1) ճանապարհատրանսպորտային պատահարի դեպքում.2) կանգառն արգելված տեղերում հարկադրված կանգառի դեպքում.3) լապտերների լույսից վարորդի շլացման դեպքում.4) քարշակման դեպքում (քարշակվող տրանսպորտային միջոցի վրա):Վարորդը վթարային լուսային ազդանշանը պետք է միացնի նաև այն դեպքերում, երբ վտանգի մասին անհրաժեշտ է նախազգուշացնել երթևեկության մասնակիցներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1066,1066,102,' 23. Վթարային լուսային ազդանշանը միացնելուց հետո (ինչպես նաև, երբ այն անսարք է կամ բացակայում է) անհապաղ պետք է տեղադրվի «Վթարային կանգառ» ճանաչման նշանը (թարթող կարմիր լապտերիկ)`1) ճանապարհատրանսպորտային պատահարի դեպքում.2) կանգառն արգելված տեղերում հարկադրված կանգառի դեպքում, ինչպես նաև այն տեղերում, որտեղ, ելնելով տեսանելիության պայմաններից, տրանսպորտային միջոցը չի կարող ժամանակին նկատվել այլ վարորդների կողմից: Այս պահանջը կատարելուց հետո վարորդը պետք է կատարի կանոնների 83-րդ կետի պահանջները:Ելնելով վարորդներին ժամանակին զգուշացնելու անհրաժեշտությունից` «Վթարային կանգառ» նշանը (թարթող կարմիր լապտերիկ) տեղադրվում է բնակավայրերում` տրանսպորտային միջոցից ոչ պակաս 15 մ, իսկ բնակավայրերից դուրս` 30 մ հեռավորության վրա: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1067,1067,102,' 24. Վթարային լուսային ազդանշանի բացակայության կամ անսարքության դեպքում «Վթարային կանգառ» նշանը տեղադրվում է քարշակվող տրանսպորտային միջոցի հետևի մասում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1068,1068,102,' 25. Արգելվում է առավելություն ստանալու, ինչպես նաև կանգառն արգելված վայրերում կանգառ կատարելու (բացառությամբ հարկադրված կանգառի) նպատակով վթարային ազդանշանի օգտագործումը:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1069,1069,102,'26. Կապույտ գույնի առկայծող փարոսիկը միացրած տրանսպորտային միջոցների վարորդները, անհետաձգելի ծառայողական առաջադրանքներ կատարելիս, ապահովելով երթևեկության անվտանգությունը, կարող են չպահպանել կանոնների II (բացի կարգավորողի ազդանշաններից), V-XVI, XIX և XXI բաժինների պահանջները, որը տարբերվում է տրանսպորտային միջոցների ձայնային ազդանշաններից: Երթևեկության մյուս մասնակիցների նկատմամբ առավելություն ստանալու համար նրանք պետք է միացնեն կապույտ գույնի առկայծող փարոսիկը և հատուկ ձայնային ազդանշանը, որը բարձր և ցածր ձայնային երանգների ու տարբերվում է տրանսպորտային միջոցների ձայնային ազդանշաններից: Այդպիսի տրանսպորտային միջոցների վարորդներն առավելությունից կարող են օգտվել միայն համոզվելով, որ ճանապարհն իրենց զիջում են: Այդ իրավունքից օգտվում են նաև այն վարորդները, որոնց տրանսպորտային միջոցներն ուղեկցվում են կապույտ և կարմիր գույների առկայծող փարոսիկներ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոցներով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1070,1070,102,' 27. Հայաստանի Հանրապետության կառավարությանն առընթեր Հայաստանի Հանրապետության ոստիկանության ճանապարհային ոստիկանության (այսուհետ` ճանապարհային ոստիկանություն), Հայաստանի Հանրապետության պետական պահպանության ծառայության և Հայաստանի Հանրապետության պաշտպանության նախարարության ռազմական ոստիկանության զինվորական ավտոտեսչության տրանսպորտային միջոցների վրա կարող է միացված լինել նաև կարմիր գույնի առկայծող փարոսիկ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1071,1071,102,' 28. Կապույտ գույնի առկայծող փարոսիկ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոցի մոտենալու դեպքում վարորդները պետք է զիջեն ճանապարհը` նշված տրանսպորտային միջոցի անխոչընդոտ անցումն ապահովելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1072,1072,102,' 29. Կապույտ և կարմիր գույների առկայծող փարոսիկներ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոց մոտենալու դեպքում վարորդները պետք է իջեցնեն արագությունը և զիջեն ճանապարհը` նշված, ինչպես նաև դրանով ուղեկցվող տրանսպորտային միջոցների անխոչընդոտ անցումն ապահովելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1073,1073,102,' 30. Կապույտ կամ կապույտ և կարմիր գույների առկայծող փարոսիկներ միացրած, կանգնած վիճակում գտնվող տրանսպորտային միջոցին մոտենալիս` վարորդները պետք է իջեցնեն արագությունը, որպեսզի անհրաժեշտության դեպքում հնարավորություն ունենան անմիջապես կանգ առնել: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1074,1074,102,' 31. Կարմիր գույնի առկայծող փարոսիկ միացրած, կանգնած վիճակում գտնվող տրանսպորտային միջոցին մոտենալիս` տվյալ ուղղությամբ երթևեկող տրանսպորտային միջոցների վարորդները պետք է կանգ առնեն և շարունակեն երթևեկությունը միայն թույլտվություն ստանալուց հետո: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1075,1075,102,' 32. Դեղին կամ նարնջագույն առկայծող փարոսիկները երթևեկության առավելություն չեն տալիս և ծառայում են երթևեկության մյուս մասնակիցներին վտանգի մասին նախազգուշացնելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1076,1076,102,' 33.Դեղին կամ նարնջագույն առկայծող փարոսիկները պետք է միացված լինեն` 1) այն տրանսպորտային միջոցների վրա, որոնք իրականացնում են ճանապարհների շինարարության, վերանորոգման, պահպանման կամ մաքրման, անսարք, վթարված և այլ տրանսպորտային միջոցների բարձման ու փոխադրման աշխատանքներ.2) կանոնների 163-րդ կետով սահմանված ցուցանիշները գերազանցող չափերով, մեծ եզրաչափերով բեռներ փոխադրող և դրանք ուղեկցող տրանսպորտային միջոցների վրա.3) վտանգավոր բեռներ և չվնասազերծված տարա փոխադրող ու դրանք ուղեկցող տրանսպորտային միջոցների վրա: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1077,1077,102,' 34. Դեղին կամ նարնջագույն առկայծող փարոսիկներ միացրած` կանոնների 33-րդ կետի 1-ին ենթակետում նշված տրանսպորտային միջոցների վարորդները, ապահովելով երթևեկության անվտանգությունը, կարող են չպահպանել կանոնների 42-րդ, 55-60-րդ, 63-րդ և 116-րդ կետերի, գծանշումների և նշանների պահանջները` բացառությամբ 2.2` «Գլխավոր ճանապարհի վերջ», 2.4` «Զիջեք ճանապարհը», 2.5` «Երթևեկությունն առանց կանգառի արգելվում է», 2.6` «Հանդիպակաց երթևեկության առավելություն», 3.11` «Զանգվածի սահմանափակում», 3.12` «Սռնու վրա բեռնվածության սահմանափակում», 3.13` «Բարձրության սահմանափակում», 3.14` «Լայնության սահմանափակում», 3.17.2` «Վտանգ», 3.20` «Վազանցն արգելվում է» ճանապարհային նշանների: Դեղին կամ նարնջագույն առկայծող փարոսիկներ միացրած` կանոնների 33-րդ կետի 2-րդ ենթակետում նշված տրանսպորտային միջոցների վարորդները, ապահովելով երթևեկության անվտանգությունը, կարող են չպահպանել կանոնների 60-րդ կետի և գծանշումների պահանջները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1078,1078,102,' 35. Լուսնասպիտակ գույնի առկայծող փարոսիկներով կահավորված տրանսպորտային միջոցների վարորդները կարող են դրանք միացնել, ընդ որում, հատուկ ձայնային ազդանշանի հետ միասին, միայն այդ տրանսպորտային միջոցների վրա հարձակում գործելու դեպքում: Այդ փարոսիկները երթևեկության առավելություն չեն տալիս ու ծառայում են միայն ոստիկանության ծառայողների և այլ անձանց ուշադրությունը գրավելու համար:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1079,1079,102,'36. Երթևեկությունն սկսելուց կամ մանևր կատարելուց առաջ երթևեկության այլ մասնակիցներին նախազգուշացնելու համար վարորդը պետք է տա ազդանշան համապատասխան ուղղության շրջադարձի լուսային ցուցիչով, իսկ եթե այն բացակայում է կամ անսարք է` ձեռքով: Ազդանշան տալը պարտադիր չէ, եթե տրանսպորտային միջոցն առանց վերադասավորում կատարելու երթևեկում է ճանապարհի` հատակագծում կորագծային հատվածով: Ազդանշանը պետք է տրվի նախօրոք, մինչև երթևեկությունը կամ մանևրն սկսելը և դադարեցվի երթևեկությունը կամ մանևրն ավարտելուց անմիջապես հետո (ձեռքով տրվող ազդանշանը դադարեցվում է երթևեկությունը կամ մանևրն սկսելուց անմիջապես առաջ): Այն պետք է տրվի հստակ, շփոթության մեջ չգցի երթևեկության մասնակիցներին, իսկ մանևրը` խոչընդոտ չստեղծի նրանց համար: Ազդանշան տալը երթևեկության մյուս մասնակիցների նկատմամբ առավելություն չի տալիս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1080,1080,102,' 37. Ձախ շրջադարձի (հետադարձի) ազդանշանին համապատասխանում է դեպի կողմ ուղղված ձախ ձեռքը կամ արմունկում ուղիղ անկյան տակ դեպի վեր ծալված աջ ձեռքը: Աջ շրջադարձի ազդանշանին համապատասխանում է դեպի կողմ ուղղված աջ ձեռքը կամ արմունկում ուղիղ անկյան տակ դեպի վեր ծալված ձախ ձեռքը: Արգելակման ազդանշանին համապատասխանում է դեպի վեր պարզված աջ կամ ձախ ձեռքը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1081,1081,102,' 38. Մերձակա տարածքից ճանապարհ դուրս գալիս՝ վարորդը պետք է ճանապարհը զիջի դրանով երթևեկող տրանսպորտային միջոցներին, իսկ ճանապարհից մերձակա տարածք մուտք գործելիս` հեծանվորդներին: Երկու դեպքում էլ չպետք է ստեղծվի խոչընդոտ հետիոտների համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1082,1082,102,' 39. Վերադասավորման ժամանակ վարորդը պետք է ճանապարհը զիջի համընթաց, հարևան երթևեկության գոտիներով առանց ուղղությունը փոխելու երթևեկող տրանսպորտային միջոցներին: Համընթաց ուղղությամբ երթևեկող տրանսպորտային միջոցների միաժամանակյա վերադասավորման դեպքում ճանապարհը պետք է զիջի ձախից ընթացող տրանսպորտային միջոցի վարորդը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1083,1083,102,' 40.Շրջադարձից կամ հետադարձից առաջ վարորդը պետք է նախապես զբաղեցնի երթևեկության տվյալ ուղղության համար նախատեսված երթևեկելի մասի համապատասխան եզրային գոտին` բացառությամբ այն դեպքերի, երբ`1) մուտք է գործում շրջանաձև երթևեկությամբ խաչմերուկ.2) ճանապարհային նշանով կամ գծանշմամբ թույլատրվում է դա կատարել նաև այլ գոտիներից.3) հնարավորություն չունի դա կատարելու՝ տրանսպորտային միջոցի եզրաչափերի կամ այլ պատճառներով:Երթևեկելի մասի ձախ կողմում, նույն մակարդակի վրա համընթաց ուղղության տրամվայի գծերի առկայության դեպքում, ձախ շրջադարձը և հետադարձը պետք է կատարվեն այդ գծերի վրայից, եթե 5.15.1` «Երթևեկության ուղղությունները գոտիներով» կամ 5.15.2` «Երթևեկության ուղղությունները գոտիով» նշաններով կամ էլ 1.18 գծանշմամբ երթևեկության այլ կարգավորում նախատեսված չէ: Այդ դեպքում չպետք է խոչընդոտ ստեղծվի տրամվային: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1084,1084,102,' 41. Շրջադարձը պետք է իրականացվի այնպես, որպեսզի երթևեկելի մասերի փոխհատումից դուրս գալիս տրանսպորտային միջոցը չհայտնվի երթևեկության հանդիպակաց կողմում: Աջ շրջադարձի ժամանակ տրանսպորտային միջոցը պետք է երթևեկի երթևեկելի մասի աջ եզրին հնարավորին չափ մոտ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1085,1085,102,' 42. Շրջադարձը դեպի դարձափոխային երթևեկությամբ ճանապարհ պետք է իրականացվի այնպես, որպեսզի երթևեկելի մասերի փոխհատումից դուրս գալիս տրանսպորտային միջոցը հայտնվի աջ եզրային մասում, որից հետո, անհրաժեշտության դեպքում, կարելի է վերադասավորվել, եթե վարորդը համոզված է, որ տվյալ ուղղությամբ երթևեկությունը թույլատրվում է նաև այլ գոտիով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1086,1086,102,' 43. Խաչմերուկներում, ինչպես նաև դրանցից դուրս, շրջադարձ կամ հետադարձ կատարելիս, տրանսպորտային միջոցի եզրաչափերի կամ այլ պատճառով կանոնների 40-րդ կետի պահանջներն ապահովելու հնարավորություն չունենալու դեպքում վարորդը պետք է միացնի վթարային լուսային ազդանշանը և զիջի ճանապարհը՝ ինչպես համընթաց, այնպես էլ՝ հանդիպակաց ուղղություններից մոտեցող տրանսպորտային միջոցների վարորդներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1087,1087,102,' 44. Խաչմերուկից դուրս ձախ շրջադարձի և հետադարձի ժամանակ ոչ ռելսագնաց տրանսպորտային միջոցի վարորդը պետք է ճանապարհը զիջի հանդիպակաց տրանսպորտային միջոցներին և համընթաց երթևեկող տրամվային: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1088,1088,102,' 45. Այն դեպքերում, երբ տրանսպորտային միջոցների երթևեկության ուղիները հատվում են, իսկ անցման հերթականությունը կանոններով սահմանված չէ, ճանապարհը պետք է զիջի այն վարորդը, որին տրանսպորտային միջոց է մոտենում աջից: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1089,1089,102,' 46.Եթե հանդիպակաց երթևեկությունը դժվարացած է, ճանապարհը պետք է զիջի իր առջևում խոչընդոտ ունեցող վարորդը: 1.13` «Կտրուկ վայրէջք» և 1.14` «Կտրուկ վերելք» նշաններով կահավորված երկայնական թեքությամբ ճանապարհահատվածներում, անկախ խոչընդոտի դասավորությունից, ճանապարհը պետք է զիջի վայրէջքի ուղղությամբ ընթացող տրանսպորտային միջոցի վարորդը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1090,1090,102,' 47. Արգելակման գոտու առկայության դեպքում շրջադարձ կատարելու մտադրություն ունեցող վարորդը պետք է նախապես վերադասավորվի այդ գոտի, որտեղ միայն իջեցնի արագությունը: Ճանապարհ մուտք գործելու վայրում, թափառքի գոտու առկայության դեպքում վարորդը պետք է շարունակի երթևեկել դրանով և վերադասավորվի հարևան գոտի` զիջելով ճանապարհով ընթացող տրանսպորտային միջոցներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1091,1091,102,' 48. Տրանսպորտային միջոցների հետընթացը թույլատրվում է, եթե դրա կատարումն անվտանգ է և խոչընդոտ չի ստեղծում երթևեկության մյուս մասնակիցների համար: Անհրաժեշտության դեպքում վարորդը պետք է դիմի այլ անձանց օգնությանը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1092,1092,102,' 49. Հետընթացն արգելվում է խաչմերուկներում, մերձակա տարածքից ճանապարհ դուրս գալիս և կանոնների 50-րդ կետում թվարկված տեղերում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1093,1093,102,' 50. Հետադարձն արգելվում է`1) հետիոտնային անցումների վրա.2) թունելներում.3) կամուրջների, ուղեկամուրջների,էստակադների վրա և դրանց տակ.4) երկաթուղային գծանցներում.5) ճանապարհի թեկուզ և մեկ ուղղությամբ 100 մ-ից պակաս տեսանելիության տեղերում.6) երթևեկելի մասերի այն հատվածներում, որտեղ առկա են ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետեր.7) միակողմ երթևեկությամբ ճանապարհներին:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1094,1094,102,'51. Ոչ ռելսագնաց տրանսպորտային միջոցների համար երթևեկության գոտիների քանակը որոշվում է գծանշմամբ կամ 5.15.1` «Երթևեկության ուղղությունները գոտիներով», 5.15.2` «Երթևեկության ուղղությունները գոտիով», 5.15.7` «Երթևեկության ուղղությունը գոտիներով» և 5.15.8 «Գոտիների քանակը» նշաններով, իսկ եթե դրանք բացակայում են, ապա վարորդների կողմից` հաշվի առնելով երթևեկելի մասի լայնությունը, տրանսպորտային միջոցների եզրաչափերը և (կամ) դրանց միջև անհրաժեշտ միջկողային տարածությունը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1095,1095,102,' 52. Երկկողմ երթևեկությամբ ճանապարհներին գծանշման բացակայության դեպքում հանդիպակաց երթևեկության կողմ է համարվում երթևեկելի մասի լայնության ձախ կեսը` չհաշված երթևեկելի մասի լայնացումները (թափառքի և արգելակման գոտիներ, ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի համար լայնացված տեղեր և այլն): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1096,1096,102,' 53. Երկկողմ երթևեկությամբ չորս և ավելի գոտի ունեցող ճանապարհներին արգելվում է դուրս գալ ճանապարհի հանդիպակաց երթևեկության համար նախատեսված կողմը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1097,1097,102,' 54. Երկկողմ երթևեկությամբ երեք գոտի ունեցող գծանշված (բացառությամբ 1.9 գծանշման) ճանապարհներին, որոնցից միջինն օգտագործվում է երկու ուղղություններով երթևեկության համար, թույլատրվում է դուրս գալ այդ գոտի միայն վազանցի, շրջանցման, ձախ շրջադարձի կամ հետադարձի համար: Արգելվում է մուտք գործել ձախ եզրային գոտի, որը նախատեսված է միայն հանդիպակաց երթևեկության համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1098,1098,102,' 55. Բնակավայրերից դուրս, ինչպես նաև բնակավայրերում` 5.1` «Ավտոմայրուղի» կամ 5.3` «Ճանապարհ ավտոմոբիլների համար» նշաններով կահավորված ճանապարհներին կամ որտեղ թույլատրվում է երթևեկել 80 կմ/ժ ավելի արագությամբ, տրանսպորտային միջոցների վարորդները պետք է դրանք վարեն երթևեկելի մասի աջ եզրին հնարավորինս մոտ: Այդ դեպքերում արգելվում է զբաղեցնել երթևեկության ձախ գոտիները` ազատ աջ գոտիների դեպքում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1099,1099,102,' 56. Բնակավայրերում, հաշվի առնելով «Ճանապարհային երթևեկության անվտանգության ապահովման մասին» Հայաստանի Հանրապետության օրենքի 24-րդ հոդվածի 8-րդ մասի և կանոնների 55-րդ, 57-58-րդ ու 116-րդ կետերի պահանջները, տրանսպորտային միջոցների վարորդները կարող են երթևեկել իրենց համար հարմար երթևեկության գոտիով: Ինտենսիվ երթևեկության ժամանակ, երբ զբաղված են բոլոր գոտիները, դրանք թույլատրվում է փոխել ձախ և աջ շրջադարձերից, հետադարձից, արգելքը շրջանցելուց կամ կանգառից առաջ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1100,1100,102,' 57. Բոլոր ճանապարհներին, միևնույն ուղղությամբ երթևեկության երեք և ավելի գոտիների առկայության դեպքում, ձախ եզրայինը թույլատրվում է զբաղեցնել միայն ինտենսիվ երթևեկության ժամանակ, երբ զբաղված են մյուս գոտիները, ինչպես նաև վազանց, ձախ շրջադարձ կամ հետադարձ կատարելիս, իսկ 3,5 տ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներին և ուղևորների կանոնավոր փոխադրումներ իրականացնող տրանսպորտային միջոցներին` միայն ձախ շրջադարձ կամ հետադարձ կատարելու համար: Միակողմ երթևեկությամբ ճանապարհներին կանգառի կամ կայանման նպատակով ձախ եզրային գոտի դուրս գալն իրականացվում է կանոնների 79-րդ կետի պահանջներին համապատասխան: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1101,1101,102,' 58. Տրանսպորտային միջոցները, որոնց երթևեկության արագությունը չպետք է գերազանցի 40 կմ/ժ, կամ որոնք տեխնիկական պատճառներով չեն կարող զարգացնել այդպիսի արագություն, պետք է երթևեկեն աջ եզրային գոտիով` բացառությամբ շրջանցման, վազանցի կամ ձախ շրջադարձից, հետադարձից կամ թույլատրված դեպքերում ձախ կողմում կանգառ կատարելուց առաջ վերադասավորվելու դեպքերի: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1102,1102,102,' 59. Երթևեկելի մասի ձախ կողմում նույն մակարդակի վրա գտնվող համընթաց ուղղության տրամվայի գծերով երթևեկել թույլատրվում է, եթե բոլոր գոտիներն այդ ուղղությամբ զբաղված են, ինչպես նաև վազանցի, արգելքը շրջանցելու, ձախ շրջադարձի կամ հետադարձի ժամանակ` հաշվի առնելով կանոնների 40-րդ կետը: Ընդ որում, խոչընդոտ չպետք է ստեղծվի տրամվային: Եթե խաչմերուկից առաջ տեղադրված են 5.15.1` «Երթևեկության ուղղությունները գոտիներով» կամ 5.15.2` «Երթևեկության ուղղությունները գոտիով» նշանները, խաչմերուկում երթևեկությունը տրամվայի գծերով արգելվում է: Արգելվում է երթևեկել հանդիպակաց ուղղությամբ տրամվայի գծերով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1103,1103,102,' 60. Եթե երթևեկելի մասը գծանշմամբ բաժանված է գոտիների, ապա տրանսպորտային միջոցների երթևեկությունը պետք է իրականացվի նշված գոտիներով: Ընդհատվող գծերը կարելի է հատել միայն վերադասավորվելիս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1104,1104,102,' 61. Արգելվում է տրանսպորտային միջոցների երթևեկությունը կողնակներով, մայթերով և հետիոտնային արահետներով՝ բացառությամբ կանոնների 81-րդ կետում նշված դեպքերում մայթեզրին կայանելու նպատակով մանևրելիս: Թույլատրվում է, այլ հնարավորության բացակայության դեպքում, ճանապարհային և կոմունալ սպասարկման ծառայությունների մեքենաներին երթևեկել, իսկ անմիջապես ճանապարհի կողնակների, մայթերի կամ հետիոտնային արահետների մոտ տեղակայված առևտրային և այլ օբյեկտներ սպասարկող տրանսպորտային միջոցներին` ամենակարճ ճանապարհով մոտենալ դրանց` խոչընդոտ չհանդիսանալով հետիոտներին և ապահովելով երթևեկության անվտանգությունը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1105,1105,102,' 62. Վարորդը պետք է իր և առջևից ընթացող տրանսպորտային միջոցի միջև պահպանի այնպիսի տարածություն, իսկ կողքով ընթացողներից` այնպիսի միջկողային տարածություն, որպեսզի հնարավորություն ունենա խուսափել դրանց հետ բախվելուց: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1106,1106,102,' 63. Բնակավայրերից դուրս յուրաքանչյուր ուղղության համար մեկ գոտի ունեցող երկկողմ երթևեկությամբ ճանապարհներին արագության սահմանափակում կամ 7 մ ավելի երկարություն ունեցող տրանսպորտային միջոցների վարորդները մինչև առջևից ընթացող տրանսպորտային միջոցը պետք է ապահովեն այնպիսի տարածություն, որպեսզի իրենց վազանցող տրանսպորտային միջոցների վարորդներին հնարավորություն տան անհրաժեշտության դեպքում առանց խոչընդոտի վերադասավորվելու նախկինում զբաղեցրած գոտի: Այդ պահանջը չի գործում վազանցն արգելված ճանապարհահատվածներում, ինչպես նաև ինտենսիվ երթևեկության ժամանակ և կազմակերպված տրանսպորտային շարասյան կազմում երթևեկելիս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1107,1107,102,' 64. Վարորդը երկկողմ երթևեկությամբ ճանապարհին, բաժանարար գոտու բացակայության դեպքում երթևեկելի մասում գտնվող անվտանգության կղզյակները, կարճասյուները և ճանապարհային կառույցների (կամուրջների, ուղեկամուրջների հենասյուներ և այլն) տարրերը պետք է շրջանցի աջ կողմից, եթե նշանները և գծանշումներն այլ բան չեն թելադրում:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1108,1108,102,'65. Վարորդը տրանսպորտային միջոցը պետք է վարի սահմանված արագությունը չգերազանցող արագությամբ` հաշվի առնելով երթևեկության ինտենսիվությունն ու տրանսպորտային միջոցի և բեռի վիճակն ու առանձնահատկությունները, ճանապարհային և օդերևութաբանական պայմանները, մասնավորապես, ճանապարհային ծածկույթի վիճակն ու տեսանելիությունը երթևեկության ուղղությամբ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1109,1109,102,' 66. Վարորդը պետք է ընտրի այնպիսի արագություն, որը հնարավորություն է տալիս նրան կանոնների պահանջներին համապատասխան ապահովելու տրանսպորտային միջոցի լիարժեք կառավարումը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1110,1110,102,' 67. Երթևեկության համար խոչընդոտ կամ վտանգ առաջանալու դեպքում, որը վարորդն ի վիճակի էր հայտնաբերել, նա պետք է միջոցներ ձեռնարկի արագությունն իջեցնելու` ընդհուպ մինչև տրանսպորտային միջոցը կանգնեցնելը: Այդ դեպքում կողանցումն ու շրջանցումը թույլատրելի է, եթե վարորդը համոզված է, որ դա անվտանգ է երթևեկության մյուս մասնակիցների համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1111,1111,102,' 68. Բնակավայրերում տրանսպորտային միջոցների երթևեկությունը թույլատրվում է 60 կմ/ժ ոչ ավելի արագությամբ, իսկ այն տարածքներում, որոնց մուտքն ու ելքը նշված են 5.21` «Բնակելի գոտի» և 5.22` «Բնակելի գոտու վերջ» նշաններով, ինչպես նաև բակային տարածքներում` 20 կմ/ժ ոչ ավելի արագությամբ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1112,1112,102,' 69.Բնակավայրերից դուրս երթևեկությունը թույլատրվում է`1) 90 կմ/ժ ոչ ավելի արագությամբ` թեթև մարդատար ավտոմոբիլներով և 3,5 տ ոչ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներով (110 կմ/ժ ոչ ավելի արագությամբ` ավտոմայրուղիներով).2) 90 կմ/ժ ոչ ավելի արագությամբ` մերձքաղաքային, միջմարզային և միջքաղաքային փոխադրումներ իրականացնող ավտոբուսներով, միկրոավտոբուսներով ու մոտոցիկլներով` բոլոր ճանապարհներին.3) 70 կմ/ժ ոչ ավելի արագությամբ` մնացած բոլոր ավտոբուսներով, կցորդի հետ կցված թեթև մարդատար ավտոմոբիլներին և 3,5 տ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներին (90 կմ/ժ ոչ ավելի արագությամբ` ավտոմայրուղիներով): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1113,1113,102,' 70. Բնակավայրերում և բնակավայրերից դուրս ճանապարհների առանձին հատվածներում, 3.24` «Առավելագույն արագության սահմանափակում» նշանի կիրառմամբ, կարող է սահմանվել սույն կանոնների 68-70-րդ կետերով սահմանված առավելագույն արագությունից ինչպես ցածր, այնպես էլ բարձր արագություն: 3.24` «Առավելագույն արագության սահմանափակում» նշանի կիրառմամբ սույն կանոնների 68-70-րդ կետերով սահմանված առավելագույն արագությունից բարձր արագություն սահմանելու դեպքում այն չի կարող գերազանցել բնակավայրում 80 կմ/ժ-ը, իսկ բնակավայրից դուրս՝ 110 կմ/ժ-ը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1114,1114,102,' 71. Թույլատրվում է երթևեկել`1) 60 կմ/ժ ոչ ավելի արագությամբ` կահավորված թափքում մարդ փոխադրող բեռնատար ավտոմոբիլներով և երեխաների կազմակերպված խմբեր փոխադրող տրանսպորտային միջոցներով.2) 50 կմ/ժ ոչ ավելի արագությամբ` միմյանց կցված մեխանիկական տրանսպորտային միջոցներով քարշակում կատարելիս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1115,1115,102,' 72. Վարորդին արգելվում է`1) գերազանցել տվյալ տրանսպորտային միջոցի տեխնիկական բնութագրով սահմանված առավելագույն արագությունը.2) գերազանցել տրանսպորտային միջոցի վրա տեղադրված «Արագության սահմանափակում» ճանաչման նշանով նախատեսված արագությունը.3) մեծ եզրաչափերով, վտանգավոր կամ ծանրաքաշ բեռ փոխադրելիս` գերազանցել փոխադրման պայմանների համաձայնեցման ժամանակ որոշված արագությունը.4) առանց անհրաժեշտության ընթանալ շատ ցածր արագությամբ` խոչընդոտելով մյուս տրանսպորտային միջոցների երթևեկությանը.5) կտրուկ արգելակել, եթե դա անհրաժեշտ չէ ճանապարհատրանսպորտային պատահար կանխելու համար:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1116,1116,102,'73. Վազանցն սկսելուց առաջ վարորդը պետք է համոզվի, որ՝1) հանդիպակաց երթևեկության գոտին, որը նա պատրաստվում է զբաղեցնել, բավարար տարածությամբ ազատ է վազանցի համար, և որ դրանով խոչընդոտ չի ստեղծի հանդիպակաց ընթացող տրանսպորտային միջոցների համար.2) իր հետևից նույն գոտիով ընթացող տրանսպորտային միջոցը վազանց չի սկսել, իսկ առջևից ընթացողը վազանցի (ձախ շրջադարձի, հետադարձի) ազդանշան չի տվել.3) վազանցն ավարտելիս անհրաժեշտության դեպքում կարող է առանց վազանցվող տրանսպորտային միջոցի (միջոցների) համար խոչընդոտ ստեղծելու վերադառնալ նախկինում զբաղեցրած գոտի: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1117,1117,102,' 74. Ոչ ռելսագնաց տրանսպորտային միջոցին վազանցել թույլատրվում է միայն ձախ կողմից: Սակայն եթե առջևից ընթացող տրանսպորտային միջոցի վարորդը տվել է ձախ շրջադարձի ազդանշան և սկսել մանևրի կատարումը, ապա այդ տրանսպորտային միջոցին վազանցը կատարվում է աջից: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1118,1118,102,' 75. Վազանցվող տրանսպորտային միջոցի վարորդին արգելվում է արագությունը բարձրացնելով կամ որևէ այլ գործողությամբ խոչընդոտել վազանց կատարելուն: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1119,1119,102,' 76. Եթե բնակավայրերից դուրս դանդաղընթաց կամ մեծ եզրաչափեր ունեցող տրանսպորտային միջոցին վազանց կատարելը դժվար է, ապա դրա վարորդը (իսկ ուղեկցման դեպքում` նաև ուղեկցող տրանսպորտային միջոցի վարորդը) պետք է երթևեկի հնարավորինս աջով, իսկ անհրաժեշտության դեպքում կանգ առնի և բաց թողնի իր հետևից ընթացող տրանսպորտային միջոցների վարորդներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1120,1120,102,' 77. Վազանցն արգելվում է`1) խաչմերուկներում.2) հետիոտնային անցումների վրա.3) երկաթուղային գծանցների վրա և մինչև 100 մ դրանցից առաջ.4) եթե վազանցվող տրանսպորտային միջոցի վարորդը կատարում է վազանց կամ շրջանցում է արգելքը.5) թունելներում, էստակադների, կամուրջների, ուղեկամուրջների վրա և դրանց տակ, ինչպես նաև ճանապարհների նեղացումներում.6) կապույտ գույնի առկայծող փարոսիկ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոցին.7) եթե վազանցվող տրանսպորտային միջոցը երթևեկում է կապույտ և կարմիր գույների առկայծող փարոսիկներ ու հատուկ ձայնային ազդանշան միացրած վիճակում կամ ուղեկցվում է այդպիսի տրանսպորտային միջոցներով.8) վերելքի վերջում և ճանապարհի սահմանափակ տեսանելիությամբ հատվածներում, երբ վազանցը կատարվում է հանդիպակաց երթևեկության գոտի դուրս գալով:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1121,1121,102,'78. Տրանսպորտային միջոցների կանգառը և կայանումը թույլատրվում է ճանապարհի աջ մասում` մայթի մոտ կամ կողնակին, դրանց բացակայության դեպքում` երթևեկելի մասի եզրին: Կանոնների 81-րդ կետով նախատեսված դեպքում կայանումը թույլատրվում է նաև մայթեզրին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1122,1122,102,' 79. Բնակավայրերում, երթևեկելի մասի ձախ կողմում կանգառ ու կայանում թույլատրվում է`1) յուրաքանչյուր ուղղությամբ մեկ երթևեկելի գոտի ունեցող, մեջտեղում տրամվայի գծեր չունեցող ճանապարհներին.2) միակողմ երթևեկության ճանապարհներին (3,5 տ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներին թույլատրվում է միայն կանգառ` բեռնելու կամ բեռնաթափելու, ինչպես նաև ուղևորի նստելու կամ իջնելու համար): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1123,1123,102,' Տրանսպորտային միջոցը տեղակայել թույլատրվում է երթևեկելի մասի եզրին զուգահեռ մեկ շարքով` բացառությամբ այն տեղերի (երթևեկելի մասի տեղային լայնացում), որտեղ գծանշմամբ թույլատրված են տրանսպորտային միջոցների դասավորման այլ ձևեր: Առանց կողային կցորդի երկանիվ տրանսպորտային միջոցները թույլատրվում է կանգնեցնել երկու շարքով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1124,1124,102,' 81. Երթևեկելի մասին սահմանակից մայթեզրին կայանման նպատակով կանգնեցնել թույլատրվում է միայն թեթև մարդատար ավտոմոբիլները, մոտոցիկլները, մոպեդները և հեծանիվները` 6.4` «Կայանման տեղ» նշանի և 8.6.2, 8.6.3, 8.6.6-8.6.9` «Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում» ցուցանակներից որևէ մեկի առկայության դեպքում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1125,1125,102,' 82. Բնակավայրերից դուրս երկարատև հանգստի, գիշերակացի և այլ նպատակներով կայանել թույլատրվում է միայն դրանց համար նախատեսված հրապարակներում կամ ճանապարհի սահմաններից դուրս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1126,1126,102,' 83. Կանգառն արգելված վայրում հարկադրված կանգառ կատարելու դեպքում կանոնների 22-րդ և 23-րդ կետերի պահանջները կատարելուց հետո վարորդը պետք է ձեռնարկի բոլոր անհրաժեշտ միջոցները` տրանսպորտային միջոցն այդ վայրից դուրս բերելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1127,1127,102,' 84. Կանգառն արգելվում է`1) մայթերին, բացառությամբ 61-րդ կետում նշված դեպքերի, ինչպես նաև տրամվայի գծերի վրա և անմիջապես դրանց մոտ, եթե դա խոչընդոտում է տրամվայների երթևեկությունը.2) երկաթուղային գծանցների վրա, թունելներում, ինչպես նաև էստակադների, կամուրջների, ուղեկամուրջների վրա և դրանց տակ.3) այն վայրերում, որտեղ կանգնած տրանսպորտային միջոցի և հոծ գծի (բացառությամբ երթևեկելի մասի եզրը ցույց տվող) կամ բաժանարար գոտու կամ երթևեկելի մասի հակառակ կողմի եզրի կամ որևէ արգելքի միջև տարածությունը 3 մ պակաս է.4) հետիոտնային անցումների վրա և շարժման ուղղությամբ հետիոտնային անցումից առաջ՝ 5 մ մոտ վայրում5) երթևեկելի մասի վրա` ճանապարհի այն վտանգավոր շրջադարձերին և երկայնական պրոֆիլի ուռուցիկ բեկվածքներին մոտիկ, որտեղ ճանապարհի տեսանելիությունը թեկուզ մեկ ուղղությամբ պակաս է 100 մ-ից.6) խաչմերուկներում, երթևեկելի մասերի հատման վրա և հատվող երթևեկելի մասի եզրից 5 մ պակաս վայրում` բացառությամբ երթևեկելի մասերի եռակողմ հատման հոծ գծով կամ բաժանարար գոտիով առանձնացված կողմի վրա (շարունակություն չունեցող կողմի դիմաց).7) 1.17 գծանշմամբ նշված ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետերից կամ, այդ գծանշման բացակայության դեպքում, ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կամ տաքսիների կայանման տեղերի ցուցիչներից 15 մ մոտ.8) այն վայրում, որտեղ տրանսպորտային միջոցը թույլ չի տա երթևեկության մասնակիցներին տեսնելու լուսացույցի ազդանշանները, ճանապարհային նշանները կամ որևէ այլ կերպ կսահմանափակի տեսանելիությունը մյուս տրանսպորտային միջոցների վարորդների ու հետիոտների համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1128,1128,102,' 85. Ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառն արգելվում է նաև ընդհանուր օգտագործման տրանսպորտային միջոցների կանգառի կետերի տարածքից դուրս` բացառությամբ հարկադրված կանգառի դեպքերի: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1129,1129,102,' 86. Կայանումն արգելվում է`1) կանգառն արգելված վայրում.2) բնակավայրերից դուրս` 2.1. «Գլխավոր ճանապարհ» ճանապարհային նշանով նշված ճանապարհների երթևեկելի մասի վրա.3) երկաթուղային գծանցներին 50 մ-ից մոտ:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1130,1130,102,'86.1. Խաչմերուկին մոտենալիս վարորդը պետք է առանձնահատուկ ուշադրություն ցուցաբերի՝ ելնելով տեղի պայմաններից: Մասնավորապես, վարորդը տրանսպորտային միջոցը պետք է վարի այնպիսի արագությամբ, որ հնարավորություն ունենա կանգնելու և բաց թողնելու անցման առաջնահերթության իրավունք ունեցող փոխադրամիջոցները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1131,1131,102,' 87. Աջ կամ ձախ շրջադարձ կատարելիս խաչմերուկից դուրս գալիս` վարորդը պետք է խոչընդոտ չստեղծի երթևեկելի մասը հատող հետիոտների համար և պետք է ճանապարհը զիջի հեծանվային արահետով երթևեկող հեծանվորդներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1132,1132,102,' 88. Արգելվում է մուտք գործել խաչմերուկ կամ երթևեկելի մասերի հատում, եթե առաջացել է խցանում, որը վարորդին կհարկադրի կանգ առնել` խոչընդոտելով այլ տրանսպորտային միջոցների երթևեկությանը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1133,1133,102,' 89. Այն խաչմերուկը, որտեղ երթևեկության հերթականությունը որոշվում է կարգավորողի կամ լուսացույցի ազդանշաններով, համարվում է կարգավորվող: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1134,1134,102,' 90. Լուսացույցի կանաչ ազդանշանի դեպքում ձախ շրջադարձ կամ հետադարձ կատարելիս` ոչ ռելսագնաց տրանսպորտային միջոցի վարորդը պետք է ճանապարհը զիջի հանդիպակաց ուղղությունից ուղիղ և դեպի աջ ընթացող տրանսպորտային միջոցներին: Նույն կանոնով պետք է ղեկավարվեն նաև տրամվայների վարորդները միմյանց հետ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1135,1135,102,' 91. Լուսացույցի դեղին կամ կարմիր ազդանշանի հետ միաժամանակ միացված լրացուցիչ սեկցիայի սլաքի ուղղությամբ երթևեկող վարորդը պետք է ճանապարհը զիջի այլ ուղղություններից ընթացող տրանսպորտային միջոցներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1136,1136,102,' 92.Եթե կարգավորողի կամ լուսացույցի ազդանշանները թույլատրում են տրամվայի և ոչ ռելսագնաց տրանսպորտային միջոցների միաժամանակյա երթևեկություն, ապա, անկախ շարժման ուղղությունից, երթևեկության առավելություն ունի տրամվայի վարորդը: Սակայն լուսացույցի դեղին կամ կարմիր ազդանշանի հետ միաժամանակ միացված լրացուցիչ սեկցիայի սլաքի ուղղությամբ երթևեկելու դեպքում տրամվայի վարորդը պետք է ճանապարհը զիջի այլ ուղղություններից մոտեցող տրանսպորտային միջոցներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1137,1137,102,' 93. Լուսացույցի թույլատրող ազդանշանի դեպքում խաչմերուկ մուտք գործած վարորդը կարող է այն ազատել նախընտրած ուղղությամբ, սակայն պայմանով, որ դա չի խանգարի երթևեկության մյուս մասնակիցների շարժմանն այն ուղղությամբ, որով երթևեկությունը բաց է` անկախ ելքի լուսացույցի ազդանշանից, սակայն եթե խաչմերուկում տրանսպորտային միջոցի ընթացքի ուղղությամբ տեղադրված լուսացույցներից առաջ առկա է 1.12` «Կանգ-գիծ» գծանշումը (կամ 6.16` «Կանգ-գիծ» նշաններ), նա պետք է ղեկավարվի յուրաքանչյուր լուսացույցի ազդանշաններով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1138,1138,102,' Չկարգավորվող խաչմերուկներ  ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1139,1139,102,' 95. Այն խաչմերուկը, որտեղ բացակայում է լուսացույցը կամ կարգավորողը, չի աշխատում լուսացույցը, կամ միացված է լուսացույցի դեղին թարթող ազդանշանը, համարվում է չկարգավորվող: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1140,1140,102,' 96. Երկրորդական ճանապարհով անհավասարազոր ճանապարհների խաչմերուկին մոտեցող տրանսպորտային միջոցի վարորդը պետք է ճանապարհը զիջի գլխավոր ճանապարհով ընթացող տրանսպորտային միջոցներին` անկախ դրանց հետագա երթևեկության ուղղությունից:Այդպիսի խաչմերուկներում տրամվայը, անկախ երթևեկության ուղղությունից, առավելություն ունի հավասարազոր ճանապարհով համընթաց կամ հանդիպակաց ուղղությամբ երթևեկող ոչ ռելսագնաց տրանսպորտային միջոցների նկատմամբ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1141,1141,102,' 97. Եթե գլխավոր ճանապարհը խաչմերուկում փոխում է ուղղությունը, ապա դրանով ընթացող վարորդներն իրենց գործողություններում միմյանց նկատմամբ ղեկավարվում են հավասարազոր ճանապարհների խաչմերուկի անցման կանոններով: Նույն կանոններով միմյանց նկատմամբ պետք է ղեկավարվեն երկրորդական ճանապարհներով երթևեկող տրանսպորտային միջոցների վարորդները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1142,1142,102,' 98.Հավասարազոր ճանապարհների խաչմերուկում ոչ ռելսագնաց տրանսպորտային միջոցի վարորդը պետք է ճանապարհը զիջի աջ կողմից մոտեցող տրանսպորտային միջոցների վարորդներին: Նույն կանոնով միմյանց նկատմամբ պետք է ղեկավարվեն նաև տրամվայների վարորդները: Այդպիսի խաչմերուկում տրամվայը, անկախ երթևեկության ուղղությունից, առավելություն ունի ոչ ռելսագնաց տրանսպորտային միջոցների նկատմամբ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1143,1143,102,' 98.1. 4.3` «Շրջանաձև երթևեկություն» նշանով կահավորված շրջանաձև երթևեկությամբ խաչմերուկ մուտք գործելիս տրանսպորտային միջոցի վարորդը պարտավոր է ճանապարհը զիջել այդպիսի խաչմերուկում երթևեկող տրանսպորտային միջոցներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1144,1144,102,' 99. Ձախ շրջադարձի կամ հետադարձի ժամանակ ոչ ռելսագնաց տրանսպորտային միջոցի վարորդը պետք է ճանապարհը զիջի հավասարազոր ճանապարհով հանդիպակաց ուղղությունից ուղիղ կամ դեպի աջ ընթացող տրանսպորտային միջոցների վարորդներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1145,1145,102,' 100. Չկարգավորվող խաչմերուկներում տրամվայի վարորդը, անկախ երթևեկության ուղղությունից, երթևեկության առավելություն ունի հավասարազոր ճանապարհով համընթաց կամ հանդիպակաց ուղղությամբ ընթացող ոչ ռելսագնաց տրանսպորտային միջոցների վարորդների նկատմամբ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1146,1146,102,' 101. Երբ վարորդը չի կարող որոշել ճանապարհի ծածկույթի առկայությունը (օրվա մութ ժամանակ, ցեխ, ձյուն և այլն), և բացակայում են առավելության նշանները, ապա նա պետք է համարի, որ գտնվում է երկրորդական ճանապարհի վրա:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1147,1147,102,'102. Կարգավորվող և չկարգավորվող հետիոտնային անցում հասկացությունները համանման են կարգավորվող և չկարգավորվող խաչմերուկ հասկացություններին, որոնք սահմանված են կանոնների 89-րդ և 95-րդ կետերով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1148,1148,102,' 103. Տրանսպորտային միջոցի վարորդը չպետք է խոչընդոտ ստեղծի չկարգավորվող հետիոտնային անցումներով երթևեկելի մասը հատող հետիոտներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1149,1149,102,' 104. Եթե որևէ տրանսպորտային միջոց չկարգավորվող հետիոտնային անցումից առաջ դանդաղեցրել է ընթացքը կամ կանգնել, ապա հարևան շարքերով ընթացող մյուս տրանսպորտային միջոցների վարորդները կարող են շարունակել երթևեկությունը` միայն համոզվելով, որ այդ տրանսպորտային միջոցի առջևում հետիոտներ չկան: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1150,1150,102,' 105. Կարգավորվող հետիոտնային անցումներում, լուսացույցի թույլատրող ազդանշանը միանալուց հետո վարորդը պետք է հնարավորություն տա հետիոտներին ավարտելու ընտրված ուղղությամբ երթևեկելի մասի հատումը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1151,1151,102,' 106. Հետիոտնային անցումից հետո խցանում առաջանալու դեպքում արգելվում է մուտք գործել անցում, եթե դա կհարկադրի վարորդին կանգնել հետիոտնային անցման վրա: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1152,1152,102,' 107. Բոլոր դեպքերում, այդ թվում նաև՝ հետիոտնային անցումներից դուրս, վարորդը չպետք է խոչընդոտ ստեղծի երթևեկելի մասը հատող կույր հետիոտներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1153,1153,102,' 108. Կույր հետիոտներն իրենց գործողությունների մասին պետք է ազդանշան տան սպիտակ ձեռնափայտով:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1154,1154,102,'109. Տրանսպորտային միջոցների վարորդները երկաթուղային գծերը կարող են հատել միայն երկաթուղային գծանցներով` ճանապարհը զիջելով գնացքին (լոկոմոտիվին, երկաթուղասայլակին): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1155,1155,102,' 110. Երկաթուղային գծանցին մոտենալիս վարորդը պետք է ղեկավարվի գծանցի հերթապահի ցուցումներով, երկաթուղային գծանցներով երթևեկությունը կարգավորելու համար նախատեսված լուսացույցների, նշանների, գծանշումների պահանջներով, ուղեփակոցի դիրքով և համոզվի, որ գծանցին գնացք (լոկոմոտիվ, երկաթուղասայլակ) չի մոտենում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1156,1156,102,' 111. Այն դեպքերում, երբ գծանցով երթևեկությունն արգելված է, վարորդը պետք է կանգնի 1.12` «Կանգ» գծի, 2.5` «Երթևեկությունն առանց կանգառի արգելված է» նշանի կամ լուսացույցի մոտ, եթե դրանք բացակայում են` ուղեփակոցից ոչ պակաս, քան 5 մ, իսկ եթե բացակայում է նաև ուղեփակոցը, ապա մոտակա ռելսից ոչ պակաս, քան 10 մ հեռավորության վրա: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1157,1157,102,' 112. Գծանցի վրա հարկադրված կանգառ կատարելու դեպքում վարորդը պետք է`1) անհապաղ իջեցնի ուղևորներին և միջոցներ ձեռնարկի գծանցն ազատելու համար.2) հնարավորության դեպքում գծի երկայնքով երկու մարդ ուղարկի գծանցի ամեն մի կողմը 1000 մ հեռավորության վրա (եթե մեկին, ապա վատ տեսանելիության կողմը)` նրանց բացատրելով մոտեցող գնացքի մեքենավարին կանգառի ազդանշան տալու կարգը.3) մնա տրանսպորտային միջոցի մոտ և տա ընդհանուր տագնապի ազդանշան։4) գնացք երևալու դեպքում վազի ընդառաջ` տալով կանգառի ազդանշանԸնդհանուր տագնապի ազդանշան է ծառայում իրար հետևից տրվող մեկ երկար և երեք կարճ ձայնային ազդանշանների համակցությունը, իսկ որպես մեքենավարին տրվող կանգառի ազդանշան ընդունված է ձեռքի շրջանաձև շարժումը (ցերեկը` վառ գույնի լաթով կամ որևէ լավ տեսանելի առարկայով, գիշերը` ջահով կամ լապտերով): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1158,1158,102,' 113. Վարորդին արգելվում է մուտք գործել գծանց`1) փակ կամ փակվող ուղեփակոցի դեպքում (լուսացույցի ազդանշանից անկախ).2) լուսացույցի արգելող ազդանշանի դեպքում (ուղեփակոցի առկայությունից և դիրքից անկախ).3) եթե գծանցից հետո առաջացել է խցանում, որը վարորդին կհարկադրի կանգնել գծանցի վրա.4) եթե տեսանելիության սահմաններում գծանցին մոտենում է գնացք (լոկոմոտիվ, երկաթուղասայլակ).5) գծանցի հերթապահի արգելող ազդանշանի դեպքում.Գծանցի հերթապահի արգելող ազդանշան է հանդիսանում հերթապահի կրծքով կամ մեջքով դեպի վարորդն ուղղված դիրքը, ցուցաձողը, կարմիր լապտերը կամ գլխից վեր բարձրացրած դրոշակը կամ կողմ պարզած ձեռքերը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1159,1159,102,' 114. Վարորդին արգելվում է նաև`1) հանդիպակաց երթևեկության գոտի դուրս գալով` շրջանցել գծանցից առաջ կանգնած տրանսպորտային միջոցները.2) ինքնակամ բացել ուղեփակոցը.3) գծանցով փոխադրել ոչ տրանսպորտային վիճակում գտնվող գյուղատնտեսական, ճանապարհային, շինարարական և այլ մեքենաներ ու մեխանիզմներ.4) առանց երկաթգծի ուղեմասի պետի թույլտվության գծանցով երթևեկել դանդաղընթաց մեքենաներով` 8 կմ/ժ ցածր արագությամբ և տափանների հետ կցված տրակտորներով:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1160,1160,102,'115. Ավտոմայրուղին 5.1` «Ավտոմայրուղի» ճանապարհային նշանի ազդման գոտում գտնվող ճանապարհ է, որը նույն մակարդակի վրա չունի հատումներ կամ հարակցումներ այլ ճանապարհների, երկաթուղային գծանցների կամ տրամվայի գծերի, հետիոտնային անցումների կամ հեծանվային արահետների հետ, չի սպասարկում ճանապարհամերձ տիրույթները և որում հանդիպակաց երթևեկելի մասերը բաժանված են բաժանարար գոտիով կամ ճանապարհային ցանկապատով: Ավտոմայրուղի համարվող ճանապարհի սկիզբը և վերջը նշվում են 5.1` «Ավտոմայրուղի» և 5.2` «Ավտոմայրուղու վերջը» նշաններով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1161,1161,102,' 116. Ավտոմայրուղիներում արգելվում են`1) հետիոտների տեղաշարժը, բեռնակիր, հեծկան կամ այլ կենդանիներ քշելը.2) հեծանիվների, մոպեդների, լծասայլերի (լծասահնակների), տրակտորների ու ինքնագնաց մեքենաների և այն տրանսպորտային միջոցների երթևեկությունը, որոնց արագությունը, տեխնիկական բնութագրերից կամ վիճակից ելնելով, չի գերազանցում 40 կմ/ժ.3) 3,5 տ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների երթևեկությունը` երկրորդ գոտուց ձախ գտնվող այլ գոտիով.4) կանգառը` 6.4` «Կայանման տեղ» կամ 7.11` «Հանգստի վայր» նշաններով կահավորված կայանման հատուկ հարթակներից դուրս.5) մուտքը բաժանարար գոտու տեխնոլոգիական խզվածքներ, բացառությամբ ճանապարհների պահպանման կամ մաքրման աշխատանքներ իրականացնող տրանսպորտային միջոցների.6) հետընթացը.7) ուսումնական վարումը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1162,1162,102,' 117. Սույն բաժնի պահանջները տարածվում են նաև 5.3` «Ճանապարհ ավտոմոբիլների համար» նշանով կահավորված, իսկ 116-րդ կետի 5-րդ ենթակետի պահանջները` նաև ընդհանուր օգտագործման ճանապարհների վրա:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1163,1163,102,'118. Բնակելի գոտին կառուցապատված տարածք է, որի մուտքն ու ելքը նշված են 5.21` «Բնակելի գոտի» և 5.22` «Բնակելի գոտու վերջ» ճանապարհային նշաններով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1164,1164,102,' 119. Բնակելի գոտում հետիոտների տեղաշարժը թույլատրվում է ինչպես մայթերով, այնպես էլ երթևեկելի մասով: Բնակելի գոտում հետիոտներն ունեն առավելություն, սակայն նրանք չպետք է անտեղի խոչընդոտեն տրանսպորտային միջոցների երթևեկությունը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1165,1165,102,' 120. Բնակելի գոտուց դուրս գալիս՝ վարորդները պետք է ճանապարհը զիջեն մյուս տրանսպորտային միջոցների վարորդներին և չստեղծեն խոչընդոտ հետիոտների համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1166,1166,102,' 121. Բնակելի գոտիներում արգելվում են`1) ուսումնական վարումը.2) միջանցիկ երթևեկությունը.3) կայանելը` աշխատող շարժիչով.4) 3,5 տ ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների և ավտոբուսների (բացառությամբ միկրոավտոբուսների) կայանելը դրա համար նախատեսված և նշաններով կահավորված ու (կամ) գծանշված տեղերից դուրս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1167,1167,102,' 122. Սույն բաժնի պահանջները տարածվում են նաև այն բակային տարածքների վրա, որոնք նշված չեն 5.21` «Բնակելի գոտի» ճանապարհային նշանով, սակայն ամբողջ պարագծով պարփակված են բնակելի շենքերով:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1168,1168,102,'123. Խաչմերուկներից դուրս, որտեղ տրամվայի գծերը հատում են երթևեկելի մասը, տրամվայն ունի առավելություն ոչ ռելսագնաց տրանսպորտային միջոցների նկատմամբ` բացառությամբ, երբ այն դուրս է գալիս դեպոյից: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1169,1169,102,' 124.5.14` «Ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտի», 5.11` «Ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտիով ճանապարհ», 5.13.1 և 5.13.2` «Ելք դեպի ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտիով ճանապարհ» նշաններով նշված, ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտի ունեցող ճանապարհներին արգելվում է այլ տրանսպորտային միջոցների երթևեկությունն ու կանգառն այդ գոտում: Եթե ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտին մնացած երթևեկելի մասից բաժանված է ընդհատվող գծանշմամբ, ապա, նման գոտիով ճանապարհ մուտք գործելիս, թույլատրվում է մտնել այդ գոտի` հարևան գոտի անհապաղ վերադասավորվելու պայմանով: Թույլատրվում է նաև նման գծանշմամբ գոտիներ մուտք գործել ինչպես ուղևորներ իջեցնելու և նստեցնելու, այնպես էլ այդ ճանապարհից շրջադարձ կատարելու համար: Նշված գծանշմամբ գոտիներ մուտք գործելիս և դրանցից դուրս գալիս՝ վարորդները պետք է ճանապարհը զիջեն ընդհանուր օգտագործման տրանսպորտային միջոցների վարորդներին, ինչպես նաև չխոչընդոտեն նրանց երթևեկությունը` այդպիսի գոտիներում ուղևորներ իջեցնելիս և նստեցնելիս: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1170,1170,102,' 125. Բնակավայրերում կահավորված և նշված կանգառի կետերի տարածքից երթևեկությունն սկսող ընդհանուր օգտագործման տրանսպորտային միջոցների վարորդներն ունեն երթևեկության առավելություն, սակայն այն սկսել կարող են միայն՝ համոզվելով, որ հարևան գոտիով մոտեցող տրանսպորտային միջոցներն իրենց համար խոչընդոտ չեն ստեղծում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1171,1171,102,' 126. Վարորդները պետք է խոչընդոտ չստեղծեն ընդհանուր օգտագործման տրանսպորտային միջոցի կանգառի կետում կանգնած ընդհանուր օգտագործման տրանսպորտային միջոցին մոտեցող կամ դրանից (դռների կողմից) հեռացող հետիոտներին, եթե իջնելն ու նստելը կատարվում է երթևեկելի մասից կամ երթևեկելի մասում գտնվող կանգառի հարթակից:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1172,1172,102,'127. Օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, անկախ ճանապարհի լուսավորվածությունից, ինչպես նաև թունելներում երթևեկող տրանսպորտային միջոցների վրա պետք է միացված լինեն հետևյալ լուսային սարքերը`1) բոլոր մեխանիկական տրանսպորտային միջոցների և մոպեդների վրա` լապտերների հեռահար կամ մոտակա լույսը, հեծանիվների վրա` լապտերները կամ լապտերիկները, իսկ լծասայլերի վրա` լապտերիկները (առկայության դեպքում).2) կցորդների և քարշակվող մեխանիկական տրանսպորտային միջոցների վրա` եզրաչափային լույսերը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1173,1173,102,' 128. Լապտերների հեռահար լույսը պետք է փոխարկվի մոտակայի`1) բնակավայրերում, եթե ճանապարհը լուսավորված է.2) հանդիպակաց երթևեկող տրանսպորտային միջոցից 150 մ ոչ պակաս հեռավորության վրա, իսկ եթե այդ տրանսպորտային միջոցի վարորդը, պարբերաբար փոխարկելով լապտերների լույսը, տեղեկացնում է դրա անհրաժեշտության մասին, ապա ավելի մեծ հեռավորության վրա.3) ցանկացած այլ դեպքերում` հանդիպակաց և համընթաց երթևեկող տրանսպորտային միջոցների վարորդներին շլացնելու հնարավորությունը բացառելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1174,1174,102,' 129. Շլանալու դեպքում վարորդը պետք է միացնի վթարային լուսային ազդանշանը և չփոխելով երթևեկության գոտին, իջեցնի արագությունը, իսկ անհրաժեշտության դեպքում կանգնի: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1175,1175,102,' 130. Օրվա մութ ժամանակ ճանապարհի չլուսավորված հատվածներում, իսկ անբավարար տեսանելիության պայմաններում` անկախ ճանապարհի լուսավորվածությունից, կանգառի և կայանման դեպքում պետք է միացված լինեն տրանսպորտային միջոցի եզրաչափային լույսերը: Անբավարար տեսանելիության պայմաններում եզրաչափային լույսերի հետ լրացուցիչ կարող են միացվել նաև լապտերների մոտակա լույսերը, հակամառախուղային լապտերները կամ հետին հակամառախուղային լապտերիկները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1176,1176,102,' 131. Հետին հակամառախուղային լապտերիկները կարող են օգտագործվել միայն անբավարար տեսանելիության պայմաններում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1177,1177,102,' 132. Հակամառախուղային լապտերները երթևեկող տրանսպորտային միջոցների վրա կարող են օգտագործվել`1) օրվա մութ ժամանակ ճանապարհների չլուսավորված հատվածներում` մոտակա կամ հեռահար լույսերի հետ միաժամանակ.2) անբավարար տեսանելիության պայմաններում` ինչպես առանձին, այնպես էլ լապտերների մոտակա կամ հեռահար լույսերի հետ միաժամանակ.3) լապտերների մոտակա լույսի փոխարեն` կանոնների 133-րդ կետում նախատեսված դեպքերում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1178,1178,102,' 133. Օրվա լուսավոր ժամերին երթևեկող տրանսպորտային միջոցը նշելու նպատակով լապտերների մոտակա լույսը պետք է միացված լինի`1) մոտոցիկլների և մոպեդների վրա.2) կազմակերպված տրանսպորտային շարասյունում երթևեկելիս.3) հատուկ առանձնացված գոտիով, հիմնական հոսքին հանդիպակաց երթևեկող ընդհանուր օգտագործման տրանսպորտային միջոցների վրա.4) երեխաների խմբերի կազմակերպված փոխադրումներ կատարելիս.5) մեծ եզրաչափերով, ծանրաքաշ, վտանգավոր բեռներ և չվնասազերծված տարա փոխադրելիս.6) մեխանիկական տրանսպորտային միջոցներ քարշակելիս (քարշակող տրանսպորտային միջոցի վրա): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1179,1179,102,' 134. Լապտեր-լուսարձակ և փնտրող լապտեր թույլատրվում է օգտագործել միայն բնակավայրերից դուրս` հանդիպակաց և համընթաց տրանսպորտային միջոցների բացակայության դեպքում: Բնակավայրերում այդպիսի լապտերներից կարող են օգտվել միայն սահմանված կարգով կապույտ կամ կապույտ և կարմիր առկայծող փարոսիկներով և հատուկ ձայնային ազդանշանով կահավորված տրանսպորտային միջոցների վարորդները` ծառայողական առաջադրանք կատարելիս:135. «Ավտոգնացք» ճանաչման նշանը պետք է միացված լինի երթևեկության մեջ գտնվող ավտոգնացքի վրա (բացառությամբ կցորդի հետ կցված թեթև մարդատար ավտոմոբիլների), իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, հաշվի առնելով կանոնների 130-րդ կետի պահանջները, նաև կանգառի և կայանման ժամանակ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1180,1180,102,' «Ավտոգնացք» ճանաչման նշանը պետք է միացված լինի շարժման մեջ գտնվող ավտոգնացքի վրա, իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, հաշվի առնելով կանոնների 130-րդ կետի պահանջները, նաև կանգառի և կայանման ժամանակ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1181,1181,102,' 136. Ձայնային ազդանշանները կարող են կիրառվել միայն`1) բնակավայրերից դուրս վազանց կատարելու մտադրության մասին մյուս վարորդներին նախազգուշացնելու համար.2) այն դեպքերում, երբ դա անհրաժեշտ է ճանապարհատրանսպորտային պատահարը կանխելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1182,1182,102,' 137. Վազանցի մասին նախազգուշացնելու համար ձայնային ազդանշանի փոխարեն (կամ նրա հետ միաժամանակ) կարող է տրվել լուսային ազդանշան, որն իրենից ներկայացնում է օրվա լուսավոր ժամանակ լապտերների լույսի պարբերաբար միացումն ու անջատումը, իսկ օրվա մութ ժամանակ` լապտերների լույսի բազմակի փոխարկումները մոտակայից հեռահարի:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1183,1183,102,'138. Կոշտ կամ ճկուն կցիչով քարշակումը պետք է իրականացվի քարշակվող տրանսպորտային միջոցի ղեկին վարորդի առկայության դեպքում, բացի այն դեպքերից, երբ կոշտ կցիչի կառուցվածքն ուղղագիծ երթևեկության ժամանակ ապահովում է քարշակվող տրանսպորտային միջոցի ընթացքը քարշակողի հետագծով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1184,1184,102,' 139. Կոշտ կամ ճկուն կցիչով քարշակման ժամանակ արգելվում է քարշակվող ավտոբուսում, տրոլեյբուսում և բեռնատար ավտոմոբիլի թափքում մարդկանց փոխադրումը: Մասնակի բեռնման եղանակով քարշակելիս` արգելվում է մարդկանց գտնվելն ինչպես քարշակվող տրանսպորտային միջոցի խցիկում կամ թափքում, այնպես էլ քարշակողի թափքում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1185,1185,102,' 140. Քարշակող և քարշակվող տրանսպորտային միջոցների միջև պետք է ապահովվի` ճկուն կցիչով քարշակելիս 4-6 մ, իսկ կոշտ կցիչով` 4 մ ոչ ավելի հեռավորություն: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1186,1186,102,' 141. Մեխանիկական տրանսպորտային միջոցներ քարշակելիս` ճկուն կապող օղակը նկատելի դարձնելու նպատակով այն պետք է կահավորվի նախազգուշական հարմարանքներով, որոնք անկյունագծով 50 մմ լայնությամբ իրար հաջորդող կարմիր և սպիտակ գույնի զոլերով, 200 x 200 մմ չափերի լուսանդրադարձիչ մակերևույթով դրոշակներ կամ վահանակներ են: Ճկուն կապող օղակի վրա պետք է տեղադրվեն երկուսից ոչ պակաս նախազգուշացնող հարմարանքներ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1187,1187,102,' 142. Կոշտ կցման հարմարանքի կառուցվածքը պետք է համապատասխանի ստանդարտների պահանջներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1188,1188,102,' 143. Քարշակումն արգելվում է`1) երկու և ավելի մեխանիկական տրանսպորտային միջոցների.2) առանց կողային կցորդի մոտոցիկլներով, ինչպես նաև դրանց.3) մերկասառույցի պայմաններում` ճկուն կցիչով.4) այն տրանսպորտային միջոցների, որոնց ապակեմաքրիչները և կառուցվածքով նախատեսված ապակեողողիչները չեն աշխատում` այն դեպքում, երբ քարշակվող տրանսպորտային միջոցի ղեկավարումն իրականացվում է վարորդի կողմից.5) այն տրանսպորտային միջոցների, որոնց ղեկային կառավարումը չի գործում (բացառությամբ մասնակի բեռնմամբ եղանակով քարշակելիս).6) այն տրանսպորտային միջոցի, որի արգելակային համակարգը չի գործում և դրա փաստացի զանգվածը գերազանցում է քարշակողի փաստացի զանգվածի կեսը: Քարշակվողի փաստացի զանգվածը քարշակողի փաստացի զանգվածի կեսից քիչ լինելու դեպքում քարշակումը թույլատրվում է միայն կոշտ կցիչով կամ մասնակի բեռնման եղանակով։ ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1189,1189,102,' 144. Կանոնների 143-րդ կետի 5-րդ և 6-րդ ենթակետերում չգործող են համարվում ղեկային կառավարման և արգելակային այն համակարգերը, որոնք վարորդին թույլ չեն տալիս իրականացնել երթևեկության ուղղության փոփոխություն կամ կանգնեցնել տրանսպորտային միջոցը` անգամ նվազագույն արագությամբ երթևեկելիս:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1190,1190,102,'145. Տրանսպորտային միջոցների վարման սկզբնական ուսուցումը պետք է կատարվի փակ հրապարակներում կամ ավտոդրոմներում: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1191,1191,102,' 146. Ճանապարհներին ուսումնական վարումը թույլատրվում է միայն սովորեցնողի հետ: Սովորողը պետք է գիտենա և կարողանա կատարել կանոնների պահանջները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1192,1192,102,' 147. Անհատական կարգով սովորեցնողը պետք է իր մոտ ունենա տվյալ կարգի տրանսպորտային միջոցներ վարելու իրավունքի վարորդական վկայական: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1193,1193,102,' 148. Տրանսպորտային միջոց վարել սովորողը պետք է լինի առնվազն 16 տարեկան: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1194,1194,102,' 149. Ուսումնական վարում թույլատրվում է տեղական ինքնակառավարման մարմինների կողմից (Երևանում` Երևանի քաղաքապետի) սահմանած ճանապարհներին:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1195,1195,102,'150. «C» կարգի տրանսպորտային միջոցներով (բեռնատարներով) թույլատրվում է փոխադրել մինչև 8 ուղևոր, իսկ դրանից ավելի մարդ փոխադրելու դեպքում վարորդը պետք է ունենա նաև «D» կամ «DE» կարգերի կամ «D1» կամ «D1E» ենթակարգերի տրանսպորտային միջոց վարելու իրավունքի վկայական: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1196,1196,102,' 151. Մեկնելուց առաջ բեռնատար ավտոմոբիլի վարորդը պետք է ուղևորներին հրահանգավորի նստելու, թափքում տեղավորվելու և իջնելու կարգի, ինչպես նաև ընթացքի ժամանակ նստատեղը չլքելու մասին: Շարժվել կարելի է, միայն համոզվելով, որ ուղևորների անվտանգ փոխադրման պայմաններն ապահովված են: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1197,1197,102,' 152. Բեռնատար ավտոմոբիլի թափքում, ինչպես նաև միջքաղաքային, զբոսաշրջության երթուղիներով երթևեկող կամ երեխաների կազմակերպված խմբեր փոխադրող ավտոբուսների սրահում մարդկանց թիվը չպետք է գերազանցի կահավորված նստատեղերի քանակը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1198,1198,102,' 153. Մարդկանց փոխադրումը կողավոր թափքով բեռնատար ավտոմոբիլի թափքում թույլատրվում է, եթե այն կահավորված է կողի վերին եզրից առնվազն 0,3 մ-ից ցածր և հատակից` 0,3-0,5 մ բարձր ամրացված նստարաններով: Հետևի կամ կողերի երկայնքով ամրացված նստարանները պետք է ունենան ամուր թիկնակներ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1199,1199,102,' 154.Մարդկանց փոխադրելու համար չկահավորված կողավոր թափքով բեռնատար ավտոմոբիլների թափքում երթևեկության ժամանակ թույլատրվում է գտնվել միայն բեռն ուղեկցող կամ այն ստանալու համար մեկնող անձանց` պայմանով, որ նրանք ապահովված են կանոնների 153-րդ կետով նախատեսված ցուցանիշներին համապատասխան տեղադրված նստատեղերով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1200,1200,102,' 155. Երեխաների խմբերի կազմակերպված փոխադրումը պետք է իրականացվի սույն Կանոններին, ինչպես նաև այդպիսի փոխադրումների կազմակերպման համար Հայաստանի Հանրապետության կառավարության կողմից հաստատված կանոններին համապատասխան՝ «Երեխաների փոխադրում» ճանաչման նշաններով կահավորված ավտոբուսով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1201,1201,102,' 156. «Երեխաների փոխադրում» ճանաչման նշանով կահավորված տրանսպորտային միջոցներ երեխաների նստեցման և իջեցման ժամանակ պետք է միացված լինի վթարային լուսային ազդանշանը: Այդ տրանսպորտային միջոցներին մոտենալիս` վարորդները պետք է նվազեցնեն արագությունը, իսկ անհրաժեշտության դեպքում պետք է կանգնեն` երեխաներին երթևեկելի մասն անարգել անցնել թույլ տալու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1202,1202,102,' 157. Վարորդը պետք է դռները փակ պահի մինչև տրանսպորտային միջոցի լրիվ կանգնելը, որից հետո միայն հնարավորություն տա ուղևորներին նստել կամ իջնել, իսկ երթևեկությունն սկսի դռները փակելուց հետո: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1203,1203,102,' 158. Մարդկանց փոխադրումն արգելվում է`1) ավտոմոբիլի (բացի կողավոր թափքով բեռնատար ավտոմոբիլի թափքում և ֆուրգոն թափքում մարդկանց փոխադրելու դեպքերի), տրակտորի, այլ ինքնագնաց մեքենաների խցիկներից դուրս, բեռնատար կցորդում, կցորդ-ամառանոցում, բեռնատար մոտոտրանսպորտային միջոցի թափքում և մոտոցիկլի կառուցվածքով նախատեսված նստատեղերից դուրս.2) տրանսպորտային միջոցի տեխնիկական բնութագրով նախատեսված քանակից ավելի: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1204,1204,102,' 159. Մինչև 7 տարեկան երեխաների փոխադրումը թեթև մարդատար ավտոմոբիլում և բեռնատար ավտոմոբիլի խցիկում, որոնց կառուցվածքով նախատեսված են անվտանգության գոտիներ կամ անվտանգության գոտիներ և «ISOFIX» մանկական պահող համակարգ, պետք է իրականացվի երեխայի քաշին և հասակին համապատասխանող մանկական պահող համակարգերի (սարքերի) օգտագործման միջոցով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1205,1205,102,' 159.1. 7-ից մինչև 12 տարեկան երեխաների փոխադրումը թեթև մարդատար ավտոմոբիլում և բեռնատար ավտոմոբիլի խցիկում, որոնց կառուցվածքով նախատեսված են անվտանգության գոտիներ կամ անվտանգության գոտիներ և «ISOFIX» մանկական պահող համակարգ, պետք է իրականացվի երեխայի քաշին և հասակին համապատասխանող մանկական պահող համակարգերի (սարքերի) օգտագործման միջոցով կամ անվտանգության ամրագոտիների օգտագործման միջոցով, իսկ թեթև մարդատար ավտոմոբիլի առջևի նստատեղում՝ միայն երեխայի քաշին և հասակին համապատասխանող մանկական պահող համակարգերի (սարքերի) օգտագործման միջոցով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1206,1206,102,' 159.2. Թեթև մարդատար ավտոմոբիլում և բեռնատար ավտոմոբիլի խցիկում մանկական պահող համակարգերի (սարքերի) տեղադրումն ու դրանցում երեխաներին տեղավորումը պետք է իրականացվեն նշված համակարգերի (սարքերի) շահագործման հրահանգներին (կանոններին) համապատասխան: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1207,1207,102,' 159.3. Արգելվում է մինչև 12 տարեկան երեխաներին փոխադրել մոտոցիկլի հետևի նստատեղին, ինչպես նաև բեռնատար ավտոմոբիլի թափքում (բացառությամբ ֆուրգոն թափքով ավտոմոբիլի):','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1208,1208,102,'160. Փոխադրվող բեռի զանգվածը և ըստ սռնիների բեռնվածության բաշխումը չպետք է գերազանցեն արտադրող գործարանի կողմից տվյալ տրանսպորտային միջոցի համար սահմանված մեծությունները: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1209,1209,102,' 161. Շարժումն սկսելուց առաջ և երթևեկության ընթացքում վարորդը պետք է հսկի բեռի վիճակը, տեղաբաշխումն ու ամրացումը` վայր ընկնելուց և որևէ այլ կերպ երթևեկության խոչընդոտ ստեղծելուց խուսափելու համար: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1210,1210,102,' 162. Տրանսպորտային միջոցի առջևի կամ հետևի եզրաչափերից 1մ ավելի կամ կողքից` եզրաչափային լույսի արտաքին եզրից 0,4 մ ավելի դուրս ցցվելու դեպքում օրվա լուսավոր ժամերին բեռը պետք է նշվի «Մեծ եզրաչափերով բեռ» ճանաչման նշանով, իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, նաև` առջևից սպիտակ, իսկ հետևից` կարմիր գույնի լապտերիկներով կամ լուսանդրադարձիչով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1211,1211,102,' 163. Հայաստանի Հանրապետության օրենսդրությամբ սահմանված հատուկ կանոններով են կարգավորվում այն տրանսպորտային միջոցների երթևեկությունը`1) որոնք օգտագործվում են ծանրաքաշ, վտանգավոր բեռներ կամ չվնասազերծված տարա փոխադրելու համար.2) որոնք շահագործվում են երկու և ավելի կցորդների հետ միասին` ավտոգնացքի կազմում.3) որոնց եզրաչափերը (կամ դրանցից որևէ մեկը), բեռով կամ առանց բեռի, գերազանցում են`ա. ըստ լայնության` 2,55 մ (իզոթերմիկ կամ սառնարանային թափքով տրանսպորտային միջոցների համար՝ 2,6 մ),բ. ըստ երկարության` 12 մ, իսկ մեկ կցորդով (կիսակցորդով)` 20 մ,գ. ըստ բարձրության (երթևեկելի մասի մակերևույթից)` 4 մ.4) որոնց բեռը դուրս է ցցված հետևի եզրաչափից ավելի քան 2 մ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1212,1212,102,' 164. Բեռի փոխադրումն արգելվում է, եթե այն`1) սահմանափակում է վարորդի տեսադաշտը.2) դժվարացնում է տրանսպորտային միջոցի ղեկավարումը և թուլացնում կայունությունը.3) ծածկում է արտաքին լուսային սարքերն ու լուսանդրադարձիչները, համարանիշերը կամ ճանաչման նշանները, ինչպես նաև խանգարում ձեռքով տրվող ազդանշանների ընկալմանը.4) զգալի աղմուկ է հանում, փոշի բարձրացնում կամ աղտոտում ճանապարհն ու շրջակա միջավայրը: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1213,1213,102,' 165. Եթե բեռի վիճակն ու դասավորությունը հնարավորություն չեն տալիս կատարել դրա փոխադրումը կանոնների պահանջներին համապատասխան, ապա վարորդը պետք է միջոցներ ձեռնարկի խախտումները վերացնելու համար կամ դադարեցնի հետագա երթևեկությունը:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1214,1214,102,'166. Ճանապարհային նշանները, գծանշումները և դրանց համարակալումները համապատասխանում են ստանդարտներին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1215,1215,102,' 167. Ճանապարհային նշանները բաժանվում են 8 խմբի`1) նախազգուշացնող.2) առավելության.3) արգելող.4) թելադրող.5) հատուկ թելադրանքի.6) տեղեկատվության.7) սպասարկման.8) լրացուցիչ տեղեկատվության (ցուցանակներ): ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1216,1216,102,' 167.1. Շարժական կանգնակների վրա տեղադրված 1.8՝ «Լուսացուցային կարգավորում», 1.15՝ «Սայթաքուն ճանապարհ», 1.16՝ «Անհարթ ճանապարհ», 1.18՝ «Խճի արտանետում», 1.19՝ «Վտանգավոր կողնակ», 1.20.1-1.20.3՝ «Ճանապարհի նեղացում», 1.21՝ «Երկկողմ երթևեկություն», 1.33՝ «Այլ վտանգներ», 2.6՝ «Հանդիպակաց երթևեկության առավելություն», 3.11՝ «Զանգվածի սահմանափակում», 3.12՝ «Սռնու վրա բեռնվածության սահմանափակում», 3.13՝ «Բարձրության սահմանափակում», 3.14՝ «Լայնության սահմանափակում», 3.15՝ «Երկարության սահմանափակում», 3.16՝ «Նվազագույն միջտարածության սահմանափակում», 3.18.1՝ «Աջ շրջադարձն արգելվում է», 3.18.2՝ «Ձախ շրջադարձն արգելվում է», 3.19՝ «Հետադարձն արգելվում է», 3.20՝ «Վազանցն արգելվում է», 3.21՝ «Վազանցի արգելման գոտու վերջ», 3.22՝ «Բեռնատար ավտոմոբիլներով վազանցն արգելվում է», 3.23՝ «Բեռնատար ավտոմոբիլներով վազանցի արգելման գոտու վերջ», 3.24՝ «Առավելագույն արագության սահմանափակում», 3.25՝ «Առավելագույն արագության սահմանափակման գոտու վերջ» ժամանակավոր նշանների սպիտակ հիմնագույնը կարող է լինել դեղին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1217,1217,102,' 168. Ճանապարհային գծանշումները կիրառվում են ինքնուրույն կամ ճանապարհային նշանների և լուսացույցների հետ միասին: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1218,1218,102,' 169. Ճանապարհային գծանշումները բաժանվում են 2 խմբի`1) հորիզոնական.br>2) ուղղաձիգ: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1219,1219,102,' 170. Հորիզոնական գծանշումը երթևեկելի մասի վրա գծեր, սլաքներ, գրառումներ և այլ նշումներ են ու սահմանում են երթևեկության որոշակի ռեժիմ և կարգ: Հորիզոնական գծանշումը լինում է`1) մշտական, որը սպիտակ գույնի է, բացի`ա. 1.4-րդ, 1.10-րդ, 1.14.1-ին, 1.14.2-րդ, 1.26-րդ գծանշումներից, որոնք դեղին գույնի են,բ. 1.17-րդ գծանշումից, որը կարմիր գույնի է.2) ժամանակավոր, որը նարնջագույն է: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1220,1220,102,' 171. Ուղղաձիգ գծանշումը ճանապարհային կառույցների և կահավորման տարրերի վրա սև ու սպիտակ զոլերի զուգակցություն է, որը ցույց է տալիս դրանց եզրաչափերը և ծառայում որպես տեսողական կողմնորոշման միջոց: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1221,1221,102,' 172. Եթե հաստատուն տեղադրված նշանների պահանջները հակասում են շարժական կանգնակների վրա տեղադրված ժամանակավոր նշանների պահանջներին, ապա երթևեկության մասնակիցները պետք է ղեկավարվեն ժամանակավոր նշաններով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1222,1222,102,' 173. Եթե լուսացույցի ազդանշանների նշանակությունները հակասում են առավելության նշանների պահանջներին, ապա վարորդները պետք է ղեկավարվեն լուսացույցի ազդանշաններով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1223,1223,102,' 174. Եթե գծանշման պահանջները հակասում են շարժական կանգնակի վրա տեղադրված ժամանակավոր նշանների պահանջներին, ապա երթևեկության մասնակիցները պետք է ղեկավարվեն այդ նշաններով: Եթե ժամանակավոր և մշտական գծանշումների պահանջներն իրար հակասում են, ապա վարորդները պետք է ղեկավարվեն ժամանակավոր գծանշման պահանջներով: ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1224,1224,102,' 175. Տրանսպորտային միջոցների վրա անհրաժեշտության դեպքում պետք է տեղադրվեն կամ պատկերվեն տրանսպորտային միջոցի ճանաչման նշաններ: Բացի «Բժիշկ» և «Հաշմանդամ» ճանաչման նշաններից, որոնք տեղադրվում են վարորդի ցանկությամբ, մյուս բոլոր ճանաչման նշանների տեղադրումը պարտադիր է, եթե առկա է դրանցով նշվող հանգամանքը:','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_rule_translations VALUES(1225,1021,101,'1. По правилам дорожного движения Республики Армения (далее-Правила) устанавливается единый порядок дорожного движения на территории Республики Армении, который регулирует соотношения светофора, сигналов регулировщика, аварийных, особых сигналов, пользования внешними световыми приборами и звуковыми сигналами транспортных средств, разных условий движения, регулирования скорости движения, обгон, остановка и стоянка, проезд перекрестков, пешеходные переходы, буксировка транспортных средств, учебная езда, перевозка людей и грузов, а также дорожные знаки.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1226,1022,101,'2. На дорогах Республики Армении установлено правостороннее движение транспортных средств.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1227,1023,101,'3. В Правилах используются следующие понятия: ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1228,1024,101,'1) главная дорога - дорога, обозначенная знаками 2.1 ''Главная дорога'', 2.3.1 - ''Пересечение со второстепенной дорогой'', 2.3.2 – 2.3.7 - ''Примыкание второстепенной дороги'' или 5.1 ''Автомагистраль'', по отношению к пересекаемой (примыкающей), или дорога с твердым покрытием (асфальто и цементобетон, каменные материалы и тому подобное) по отношению к грунтовой, либо любая дорога по отношению к выездам с прилегающих территорий. Наличие на второстепенной дороге непосредственно перед перекрестком участка с покрытием не делает ее равной по значению с пересекаемой. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1229,1025,101,'2) преимущество движения - право на первоочередное движение в намеченном направлении по отношению к другим участникам движения (далее водитель). ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1230,1026,101,'3) не создавать помех для других участников движения – требование к участникам движения, по которому они не должны препятствовать движению: пешеходы – транспортных средств, а водители – пешеходов и других транспортных средств. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1231,1027,101,'4) организованная транспортная колонна - группа из трех и более механических транспортных средств, следующих непосредственно друг за другом по одной и той же полосе движения с постоянно включенными фарами в сопровождении головного транспортного средства с нанесенными на наружные поверхности специальными цветографическими схемами и включенными проблесковыми маячками синего и красного цветов. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1232,1028,101,'5) начало движения – начало движения транспортных средств с места остановки или стоянки связанное с выездом в соседний ряд или без этого.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1233,1029,101,'6) маневрирование - начало движения транспортного средства (связанное с выездом в соседний ряд), перестроение, изменение направления движения, остановка (с перестроением) и движение в обратном направлении. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1234,1030,101,'7) перестроение - выезд из занимаемой полосы или занимаемого ряда с сохранением первоначального направления движения.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1235,1031,101,'8) изменение направления движения - изменение ранее выбранного направления движения (кроме движения в обратном направлении) с помощью разворота или поворота.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1236,1032,101,'9) поворот - маневр, который осуществляют транспортные средства, для выезда на другую дорогу или с дороги на окрестность.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1237,1033,101,'10) разворот - маневр, который осуществляют транспортные средства, для изменения направления движения на направление предназначенное для встречного движения.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1238,1034,101,'11) обгон - опережение одного или нескольких транспортных средств, связанное с выездом на полосу предназначенную для встречного движения.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1239,1035,101,'12) препятствие - неподвижный объект на полосе движения (неисправное или поврежденное транспортное средство, дефект проезжей части, посторонние предметы и т.п.), не позволяющий продолжить движение по этой полосе. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1240,1036,101,'13) опасность для движения - ситуация, возникшая в процессе дорожного движения, при которой продолжение движения в том же направлении и (или) с той же скоростью создает угрозу возникновения дорожно-транспортного происшествия. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1241,1037,101,'14) опережение - движение транспортного средства со скоростью, большей скорости попутного транспортного средства, который не подразумевает выезд на соседнюю полосу. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1242,1038,101,'15) опасный груз - вещества, изделия из них, вредные отходы, которые в силу присущих им свойств могут при перевозке создать угрозу для жизни и здоровья людей, нанести вред окружающей среде, повредить или уничтожить транспортные средства или здания. ','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1243,1039,101,'16) организованная перевозка группы детей - специальная перевозка двух и более детей дошкольного и школьного возраста, осуществляемая в механическом транспортном средстве (не относящемся к маршрутному транспортному средству).','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1244,1040,101,'17) ограниченная видимость - видимость водителем дороги в направлении движения, ограниченная транспортными средствами, рельефом местности, геометрическими параметрами дороги, растительностью, строениями, сооружениями и иными объектами.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1245,1044,101,'4. В светофорах применяются световые сигналы зеленого, желтого, красного и бело-лунного цвета.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1246,1045,101,'5. В зависимости от назначения светофоры могут быть транспортные, пешеходные и велосипедные, а их сигналы могут быть круглые, в виде стрелки (стрелок), силуэта пешехода или велосипеда и X-образные.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1247,1046,101,'6. Светофоры с круглыми сигналами могут иметь одну или две дополнительные секции с сигналами в виде зеленой стрелки (стрелок), которые располагаются на уровне зеленого круглого сигнала.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1248,1047,101,'7. Круглые сигналы светофора имеют следующие значения: 1) Зеленый сигнал разрешает движение (для информирования водителей о времени в секундах, остающемся до конца горения зеленого сигнала, могут применяться цифровые табло) 2) Зеленый мигающий сигнал разрешает движение и информирует, что время его действия истекает и вскоре будет включен запрещающий сигнал. 3) Желтый сигнал запрещает движение (кроме случаев, предусмотренных пунктом 19 Правил), и предупреждает о предстоящей смене сигналов. 4) Желтый мигающий сигнал разрешает движение и информирует о наличии нерегулируемого перекрестка или пешеходного перехода, предупреждает об опасности. 5) Красный сигнал, в том числе мигающий, запрещает движение (для информирования водителей о времени в секундах, остающемся до конца горения красного сигнала, могут применяться цифровые табло). 6) Сочетание красного и желтого сигналов запрещает движение и информирует о предстоящем включении зеленого сигнала.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1249,1048,101,'8. Сигналы светофора, выполненные в виде стрелок красного, желтого и зеленого цветов, имеют то же значение, что и круглые сигналы соответствующего цвета, но их действие распространяется только на направление (направления), указываемое стрелками. При этом стрелка, разрешающая поворот налево, разрешает и разворот, если это не запрещено соответствующим дорожным знаком. Такое же значение имеет зеленая стрелка в дополнительной секции. Выключенный сигнал дополнительной секции означает запрещение движения в направлении, регулируемом этой секцией.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1250,1049,101,'9. Вместо красных и желтых стрелок могут применяться круглые красные и желтые сигналы, которые имеют черные контурные стрелки.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1251,1050,101,'10. Если на основной зеленый сигнал светофора нанесена черная контурная стрелка (стрелки), то она информирует водителей о наличии дополнительной секции светофора и указывает иные разрешенные направления движения, чем сигнал дополнительной секции.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1252,1051,101,'11. Если сигнал светофора выполнен в виде силуэта пешехода (велосипеда), то его действие распространяется только на пешеходов (велосипедистов). Для регулирования движения велосипедистов может использоваться также светофор с круглыми сигналами уменьшенного размера, дополненный табличкой с изображением велосипеда.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1253,1052,101,'12. Для информирования слепых пешеходов о возможности пересечения проезжей части световые сигналы светофора могут быть дополнены звуковым (особым) сигналом, который отличается от звуковых сигналов транспортных средств.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1254,1053,101,'13. Для регулирования движения транспортных средств по полосам проезжей части, в частности по тем, направление движения по которым может изменяться на противоположное, применяются реверсивные светофоры с красным X-образным сигналом и зеленым сигналом в виде стрелы, направленной вниз. Эти сигналы соответственно запрещают или разрешают движение по полосе, над которой они расположены. Основные сигналы реверсивного светофора могут быть дополнены желтым сигналом в виде стрелы, наклоненной по диагонали вниз направо или налево, включение которой информирует о предстоящей смене сигнала и необходимости перестроиться на полосу, на которую указывает стрела. При выключенных сигналах реверсивного светофора, который расположен над полосой, обозначенной с обеих сторон разметкой 1.9, въезд на эту полосу запрещен.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1255,1054,101,'14. Для регулирования движения трамваев, а также других маршрутных транспортных средств, движущихся по выделенной для них полосе, могут применяться светофоры одноцветной сигнализации с четырьмя круглыми сигналами бело-лунного цвета, расположенными в виде буквы «Т». Движение разрешается только при включении одновременно нижнего сигнала и одного или нескольких верхних, из которых левый разрешает движение налево, средний — прямо, правый — направо. Если включены только три верхних сигнала, то движение запрещено.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1256,1055,101,'15. Круглый бело-лунный мигающий сигнал, расположенный на железнодорожном переезде, разрешает движение транспортных средств через переезд, а красный – запрещает. При выключенных мигающих бело-лунном и красном сигналах движение разрешается при отсутствии в пределах видимости приближающегося к переезду поезда (локомотива, дрезины).','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1257,1056,101,'16. Сигналы регулировщика имеют следующие значения: 1) Рука поднята вверх - движение всех транспортных средств и пешеходов запрещено во всех направлениях, кроме случаев, предусмотренных пунктом 19 Правил. 2) Руки вытянуты в стороны или опущены: a. со стороны левого и правого бока разрешено движение трамваю прямо, безрельсовым транспортным средствам прямо и направо. Пешеходам разрешено переходить проезжую часть; б. со стороны груди и спины движение всех транспортных средств и пешеходов запрещено. 3) Правая рука вытянута вперед: a. со стороны левого бока разрешено движение трамваю налево, безрельсовым транспортным средствам во всех направлениях; б. со стороны груди всем транспортным средствам разрешено движение только направо; в. со стороны правого бока и спины движение всех транспортных средств запрещено; г. пешеходам разрешено переходить проезжую часть за спиной регулировщика.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1258,1057,101,'17. Для лучшей видимости сигналов регулировщик может применять жезл или диск с красным сигналом или световозвращателем, дополнительный сигнал свистком подается для привлечения внимания участников движения. Регулировщик может подавать жестами рук и другие сигналы, понятные водителям и пешеходам.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1259,1058,101,'18. При запрещающем сигнале светофора (кроме реверсивного) или регулировщика водители должны остановиться перед стоп-линией (знаком 6.16), а при ее отсутствии: 1) на перекрестке — перед пересекаемой проезжей частью (с учетом пункта 93 правил), не создавая помех пешеходам; 2) перед железнодорожным переездом — в соответствии с пунктом 111 правил; 3) в других местах — перед светофором или регулировщиком, не создавая помех транспортным средствам и пешеходам, движение которых разрешено.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1260,1059,101,'19. Водителям, которые при включении желтого сигнала или поднятии регулировщиком руки вверх не могут остановиться, не прибегая к экстренному торможению в местах, определяемых пунктом 18 правил, разрешается дальнейшее движение. Пешеходы, которые при подаче сигнала находились на проезжей части, должны освободить ее, а если это невозможно — остановиться на линии, разделяющей транспортные потоки противоположных направлений.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1261,1060,101,'20. Водители и пешеходы должны выполнять требования сигналов и распоряжения регулировщика, даже если они противоречат сигналам светофора, требованиям дорожных знаков или разметки.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1262,1061,101,'21. На железнодорожных переездах одновременно с красным мигающим сигналом светофора может подаваться звуковой сигнал, дополнительно информирующий участников движения о запрещении движения через переезд.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1263,1065,101,'22. Аварийная световая сигнализация должна быть включена: 1) при дорожно-транспортном происшествии; 2) при вынужденной остановке в местах, где остановка запрещена; 3) при ослеплении водителя светом фар; 4) при буксировке (на буксируемом механическом транспортном средстве); Водитель должен включать аварийную световую сигнализацию и в других случаях для предупреждения участников движения об опасности, которую может создать транспортное средство.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1264,1066,101,'23. При включении аварийной световой сигнализации (также при ее неисправности или отсутствии) знак "Аварийная остановка" должен быть незамедлительно выставлен (красный мигающий фонарик): 1) при дорожно-транспортном происшествии; 2) при вынужденной остановке в местах, где она запрещена, и там, где с учетом условий видимости транспортное средство не может быть своевременно замечено другими водителями. После выполнения этого, водитель должен выполнить требования пункта 83 правил. Знак "Аварийная остановка" (красный мигающий фонарик) устанавливается на расстоянии, обеспечивающем в конкретной обстановке своевременное предупреждение других водителей об опасности. Однако это расстояние должно быть не менее 15 м от транспортного средства в населенных пунктах и 30 м — вне населенных пунктов.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1265,1067,101,'24. При отсутствии или неисправности аварийной световой сигнализации на буксируемом механическом транспортном средстве на его задней части должен быть закреплен знак "Аварийная остановка".','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1266,1068,101,'25. При преимуществе, а также при остановке в местах, где остановка запрещена (кроме вынужденной остановке), запрещается применение знака аварийной остановки.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1267,1069,101,'26. Водители транспортных средств, с включенным проблесковым маячком синего цвета, выполняя неотложное служебное задание, могут отступать от требований разделов II (кроме сигналов регулировщика) и V-XVI, XIX, XXI Правил при условии обеспечения безопасности движения. Для получения преимущества перед другими участниками движения водители таких транспортных средств должны включить проблесковый маячок синего цвета и специальный звуковой сигнал, который отличается от звуковых сигналов других транспортных средств. Воспользоваться приоритетом они могут только убедившись, что им уступают дорогу. Этим же правом пользуются водители транспортных средств, сопровождаемых транспортными средствами, имеющими нанесенные на наружные поверхности специальные цветографические схемы, с включенными проблесковыми маячками синего и красного цветов и специальным звуковым сигналом.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1268,1070,101,'27. На транспортных средствах Государственной инспекции безопасности дорожного движения Республики Армении, службы охраны Республики Армении, Государственной службы безопасности Республики Армении и Военной автомобильной инспекции дополнительно к проблесковому маячку синего цвета может быть включен проблесковый маячок красного цвета.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1269,1071,101,'28. При приближении транспортного средства с включенным проблесковым маячком синего цвета и специальным звуковым сигналом водители обязаны уступить дорогу для обеспечения беспрепятственного проезда указанного транспортного средства.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1270,1072,101,'29. При приближении транспортного средства, имеющего нанесенные на наружные поверхности специальные цветографические схемы, с включенными проблесковыми маячками синего и красного цветов и специальным звуковым сигналом водители обязаны уступить дорогу для обеспечения беспрепятственного проезда указанного транспортного средства, а также сопровождаемого им транспортного средства.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1271,1073,101,'30. Приближаясь к стоящему транспортному средству с включенным проблесковым маячком синего или красного цвета, водитель должен снизить скорость, чтобы иметь возможность немедленно остановиться в случае необходимости.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1272,1074,101,'31. Приближаясь к стоящему транспортному средству с включенным проблесковым маячком красного цвета, водитель должен остановиться и продолжить движение только после получения разрешения.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1273,1075,101,'32. Включенный проблесковый маячок желтого или оранжевого цвета не дает преимущества в движении и служит для предупреждения других участников движения об опасности.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1274,1076,101,'33. Проблесковый маячок желтого или оранжевого цвета должен быть включен на транспортных средствах в следующих случаях: 1) выполнение работ по строительству, ремонту или содержанию дорог, погрузке поврежденных, неисправных и перемещаемых транспортных средств; 2) сопровождение транспортных средств, перевозящих крупногабаритные, тяжеловесные и опасные грузы, по пункту 163 правил. 3) сопровождение транспортных средств, перевозящих опасные грузы и контейнеры.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1275,1077,101,'34. Водители транспортных средств с включенным проблесковым маячком желтого или оранжевого цвета при выполнении работ по строительству, ремонту или содержанию дорог, погрузке поврежденных, неисправных и перемещаемых транспортных средств могут отступать от требований дорожных знаков 42, 55-60, 63 и 116, кроме знаков 2.2 "Конец главной дороги", 2.4 "Уступите дорогу", 2.5 "Движение без остановки запрещено", 2.6 "Преимущество встречного движения", 3.11 "Ограничение массы", 3.12 "Ограничение массы приходящийся на ось транспортного средства", 3.13 "Ограничение высоты", 3.14 "Ограничение ширины", 3.17.2 "Опасность", 3.20 "Обгон запрещен" и дорожной разметки. Водители транспортных средств с включенным проблесковым маячком желтого или оранжевого цвета, по пункту 2 пункта 33 Правил, могут отступать от требований дорожной разметки пункта 60 Правил при условии обеспечения безопасности дорожного движения.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1276,1078,101,'35. Водители транспортных средств могут включать проблесковый маячок бело-лунного цвета и специальный звуковой сигнал только при нападениях на указанные транспортные средства. Проблесковый маячок бело-лунного цвета не дает преимущества в движении и служит для привлечения внимания сотрудников милиции и иных лиц.','2025-11-06 21:29:05','2025-11-06 21:29:05');
INSERT INTO pdd_rule_translations VALUES(1277,1079,101,'36. Перед началом движения или маневрированием водитель обязан подавать сигналы световыми указателями поворота соответствующего направления, а если они отсутствуют или неисправны — рукой. Подавать сигнал не обязательно, если транспортное средство движется по закругленной дорогой без перестановки. Подача сигнала указателями поворота или рукой должна производиться заблаговременно до начала выполнения маневра и прекращаться немедленно после его завершения (подача сигнала рукой может быть закончена непосредственно перед выполнением маневра). При этом сигнал не должен вводить в заблуждение других участников движения. Подача сигнала не дает водителю преимущества и не освобождает его от принятия мер предосторожности.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1278,1080,101,'37. Сигналу левого поворота (разворота) соответствует вытянутая в сторону левая рука либо правая, вытянутая в сторону и согнутая в локте под прямым углом вверх. Сигналу правого поворота соответствует вытянутая в сторону правая рука либо левая, вытянутая в сторону и согнутая в локте под прямым углом вверх. Сигнал торможения подается поднятой вверх левой или правой рукой.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1279,1081,101,'38. При выезде на дорогу с прилегающей территории водитель должен уступить дорогу транспортным средствам и пешеходам, движущимся по ней, а при съезде с дороги — пешеходам и велосипедистам. В двух случаях сигнал не должен вводить в заблуждение других участников движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1280,1082,101,'39. При перестроении водитель должен уступить дорогу транспортным средствам, движущимся попутно без изменения направления движения. При одновременном перестроении транспортных средств, движущихся попутно, дорогу должен уступить водитель, который находится слева.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1281,1083,101,'40. Перед поворотом или разворотом водитель обязан заблаговременно занять соответствующее крайнее положение на проезжей части, предназначенной для движения в данном направлении, кроме случаев, когда: 1) совершается поворот при выезде на перекресток, где организовано круговое движение, 2) знаками или разметкой разрешается поворот также из других линий, 3) не может выполнить поворот из-за своих габаритов или по другим причинам. При наличии слева трамвайных путей попутного направления, расположенных на одном уровне с проезжей частью, поворот налево и разворот должны выполняться с них, если знаками 5.15.1 "Направления движения по полосам" или 5.15.2 - "Направления движения по полосе" либо разметкой 1.18 не предписан иной порядок движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1282,1084,101,'41. Поворот должен осуществляться таким образом, чтобы при выезде с пересечения проезжих частей транспортное средство не оказалось на стороне встречного движения. При повороте направо транспортное средство должно двигаться по возможности ближе к правому краю проезжей части.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1283,1085,101,'42. При повороте на дорогу с реверсивным движением водитель должен вести транспортное средство таким образом, чтобы при выезде с пересечения проезжих частей транспортное средство заняло крайнюю правую полосу. Перестроение разрешается только после того, как водитель убедится, что движение в данном направлении разрешается и по другим полосам.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1284,1086,101,'43. Если транспортное средство из-за своих габаритов или по другим причинам не может выполнить поворот или разворот с соблюдением требований пункта 40 Правил, водитель должен включить аварийные сигналы и уступить дорогу транспортным средствам, которые движутся во встречном и попутном направлениях.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1285,1087,101,'44. При повороте налево или развороте вне перекрестка водитель безрельсового транспортного средства обязан уступить дорогу встречным транспортным средствам и трамваю попутного направления.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1286,1088,101,'45. В случаях, когда траектории движения транспортных средств пересекаются, а очередность проезда не оговорена Правилами, дорогу должен уступить водитель, к которому транспортное средство приближается справа.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1287,1089,101,'46. В случае если встречный разъезд затруднен, водитель, на стороне которого имеется препятствие, должен уступить дорогу. Уступить дорогу при наличии препятствия на уклонах, обозначенных знаками 1.13 "Крутой спуск" и 1.14 "Крутой подъем", должен водитель транспортного средства, движущегося на спуск.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1288,1090,101,'47. При наличии тормозной линии водитель, который хочет выполнить поворот, должен заранее перестроится в эту линию, и в этом линии снизить скорость. Водитель должен продолжить движение и перестроится в соседнюю линию не создавая помех другим транспортным средствам.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1289,1091,101,'48. Движение транспортного средства задним ходом разрешается при условии, что этот маневр будет безопасен и не создаст помех другим участникам движения. При необходимости водитель должен прибегнуть к помощи других лиц.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1290,1092,101,'49. Движение задним ходом запрещается на перекрестках и в местах, где запрещен разворот согласно пункту 50 Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1291,1093,101,'50. Разворот запрещается: 1) на пешеходных переходах; 2) в тоннелях; 3) на мостах, путепроводах, эстакадах и под ними; 4) на железнодорожных переездах; 5) в местах с видимостью дороги хотя бы в одном направлении менее 100 м; 6) в местах остановок маршрутных транспортных средств; 7) в односторонних дорогах.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1292,1094,101,'51. Количество полос движения для безрельсовых транспортных средств определяется разметкой и (или) знаками 5.15.1 - "Направления движения по полосам", 5.15.2 - "Направления движения по полосе", 5.15.7 - "Направление движения по полосам", 5.15.8 - "Число полос", а если их нет, то самими водителями с учетом ширины проезжей части, габаритов транспортных средств и необходимых интервалов между ними.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1293,1095,101,'52. Стороной, предназначенной для встречного движения на дорогах с двусторонним движением без разделительной полосы, считается половина ширины проезжей части, расположенная слева, не считая местных расширений проезжей части (переходно-скоростные полосы, дополнительные полосы на подъем, заездные карманы мест остановок маршрутных транспортных средств).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1294,1096,101,'53. На дорогах с двусторонним движением, имеющих четыре или более полосы, запрещается выезжать для обгона или объезда на полосу, предназначенную для встречного движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1295,1097,101,'54. На дорогах с двусторонним движением, имеющих три полосы, обозначенные разметкой (за исключением разметки 1.9), из которых средняя полоса используется для движения в обоих направлениях, разрешается выезжать на эту полосу только для обгона, объезда, поворота налево или разворота. Выезжать на крайнюю левую полосу, предназначенную для встречного движения, запрещается.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1296,1098,101,'55. Вне населенных пунктов, а также в населенных пунктах на дорогах, обозначенных знаком 5.1 - "Автомагистраль" или 5.3 - "Дорога для автомобилей" или где разрешено движение со скоростью более 80 км/ч, водители транспортных средств должны вести их по возможности ближе к правому краю проезжей части. Запрещается занимать левые полосы движения при свободных правых.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1297,1099,101,'56. В населенных пунктах с учетом правил дорожного движения Республики Армении и пунктов 55, 57-58 и 116 Правил водители транспортных средств могут использовать наиболее удобную для них полосу движения. При интенсивном движении, когда все полосы движения заняты, менять полосу разрешается только для поворота налево или направо, разворота, остановки или объезда препятствия.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1298,1100,101,'57. На любых дорогах, имеющих для движения в данном направлении три полосы и более, занимать крайнюю левую полосу разрешается только при интенсивном движении, когда заняты другие полосы, а также для поворота налево или разворота, а грузовым автомобилям с разрешенной максимальной массой более 3,5 т — только для поворота налево или разворота. Выезд на левую полосу дорог с односторонним движением для остановки и стоянки осуществляется в соответствии с пунктом 79 Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1299,1101,101,'58. Транспортные средства, скорость движения которых не должна превышать 40 км/ч или которые по техническим причинам не могут развивать такую скорость, должны двигаться по крайней правой полосе, кроме случаев объезда, обгона или перестроения перед поворотом налево разворотом или остановкой в разрешенных случаях на левой стороне дороги.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1300,1102,101,'59. Разрешается движение по трамвайным путям попутного направления, расположенным слева на одном уровне с проезжей частью, когда заняты все полосы данного направления, а также при объезде, обгоне, повороте налево или развороте с учетом пункта 8.5 Правил. При этом не должно создаваться помех трамваю. Если перед перекрестком установлены дорожные знаки 5.15.1 "Направления движения по полосам" или 5.15.2 - "Направления движения по полосе", движение по трамвайным путям через перекресток запрещается. Выезжать на трамвайные пути встречного направления запрещается.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1301,1103,101,'60. Если проезжая часть разделена на полосы линиями разметки, движение транспортных средств должно осуществляться строго по обозначенным полосам. Наезжать на прерывистые линии разметки разрешается лишь при перестроении.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1302,1104,101,'61. Запрещается движение транспортных средств по разделительным полосам и обочинам, тротуарам и пешеходным дорожкам, за исключением случаев, оговоренных в пункте 81 Правил. Допускается движение машин дорожно-эксплуатационных и коммунальных служб, а также подъезд по кратчайшему пути транспортных средств, подвозящих грузы к торговым и другим предприятиям и объектам, расположенным непосредственно у обочин, тротуаров или пешеходных дорожек, при отсутствии других возможностей подъезда. При этом должна быть обеспечена безопасность движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1303,1105,101,'62. Водитель должен соблюдать такую дистанцию до движущегося впереди транспортного средства, которая позволила бы избежать столкновения, а также необходимый боковой интервал, обеспечивающий безопасность движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1304,1106,101,'63. Вне населенных пунктов на дорогах с двусторонним движением, имеющих две полосы, водитель транспортного средства, для которого установлено ограничение скорости, а также водитель транспортного средства (состава транспортных средств) длиной более 7 м должен поддерживать между своим и движущимся впереди транспортным средством такую дистанцию, чтобы обгоняющие его транспортные средства могли без помех перестроиться на ранее занимаемую ими полосу. Это требование не действует при движении по участкам дорог, на которых запрещается обгон, а также при интенсивном движении и движении в организованной транспортной колонне.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1305,1107,101,'64. На дорогах с двусторонним движением при отсутствии разделительной полосы островки безопасности, тумбы и элементы дорожных сооружений (опоры мостов, путепроводов и тому подобное), находящиеся на середине проезжей части, водитель должен объезжать справа, если знаки и разметка не предписывают иное.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1306,1108,101,'65. Водитель должен вести транспортное средство со скоростью, не превышающей установленного ограничения, учитывая при этом интенсивность движения, особенности и состояние транспортного средства и груза, дорожные и метеорологические условия, в частности видимость в направлении движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1307,1109,101,'66. Водитель должен выбирать такую скорость, которая бы обеспечивала водителю возможность постоянного контроля за движением транспортного средства для выполнения требований Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1308,1110,101,'67. При возникновении опасности для движения, которую водитель в состоянии обнаружить, он должен принять возможные меры к снижению скорости вплоть до остановки транспортного средства. В этом случае разрешается опережение и обгон, если водитель знает, что это не вредно для других участников движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1309,1111,101,'68. В населенных пунктах разрешается движение транспортных средств со скоростью не более 60 км/ч, а в жилых зонах и на дворовых территориях не более 20 км/ч, по знаками 5.21 - "Жилая зона" и 5.22 - "Конец жилой зоны".','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1310,1112,101,'69. Вне населенных пунктов разрешается движение: 1) легковым автомобилям и грузовым автомобилям с разрешенной максимальной массой не более 3,5т со скоростью не более 90 км/ч (на автомагистралях со скоростью не более 110 км/ч), 2) междугородним и маломестным автобусам и мотоциклам на всех дорогах — не более 90 км/ч; 3) другим автобусам, легковым автомобилям при буксировке прицепа, грузовым автомобилям с разрешенной максимальной массой более 3,5 т на автомагистралях — не более 90 км/ч, на остальных дорогах — не более 70 км/ч;','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1311,1113,101,'70. В населенных пунктах и на отдельных дорогах вне населенных пунктов, по знаку 3.24 "Ограничение максимальной скорости", разрешается двигаться скоростью больше максимальной.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1312,1114,101,'71. Разрешается движение: 1) грузовым автомобилям, перевозящим людей в кузове, транспортным средствам, осуществляющим организованные перевозки групп детей, — не более 60 км/ч; 2) транспортным средствам, буксирующим механические транспортные средства - не более 50 км/ч.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1313,1115,101,'72. Водителю запрещается: 1) превышать максимальную скорость, определенную технической характеристикой транспортного средства; 2) превышать скорость, указанную на опознавательном знаке «Ограничение скорости», установленном на транспортном средстве; 3) превышать скорость при перевозке крупногабаритных или опасных грузов. 4) создавать помехи другим транспортным средствам, двигаясь без необходимости со слишком малой скоростью; 5) резко тормозить, если это не требуется для предотвращения дорожно-транспортного происшествия.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1314,1116,101,'73. Прежде чем начать обгон, водитель обязан убедиться, что: 1) полоса движения, на которую он собирается выехать, свободна на достаточном для обгона расстоянии и в процессе обгона он не создаст опасности для движения и помех другим участникам дорожного движения; 2) следующее за ним транспортное средство не начало обгон, а транспортное средство, движущееся впереди по той же полосе, не подало сигнал обгона (поворота налево, разворота); 3) по завершении обгона он сможет, не создавая опасности для движения и помех обгоняемому транспортному средству, вернуться на ранее занимаемую полосу.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1315,1117,101,'74. Безрельсового транспортного средства разрешается обгон только слева. Но если транспортное средство, которое движется впереди, дал сигнал левого поворота и начал маневрирование, то в этом случае обгон этого транспортного средства разрешается справа.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1316,1118,101,'75. Водителю обгоняемого транспортного средства запрещается препятствовать обгону повышением скорости движения или иными действиями.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1317,1119,101,'76. В случае если вне населенных пунктов обгон или опережение тихоходного транспортного средства или транспортного средства, перевозящего крупногабаритный груз, затруднены, водитель такого транспортного средства должен принять как можно правее, а при необходимости остановиться, чтобы пропустить следующие за ним транспортные средства.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1318,1120,101,'77. Обгон запрещен: 1) на перекрестках; 2) на пешеходных переходах; 3) на железнодорожных переездах и ближе чем за 100 метров перед ними; 4) если обгоняющийся транспортное средство делает обгон или обходит барьер; 5) на мостах, путепроводах, эстакадах и под ними, а также в тоннелях; 6) транспортному средству с включенными проблесковыми маячками синего цвета и специальными звуковыми сигналами. 7) если обгоняемое транспортное средство движется с включенными проблесковыми маячками синего и красного цвета и специальными звуковыми сигналами, или сопровождается такими транспортными средствами. 8) в конце подъема и в дорогах недостаточной видимости, когда обгон происходит на встречном направлении.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1319,1121,101,'78. Остановка и стоянка транспортных средств разрешаются на правой стороне дороги на обочине, а при ее отсутствии — на проезжей части у ее края и в случаях, установленных пунктом 81 Правил, — на тротуаре.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1320,1122,101,'79. На левой стороне дороги остановка и стоянка разрешаются в населенных пунктах: 1) на дорогах с одной полосой движения для каждого направления без трамвайных путей посередине, 2) на дорогах с односторонним движением (грузовым автомобилям с разрешенной максимальной массой более 3,5 т на левой стороне дорог с односторонним движением разрешается лишь остановка для загрузки или разгрузки).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1321,1123,101,'80. Ставить транспортное средство разрешается в один ряд параллельно краю проезжей части, за исключением тех мест, конфигурация (местное уширение проезжей части) которых допускает иное расположение транспортных средств. Двухколесные транспортные средства без бокового прицепа допускается ставить в два ряда.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1322,1124,101,'81. Стоянка на краю тротуара, граничащего с проезжей частью, разрешается только легковым автомобилям, мотоциклам, мопедам и велосипедам в местах, обозначенных знаком 6.4 "Место стоянки" и с одной из табличек 8.6.2, 8.6.3, 8.6.6 – 8.6.9 - "Способ постановки транспортного средства на стоянку".','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1323,1125,101,'82. Стоянка с целью длительного отдыха, ночлега и тому подобное вне населенного пункта разрешается только на предусмотренных для этого площадках или за пределами дороги.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1324,1126,101,'83. При вынужденной остановке в местах, где остановка запрещена, после выполнения пунктов 22 и 23 Правил, водитель должен принять все возможные меры для отвода транспортного средства из этих места.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1325,1127,101,'84. Остановка запрещается: 1) на тротуарах, за исключением пункта 61 Правил, а также трамвайных путях и в непосредственной близости от них, если это создаст помехи движению трамваев; 2) на железнодорожных переездах, в тоннелях, а также на эстакадах, мостах, путепроводах и под ними; 3) в местах, где расстояние между сплошной линией разметки (кроме обозначающей край проезжей части), разделительной полосой или противоположным краем проезжей части и остановившимся транспортным средством менее 3 м; 4) на пешеходных переходах и ближе 5 м перед ними; 5) на проезжей части вблизи опасных поворотов и выпуклых переломов продольного профиля дороги при видимости дороги менее 100 м хотя бы в одном направлении; 6) на пересечении проезжих частей и ближе 5 м от края пересекаемой проезжей части, за исключением стороны напротив бокового проезда трехсторонних пересечений (перекрестков), имеющих сплошную линию разметки или разделительную полосу; 7) ближе 15 метров от мест остановки маршрутных транспортных средств, обозначенных разметкой 1.17, а при ее отсутствии — от указателя места остановки маршрутных транспортных средств; 8) в местах, где транспортное средство закроет от других водителей сигналы светофора, дорожные знаки или сделает невозможным движение (въезд или выезд) других транспортных средств, или создаст помехи для движения пешеходов.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1326,1128,101,'85. Остановка маршрутных транспортных средств запрещается и в местах вне зоны остановки таких транспортных средств, кроме вынужденной остановки в местах, где остановка запрещена.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1327,1129,101,'86. Стоянка запрещается: 1) в местах, где запрещена остановка; 2) вне населенных пунктов на проезжей части дорог, обозначенных знаком 2.1 "Главная дорога"; 3) ближе 50 м от железнодорожных переездов.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1328,1130,101,'87. При повороте направо или налево водитель не должен создавать помех пешеходам, уступать дорогу пешеходам, а также велосипедистам, пересекающим ее по велосипедной дорожке.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1329,1131,101,'88. Запрещается выезжать на перекресток или пересечение проезжих частей, если образовался затор, который вынудит водителя остановиться, создав препятствие для движения транспортных средств в поперечном направлении.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1330,1132,101,'89. Перекресток, где очередность движения определяется сигналами светофора или регулировщика, считается регулируемым.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1331,1133,101,'90. При повороте налево или развороте по зеленому сигналу светофора водитель безрельсового транспортного средства обязан уступить дорогу транспортным средствам, движущимся со встречного направления прямо и направо. Таким же правилом должны руководствоваться между собой водители трамваев.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1332,1134,101,'91. При движении в направлении стрелки, включенной в дополнительной секции одновременно с желтым или красным сигналом светофора, водитель обязан уступить дорогу транспортным средствам, движущимся с других направлений.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1333,1135,101,'92. Если сигналы светофора или регулировщика разрешают движение одновременно трамваю и безрельсовым транспортным средствам, то трамвай имеет преимущество независимо от направлений его движения. Однако при движении в направлении стрелки, включенной в дополнительной секции одновременно с красным или желтым сигналом светофора, трамвай должен уступить дорогу транспортным средствам, движущимся с других направлений.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1334,1136,101,'93. Водитель, въехавший на перекресток при разрешающем сигнале светофора, должен выехать в намеченном направлении независимо от сигналов светофора на выходе с перекрестка. Однако, если на перекрестке перед светофорами, расположенными на пути следования водителя, имеются разметка 1.12 "Стоп-линия" (или знаки 6.16 "Стоп-линия"), водитель обязан руководствоваться сигналами каждого светофора.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1335,1137,101,'94. При включении разрешающего сигнала светофора водитель обязан уступить дорогу транспортным средствам, завершающим движение через перекресток, и пешеходам, не закончившим переход проезжей части данного направления.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1336,1138,101,'95. Перекресток, где нет светофора или регулировщика, не работает светофор, или включен желтый мигающий сигнал светофора, считается нерегулируемым.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1337,1139,101,'96. На перекрестке неравнозначных дорог водитель транспортного средства, движущегося по второстепенной дороге, должен уступить дорогу транспортным средствам, приближающимся по главной, независимо от направления их дальнейшего движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1338,1140,101,'97. В случае, когда главная дорога на перекрестке меняет направление, водители, движущиеся по главной дороге, должны руководствоваться между собой правилами проезда перекрестков равнозначных дорог. Этими же правилами должны руководствоваться водители, движущиеся по второстепенным дорогам.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1339,1141,101,'98. На перекрестке равнозначных дорог водитель безрельсового транспортного средства обязан уступить дорогу транспортным средствам, приближающимся справа. Этим же правилом должны руководствоваться между собой водители трамваев. На таких перекрестках трамвай имеет преимущество перед безрельсовыми транспортными средствами независимо от направления его движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1340,1142,101,'99. При повороте налево или развороте водитель безрельсового транспортного средства обязан уступить дорогу транспортным средствам, движущимся по равнозначной дороге со встречного направления прямо или направо. Этим же правилом должны руководствоваться между собой водители трамваев.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1341,1143,101,'100. На нерегулируемых перекрестках трамвай имеет преимущество перед безрельсовыми транспортными средствами, движущимися в попутном или встречном направлении по равнозначной дороге, независимо от направления его движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1342,1144,101,'101. Если водитель не может определить наличие покрытия на дороге (темное время суток, грязь, снег и тому подобное), а знаков приоритета нет, он должен считать, что находится на второстепенной дороге.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1343,1147,101,'102. Понятия регулируемого и нерегулируемого пешеходного перехода аналогичны понятиям регулируемого и нерегулируемого перекрестка, установленным в пунктах 89 и 95 Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1344,1148,101,'103. Водитель транспортного средства не должен создавать помех пешеходам, которые движутся по нерегулируемым пешеходным переходам.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1345,1149,101,'104. Если перед нерегулируемым пешеходным переходом остановилось или замедлило движение транспортное средство, то водители других транспортных средств, движущихся по соседним полосам, могут продолжать движение лишь убедившись, что перед указанным транспортным средством нет пешеходов.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1346,1150,101,'105. На регулируемых пешеходных переходах при включении разрешающего сигнала светофора водитель должен дать возможность пешеходам закончить переход проезжей части данного направления.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1347,1151,101,'106. Запрещается въезжать на пешеходный переход, если за ним образовался затор, который вынудит водителя остановиться на пешеходном переходе.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1348,1152,101,'107. Во всех случаях, в том числе и вне пешеходных переходов, водитель обязан пропустить слепых пешеходов.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1349,1153,101,'108. Слепые пешеходы должны подать сигнал белой тростью.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1350,1154,101,'109. Водители транспортных средств могут пересекать железнодорожные пути только по железнодорожным переездам, уступая дорогу поезду (локомотиву, дрезине).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1351,1155,101,'110. При подъезде к железнодорожному переезду водитель обязан руководствоваться требованиями дорожных знаков, светофоров, разметки, положением шлагбаума и указаниями дежурного по переезду и убедиться в отсутствии приближающегося поезда (локомотива, дрезины).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1352,1156,101,'111. В случаях, когда движение через переезд запрещено, водитель должен остановиться у знака 1.12 "Стоп-линия", знака 2.5 "Движение без остановки запрещено" или светофора, если их нет — не ближе 5 м от шлагбаума, а при отсутствии последнего — не ближе 10 м до ближайшего рельса.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1353,1157,101,'112. При вынужденной остановке на переезде водитель должен: 1) немедленно высадить людей и принять меры для освобождения переезда, 2) при имеющейся возможности послать двух человек вдоль путей в обе стороны от переезда на 1000 м (если одного, то в сторону худшей видимости пути), объяснив им правила подачи сигнала остановки машинисту приближающегося поезда, 3) оставаться возле транспортного средства и подавать сигналы общей тревоги, 4) при появлении поезда бежать ему навстречу, подавая сигнал остановки.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1354,1158,101,'113. Запрещается выезжать на переезд: 1) при закрытом или начинающем закрываться шлагбауме (независимо от сигнала светофора); 2) при запрещающем сигнале светофора (независимо от положения и наличия шлагбаума); 3) если за переездом образовался затор, который вынудит водителя остановиться на переезде; 4) если к переезду в пределах видимости приближается поезд (локомотив, дрезина); 5) при запрещающем сигнале дежурного по переезду. Запрещающий сигнал дежурного по переезду - дежурный обращен к водителю грудью или спиной с поднятым над головой жезлом, красным фонарем или флажком, либо с вытянутыми в сторону руками.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1355,1159,101,'114. Кроме того, запрещается: 1) объезжать с выездом на полосу встречного движения стоящие перед переездом транспортные средства; 2) самовольно открывать шлагбаум; 3) провозить через переезд в нетранспортном положении сельскохозяйственные, дорожные, строительные и другие машины и механизмы; 4) без разрешения начальника дистанции пути железной дороги движение тихоходных машин, скорость которых менее 8 км/ч, а также тракторных саней-волокуш.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1356,1160,101,'115. Дорога, обозначенная знаком 5.1 "Автомагистраль" и имеющая в каждом направлении движения проезжие части, отделенные друг от друга разделительной полосой (а при ее отсутствии — дорожным ограждением), без пересечений на одном уровне с другими дорогами, железнодорожными или трамвайными путями, пешеходными или велосипедными дорожками, не обслуживает дворовые зоны и в котором встречные зоны движения разделены разделительной линией или дорожным ограждением. Начало и конец автомагистрали указаны знаками 5.1 "Автомагистраль" и 5.2 "Конец автомагистрали".','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1357,1161,101,'116. На автомагистралях запрещается: 1) движение пешеходов, домашних или иных животных, 2) движение велосипедов, мопедов, тракторов и самоходных машин, иных транспортных средств, скорость которых по технической характеристике или их состоянию менее 40 км/ч; 3) движение грузовых автомобилей с разрешенной максимальной массой более 3,5 т далее второй полосы; 4) остановка вне специальных площадок для стоянки, обозначенных знаком 6.4 "Место стоянки" или 7.11 "Место отдыха"; 5) разворот и въезд в технологические разрывы разделительной полосы; 6) движение задним ходом; 7) учебная езда.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1358,1162,101,'117. Требования данного раздела распространяются также на дороги, обозначенные знаком 5.3 "Дорога для автомобилей", а пункт 5 пункта 116 Правил – на дорогах общего применения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1359,1163,101,'118. Жилая зона – построенная площадка, вход и выход которой обозначены знаками 5.21 "Жилая зона" и 5.22 "Конец жилой зоны".','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1360,1164,101,'119. В жилой зоне движение пешеходов разрешается как по тротуарам, так и по проезжей части. В жилой зоне пешеходы имеют преимущество, однако они не должны создавать необоснованные помехи для движения транспортных средств.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1361,1165,101,'120. При выезде из жилой зоны водители должны уступить дорогу другим участникам движения и не должны создавать необоснованные помехи для пешеходов.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1362,1166,101,'121. В жилой зоне запрещаются: 1) учебная езда, 2) сквозное движение, 3) стоянка с работающим двигателем, 4) стоянка грузовых автомобилей и автобусов (кроме микроавтобусов) с разрешенной максимальной массой более 3,5 т вне специально выделенных и обозначенных знаками и (или) разметкой мест.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1363,1167,101,'122. Требования данного раздела распространяются также и на дворовые территории, которые не указаны знаком 5.21 "Жилая зона", но по всему периметру замкнуты жилыми зданиями.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1364,1168,101,'123. Вне перекрестков, где трамвайные пути пересекают проезжую часть, трамвай имеет преимущество перед безрельсовыми транспортными средствами, кроме случаев выезда из депо.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1365,1169,101,'124. На дорогах с полосой для маршрутных транспортных средств, обозначенных знаками 5.14 "Полоса для маршрутных транспортных средств", 5.11 "Дорога с полосой для маршрутных транспортных средств", 5.13.1 и 5.13.2 "Выезд на дорогу с полосой для маршрутных транспортных средств", запрещаются движение и остановка других транспортных средств на этой полосе. Если эта полоса отделена от остальной проезжей части прерывистой линией разметки, то при поворотах транспортные средства должны перестраиваться на нее. Разрешается также в таких местах заезжать на эту полосу при въезде на дорогу и для посадки и высадки пассажиров у правого края проезжей части при условии, что это не создает помех маршрутным транспортным средствам.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1366,1170,101,'125. Водители маршрутных транспортных средств, которые начинают движение из населенных пунктов и остановок, имеют преимущество, но они могут начать движение после того, как убедятся, что другие транспортные средства не создают помехи для них.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1367,1171,101,'126. Водители не должны создавать помех для пешеходов, которые садятся или выходят из маршрутных транспортных средств.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1368,1172,101,'127. В темное время суток и в условиях недостаточной видимости независимо от освещения дороги, а также в тоннелях на движущемся транспортном средстве должны быть включены следующие световые приборы: 1) на всех механических транспортных средствах и моледах — фары дальнего или ближнего света, на велосипедах — фары или фонари, на гужевых повозках — фонари (при их наличии); 2) на прицепах и буксируемых механических транспортных средствах — габаритные огни.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1369,1173,101,'128. Дальний свет должен быть переключен на ближний: 1) в населенных пунктах, если дорога освещена; 2) при встречном разъезде на расстоянии не менее чем за 150 м до транспортного средства, а также и при большем, если водитель встречного транспортного средства периодическим переключением света фар покажет необходимость этого; 3) в любых других случаях для исключения возможности ослепления водителей как встречных, так и попутных транспортных средств.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1370,1174,101,'129. При ослеплении водитель должен включить аварийную световую сигнализацию и, не меняя полосу движения, снизить скорость и остановиться.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1371,1175,101,'130. При остановке и стоянке в темное время суток на неосвещенных участках дорог, а также в условиях недостаточной видимости на транспортном средстве должны быть включены габаритные огни. В условиях недостаточной видимости дополнительно к габаритным огням могут быть включены фары ближнего света, противотуманные фары и задние противотуманные фонари.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1372,1176,101,'131. Задние противотуманные фонари могут применяться только в условиях недостаточной видимости.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1373,1177,101,'132. Противотуманные фары могут использоваться: 1) в условиях недостаточной видимости с ближним или дальним светом фар; 2) в темное время суток на неосвещенных участках дорог совместно с ближним или дальним светом фар; 3) вместо ближнего света фар в соответствии с пунктом 133 Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1374,1178,101,'133. В светлое время суток с целью их обозначения должны включаться фары ближнего света: 1) на мотоциклах и моледах, 2) при движении в организованной транспортной колонне, 3) специальной отдельной зоне на маршрутных транспортных средствах, 4) при организованной перевозке групп детей, 5) при перевозке крупногабаритных, опасных грузов, 6) при буксировке механических транспортных средств.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1375,1179,101,'134. Фарой-промектором и фарой-искателем разрешается пользоваться только вне населенных пунктов при отсутствии встречных транспортных средств. В населенных пунктах пользоваться такими фарами могут только водители транспортных средств, оборудованных в установленном порядке проблесковыми маячками синего цвета и специальными звуковыми сигналами, при выполнении неотложного служебного задания.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1376,1180,101,'135. Опознавательный знак «Автопоезд» должен быть включен при движении автопоезда, а в темное время суток и в условиях недостаточной видимости, кроме того, и на время его остановки или стоянки, и с учетом пункта 130 правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1377,1181,101,'136. Звуковые сигналы могут применяться только: 1) для предупреждения других водителей о намерении произвести обгон вне населенных пунктов; 2) в случаях, когда это необходимо для предотвращения дорожно- транспортного происшествия.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1378,1182,101,'137. Для предупреждения об обгоне вместо звукового сигнала (или совместно с ним) может подаваться световой сигнал, представляющий собой кратковременное переключение фар с ближнего на дальний свет.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1379,1183,101,'138. Буксировка на жесткой или гибкой сцепке должна осуществляться только при наличии водителя за рулем буксируемого транспортного средства, кроме случаев, когда конструкция жесткой сцепки обеспечивает при прямолинейном движении следование буксируемого транспортного средства по траектории буксирующего.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1380,1184,101,'139. При буксировке на гибкой или жесткой сцепке запрещается перевозка людей в буксируемом автобусе, троллейбусе и в кузове буксируемого грузового автомобиля, а при буксировке путем частичной погрузки — нахождение людей в кабине или кузове буксируемого транспортного средства, а также в кузове буксирующего.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1381,1185,101,'140. При буксировке на гибкой сцепке должно быть обеспечено расстояние между буксирующим и буксируемым транспортными средствами в пределах 4 — 6 м, а при буксировке на жесткой сцепке — не более 4 м.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1382,1186,101,'141. При буксировке механических транспортных средств на гибкой сцепке связующее звено должно быть оборудовано предупреждающими устройствами, которые по диагонали имеют полосу шириной 50мм. На гибкой сцепке должно быть не менее двух предупреждающих устройств.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1383,1187,101,'142. Жесткое связующее звено должно соответствовать требованиям стандартов.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1384,1188,101,'143. Буксировка запрещается: 1) двух и более транспортных средств; 2) мотоциклами без бокового прицепа, а также таких мотоциклов; 3) в гололедицу на гибкой сцепке; 4) транспортных средств, у которых не действует стеклоочистители, если управление буксируемого транспортного средства выполняется с помощью водителя; 5) транспортных средств, у которых не действует рулевое управление (допускается буксировка методом частичной погрузки); 6) транспортных средств с недействующей тормозной системой, если их фактическая масса более половины фактической массы буксирующего транспортного средства. При меньшей фактической массе буксировка таких транспортных средств допускается только на жесткой сцепке или методом частичной погрузки.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1385,1189,101,'144. По пунктам 5 и 6 пункта 143 Правил недействующими считаются системы, которые не позволяют водителю остановить транспортное средство или осуществить маневр при движении даже с минимальной скоростью.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1386,1190,101,'145. Первоначальное обучение вождению транспортных средств должно проводиться на закрытых площадках или автодромах.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1387,1191,101,'146. Учебная езда на дорогах допускается только с обучающим и при наличии первоначальных навыков управления у обучаемого. Обучаемый обязан знать и выполнять требования Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1388,1192,101,'147. Обучающий должен иметь при себе документ на право обучения вождению транспортного средства данной категории, а также удостоверение на право управления транспортным средством соответствующей категории.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1389,1193,101,'148. Обучаемому на автомобиле должно быть не менее 16 лет.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1390,1194,101,'149. Учебная езда разрешается местными управляющими лицами (в Ереване мером Еревана).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1391,1195,101,'150. Водителями, имеющими удостоверение на право управления транспортными средствами категории «С» разрешается перевозить 8 человек (в грузовых машинах), при перевозке более 8 человек, водитель должен иметь удостоверение на право управления транспортными средствами категории «D» и «DE» или «DI» и «DIE».','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1392,1196,101,'151. Перед поездкой водитель грузового автомобиля должен проинструктировать пассажиров о порядке посадки, высадки и размещения в кузове. Начинать движение можно только убедившись, что обеспечены условия безопасной перевозки пассажиров.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1393,1197,101,'152. Число перевозимых людей в кузове грузового автомобиля, а также салоне автобуса, осуществляющего перевозку на междугородном, горном, туристическом или экскурсионном маршруте, и при организованной перевозке группы детей не должно превышать количества оборудованных для сидения мест.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1394,1198,101,'153. Перевозка людей в боковом кузове грузового автомобиля разрешается, если он оборудован сверху не менее 0.3м и снизу 0.3-0.5м высотой прикрепленными скамейками.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1395,1199,101,'154. Проезд в кузове грузового автомобиля с бортовой платформой, не оборудованной для перевозки людей, разрешается только лицам, сопровождающим груз или следующим за его получением, при условии, что они обеспечены местом для сидения, расположенным ниже уровня бортов согласно пункту 153 Правил.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1396,1200,101,'155. Организованная перевозка группы детей должна осуществляться в соответствии со специальными правилами в имеющих опознавательные знаки «Перевозка детей» автобусе или грузовом автомобиле с кузовом-фургоном, предназначенным для перевозки людей. При организованной перевозке группы детей с ними должен находиться взрослый сопровождающий (сопровождающие).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1397,1201,101,'156. Организованная перевозка группы детей должна осуществляться в соответствии со специальными правилами с имеющимися опознавательными знаками «Перевозка детей». Должен быть включен аварийный сигнал. Приближаясь к таким транспортным средствам водители должны снизить скорость и при необходимости остановиться.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1398,1202,101,'157. Водитель обязан осуществлять посадку и высадку пассажиров только после полной остановки транспортного средства, а начинать движение только с закрытыми дверями и не открывать их до полной остановки.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1399,1203,101,'158. Запрещается перевозить людей: 1) вне кабины автомобиля (кроме случаев перевозки людей в кузове грузового автомобиля с бортовой платформой или в кузове-фургоне), трактора, других самоходных машин, на грузовом прицепе, в прицепе - даче, в кузове грузового мотоцикла и вне предусмотренных конструкцией мотоцикла мест для сидения; 2) сверх количества, предусмотренного технической характеристикой транспортного средства.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1400,1204,101,'159. Запрещается перевозка детей до 12-летнего возраста: 1) в фургоне грузовых автомобилей (кроме фургонных автомобилей), 2) на заднем сиденье мотоцикла, 3) в легковых автомобилях: а. на переднем сиденье, не оборудованным специальными детскими удерживающими устройствами. б. На заднем сиденье, не оборудованным иными средствами, позволяющих пристегнуть ребенка с помощью ремней безопасности, предусмотренных конструкцией транспортного средства.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1401,1208,101,'160. Масса перевозимого груза и распределение нагрузки по осям не должны превышать величин, установленных предприятием-изготовителем для данного транспортного средства.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1402,1209,101,'161. Перед началом и во время движения водитель обязан контролировать размещение, крепление и состояние груза во избежание его падения, создания помех для движения.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1403,1210,101,'162. Груз, выступающий за габариты транспортного средства спереди и сзади более чем на 1 м или сбоку более чем на 0,4 м от внешнего края габаритного огня, должен быть обозначен опознавательными знаками «Крупногабаритный груз», а в темное время суток и в условиях недостаточной видимости, кроме того, спереди — фонарем или световозвращателем белого цвета, сзади — фонарем или световозвращателем красного цвета.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1404,1211,101,'163. По особым правилам, установленным законодательством Республики Армении, регулируется движения транспортных средств, которые: 1) используются для перевозки крупногабаритных грузов и опасных грузов, 2) используются в комбинации с двумя и более прицепами, в числе автопоезда, 3) габаритные параметры которого с грузом или без него превышают: a. по ширине 2,55 м (2,6 м — для рефрижераторов и изотермических кузовов) б. по длине 12 м, а с одним прицепом (полуприцеп) 20 м. в. по высоте 4 м (от поверхности проезжей части). 4) с грузом, выступающим за заднюю точку габарита транспортного средства более чем на 2 м','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1405,1212,101,'164. Перевозка груза запрещается, если он: 1) ограничивает водителю обзор; 2) затрудняет управление и не нарушает устойчивость транспортного средства; 3) закрывает внешние световые приборы и световозвращатели, регистрационные и опознавательные знаки, а также не препятствует восприятию сигналов, подаваемых рукой; 4) создает шум, не пылит, не загрязняет дорогу и окружающую среду.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1406,1213,101,'165. Если состояние и размещение груза не удовлетворяют указанным требованиям, водитель обязан принять меры к устранению нарушений перечисленных правил перевозки либо прекратить дальнейшее движение.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1407,1214,101,'166. Дорожные знаки, разметки и их нумерация соответствуют стандартам.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1408,1215,101,'167. Дорожные знаки разделяются на 8 групп: 1) предупреждающие знаки, 2) знаки приоритета, 3) запрещающие знаки, 4) предписывающие знаки, 5) знаки особых предписаний, 6) информационные знаки, 7) знаки сервиса, 8) знаки дополнительной информации (таблички).','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1409,1216,101,'168. Дорожные разметки действуют сами по себе или с дорожными знаками и светофорами.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1410,1217,101,'169. Дорожные разметки разделяются на 2 группы: 1) горизонтальная; 2) вертикальная.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1411,1218,101,'170. Горизонтальная разметка - линии, стрелы, надписи и другие обозначения на проезжей части, устанавливает определенные режимы и порядок движения. Горизонтальная разметка бывает: 1) постоянной, который имеет белый цвет, кроме: a. линий 1.4, 1.10, 1.14.1 и 1.14.2, которые имеют желтый цвет, б. линии 1.17, который имеет красный цвет. 2) временной, который имеет оранжевый цвет.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1412,1219,101,'171. Вертикальная разметка в виде сочетания черных и белых полос на дорожных сооружениях и элементах оборудования дорог показывает их габариты и служит средством зрительного ориентирования.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1413,1220,101,'172. Если требования постоянных знаков противоречат требованиям временных, то водители должны управляется временными знаками.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1414,1221,101,'173. Если сигналы светофоров противоречат требованиям знаков приоритета, то водители должны управляется сигналами светофоров.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1415,1222,101,'174. Если требования постоянных разметок противоречат требованиям временных знаков, то участники движения должны управляется этими знаками. Если требования постоянных и временных разметок противоречат друг друга, то водители должны управляется временными разметками.','2025-11-06 21:29:06','2025-11-06 21:29:06');
INSERT INTO pdd_rule_translations VALUES(1416,1223,101,'175. На транспортных средствах при необходимости должны ставиться знаки признания транспортного средства. Кроме знаков «Доктор» и «Инвалид», которые ставятся по желанию водителя, все другие знаки обязательны.','2025-11-06 21:29:06','2025-11-06 21:29:06');
