INSERT INTO road_sign_translations VALUES(411,411,102,'«Երկաթուղային գծանց` ուղեփակոցով»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.1');
INSERT INTO road_sign_translations VALUES(412,412,102,'«Երկաթուղային գծանց` առանց ուղեփակոցի»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.2');
INSERT INTO road_sign_translations VALUES(413,413,102,'«Միագիծ երկաթուղի»','ուղեփակոցով չկահավորված երկաթուղային գծանցի նշում` մեկ ուղիով.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.3.1');
INSERT INTO road_sign_translations VALUES(414,414,102,'«Բազմագիծ երկաթուղի»','ուղեփակոցով չկահավորված երկաթուղային գծանցի նշում՝ երկու և ավելի ուղիներով.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.3.2');
INSERT INTO road_sign_translations VALUES(415,415,102,'«Մոտեցում երկաթուղային գծանցին»','լրացուցիչ նախազգուշացում բնակավայրերից դուրս երկաթուղային գծանցին մոտենալու մասին.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.4.1');
INSERT INTO road_sign_translations VALUES(416,416,102,'«Հատում տրամվայի գծի հետ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.5');
INSERT INTO road_sign_translations VALUES(417,417,102,'«Հավասարազոր ճանապարհների հատում»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.6');
INSERT INTO road_sign_translations VALUES(418,418,102,'«Հատում շրջանաձև երթևեկության հետ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.7');
INSERT INTO road_sign_translations VALUES(419,419,102,'«Լուսացուցային կարգավորում»','խաչմերուկ, հետիոտնային անցում կամ ճանապարհի տեղամաս, որտեղ երթևեկությունը կարգավորվում է լուսացույցով.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.8');
INSERT INTO road_sign_translations VALUES(420,420,102,'«Բացվող կամուրջ»','բացվող կամուրջ կամ լաստանավային անցում.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.9');
INSERT INTO road_sign_translations VALUES(421,421,102,'«Ելք դեպի առափ»','առափ կամ ափ դուրս գալու տեղ.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.10');
INSERT INTO road_sign_translations VALUES(422,422,102,'«Վտանգավոր շրջադարձ»','փոքր շառավղով կամ սահմանափակ տեսադաշտով ճանապարհի կորացում` 1.11.1` դեպի աջ, 1.11.2` դեպի ձախ.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.11.1');
INSERT INTO road_sign_translations VALUES(423,423,102,'«Վտանգավոր շրջադարձեր»','վտանգավոր շրջադարձերով ճանապարհի հատված` 1.12.1` առաջին շրջադարձը դեպի աջ, 1.12.2` առաջին շրջադարձը դեպի ձախ.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.12.1');
INSERT INTO road_sign_translations VALUES(424,424,102,'«Կտրուկ վայրէջք»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.13');
INSERT INTO road_sign_translations VALUES(425,425,102,'«Կտրուկ վերելք»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.14');
INSERT INTO road_sign_translations VALUES(426,426,102,'«Սայթաքուն ճանապարհ»','առավել սայթաքուն երթևեկելի մասով ճանապարհի հատված.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.15');
INSERT INTO road_sign_translations VALUES(427,427,102,'«Անհարթ ճանապարհ»','երթևեկելի մասի անհարթություններով ճանապարհի հատված (ալիքավորություն, խանդակներ, կամուրջների հետ ոչ սահուն լծորդումներ և այլն).','2025-05-04 00:23:30','2025-05-04 00:23:30','1.16');
INSERT INTO road_sign_translations VALUES(428,428,102,'«Արհեստական անհարթություն»','արագությունը հարկադրաբար իջեցնելու համար արհեստական անհարթությամբ (անհարթություններով) ճանապարհի հատված.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.17');
INSERT INTO road_sign_translations VALUES(429,429,102,'«Խճի արտանետում»','ճանապարհի հատված, որտեղ տրանսպորտային միջոցների անիվների տակից հնարավոր է խճի, քարակտորների և այլնի արտանետում.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.18');
INSERT INTO road_sign_translations VALUES(430,430,102,'«Վտանգավոր կողնակ»','ճանապարհի հատված, որտեղ կողնակ դուրս գալը վտանգավոր է.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.19');
INSERT INTO road_sign_translations VALUES(431,431,102,'«Ճանապարհի նեղացում»','` նեղացում երկու կողմից, 1.20.2` աջից, 1.20.3` ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.20.1');
INSERT INTO road_sign_translations VALUES(432,432,102,'«Երկկողմ երթևեկություն»','ճանապարհի (երթևեկելի մասի) հանդիպակաց երթևեկությամբ հատվածի սկիզբ.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.21');
INSERT INTO road_sign_translations VALUES(433,433,102,'«Հետիոտնային անցում»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.22');
INSERT INTO road_sign_translations VALUES(434,434,102,'«Երեխաներ»','մանկական հիմնարկների (դպրոցներ, մանկապարտեզներ և այլն) մոտով անցնող ճանապարհի հատված, որի երթևեկելի մասում հնարավոր է երեխաների հայտնվելը.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.23');
INSERT INTO road_sign_translations VALUES(435,435,102,'«Հատում հեծանվային արահետի հետ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.24');
INSERT INTO road_sign_translations VALUES(436,436,102,'«Ճանապարհային աշխատանքներ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.25');
INSERT INTO road_sign_translations VALUES(437,437,102,'«Անասունների քշում»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.26');
INSERT INTO road_sign_translations VALUES(438,438,102,'«Վայրի կենդանիներ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.27');
INSERT INTO road_sign_translations VALUES(439,439,102,'«Քարերի անկում»','ճանապարհի հատված, որտեղ հնարավոր են փլուզումներ, սողանք, քարերի անկում.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.28');
INSERT INTO road_sign_translations VALUES(440,440,102,'«Կողային քամի»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.29');
INSERT INTO road_sign_translations VALUES(441,441,102,'«Ցածրաթռիչք ինքնաթիռներ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','1.30');
INSERT INTO road_sign_translations VALUES(442,442,102,'«Թունել»','թունել, որտեղ բացակայում է արհեստական լուսավորությունը, կամ թունել, որի ճակատամուտքի տեսանելիությունը սահմանափակ է.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.31');
INSERT INTO road_sign_translations VALUES(443,443,102,'«Խցանում»','ճանապարհի հատված, որտեղ առաջացել է խցանում.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.32');
INSERT INTO road_sign_translations VALUES(444,444,102,'«Այլ վտանգներ»','ճանապարհի հատված, որտեղ առկա են թվարկված նախազգուշացնող նշաններով չնախատեսված վտանգներ.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.33');
INSERT INTO road_sign_translations VALUES(446,446,102,'«Շրջադարձի ուղղություն»','T-աձև խաչմերուկում կամ ճանապարհի ճյուղավորման վրա երթևեկության ուղղություններ. ճանապարհի նորոգվող հատվածի շրջանցման ուղղություններ.','2025-05-04 00:23:30','2025-05-04 00:23:30','1.34.3');
INSERT INTO road_sign_translations VALUES(447,447,102,'«Գլխավոր ճանապարհ»','ճանապարհ, որով երթևեկողներին չկարգավորվող խաչմերուկների անցման առավելություն է տրվում.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.1');
INSERT INTO road_sign_translations VALUES(448,448,102,'«Գլխավոր ճանապարհի վերջ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','2.2');
INSERT INTO road_sign_translations VALUES(449,449,102,'«Հատում երկրորդական ճանապարհի հետ»','','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.1');
INSERT INTO road_sign_translations VALUES(450,450,102,'«Երկրորդական ճանապարհի հարում»',', 2.3.4, 2.3.6` հարում աջից, 2.3.3, 2.3.5, 2.3.7` հարում ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.2');
INSERT INTO road_sign_translations VALUES(451,451,102,'«Զիջեք ճանապարհը»','վարորդը պետք է զիջի ճանապարհը հատող ճանապարհով, իսկ 8.13` «Գլխավոր ճանապարհի ուղղություն» ցուցանակի առկայության դեպքում` գլխավոր ճանապարհով ընթացող տրանսպորտային միջոցներին.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.4');
INSERT INTO road_sign_translations VALUES(452,452,102,'«Երթևեկությունն առանց կանգառի արգելվում է»','արգելվում է երթևեկել առանց «Կանգ» գծից առաջ (դրա բացակայության դեպքում` հատվող երթևեկելի մասի եզրից առաջ) կանգնելու: Վարորդը պետք է զիջի ճանապարհը հատող ճանապարհով, իսկ 8.13` «Գլխավոր ճանապարհի ուղղություն» ցուցանակի առկայության դեպքում` գլխավոր ճանապարհով ընթացող տրանսպորտային միջոցներին: Եթե 2.5 նշանը տեղադրված է երկաթուղային գծանցից կամ կարանտինային պահակետից առաջ, ապա վարորդը պետք է կանգնի «Կանգ» գծից առաջ, իսկ դրա բացակայության դեպքում` նշանից առաջ.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.5');
INSERT INTO road_sign_translations VALUES(453,453,102,'«Հանդիպակաց երթևեկության առավելություն»','արգելվում է մուտք գործել ճանապարհի նեղ հատված, եթե դա կարող է դժվարացնել հանդիպակաց երթևեկությունը: Վարորդը պետք է ճանապարհը զիջի նեղ հատվածին հանդիպակաց կողմից մոտեցող տրանսպորտային միջոցներին.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.6');
INSERT INTO road_sign_translations VALUES(454,454,102,'«Առավելություն հանդիպակաց երթևեկության նկատմամբ»','ճանապարհի նեղ հատված, որով երթևեկելիս վարորդն առավելություն ունի հանդիպակաց տրանսպորտային միջոցների նկատմամբ:','2025-05-04 00:23:30','2025-05-04 00:23:30','2.7');
INSERT INTO road_sign_translations VALUES(455,455,102,'«Մուտքն արգելվում է»','արգելվում է տրանսպորտային միջոցների մուտքը տվյալ ուղղությամբ.','2025-05-04 00:23:30','2025-05-04 00:23:30','3.1');
INSERT INTO road_sign_translations VALUES(456,456,102,'«Երթևեկությունն արգելվում է»','արգելվում է բոլոր տրանսպորտային միջոցների երթևեկությունը.','2025-05-04 00:23:30','2025-05-04 00:23:30','3.2');
INSERT INTO road_sign_translations VALUES(457,457,102,'«Մեխանիկական տրանսպորտային միջոցների երթևեկությունն արգելվում է»','','2025-05-04 00:23:30','2025-05-04 00:23:30','3.3');
INSERT INTO road_sign_translations VALUES(458,458,102,'«Բեռնատար ավտոմոբիլների երթևեկությունն արգելվում է»','արգելվում է 3.5 տոննայից ավելի (եթե նշանի վրա զանգվածը չի նշված) կամ նշանի վրա նշվածից մեծ թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների և տրանսպորտային միջոցների շարժակազմերի, ինչպես նաև տրակտորների և ինքնագնաց մեքենաների երթևեկությունը.','2025-05-04 00:23:30','2025-05-04 00:23:30','3.4');
INSERT INTO road_sign_translations VALUES(459,459,102,'«Մոտոցիկլների երթևեկությունն արգելվում է»','','2025-05-04 00:23:30','2025-05-04 00:23:30','3.5');
INSERT INTO road_sign_translations VALUES(460,460,102,'«Տրակտորների երթևեկությունն արգելվում է»','արգելվում է տրակտորների և ինքնագնաց մեքենաների երթևեկությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.6');
INSERT INTO road_sign_translations VALUES(461,461,102,'«Կցորդով երթևեկությունն արգելվում է»','արգելվում է ցանկացած տեսակի կցորդով բեռնատար ավտոմոբիլների և տրակտորների երթևեկությունը, ինչպես նաև մեխանիկական տրանսպորտային միջոցների քարշակումը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.7');
INSERT INTO road_sign_translations VALUES(462,462,102,'«Լծասայլերի երթևեկությունն արգելվում է»','արգելվում է լծասայլերի (լծասահնակների), հեծկան կամ բեռնակիր կենդանիներով երթևեկությունը և անասուններ քշելը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.8');
INSERT INTO road_sign_translations VALUES(463,463,102,'«Հեծանիվներով երթևեկությունն արգելվում է»','արգելվում է մոպեդներով և հեծանիվներով երթևեկությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.9');
INSERT INTO road_sign_translations VALUES(464,464,102,'«Հետիոտների տեղաշարժն արգելվում է»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.10');
INSERT INTO road_sign_translations VALUES(465,465,102,'«Զանգվածի սահմանափակում»','արգելվում է այն տրանսպորտային միջոցների (այդ թվում` ավտոգնացքների) երթևեկությունը, որոնց ընդհանուր փաստացի զանգվածը մեծ է նշանի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.11');
INSERT INTO road_sign_translations VALUES(466,466,102,'«Սռնու վրա բեռնվածության սահմանափակում»','արգելվում է այն տրանսպորտային միջոցների երթևեկությունը, որոնց որևէ սռնու վրա բեռնվածությունը մեծ է նշանի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.12');
INSERT INTO road_sign_translations VALUES(467,467,102,'«Բարձրության սահմանափակում»','արգելվում է այն տրանսպորտային միջոցների երթևեկությունը, որոնց եզրաչափային բարձրությունը (բեռով կամ առանց բեռի) ավելի է նշանի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.13');
INSERT INTO road_sign_translations VALUES(468,468,102,'«Լայնության սահմանափակում»','արգելվում է այն տրանսպորտային միջոցների երթևեկությունը, որոնց եզրաչափային լայնությունը (բեռով կամ առանց բեռի) ավելի է նշանի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.14');
INSERT INTO road_sign_translations VALUES(469,469,102,'«Երկարության սահմանափակում»','արգելվում է այն տրանսպորտային միջոցների (այդ թվում` ավտոգնացքների) երթևեկությունը, որոնց եզրաչափային երկարությունը (բեռով կամ առանց բեռի) ավելի է նշանի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.15');
INSERT INTO road_sign_translations VALUES(470,470,102,'«Նվազագույն միջտարածության սահմանափակում»','արգելվում է տրանսպորտային միջոցների երթևեկությունը, եթե դրանց միջև տարածությունը փոքր է նշանի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.16');
INSERT INTO road_sign_translations VALUES(471,471,102,'«Մաքսային կետ»','արգելվում է առանց կանգառի անցումը մաքսային կետի մոտով.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.17.1');
INSERT INTO road_sign_translations VALUES(472,472,102,'«Վտանգ»','արգելվում էբոլոր տրանսպորտային միջոցների հետագա երթևեկությունը ճանապարհատրանսպորտային պատահարի, հրդեհի, վթարի և այլ վտանգի կապակցությամբ, բացառությամբ ոստիկանության, շտապ բժշկական օգնության, փրկարարական և վտանգի վերացման նպատակով ժամանած այլ ծառայությունների տրանսպորտային միջոցների, երթևեկությունը շարունակել կարելի է միայն թույլտվություն ստանալուց հետո.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.17.2');
INSERT INTO road_sign_translations VALUES(473,473,102,'«Հսկիչ կետ»','արգելվում է առանց կանգառի անցումը հսկիչ կետով.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.17.3');
INSERT INTO road_sign_translations VALUES(474,474,102,'«Աջ շրջադարձն արգելվում է»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.18.1');
INSERT INTO road_sign_translations VALUES(475,475,102,'«Ձախ շրջադարձն արգելվում է»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.18.2');
INSERT INTO road_sign_translations VALUES(476,476,102,'«Հետադարձն արգելվում է»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.19');
INSERT INTO road_sign_translations VALUES(477,477,102,'«Վազանցն արգելվում է»','արգելվում է բոլոր տեսակի տրանսպորտային միջոցներով վազանցի կատարումը: Թույլատրվում է վազանցել դանդաղընթաց տրանսպորտային միջոցները, լծասայլերը, առանց կողային կցորդի երկանիվ մոտոցիկլները, մոպեդները և հեծանիվները.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.20');
INSERT INTO road_sign_translations VALUES(478,478,102,'«Վազանցի արգելման գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.21');
INSERT INTO road_sign_translations VALUES(479,479,102,'«Բեռնատար ավտոմոբիլներով վազանցն արգելվում է»','բոլոր տեսակի տրանսպորտային միջոցներով վազանցն արգելվում է` բացառությամբ մոտոցիկլների, թեթև մարդատար ավտոմոբիլների, ավտոբուսների և մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.22');
INSERT INTO road_sign_translations VALUES(480,480,102,'«Բեռնատար ավտոմոբիլներով վազանցի արգելման գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.23');
INSERT INTO road_sign_translations VALUES(481,481,102,'«Առավելագույն արագության սահմանափակում»','արգելվում է նշանի վրա նշվածից բարձր արագությամբ (կմ/ժ) երթևեկելը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.24');
INSERT INTO road_sign_translations VALUES(482,482,102,'«Առավելագույն արագության սահմանափակման գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.25');
INSERT INTO road_sign_translations VALUES(483,483,102,'«Ձայնային ազդանշան տալն արգելվում է»','արգելվում է օգտվել ձայնային ազդանշաններից` բացի այն դեպքերից, երբ այն տրվում է ճանապարհատրանսպորտային պատահար կանխելու համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.26');
INSERT INTO road_sign_translations VALUES(484,484,102,'«Կանգառն արգելվում է»','արգելվում են տրանսպորտային միջոցների կանգառն ու կայանումը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.27');
INSERT INTO road_sign_translations VALUES(485,485,102,'«Կայանելն արգելվում է»','արգելվում է տրանսպորտային միջոցների կայանումը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.28');
INSERT INTO road_sign_translations VALUES(486,486,102,'«Կայանելն արգելվում է ամսվա կենտ օրերին»','','2025-05-04 00:23:31','2025-05-04 00:23:31','3.29');
INSERT INTO road_sign_translations VALUES(487,487,102,'«Կայանելն արգելվում է ամսվա զույգ օրերին»','3.29 և 3.30 նշանների միաժամանակյա կիրառման դեպքում տրանսպորտային միջոցները ճանապարհի մի կողմից մյուսը տեղափոխվում են ժամը 19.00 - 21.00-ի սահմաններում.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.30');
INSERT INTO road_sign_translations VALUES(488,488,102,'«Բոլոր սահմանափակումների գոտու վերջ»','նշում է 3.16, 3.20, 3.22, 3.24 և 3.26 - 3.30 նշաններից մի քանիսի ազդման գոտիների միաժամանակյա վերջը.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.31');
INSERT INTO road_sign_translations VALUES(489,489,102,'«Վտանգավոր բեռներով տրանսպորտային միջոցների երթևեկությունն արգելվում է»','արգելվում է այն տրանսպորտային միջոցների երթևեկությունը, որոնք կահավորված են «Վտանգավոր բեռ» ճանաչման նշանով.','2025-05-04 00:23:31','2025-05-04 00:23:31','3.32');
INSERT INTO road_sign_translations VALUES(490,490,102,'«Պայթուցիկ և դյուրավառ բեռներով տրանսպորտային միջոցների երթևեկությունն արգելվում է»','արգելվում է այն տրանսպորտային միջոցների երթևեկությունը, որոնք կահավորված են «Վտանգավոր բեռ» ճանաչման նշանով և նախատեսված են 1, 2.2 - 2.4, 3.1, 3.2 և 5.2 դասերի վտանգավոր բեռներ փոխադրելու համար (ըստ ստանդարտի).','2025-05-04 00:23:31','2025-05-04 00:23:31','3.33');
INSERT INTO road_sign_translations VALUES(491,491,102,'«Երթևեկությունն ուղիղ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.1.1');
INSERT INTO road_sign_translations VALUES(492,492,102,'«Երթևեկությունը դեպի աջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.1.2');
INSERT INTO road_sign_translations VALUES(493,493,102,'«Երթևեկությունը դեպի ձախ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.1.3');
INSERT INTO road_sign_translations VALUES(494,494,102,'«Երթևեկությունն ուղիղ կամ դեպի աջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.1.4');
INSERT INTO road_sign_translations VALUES(495,495,102,'«Երթևեկությունն ուղիղ կամ դեպի ձախ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.1.5');
INSERT INTO road_sign_translations VALUES(496,496,102,'«Երթևեկությունը դեպի աջ կամ դեպի ձախ»','թույլատրվում է երթևեկել միայն նշանների վրա սլաքներով ցույց տրված ուղղություններով:','2025-05-04 00:23:31','2025-05-04 00:23:31','4.1.6');
INSERT INTO road_sign_translations VALUES(497,497,102,'«Արգելքի շրջանցումն աջից»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.2.1');
INSERT INTO road_sign_translations VALUES(498,498,102,'«Արգելքի շրջանցումը ձախից»','շրջանցումը թույլատրվում է միայն սլաքով ցույց տրված կողմից.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.2.2');
INSERT INTO road_sign_translations VALUES(499,499,102,'«Արգելքի շրջանցումն աջից կամ ձախից»','շրջանցումը թույլատրվում է ինչպես աջ, այնպես էլ ձախ կողմից.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.2.3');
INSERT INTO road_sign_translations VALUES(500,500,102,'«Շրջանաձև երթևեկություն»','երթևեկությունը թույլատրվում է սլաքներով ցույց տրված ուղղությամբ.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.3');
INSERT INTO road_sign_translations VALUES(501,501,102,'«Հեծանվային արահետ»','թույլատրվում է երթևեկել միայն մոպեդներով և հեծանիվներով: Մայթի կամ հետիոտնային արահետի բացակայության դեպքում հեծանվային արահետով կարող են երթևեկել նաև հետիոտները.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.4');
INSERT INTO road_sign_translations VALUES(502,502,102,'«Հետիոտնային արահետ»','թույլատրվում է միայն հետիոտների տեղաշարժը.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.5');
INSERT INTO road_sign_translations VALUES(503,503,102,'«Նվազագույն արագության սահմանափակում»','թույլատրվում է երթևեկել միայն նշված (կմ/ժ) կամ ավելի բարձր արագությամբ.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.6');
INSERT INTO road_sign_translations VALUES(504,504,102,'«Նվազագույն արագության սահմանափակման գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','4.7');
INSERT INTO road_sign_translations VALUES(505,505,102,'«Վտանգավոր բեռներով տրանսպորտային միջոցների երթևեկության ուղղություն»','«Վտանգավոր բեռ» ճանաչման նշաններով կահավորված տրանսպորտային միջոցների երթևեկությունը թույլատրվում է միայն նշանի վրա սլաքով ցույց տրված ուղղությամբ` 4.8.1`ուղիղ, 4.8.2` դեպի աջ, 4.8.3` դեպի ձախ.','2025-05-04 00:23:31','2025-05-04 00:23:31','4.8.1');
INSERT INTO road_sign_translations VALUES(506,506,102,'«Ավտոմայրուղի»','ճանապարհ, որտեղ գործում են կանոնների` ավտոմայրուղիներով երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.1');
INSERT INTO road_sign_translations VALUES(507,507,102,'«Ավտոմայրուղու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.2');
INSERT INTO road_sign_translations VALUES(508,508,102,'«Ճանապարհ ավտոմոբիլների համար»','թույլատրվում է նաև մոտոցիկլների երթևեկությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.3');
INSERT INTO road_sign_translations VALUES(509,509,102,'«Ավտոմոբիլների համար ճանապարհի վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.4');
INSERT INTO road_sign_translations VALUES(510,510,102,'«Միակողմ երթևեկությամբ ճանապարհ»','ճանապարհ կամ երթևեկելի մաս, որով տրանսպորտային միջոցների երթևեկությունն ամբողջ լայնությամբ իրականացվում է մեկ ուղղությամբ.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.5');
INSERT INTO road_sign_translations VALUES(511,511,102,'«Միակողմ երթևեկությամբ ճանապարհի վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.6');
INSERT INTO road_sign_translations VALUES(512,512,102,'«Ելք դեպի միակողմ երթևեկությամբ ճանապարհ»','ելք դեպի միակողմ երթևեկությամբ ճանապարհ կամ երթևեկելի մաս.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.7.1');
INSERT INTO road_sign_translations VALUES(513,513,102,'«Դարձափոխային երթևեկություն»','ճանապարհի այն հատվածի սկիզբը, որտեղ մեկ կամ մի քանի գոտիներով երթևեկության ուղղությունը կարող է փոխվել հանդիպակացի.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.8');
INSERT INTO road_sign_translations VALUES(514,514,102,'«Դարձափոխային երթևեկության վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.9');
INSERT INTO road_sign_translations VALUES(515,515,102,'«Ելք դեպի դարձափոխային երթևեկությամբ ճանապարհ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.10');
INSERT INTO road_sign_translations VALUES(516,516,102,'«Ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտիով ճանապարհ»','երթևեկության հոսքին հանդիպակաց, ընդհանուր օգտագործման տրանսպորտային միջոցների երթևեկության համար հատուկ առանձնացված գոտի ունեցող ճանապարհ.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.11');
INSERT INTO road_sign_translations VALUES(517,517,102,'«Ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտիով ճանապարհի վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.12');
INSERT INTO road_sign_translations VALUES(518,518,102,'«Ելք դեպի ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտիով ճանապարհ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.13.1');
INSERT INTO road_sign_translations VALUES(519,519,102,'«Ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտի»','երթևեկության հոսքին համընթաց, միայն ընդհանուր օգտագործման տրանսպորտային միջոցների համար նախատեսված գոտի: Այդ նշանի ազդեցությունը տարածվում է այն գոտու վրա, որի վրա տեղադրված է: Ճանապարհից աջ տեղադրված նշանի ազդեցությունը տարածվում է աջ գոտու վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.14');
INSERT INTO road_sign_translations VALUES(520,520,102,'«Երթևեկության ուղղությունները գոտիներով»','գոտիների թիվը և երթևեկության թույլատրելի ուղղությունները` դրանցից յուրաքանչյուրով.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.1');
INSERT INTO road_sign_translations VALUES(521,521,102,'«Երթևեկության ուղղությունները գոտիով»','երթևեկության թույլատրելի ուղղությունները գոտիով: Ձախ եզրային գոտուց ձախ շրջադարձը թույլատրող 5.15.1 և 5.15.2 նշանները թույլատրում են նաև հետադարձն այդ գոտուց: 5.15.1 և 5.15.2 նշանների գործողությունը չի տարածվում ընդհանուր օգտագործման տրանսպորտային միջոցների վրա: Խաչմերուկից առաջ տեղադրված 5.8.1 և «5.15.2» նշանների ազդման գոտին տարածվում է ամբողջ խաչմերուկի վրա, եթե այնտեղ տեղադրված 5.15.1 կամ 5.8.2 այլ նշաններն ուրիշ ցուցումներ չեն տալիս.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.2');
INSERT INTO road_sign_translations VALUES(522,522,102,'«Գոտու սկիզբ»','արգելակման գոտու կամ վերելքի վրա լրացուցիչ գոտու սկիզբը: Եթե լրացուցիչ գոտուց առաջ տեղադրված այս նշանի վրա պատկերված է 4.6` «Նվազագույն արագության սահմանափակում» նշանը, ապա այն տրանսպորտային միջոցների վարորդները, որոնք հիմնական գոտիով չեն կարող շարունակել երթևեկությունը` առնվազն նշանի վրա ցույց տրված արագությամբ, պետք է վերադասավորվեն լրացուցիչ գոտի.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.3');
INSERT INTO road_sign_translations VALUES(523,523,102,'«Գոտու սկիզբ»','տվյալ ուղղությամբ երթևեկության համար նախատեսված եռագոտի ճանապարհի միջին գոտու հատվածի սկիզբը: Եթե 5.15.4 նշանի վրա պատկերված է որևէ տեսակի տրանսպորտային միջոցի երթևեկությունն արգելող նշան, ապա այդ տրանսպորտային միջոցների երթևեկությունը համապատասխան գոտիներով արգելվում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.4');
INSERT INTO road_sign_translations VALUES(524,524,102,'«Գոտու վերջ»','թափառքի գոտու կամ վերելքի վրա լրացուցիչ գոտու վերջը.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.5');
INSERT INTO road_sign_translations VALUES(525,525,102,'«Գոտու վերջ»','տվյալ ուղղությամբ երթևեկության համար նախատեսված եռագոտի ճանապարհի միջին գոտու հատվածի վերջը.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.6');
INSERT INTO road_sign_translations VALUES(526,526,102,'«Երթևեկության ուղղությունը գոտիներով»','եթե 5.15.7 նշանի վրա պատկերված է որևէ տրանսպորտային միջոցի երթևեկությունն արգելող նշան, ապա այդ տրանսպորտային միջոցի երթևեկությունը նշված գոտիով արգելվում է: 5.15.7 նշանը համապատասխան թվով սլաքներով կարող է կիրառվել չորս և ավելի գոտիներ ունեցող ճանապարհներին.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.7');
INSERT INTO road_sign_translations VALUES(527,527,102,'«Գոտիների քանակը»','ցույց է տալիս երթևեկության գոտիների թիվը և գոտիներով երթևեկության ռեժիմները: Վարորդը պետք է կատարի սլաքների վրա պատկերված նշանների պահանջները.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.15.8');
INSERT INTO road_sign_translations VALUES(528,528,102,'«Ավտոբուսի և (կամ) տրոլեյբուսի կանգառի տեղ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.16');
INSERT INTO road_sign_translations VALUES(529,529,102,'«Տրամվայի կանգառի տեղ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.17');
INSERT INTO road_sign_translations VALUES(530,530,102,'«Թեթև մարդատար տաքսիների կայանման տեղ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.18');
INSERT INTO road_sign_translations VALUES(531,531,102,'«Հետիոտնային անցում»','անցման վայրում 1.14.1 - 1.14.2 գծանշումների բացակայության դեպքում 5.19.1 նշանը տեղադրվում է ճանապարհից ձախ, անցման հեռավոր, իսկ 5.19.2 նշանը` ճանապարհից աջ, անցման մոտակա սահմանի մոտ.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.19.1');
INSERT INTO road_sign_translations VALUES(532,532,102,'«Արհեստական անհարթություն»','ցույց է տալիս արհեստական անհարթության սահմանները: Նշանը տեղադրվում է արհեստական անհարթությանը տրանսպորտային միջոցի մոտեցման ուղղության մոտակա սահմանի վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.20');
INSERT INTO road_sign_translations VALUES(533,533,102,'«Բնակելի գոտի»','տարածք, որտեղ գործում են կանոնների` բնակելի գոտում երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.21');
INSERT INTO road_sign_translations VALUES(534,534,102,'«Բնակելի գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.22');
INSERT INTO road_sign_translations VALUES(535,535,102,'«Բնակավայրի սկիզբ»','բնակավայրի սկիզբը, որտեղ գործում են կանոնների` բնակավայրերում երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.23.1');
INSERT INTO road_sign_translations VALUES(536,536,102,'«Բնակավայրի վերջ»','վայր, որտեղից սկսած տվյալ ճանապարհին իրենց ուժը կորցնում են կանոնների` բնակավայրերում երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.24.1');
INSERT INTO road_sign_translations VALUES(537,537,102,'«Բնակավայրի սկիզբ»','այն բնակավայրի անվանումն ու սկիզբը, որտեղ տվյալ ճանապարհին չեն գործում կանոնների` բնակավայրերում երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.25');
INSERT INTO road_sign_translations VALUES(538,538,102,'«Բնակավայրի վերջ»','5.25 նշանով նշված բնակավայրի վերջը.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.26');
INSERT INTO road_sign_translations VALUES(539,539,102,'«Կայանման սահմանափակումով գոտի»','վայր, որտեղից սկսվում է կայանումն արգելված տարածքը (ճանապարհի հատվածը).','2025-05-04 00:23:31','2025-05-04 00:23:31','5.27');
INSERT INTO road_sign_translations VALUES(540,540,102,'«Կայանման սահմանափակումով գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.28');
INSERT INTO road_sign_translations VALUES(541,541,102,'«Կարգավորվող կայանման գոտի»','վայր, որտեղից սկսվում է թույլատրված և ցուցանակների ու գծանշումների օգնությամբ կարգավորվող կայանման տարածքը (ճանապարհի հատվածը).','2025-05-04 00:23:31','2025-05-04 00:23:31','5.29');
INSERT INTO road_sign_translations VALUES(542,542,102,'«Կարգավորվող կայանման գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.30');
INSERT INTO road_sign_translations VALUES(543,543,102,'«Առավելագույն արագության սահմանափակումով գոտի»','վայր, որտեղից սկսվում է առավելագույն արագության սահմանափակմամբ տարածքը (ճանապարհի հատվածը).','2025-05-04 00:23:31','2025-05-04 00:23:31','5.31');
INSERT INTO road_sign_translations VALUES(544,544,102,'«Առավելագույն արագության սահմանափակումով գոտու վերջ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.32');
INSERT INTO road_sign_translations VALUES(545,545,102,'«Հետիոտնային գոտի»','վայր, որտեղից սկսվում է միայն հետիոտների տեղաշարժի համար թույլատրված տարածքը (ճանապարհի հատվածը).','2025-05-04 00:23:31','2025-05-04 00:23:31','5.33');
INSERT INTO road_sign_translations VALUES(546,546,102,'«Հետիոտնային գոտու վերջ»','։','2025-05-04 00:23:31','2025-05-04 00:23:31','5.34');
INSERT INTO road_sign_translations VALUES(547,547,102,'«Առավելագույն արագության ընդհանուր սահմանափակում»','կանոններով սահմանված առավելագույն արագության ընդհանուր սահմանափակում.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.1');
INSERT INTO road_sign_translations VALUES(548,548,102,'«Առաջարկվող արագություն»','ճանապարհի տվյալ հատվածում երթևեկելու համար նախընտրելի արագություն: Նշանի ազդման գոտին տարածվում է մինչև մոտակա խաչմերուկը, սակայն, եթե այդ նշանը կիրառվում է նախազգուշացնող նշանի հետ միասին, ազդման գոտին որոշվում է վտանգավոր հատվածի երկարությամբ.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.2');
INSERT INTO road_sign_translations VALUES(549,549,102,'«Հետադարձի տեղ»','ձախ շրջադարձն արգելվում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.3.1');
INSERT INTO road_sign_translations VALUES(550,550,102,'«Հետադարձի գոտի»','հետադարձի համար գոտու երկարությունը: Ձախ շրջադարձն արգելվում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.3.2');
INSERT INTO road_sign_translations VALUES(551,551,102,'«Կայանման տեղ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','6.4');
INSERT INTO road_sign_translations VALUES(552,552,102,'«Վթարային կանգառի գոտի»','կտրուկ վայրէջքի վրա վթարային կանգառի գոտի.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.5');
INSERT INTO road_sign_translations VALUES(553,553,102,'«Ստորգետնյա հետիոտնային անցում»','','2025-05-04 00:23:31','2025-05-04 00:23:31','6.6');
INSERT INTO road_sign_translations VALUES(554,554,102,'«Վերգետնյա հետիոտնային անցում»','','2025-05-04 00:23:31','2025-05-04 00:23:31','6.7');
INSERT INTO road_sign_translations VALUES(555,555,102,'«Փակուղի»','միջանցիկ անցում չունեցող ճանապարհ.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.8.1');
INSERT INTO road_sign_translations VALUES(556,556,102,'«Ուղղությունների նախնական ցուցիչ»','6.9.2. «Ուղղության նախնական ցուցիչ». երթևեկելու ուղղություններ դեպի նշանի վրա նշված բնակավայրերը և այլ օբյեկտներ: Այս նշանների վրա կարող են պատկերվել 6.14.1 նշանի պատկերը, ավտոմայրուղու, օդանավակայանի պատկերանշանները և այլ պատկերագրեր: 6.9.1 նշանի վրա կարող են պատկերվել երթևեկության առանձնահատկությունների մասին տեղեկացնող այլ նշանների պատկերներ: 6.9.1 նշանի ներքևի մասում նշվում է նշանի տեղադրման վայրից մինչև խաչմերուկ կամ արգելակման գոտու սկիզբ եղած հեռավորությունը: 6.9.1 նշանը կիրառվում է նաև 3.11 - 3.15 արգելող նշաններից որևէ մեկով կահավորված ճանապարհի հատվածի շրջանցման ուղղության մասին տեղեկություն տալու համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.9.1');
INSERT INTO road_sign_translations VALUES(557,557,102,'«Երթևեկության սխեմա»','խաչմերուկներում որոշ մանևրների արգելման դեպքում երթևեկության երթուղի կամ բարդ խաչմերուկներում երթևեկության թույլատրելի ուղղություններ.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.9.3');
INSERT INTO road_sign_translations VALUES(558,558,102,'«Ուղղությունների ցուցիչ»','6.10.2. «Ուղղության ցուցիչ». դեպի երթուղու կետերը երթևեկելու ուղղություններ: Նշանների վրա կարող են նշվել մինչև այդ օբյեկտները եղած հեռավորությունները (կմ), պատկերվել ավտոմայրուղու, օդանավակայանի պատկերանշաններ և այլ պատկերագրեր.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.10.1');
INSERT INTO road_sign_translations VALUES(559,559,102,'«Օբյեկտի անվանում»','բնակավայրերից բացի` այլ օբյեկտի անվանումը (գետ, լիճ, լեռնանցք, տեսարժան վայր և այլն).','2025-05-04 00:23:31','2025-05-04 00:23:31','6.11');
INSERT INTO road_sign_translations VALUES(560,560,102,'«Հեռավորությունների ցուցիչ»','մինչև երթուղու վրա գտնվող բնակավայրերը եղած հեռավորությունը (կմ).','2025-05-04 00:23:31','2025-05-04 00:23:31','6.12');
INSERT INTO road_sign_translations VALUES(561,561,102,'«Կիլոմետրային նշան»','մինչև ճանապարհի սկիզբը կամ վերջը եղած հեռավորությունը (կմ).','2025-05-04 00:23:31','2025-05-04 00:23:31','6.13');
INSERT INTO road_sign_translations VALUES(562,562,102,'«Երթուղու համարը»','` ճանապարհին (երթուղուն) հատկացված համարը, 6.14.2` ճանապարհի (երթուղու) համարը և ուղղությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.14.1');
INSERT INTO road_sign_translations VALUES(563,563,102,'«Երթևեկության ուղղություն բեռնատար ավտոմոբիլների համար»','բեռնատար ավտոմոբիլների, տրակտորների և ինքնագնաց մեքենաների համար առաջարկվող երթևեկության ուղղությունը, եթե խաչմերուկում դրանց երթևեկությունը որևէ ուղղությամբ արգելված է.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.15.1');
INSERT INTO road_sign_translations VALUES(564,564,102,'«Կանգ-գիծ»','լուսացույցի (կարգավորողի) արգելող ազդանշանի դեպքում տրանսպորտային միջոցների կանգառի տեղ.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.16');
INSERT INTO road_sign_translations VALUES(565,565,102,'«Շրջանցման սխեմա»','երթևեկության համար ժամանակավոր փակ ճանապարհի հատվածի շրջանցման երթուղի.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.17');
INSERT INTO road_sign_translations VALUES(566,566,102,'«Շրջանցման ուղղություն»','երթևեկության համար ժամանակավոր փակ ճանապարհի հատվածի շրջանցման ուղղություն.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.18.1');
INSERT INTO road_sign_translations VALUES(567,567,102,'«Այլ երթևեկելի մաս վերադասավորվելու նախնական ցուցիչ»','բաժանարար գոտիով ճանապարհի երթևեկելի մասի երթևեկության համար փակ հատվածի շրջանցման կամ աջակողմյան երթևեկելի մաս վերադառնալու համար երթևեկության ուղղություն:','2025-05-04 00:23:31','2025-05-04 00:23:31','6.19.1');
INSERT INTO road_sign_translations VALUES(568,568,102,'«Վթարային ելք»','թունելում ցույց է տալիս այն տեղը, որտեղ գտնվում է վթարային ելքը.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.20.1');
INSERT INTO road_sign_translations VALUES(569,569,102,'«Դեպի վթարային ելք տեղաշարժման ուղղություն»','ցույց է տալիս դեպի վթարային ելք ուղղությունը և մինչև վթարային ելքը եղած հեռավորությունը:','2025-05-04 00:23:31','2025-05-04 00:23:31','6.21.1');
INSERT INTO road_sign_translations VALUES(570,570,102,'«Առաջին բժշկական օգնության կետ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.1');
INSERT INTO road_sign_translations VALUES(571,571,102,'«Հիվանդանոց»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.2');
INSERT INTO road_sign_translations VALUES(572,572,102,'«Ավտոլցավորման կայան»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.3');
INSERT INTO road_sign_translations VALUES(573,573,102,'«Ավտոմոբիլների տեխնիկական սպասարկում»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.4');
INSERT INTO road_sign_translations VALUES(574,574,102,'«Ավտոմոբիլների լվացում»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.5');
INSERT INTO road_sign_translations VALUES(575,575,102,'«Հեռախոս»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.6');
INSERT INTO road_sign_translations VALUES(576,576,102,'«Սննդի կետ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.7');
INSERT INTO road_sign_translations VALUES(577,577,102,'«Խմելու ջուր»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.8');
INSERT INTO road_sign_translations VALUES(578,578,102,'«Հյուրանոց կամ մոթել»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.9');
INSERT INTO road_sign_translations VALUES(579,579,102,'«Հանգրվան»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.10');
INSERT INTO road_sign_translations VALUES(580,580,102,'«Հանգստի վայր»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.11');
INSERT INTO road_sign_translations VALUES(581,581,102,'«Ճանապարհային ոստիկանության ճանապարհապարեկային ծառայության պահակետ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.12');
INSERT INTO road_sign_translations VALUES(582,582,102,'«Ոստիկանություն»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.13');
INSERT INTO road_sign_translations VALUES(583,583,102,'«Միջազգային ավտոմոբիլային փոխադրումների հսկման կետ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.14');
INSERT INTO road_sign_translations VALUES(584,584,102,'«Ճանապարհային երթևեկության մասին տեղեկություն հաղորդող ռադիոկայանի գործողության գոտի»','ճանապարհի հատված, որտեղ իրականացվում է նշանի վրա նշված հաճախականության հաղորդումների ընդունում.','2025-05-04 00:23:31','2025-05-04 00:23:31','7.15');
INSERT INTO road_sign_translations VALUES(585,585,102,'«Վթարային ծառայությունների հետ ռադիոկապի գոտի»','ճանապարհի հատված, որտեղ գործում է վթարային ծառայությունների հետ ռադիոկապի համակարգ` նշանի վրա նշված քաղաքացիական հաճախականությամբ.','2025-05-04 00:23:31','2025-05-04 00:23:31','7.16');
INSERT INTO road_sign_translations VALUES(586,586,102,'«Լողավազան կամ լողափ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.17');
INSERT INTO road_sign_translations VALUES(587,587,102,'«Զուգարան»','','2025-05-04 00:23:31','2025-05-04 00:23:31','7.18');
INSERT INTO road_sign_translations VALUES(588,588,102,'«Արտակարգ կապի հեռախոս»','ցույց է տալիս այն տեղը, որտեղ գտնվում է օպերատիվ ծառայությունների հետ կապ հաստատելու հեռախոսը.','2025-05-04 00:23:31','2025-05-04 00:23:31','7.19');
INSERT INTO road_sign_translations VALUES(589,589,102,'«Կրակմարիչ»','ցույց է տալիս այն տեղը, որտեղ գտնվում է կրակմարիչը:','2025-05-04 00:23:31','2025-05-04 00:23:31','7.20');
INSERT INTO road_sign_translations VALUES(590,590,102,'«Հեռավորություն մինչև օբյեկտ»','ցույց է տալիս ընթացքի ուղղությամբ նշանից մինչև վտանգավոր հատվածի սկիզբը, համապատասխան սահմանափակում մտցնելու տեղը կամ առջևում գտնվող որոշակի օբյեկտ (վայր) եղած հեռավորությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.1.1');
INSERT INTO road_sign_translations VALUES(591,591,102,'«Հեռավորություն մինչև օբյեկտ»','ցույց է տալիս 2.4` «Զիջեք ճանապարհը» նշանից մինչև խաչմերուկ եղած հեռավորությունը, երբ խաչմերուկից անմիջապես առաջ տեղադրված է 2.5` «Երթևեկությունն առանց կանգառի արգելված է» նշանը.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.1.2');
INSERT INTO road_sign_translations VALUES(592,592,102,'«Հեռավորություն մինչև օբյեկտ»','ցույց է տալիս հեռավորությունը մինչև ճանապարհից դուրս գտնվող օբյեկտ.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.1.3');
INSERT INTO road_sign_translations VALUES(593,593,102,'«Ազդման գոտի»','ցույց է տալիս նախազգուշացնող նշաններով կահավորված ճանապարհի վտանգավոր հատվածի երկարությունը կամ արգելող և տեղեկատու-ցուցիչ նշանների ազդման գոտին.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.2.1');
INSERT INTO road_sign_translations VALUES(594,594,102,'«Ազդման գոտի»','ցուցանակները ցույց են տալիս և (կամ) տեղեկացնում են` 1) 8.2.2` 3.27` «Կանգառն արգելված է», 3.28` «Կայանելն արգելված է», 3.29` «Կայանելն արգելված է ամսվա կենտ օրերին», 3.30` «Կայանելն արգելված է ամսվա զույգ օրերին» արգելող նշանների ազդման գոտին. 2) 8.2.3` 3.27 - 3.30 նշանների ազդման գոտու վերջը. 3) 8.2.4` 3.27 - 3.30 նշանների ազդման գոտում գտնվելու մասին. 4) 8.2.5, 7.2.6` 3.27 - 3.30 նշանների ազդման ուղղությունը և գոտին, հրապարակի, շենքի ճակատի և այլ տեղերի` մի կողմի երկայնքով կանգառի կամ կայանման արգելման դեպքում.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.2.2');
INSERT INTO road_sign_translations VALUES(595,595,102,'«Ազդման ուղղություններ»','ցույց են տալիս խաչմերուկից առաջ տեղադրված նշանների ազդման ուղղությունները կամ երթևեկության ուղղությունները` դեպի անմիջապես ճանապարհին մոտ գտնվող օբյեկտները.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.3.1');
INSERT INTO road_sign_translations VALUES(596,596,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.1');
INSERT INTO road_sign_translations VALUES(597,597,102,'«Շաբաթ, կիրակի և տոն օրեր»','8.5.2. «Աշխատանքային օրեր», 8.5.3. «Շաբաթվա օրեր». ցուցանակները տեղեկացնում են շաբաթվա այն օրերի մասին, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.1');
INSERT INTO road_sign_translations VALUES(598,598,102,'«Գործողության ժամանակ»',', 8.5.5 - 8.5.7. «Գործողության ժամանակ». 8.5.4 ցուցանակը տեղեկացնում է օրվա այն ժամերը, իսկ 8.5.5 - 8.5.7 ցուցանակները` նաև շաբաթվա այն օրերը, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.4');
INSERT INTO road_sign_translations VALUES(599,599,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.1');
INSERT INTO road_sign_translations VALUES(600,600,102,'«Կայանում չգործարկված շարժիչով»','ցույց է տալիս, որ 6.4` «Կայանման տեղ» նշանով կահավորված կայանման վայրում տրանսպորտային միջոցների կայանումը թույլատրվում է միայն չգործարկված շարժիչով.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.7');
INSERT INTO road_sign_translations VALUES(601,601,102,'«Վճարովի ծառայություններ»','տեղեկացնում է, որ մատուցվող ծառայությունները վճարովի են.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.8');
INSERT INTO road_sign_translations VALUES(602,602,102,'«Կայանման տևողության սահմանափակում»','տեղեկացնում է 6.4` «Կայանման տեղ» նշանով կահավորված կայանման վայրում տրանսպորտային միջոցի գտնվելու առավելագույն տևողության մասին.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.9');
INSERT INTO road_sign_translations VALUES(603,603,102,'«Ավտոմոբիլների զննման տեղ»','տեղեկացնում է, որ 6.4` «Կայանման տեղ» կամ 7.11` «Հանգստի վայր» նշանով կահավորված հրապարակում առկա է տրանսպորտային միջոցի զննման համար նախատեսված փոս կամ այլ հարմարություն.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.10');
INSERT INTO road_sign_translations VALUES(604,604,102,'«Թույլատրելի առավելագույն զանգվածի սահմանափակում»','տեղեկացնում է, որ նշանի ազդեցությունը տարածվում է միայն այն տրանսպորտային միջոցների վրա, որոնց թույլատրելի առավելագույն զանգվածը մեծ է ցուցանակի վրա նշվածից.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.11');
INSERT INTO road_sign_translations VALUES(605,605,102,'«Վտանգավոր կողնակ»','նախազգուշացնում է, որ նորոգման աշխատանքների կատարման պատճառով կողնակ մուտք գործելը վտանգավոր է: Կիրառվում է 1.25` «Ճանապարհային աշխատանքներ» նշանի հետ.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.12');
INSERT INTO road_sign_translations VALUES(606,606,102,'«Գլխավոր ճանապարհի ուղղություն»','ցույց է տալիս գլխավոր ճանապարհի ուղղությունը խաչմերուկում.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.13');
INSERT INTO road_sign_translations VALUES(607,607,102,'«Երթևեկության գոտի»','ցույց է տալիս երթևեկության այն գոտին, որի վրա տարածվում է նշանի կամ լուսացույցի ազդեցությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.14');
INSERT INTO road_sign_translations VALUES(608,608,102,'«Կույր հետիոտներ»','տեղեկացնում է, որ հետիոտնային անցումից օգտվում են կույրերը: Կիրառվում է 1.22, 5.19.1 և 5.19.2` «Հետիոտնային անցում» նշանների և լուսացույցների հետ.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.15');
INSERT INTO road_sign_translations VALUES(609,609,102,'«Խոնավ ծածկույթ»','տեղեկացնում է, որ նշանի ազդեցությունը գործում է միայն այն ժամանակահատվածում, որի ընթացքում երթևեկելի մասի ծածկույթը խոնավ է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.16');
INSERT INTO road_sign_translations VALUES(610,610,102,'«Հաշմանդամներ»','տեղեկացնում է, որ 6.4` «Կայանման տեղ» նշանի ազդեցությունը տարածվում է միայն մոտոսայլակների և այն ավտոմոբիլների վրա, որոնք կահավորված են «Հաշմանդամ» ճանաչման նշանով.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.17');
INSERT INTO road_sign_translations VALUES(611,611,102,'«Բացի հաշմանդամներից»','տեղեկացնում է, որ նշանի ազդեցությունը չի տարածվում «Հաշմանդամ» ճանաչման նշանով կահավորված մոտոսայլակների և ավտոմոբիլների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.18');
INSERT INTO road_sign_translations VALUES(612,612,102,'«Վտանգավոր բեռի դասը»','ցույց է տալիս վտանգավոր բեռների դասի (դասերի) համարն ըստ ստանդարտի։ Կիրառվում է 3.32` «Վտանգավոր բեռներով տրանսպորտային միջոցների երթևեկությունն արգելված է» և 4.8.1 - 4.8.3` «Վտանգավոր բեռներով տրանսպորտային միջոցների երթևեկության ուղղություն» նշանների հետ.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.19');
INSERT INTO road_sign_translations VALUES(613,613,102,'«Տրանսպորտային միջոցի սայլակի տեսակը»','կիրառվում են 3.12 նշանի հետ և ցույց տալիս տրանսպորտային միջոցի մոտեցված սռնիների թիվը, որոնցից յուրաքանչյուրի համար նշանի վրա նշված զանգվածը համարվում է սահմանային թույլատրելի.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.20.1');
INSERT INTO road_sign_translations VALUES(614,614,102,'«Ընդհանուր օգտագործման տրանսպորտային միջոցի տեսակը»','Կիրառվում են 6.4 նշանի հետ և ցույց տալիս մետրոյի կայարանների, ավտոբուսի (տրոլեյբուսի) կամ տրամվայի կանգառների մոտ գտնվող տրանսպորտային միջոցների կայանման համար նախատեսված հրապարակները.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.21.1');
INSERT INTO road_sign_translations VALUES(615,615,102,'«Խոչընդոտ»','կիրառվում են 4.2.1 - 4.2.3 նշանների հետ և ցույց տալիս խոչընդոտն ու այն շրջանցելու ուղղությունը: Ցուցանակները տեղադրվում են անմիջապես նշանների տակ, որոնց հետ դրանք կիրառվում են: Եթե նշանները տեղադրված են երթևեկելի մասի, կողնակի կամ մայթի վերևում, ապա 8.2.2 - 8.2.4 և 8.13 ցուցանակները կարող են տեղադրվել նշանի կողքին:','2025-05-04 00:23:31','2025-05-04 00:23:31','8.22.1');
INSERT INTO road_sign_translations VALUES(616,616,102,'«Մոտեցում երկաթուղային գծանցին»','լրացուցիչ նախազգուշացում բնակավայրերից դուրս երկաթուղային գծանցին մոտենալու մասին.',NULL,NULL,'1.4.2');
INSERT INTO road_sign_translations VALUES(617,617,102,'«Մոտեցում երկաթուղային գծանցին»','լրացուցիչ նախազգուշացում բնակավայրերից դուրս երկաթուղային գծանցին մոտենալու մասին.',NULL,NULL,'1.4.3');
INSERT INTO road_sign_translations VALUES(618,618,102,'«Մոտեցում երկաթուղային գծանցին»','լրացուցիչ նախազգուշացում բնակավայրերից դուրս երկաթուղային գծանցին մոտենալու մասին.',NULL,NULL,'1.4.4');
INSERT INTO road_sign_translations VALUES(619,619,102,'«Մոտեցում երկաթուղային գծանցին»','լրացուցիչ նախազգուշացում բնակավայրերից դուրս երկաթուղային գծանցին մոտենալու մասին.',NULL,NULL,'1.4.5');
INSERT INTO road_sign_translations VALUES(620,620,102,'«Մոտեցում երկաթուղային գծանցին»','լրացուցիչ նախազգուշացում բնակավայրերից դուրս երկաթուղային գծանցին մոտենալու մասին.',NULL,NULL,'1.4.6');
INSERT INTO road_sign_translations VALUES(621,621,102,'«Վտանգավոր շրջադարձ»','փոքր շառավղով կամ սահմանափակ տեսադաշտով ճանապարհի կորացում` 1.11.1` դեպի աջ, 1.11.2` դեպի ձախ.',NULL,NULL,'1.11.2');
INSERT INTO road_sign_translations VALUES(622,622,102,'«Վտանգավոր շրջադարձեր»','վտանգավոր շրջադարձերով ճանապարհի հատված` 1.12.1` առաջին շրջադարձը դեպի աջ, 1.12.2` առաջին շրջադարձը դեպի ձախ.',NULL,NULL,'1.12.2');
INSERT INTO road_sign_translations VALUES(623,623,102,'«Ճանապարհի նեղացում»','1.20.1` նեղացում երկու կողմից, 1.20.2` աջից, 1.20.3` ձախից.',NULL,NULL,'1.20.2');
INSERT INTO road_sign_translations VALUES(624,624,102,'«Ճանապարհի նեղացում»','1.20.1` նեղացում երկու կողմից, 1.20.2` աջից, 1.20.3` ձախից.',NULL,NULL,'1.20.3');
INSERT INTO road_sign_translations VALUES(626,625,102,'«Շրջադարձի ուղղություն»','սահմանափակ տեսանելիությամբ ճանապարհի փոքր շառավղով կորացման վրա երթևեկության ուղղություն. ճանապարհի նորոգվող հատվածի շրջանցման ուղղություն.',NULL,NULL,'1.34.2');
INSERT INTO road_sign_translations VALUES(627,626,102,'«Շրջադարձի ուղղություն»','սահմանափակ տեսանելիությամբ ճանապարհի փոքր շառավղով կորացման վրա երթևեկության ուղղություն. ճանապարհի նորոգվող հատվածի շրջանցման ուղղություն.',NULL,NULL,'1.34.1');
INSERT INTO road_sign_translations VALUES(628,627,102,'«Երկրորդական ճանապարհի հարում»','2.3.2, 2.3.4, 2.3.6` հարում աջից, 2.3.3, 2.3.5, 2.3.7` հարում ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.3');
INSERT INTO road_sign_translations VALUES(629,628,102,'«Երկրորդական ճանապարհի հարում»','2.3.2, 2.3.4, 2.3.6` հարում աջից, 2.3.3, 2.3.5, 2.3.7` հարում ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.4');
INSERT INTO road_sign_translations VALUES(631,629,102,'«Երկրորդական ճանապարհի հարում»','2.3.2, 2.3.4, 2.3.6` հարում աջից, 2.3.3, 2.3.5, 2.3.7` հարում ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.5');
INSERT INTO road_sign_translations VALUES(632,630,102,'«Երկրորդական ճանապարհի հարում»','2.3.2, 2.3.4, 2.3.6` հարում աջից, 2.3.3, 2.3.5, 2.3.7` հարում ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.6');
INSERT INTO road_sign_translations VALUES(633,631,102,'«Երկրորդական ճանապարհի հարում»','2.3.2, 2.3.4, 2.3.6` հարում աջից, 2.3.3, 2.3.5, 2.3.7` հարում ձախից.','2025-05-04 00:23:30','2025-05-04 00:23:30','2.3.7');
INSERT INTO road_sign_translations VALUES(634,632,102,'«Վտանգավոր բեռներով տրանսպորտային միջոցների երթևեկության ուղղություն»','«Վտանգավոր բեռ» ճանաչման նշաններով կահավորված տրանսպորտային միջոցների երթևեկությունը թույլատրվում է միայն նշանի վրա սլաքով ցույց տրված ուղղությամբ` 4.8.1`ուղիղ, 4.8.2` դեպի աջ, 4.8.3` դեպի ձախ.','2025-05-04 00:23:30','2025-05-04 00:23:30','4.8.2');
INSERT INTO road_sign_translations VALUES(635,633,102,'«Վտանգավոր բեռներով տրանսպորտային միջոցների երթևեկության ուղղություն»','«Վտանգավոր բեռ» ճանաչման նշաններով կահավորված տրանսպորտային միջոցների երթևեկությունը թույլատրվում է միայն նշանի վրա սլաքով ցույց տրված ուղղությամբ` 4.8.1`ուղիղ, 4.8.2` դեպի աջ, 4.8.3` դեպի ձախ.','2025-05-04 00:23:30','2025-05-04 00:23:30','4.8.3');
INSERT INTO road_sign_translations VALUES(636,634,102,'«Բնակավայրի սկիզբ»','բնակավայրի սկիզբը, որտեղ գործում են կանոնների` բնակավայրերում երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:30','2025-05-04 00:23:30','5.23.2');
INSERT INTO road_sign_translations VALUES(638,635,102,'«Բնակավայրի վերջ»','վայր, որտեղից սկսած տվյալ ճանապարհին իրենց ուժը կորցնում են կանոնների` բնակավայրերում երթևեկության կարգը սահմանող պահանջները.','2025-05-04 00:23:30','2025-05-04 00:23:30','5.24.2');
INSERT INTO road_sign_translations VALUES(639,636,102,'«Փակուղի»','միջանցիկ անցում չունեցող ճանապարհ.','2025-05-04 00:23:30','2025-05-04 00:23:30','6.8.2');
INSERT INTO road_sign_translations VALUES(641,637,102,'«Փակուղի»','միջանցիկ անցում չունեցող ճանապարհ.','2025-05-04 00:23:30','2025-05-04 00:23:30','6.8.3');
INSERT INTO road_sign_translations VALUES(642,638,102,'«Ուղղությունների նախնական ցուցիչ»','6.9.1. «Ուղղությունների նախնական ցուցիչ», 6.9.2. «Ուղղության նախնական ցուցիչ». երթևեկելու ուղղություններ դեպի նշանի վրա նշված բնակավայրերը և այլ օբյեկտներ: Այս նշանների վրա կարող են պատկերվել 6.14.1 նշանի պատկերը, ավտոմայրուղու, օդանավակայանի պատկերանշանները և այլ պատկերագրեր: 6.9.1 նշանի վրա կարող են պատկերվել երթևեկության առանձնահատկությունների մասին տեղեկացնող այլ նշանների պատկերներ: 6.9.1 նշանի ներքևի մասում նշվում է նշանի տեղադրման վայրից մինչև խաչմերուկ կամ արգելակման գոտու սկիզբ եղած հեռավորությունը: 6.9.1 նշանը կիրառվում է նաև 3.11 - 3.15 արգելող նշաններից որևէ մեկով կահավորված ճանապարհի հատվածի շրջանցման ուղղության մասին տեղեկություն տալու համար.','2025-05-04 00:23:30','2025-05-04 00:23:30','6.9.2');
INSERT INTO road_sign_translations VALUES(643,639,102,'«Ելք դեպի միակողմ երթևեկությամբ ճանապարհ»','ելք դեպի միակողմ երթևեկությամբ ճանապարհ կամ երթևեկելի մաս.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.7.2');
INSERT INTO road_sign_translations VALUES(644,640,102,'«Ելք դեպի ընդհանուր օգտագործման տրանսպորտային միջոցների համար գոտիով ճանապարհ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','5.13.2');
INSERT INTO road_sign_translations VALUES(645,641,102,'«Հետիոտնային անցում»','անցման վայրում 1.14.1 - 1.14.2 գծանշումների բացակայության դեպքում 5.19.1 նշանը տեղադրվում է ճանապարհից ձախ, անցման հեռավոր, իսկ 5.19.2 նշանը` ճանապարհից աջ, անցման մոտակա սահմանի մոտ.','2025-05-04 00:23:31','2025-05-04 00:23:31','5.19.2');
INSERT INTO road_sign_translations VALUES(648,642,102,'«Ուղղությունների ցուցիչ»','6.10.1. «Ուղղությունների ցուցիչ», 6.10.2. «Ուղղության ցուցիչ». դեպի երթուղու կետերը երթևեկելու ուղղություններ: Նշանների վրա կարող են նշվել մինչև այդ օբյեկտները եղած հեռավորությունները (կմ), պատկերվել ավտոմայրուղու, օդանավակայանի պատկերանշաններ և այլ պատկերագրեր.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.10.2');
INSERT INTO road_sign_translations VALUES(649,643,102,'«Երթուղու համարը»','6.14.1` ճանապարհին (երթուղուն) հատկացված համարը, 6.14.2` ճանապարհի (երթուղու) համարը և ուղղությունը.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.14.2');
INSERT INTO road_sign_translations VALUES(650,644,102,'«Երթևեկության ուղղություն բեռնատար ավտոմոբիլների համար»','բեռնատար ավտոմոբիլների, տրակտորների և ինքնագնաց մեքենաների համար առաջարկվող երթևեկության ուղղությունը, եթե խաչմերուկում դրանց երթևեկությունը որևէ ուղղությամբ արգելված է.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.15.2');
INSERT INTO road_sign_translations VALUES(652,645,102,'«Երթևեկության ուղղություն բեռնատար ավտոմոբիլների համար»','բեռնատար ավտոմոբիլների, տրակտորների և ինքնագնաց մեքենաների համար առաջարկվող երթևեկության ուղղությունը, եթե խաչմերուկում դրանց երթևեկությունը որևէ ուղղությամբ արգելված է.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.15.3');
INSERT INTO road_sign_translations VALUES(653,646,102,'«Շրջանցման ուղղություն»','երթևեկության համար ժամանակավոր փակ ճանապարհի հատվածի շրջանցման ուղղություն.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.18.2');
INSERT INTO road_sign_translations VALUES(654,647,102,'«Շրջանցման ուղղություն»','երթևեկության համար ժամանակավոր փակ ճանապարհի հատվածի շրջանցման ուղղություն.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.18.3');
INSERT INTO road_sign_translations VALUES(655,648,102,'«Այլ երթևեկելի մաս վերադասավորվելու նախնական ցուցիչ»','բաժանարար գոտիով ճանապարհի երթևեկելի մասի երթևեկության համար փակ հատվածի շրջանցման կամ աջակողմյան երթևեկելի մաս վերադառնալու համար երթևեկության ուղղություն:','2025-05-04 00:23:31','2025-05-04 00:23:31','6.19.2');
INSERT INTO road_sign_translations VALUES(656,649,102,'«Վթարային ելք»','թունելում ցույց է տալիս այն տեղը, որտեղ գտնվում է վթարային ելքը.','2025-05-04 00:23:31','2025-05-04 00:23:31','6.20.2');
INSERT INTO road_sign_translations VALUES(657,650,102,'«Հեռավորություն մինչև օբյեկտ»','ցույց է տալիս հեռավորությունը մինչև ճանապարհից դուրս գտնվող օբյեկտ.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.1.4');
INSERT INTO road_sign_translations VALUES(658,651,102,'«Ազդման գոտի»','ցուցանակները ցույց են տալիս և (կամ) տեղեկացնում են` 1) 8.2.2` 3.27` «Կանգառն արգելված է», 3.28` «Կայանելն արգելված է», 3.29` «Կայանելն արգելված է ամսվա կենտ օրերին», 3.30` «Կայանելն արգելված է ամսվա զույգ օրերին» արգելող նշանների ազդման գոտին. 2) 8.2.3` 3.27 - 3.30 նշանների ազդման գոտու վերջը. 3) 8.2.4` 3.27 - 3.30 նշանների ազդման գոտում գտնվելու մասին. 4) 8.2.5, 7.2.6` 3.27 - 3.30 նշանների ազդման ուղղությունը և գոտին, հրապարակի, շենքի ճակատի և այլ տեղերի` մի կողմի երկայնքով կանգառի կամ կայանման արգելման դեպքում.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.2.3');
INSERT INTO road_sign_translations VALUES(659,652,102,'«Ազդման գոտի»','ցուցանակները ցույց են տալիս և (կամ) տեղեկացնում են` 1) 8.2.2` 3.27` «Կանգառն արգելված է», 3.28` «Կայանելն արգելված է», 3.29` «Կայանելն արգելված է ամսվա կենտ օրերին», 3.30` «Կայանելն արգելված է ամսվա զույգ օրերին» արգելող նշանների ազդման գոտին. 2) 8.2.3` 3.27 - 3.30 նշանների ազդման գոտու վերջը. 3) 8.2.4` 3.27 - 3.30 նշանների ազդման գոտում գտնվելու մասին. 4) 8.2.5, 7.2.6` 3.27 - 3.30 նշանների ազդման ուղղությունը և գոտին, հրապարակի, շենքի ճակատի և այլ տեղերի` մի կողմի երկայնքով կանգառի կամ կայանման արգելման դեպքում.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.2.4');
INSERT INTO road_sign_translations VALUES(660,653,102,'«Ազդման գոտի»','ցուցանակները ցույց են տալիս և (կամ) տեղեկացնում են` 1) 8.2.2` 3.27` «Կանգառն արգելված է», 3.28` «Կայանելն արգելված է», 3.29` «Կայանելն արգելված է ամսվա կենտ օրերին», 3.30` «Կայանելն արգելված է ամսվա զույգ օրերին» արգելող նշանների ազդման գոտին. 2) 8.2.3` 3.27 - 3.30 նշանների ազդման գոտու վերջը. 3) 8.2.4` 3.27 - 3.30 նշանների ազդման գոտում գտնվելու մասին. 4) 8.2.5, 7.2.6` 3.27 - 3.30 նշանների ազդման ուղղությունը և գոտին, հրապարակի, շենքի ճակատի և այլ տեղերի` մի կողմի երկայնքով կանգառի կամ կայանման արգելման դեպքում.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.2.5');
INSERT INTO road_sign_translations VALUES(661,654,102,'«Ազդման գոտի»','ցուցանակները ցույց են տալիս և (կամ) տեղեկացնում են` 1) 8.2.2` 3.27` «Կանգառն արգելված է», 3.28` «Կայանելն արգելված է», 3.29` «Կայանելն արգելված է ամսվա կենտ օրերին», 3.30` «Կայանելն արգելված է ամսվա զույգ օրերին» արգելող նշանների ազդման գոտին. 2) 8.2.3` 3.27 - 3.30 նշանների ազդման գոտու վերջը. 3) 8.2.4` 3.27 - 3.30 նշանների ազդման գոտում գտնվելու մասին. 4) 8.2.5, 7.2.6` 3.27 - 3.30 նշանների ազդման ուղղությունը և գոտին, հրապարակի, շենքի ճակատի և այլ տեղերի` մի կողմի երկայնքով կանգառի կամ կայանման արգելման դեպքում.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.2.6');
INSERT INTO road_sign_translations VALUES(662,655,102,'«Ազդման ուղղություններ»','ցույց են տալիս խաչմերուկից առաջ տեղադրված նշանների ազդման ուղղությունները կամ երթևեկության ուղղությունները` դեպի անմիջապես ճանապարհին մոտ գտնվող օբյեկտները.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.3.2');
INSERT INTO road_sign_translations VALUES(663,656,102,'«Ազդման ուղղություններ»','ցույց են տալիս խաչմերուկից առաջ տեղադրված նշանների ազդման ուղղությունները կամ երթևեկության ուղղությունները` դեպի անմիջապես ճանապարհին մոտ գտնվող օբյեկտները.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.3.3');
INSERT INTO road_sign_translations VALUES(664,657,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.2');
INSERT INTO road_sign_translations VALUES(665,658,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.3');
INSERT INTO road_sign_translations VALUES(666,659,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.4');
INSERT INTO road_sign_translations VALUES(667,660,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.5');
INSERT INTO road_sign_translations VALUES(669,661,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.6');
INSERT INTO road_sign_translations VALUES(670,662,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.7');
INSERT INTO road_sign_translations VALUES(671,663,102,'«Տրանսպորտային միջոցի տեսակ»','ցույց է տալիս այն տրանսպորտային միջոցի տեսակը, որի վրա տարածվում է նշանի ազդեցությունը: Այս ցուցանակների հետ կիրառվող նշանների ազդեցությունը տարածվում է` 1) 8.4.1` 3.5 տոննայից ավելի թույլատրելի առավելագույն զանգված ունեցող բեռնատար, այդ թվում նաև՝ կցորդով շահագործվող ավտոմոբիլների վրա, 2) 8.4.3` թեթև մարդատար, ինչպես նաև մինչև 3,5 տոննա թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլների վրա, 3) 8.4.8` «Վտանգավոր բեռ» ճանաչման նշանով կահավորված տրանսպորտային միջոցների վրա.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.4.8');
INSERT INTO road_sign_translations VALUES(673,664,102,'«Շաբաթ, կիրակի և տոն օրեր»','8.5.1. «Շաբաթ, կիրակի և տոն օրեր», 8.5.2. «Աշխատանքային օրեր», 8.5.3. «Շաբաթվա օրեր». ցուցանակները տեղեկացնում են շաբաթվա այն օրերի մասին, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.2');
INSERT INTO road_sign_translations VALUES(674,665,102,'«Շաբաթ, կիրակի և տոն օրեր»','8.5.1. «Շաբաթ, կիրակի և տոն օրեր», 8.5.2. «Աշխատանքային օրեր», 8.5.3. «Շաբաթվա օրեր». ցուցանակները տեղեկացնում են շաբաթվա այն օրերի մասին, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.3');
INSERT INTO road_sign_translations VALUES(675,666,102,'«Գործողության ժամանակ»','8.5.4, 8.5.5 - 8.5.7. «Գործողության ժամանակ». 8.5.4 ցուցանակը տեղեկացնում է օրվա այն ժամերը, իսկ 8.5.5 - 8.5.7 ցուցանակները` նաև շաբաթվա այն օրերը, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.5');
INSERT INTO road_sign_translations VALUES(676,667,102,'«Գործողության ժամանակ»','8.5.4, 8.5.5 - 8.5.7. «Գործողության ժամանակ». 8.5.4 ցուցանակը տեղեկացնում է օրվա այն ժամերը, իսկ 8.5.5 - 8.5.7 ցուցանակները` նաև շաբաթվա այն օրերը, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.6');
INSERT INTO road_sign_translations VALUES(677,668,102,'«Գործողության ժամանակ»','8.5.4, 8.5.5 - 8.5.7. «Գործողության ժամանակ». 8.5.4 ցուցանակը տեղեկացնում է օրվա այն ժամերը, իսկ 8.5.5 - 8.5.7 ցուցանակները` նաև շաբաթվա այն օրերը, որոնց ընթացքում նշանը գործում է.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.5.7');
INSERT INTO road_sign_translations VALUES(678,669,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.2');
INSERT INTO road_sign_translations VALUES(679,670,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.3');
INSERT INTO road_sign_translations VALUES(680,671,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.4');
INSERT INTO road_sign_translations VALUES(682,672,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.5');
INSERT INTO road_sign_translations VALUES(683,673,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.6');
INSERT INTO road_sign_translations VALUES(684,674,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.7');
INSERT INTO road_sign_translations VALUES(685,675,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.8');
INSERT INTO road_sign_translations VALUES(686,676,102,'«Տրանսպորտային միջոցի կանգնեցման ձևը կայանման տեղերում»','ցույց են տալիս տրանսպորտային միջոցների կանգնեցման ձևերը` 1) 8.6.1` երթևեկելի մասի վրա, մայթի երկարությամբ` բոլոր տրանսպորտային միջոցների համար, 2) 8.6.2 - 8.6.9` մայթամերձ կայանման տեղում` թեթև մարդատար ավտոմոբիլների և մոտոցիկլների համար.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.6.9');
INSERT INTO road_sign_translations VALUES(687,677,102,'«Տրանսպորտային միջոցի սայլակի տեսակը»','կիրառվում են 3.12 նշանի հետ և ցույց տալիս տրանսպորտային միջոցի մոտեցված սռնիների թիվը, որոնցից յուրաքանչյուրի համար նշանի վրա նշված զանգվածը համարվում է սահմանային թույլատրելի.','2025-05-04 00:23:31','2025-05-04 00:23:31','8.20.2');
INSERT INTO road_sign_translations VALUES(688,678,102,'«Խոչընդոտ»','կիրառվում են 4.2.1 - 4.2.3 նշանների հետ և ցույց տալիս խոչընդոտն ու այն շրջանցելու ուղղությունը: Ցուցանակները տեղադրվում են անմիջապես նշանների տակ, որոնց հետ դրանք կիրառվում են: Եթե նշանները տեղադրված են երթևեկելի մասի, կողնակի կամ մայթի վերևում, ապա 8.2.2 - 8.2.4 և 8.13 ցուցանակները կարող են տեղադրվել նշանի կողքին:','2025-05-04 00:23:31','2025-05-04 00:23:31','8.22.2');
INSERT INTO road_sign_translations VALUES(689,679,102,'«Խոչընդոտ»','կիրառվում են 4.2.1 - 4.2.3 նշանների հետ և ցույց տալիս խոչընդոտն ու այն շրջանցելու ուղղությունը: Ցուցանակները տեղադրվում են անմիջապես նշանների տակ, որոնց հետ դրանք կիրառվում են: Եթե նշանները տեղադրված են երթևեկելի մասի, կողնակի կամ մայթի վերևում, ապա 8.2.2 - 8.2.4 և 8.13 ցուցանակները կարող են տեղադրվել նշանի կողքին:','2025-05-04 00:23:31','2025-05-04 00:23:31','8.22.3');
INSERT INTO road_sign_translations VALUES(690,680,102,'«Ավտոգնացք»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(691,681,102,'«Արագության սահմանափակում»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(692,682,102,'«Դանդաղընթաց տրանսպորտային միջոց»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(693,683,102,'«Երեխաների փոխադրում»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(694,684,102,'«Բութակներ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(695,685,102,'«Երկարաչափ տրանսպորտային միջոց»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(696,686,102,'«Խուլ վարորդ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(697,687,102,'«Մեծ եզրաչափերով բեռ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(698,688,102,'«Վտանգավոր բեռ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(699,689,102,'«Ուսումնական տրանսպորտային միջոց»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(700,690,102,'«Բժիշկ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(701,691,102,'«Հաշմանդամ»','','2025-05-04 00:23:31','2025-05-04 00:23:31','');
INSERT INTO road_sign_translations VALUES(702,411,100,'1.1','"Railway crossing with ticket".','2025-11-06 21:13:50','2025-11-06 21:13:50','1.1');
INSERT INTO road_sign_translations VALUES(703,411,101,'1.1','«Железнодорожный переезд с билетом».','2025-11-06 21:13:50','2025-11-06 21:13:50','1.1');
INSERT INTO road_sign_translations VALUES(704,412,100,'1.2','"Railway crossing without ticket".','2025-11-06 21:13:51','2025-11-06 21:13:51','1.2');
INSERT INTO road_sign_translations VALUES(705,412,101,'1.2','«Железнодорожный переезд без билета».','2025-11-06 21:13:51','2025-11-06 21:13:51','1.2');
INSERT INTO road_sign_translations VALUES(706,413,100,'1.3.1','"One-line railway", marking of a railway line not equipped with a ticket, with one track.','2025-11-06 21:13:52','2025-11-06 21:13:52','1.3.1');
INSERT INTO road_sign_translations VALUES(707,413,101,'1.3.1','«Однопутная железная дорога», обозначение железнодорожной линии, не оборудованной билетом, с одним путем.','2025-11-06 21:13:52','2025-11-06 21:13:52','1.3.1');
INSERT INTO road_sign_translations VALUES(708,414,100,'1.3.2','"Multi-line railway", designation of an unequipped railway line with two or more tracks;','2025-11-06 21:13:54','2025-11-06 21:13:54','1.3.2');
INSERT INTO road_sign_translations VALUES(709,414,101,'1.3.2','«Многопутная железная дорога» — обозначение необорудованной железнодорожной линии с двумя и более путями;','2025-11-06 21:13:54','2025-11-06 21:13:54','1.3.2');
INSERT INTO road_sign_translations VALUES(710,415,100,'1.4.1','"Approach to the railway line". additional warning about approaching the railway line outside the settlements;','2025-11-06 21:13:55','2025-11-06 21:13:55','1.4.1');
INSERT INTO road_sign_translations VALUES(711,415,101,'1.4.1','«Подход к железнодорожной линии». дополнительное предупреждение о приближении к железнодорожной линии за пределами населенных пунктов;','2025-11-06 21:13:55','2025-11-06 21:13:55','1.4.1');
INSERT INTO road_sign_translations VALUES(712,416,100,'1.5','"Intersection with the tram line".','2025-11-06 21:13:56','2025-11-06 21:13:56','1.5');
INSERT INTO road_sign_translations VALUES(713,416,101,'1.5','«Пересечение с трамвайной линией».','2025-11-06 21:13:56','2025-11-06 21:13:56','1.5');
INSERT INTO road_sign_translations VALUES(714,417,100,'1.6','"Crossing equal roads".','2025-11-06 21:13:58','2025-11-06 21:13:58','1.6');
INSERT INTO road_sign_translations VALUES(715,417,101,'1.6','«Пересекаясь равными дорогами».','2025-11-06 21:13:58','2025-11-06 21:13:58','1.6');
INSERT INTO road_sign_translations VALUES(716,418,100,'1.7','"Intersection with roundabout".','2025-11-06 21:13:59','2025-11-06 21:13:59','1.7');
INSERT INTO road_sign_translations VALUES(717,418,101,'1.7','«Перекресток с круговым движением».','2025-11-06 21:13:59','2025-11-06 21:13:59','1.7');
INSERT INTO road_sign_translations VALUES(718,419,100,'1.8',unistr('"Photographic adjustment". intersection, crosswalk or road\u000d\u000a              area where traffic is controlled by a traffic light;'),'2025-11-06 21:14:00','2025-11-06 21:14:00','1.8');
INSERT INTO road_sign_translations VALUES(719,419,101,'1.8',unistr('«Фотокорректировка». перекресток, пешеходный переход или дорога\u000d\u000a              зона, где движение регулируется светофором;'),'2025-11-06 21:14:00','2025-11-06 21:14:00','1.8');
INSERT INTO road_sign_translations VALUES(720,420,100,'1.9','"Opening Bridge". opening bridge or ferry crossing.','2025-11-06 21:14:01','2025-11-06 21:14:01','1.9');
INSERT INTO road_sign_translations VALUES(721,420,101,'1.9','«Открывающийся мост». открытие моста или паромной переправы.','2025-11-06 21:14:01','2025-11-06 21:14:01','1.9');
INSERT INTO road_sign_translations VALUES(722,421,100,'1.10','"Exit to the coast". shore or landing place.','2025-11-06 21:14:02','2025-11-06 21:14:02','1.10');
INSERT INTO road_sign_translations VALUES(723,421,101,'1.10','«Выход на берег». берег или место приземления.','2025-11-06 21:14:02','2025-11-06 21:14:02','1.10');
INSERT INTO road_sign_translations VALUES(724,422,100,'1.11.1',unistr('"Dangerous turn". with a small radius or limited field of view\u000d\u000a              road curvature: 1.11.1 - to the right, 1.11.2 - to the left.'),'2025-11-06 21:14:03','2025-11-06 21:14:03','1.11.1');
INSERT INTO road_sign_translations VALUES(725,422,101,'1.11.1',unistr('«Опасный поворот». с небольшим радиусом или ограниченным полем зрения\u000d\u000a              кривизна дороги: 1.11.1 – вправо, 1.11.2 – влево.'),'2025-11-06 21:14:03','2025-11-06 21:14:03','1.11.1');
INSERT INTO road_sign_translations VALUES(726,423,100,'1.12.1',unistr('"Dangerous turns". on a road with dangerous twists and turns\u000d\u000a              section: 1.12.1: first turn to the right, 1.12.2: first turn to the left;'),'2025-11-06 21:14:05','2025-11-06 21:14:05','1.12.1');
INSERT INTO road_sign_translations VALUES(727,423,101,'1.12.1',unistr('«Опасные повороты». на дороге с опасными поворотами\u000d\u000a              раздел: 1.12.1: первый поворот направо, 1.12.2: первый поворот налево;'),'2025-11-06 21:14:05','2025-11-06 21:14:05','1.12.1');
INSERT INTO road_sign_translations VALUES(728,424,100,'1.13','"A sharp descent".','2025-11-06 21:14:05','2025-11-06 21:14:05','1.13');
INSERT INTO road_sign_translations VALUES(729,424,101,'1.13','«Резкий спуск».','2025-11-06 21:14:05','2025-11-06 21:14:05','1.13');
INSERT INTO road_sign_translations VALUES(730,425,100,'1.14','"A sharp rise".','2025-11-06 21:14:06','2025-11-06 21:14:06','1.14');
INSERT INTO road_sign_translations VALUES(731,425,101,'1.14','«Резкий подъем».','2025-11-06 21:14:06','2025-11-06 21:14:06','1.14');
INSERT INTO road_sign_translations VALUES(732,426,100,'1.15','"Slippery road". section of the road with the most slippery road.','2025-11-06 21:14:08','2025-11-06 21:14:08','1.15');
INSERT INTO road_sign_translations VALUES(733,426,101,'1.15','«Скользкая дорога». участок дороги с самой скользкой дорогой.','2025-11-06 21:14:08','2025-11-06 21:14:08','1.15');
INSERT INTO road_sign_translations VALUES(734,427,100,'1.16',unistr('"Uneven road". a section of the road with unevenness in the carriageway\u000d\u000a              (corrugation, ditches, uneven bridges, etc.).'),'2025-11-06 21:14:09','2025-11-06 21:14:09','1.16');
INSERT INTO road_sign_translations VALUES(735,427,101,'1.16',unistr('«Неровная дорога». участок дороги с неровностями проезжей части\u000d\u000a              (гофры, канавы, неровные мосты и т.п.).'),'2025-11-06 21:14:09','2025-11-06 21:14:09','1.16');
INSERT INTO road_sign_translations VALUES(736,428,100,'1.17',unistr('"Artificial unevenness". to force down speed\u000d\u000a              a section of the road with artificial unevenness (unevennesses).'),'2025-11-06 21:14:10','2025-11-06 21:14:10','1.17');
INSERT INTO road_sign_translations VALUES(737,428,101,'1.17',unistr('«Искусственная неровность». сбить скорость\u000d\u000a              участок дороги с искусственными неровностями (неровностями).'),'2025-11-06 21:14:10','2025-11-06 21:14:10','1.17');
INSERT INTO road_sign_translations VALUES(738,429,100,'1.18',unistr('"Cream emission". section of the road where the wheels of vehicles\u000d\u000a              from below it is possible to release gravel, stones, etc.'),'2025-11-06 21:14:12','2025-11-06 21:14:12','1.18');
INSERT INTO road_sign_translations VALUES(739,429,101,'1.18',unistr('«Кремовая эмиссия». участок дороги, где колеса транспортных средств\u000d\u000a              снизу можно выпустить гравий, камни и т.п.'),'2025-11-06 21:14:12','2025-11-06 21:14:12','1.18');
INSERT INTO road_sign_translations VALUES(740,430,100,'1.19','"Dangerous bed". a section of the road where it is dangerous to pull over.','2025-11-06 21:14:13','2025-11-06 21:14:13','1.19');
INSERT INTO road_sign_translations VALUES(741,430,101,'1.19','«Опасная кровать». участок дороги, на котором опасно останавливаться.','2025-11-06 21:14:13','2025-11-06 21:14:13','1.19');
INSERT INTO road_sign_translations VALUES(742,431,100,'1.20.1',unistr('"Narrowing of the road". 1.20.1: narrowing on both sides, 1.20.2:\u000d\u000a              from the right, 1.20.3 from the left.'),'2025-11-06 21:14:15','2025-11-06 21:14:15','1.20.1');
INSERT INTO road_sign_translations VALUES(743,431,101,'1.20.1',unistr('«Сужение дороги». 1.20.1: сужение с обеих сторон, 1.20.2:\u000d\u000a              справа, 1.20.3 слева.'),'2025-11-06 21:14:15','2025-11-06 21:14:15','1.20.1');
INSERT INTO road_sign_translations VALUES(744,432,100,'1.21',unistr('"Two way traffic". opposite the road (carriageway).\u000d\u000a              the beginning of the traffic section.'),'2025-11-06 21:14:16','2025-11-06 21:14:16','1.21');
INSERT INTO road_sign_translations VALUES(745,432,101,'1.21',unistr('«Двустороннее движение». напротив дороги (проезжей части).\u000d\u000a              начало дорожного участка.'),'2025-11-06 21:14:16','2025-11-06 21:14:16','1.21');
INSERT INTO road_sign_translations VALUES(746,433,100,'1.22','"Pedestrian crossing".','2025-11-06 21:14:17','2025-11-06 21:14:17','1.22');
INSERT INTO road_sign_translations VALUES(747,433,101,'1.22','"Пешеходный переход".','2025-11-06 21:14:17','2025-11-06 21:14:17','1.22');
INSERT INTO road_sign_translations VALUES(748,434,100,'1.23',unistr('"Children". near children''s institutions (schools, kindergartens, etc.).\u000d\u000a              section of the passing road, where children may appear on the carriageway;'),'2025-11-06 21:14:18','2025-11-06 21:14:18','1.23');
INSERT INTO road_sign_translations VALUES(749,434,101,'1.23',unistr('"Дети". Рядом детские учреждения (школы, детские сады и т.п.).\u000d\u000a              участок проезжей части дороги, где на проезжей части могут появиться дети;'),'2025-11-06 21:14:18','2025-11-06 21:14:18','1.23');
INSERT INTO road_sign_translations VALUES(750,435,100,'1.24','"Intersection with the bicycle path".','2025-11-06 21:14:20','2025-11-06 21:14:20','1.24');
INSERT INTO road_sign_translations VALUES(751,435,101,'1.24','«Пересечение с велосипедной дорожкой».','2025-11-06 21:14:20','2025-11-06 21:14:20','1.24');
INSERT INTO road_sign_translations VALUES(752,436,100,'1.25','"Road works".','2025-11-06 21:14:21','2025-11-06 21:14:21','1.25');
INSERT INTO road_sign_translations VALUES(753,436,101,'1.25','«Дорожные работы».','2025-11-06 21:14:21','2025-11-06 21:14:21','1.25');
INSERT INTO road_sign_translations VALUES(754,437,100,'1.26','"Cattle driving".','2025-11-06 21:14:22','2025-11-06 21:14:22','1.26');
INSERT INTO road_sign_translations VALUES(755,437,101,'1.26','«Перегон скота».','2025-11-06 21:14:22','2025-11-06 21:14:22','1.26');
INSERT INTO road_sign_translations VALUES(756,438,100,'1.27','"Wild animals".','2025-11-06 21:14:24','2025-11-06 21:14:24','1.27');
INSERT INTO road_sign_translations VALUES(757,438,101,'1.27','«Дикие животные».','2025-11-06 21:14:24','2025-11-06 21:14:24','1.27');
INSERT INTO road_sign_translations VALUES(758,439,100,'1.28',unistr('"Fall of stones". section of the road where collapses, landslides are possible,\u000d\u000a              fall of stones.'),'2025-11-06 21:14:25','2025-11-06 21:14:25','1.28');
INSERT INTO road_sign_translations VALUES(759,439,101,'1.28',unistr('«Падение камней». участок дороги, где возможны обвалы, оползни,\u000d\u000a              падение камней.'),'2025-11-06 21:14:25','2025-11-06 21:14:25','1.28');
INSERT INTO road_sign_translations VALUES(760,440,100,'1.29','"Side wind".','2025-11-06 21:14:26','2025-11-06 21:14:26','1.29');
INSERT INTO road_sign_translations VALUES(761,440,101,'1.29','«Боковой ветер».','2025-11-06 21:14:26','2025-11-06 21:14:26','1.29');
INSERT INTO road_sign_translations VALUES(762,441,100,'1.30','"Low-flying planes".','2025-11-06 21:14:28','2025-11-06 21:14:28','1.30');
INSERT INTO road_sign_translations VALUES(763,441,101,'1.30','«Низколетящие самолеты».','2025-11-06 21:14:28','2025-11-06 21:14:28','1.30');
INSERT INTO road_sign_translations VALUES(764,442,100,'1.31',unistr('"Tunnel". a tunnel without artificial lighting, or\u000d\u000a              a tunnel with limited front entrance visibility.'),'2025-11-06 21:14:29','2025-11-06 21:14:29','1.31');
INSERT INTO road_sign_translations VALUES(765,442,101,'1.31',unistr('«Туннель». туннель без искусственного освещения или\u000d\u000a              туннель с ограниченной видимостью перед входом.'),'2025-11-06 21:14:29','2025-11-06 21:14:29','1.31');
INSERT INTO road_sign_translations VALUES(766,443,100,'1.32','"Congestion". a section of the road where a traffic jam has occurred.','2025-11-06 21:14:30','2025-11-06 21:14:30','1.32');
INSERT INTO road_sign_translations VALUES(767,443,101,'1.32','"Скопление". участок дороги, на котором образовалась пробка.','2025-11-06 21:14:30','2025-11-06 21:14:30','1.32');
INSERT INTO road_sign_translations VALUES(768,444,100,'1.33',unistr('"Other dangers". section of road where there are listed warning signs\u000d\u000a              hazards not foreseen by signs.'),'2025-11-06 21:14:31','2025-11-06 21:14:31','1.33');
INSERT INTO road_sign_translations VALUES(769,444,101,'1.33',unistr('«Другие опасности». участок дороги, на котором имеются предупреждающие знаки\u000d\u000a              опасности, не предусмотренные знаками.'),'2025-11-06 21:14:31','2025-11-06 21:14:31','1.33');
INSERT INTO road_sign_translations VALUES(770,446,100,'1.34.3',unistr('"Turn direction". At a T-intersection or on a fork in the road\u000d\u000a              traffic directions. directions for bypassing the part of the road under repair.'),'2025-11-06 21:14:33','2025-11-06 21:14:33','1.34.3');
INSERT INTO road_sign_translations VALUES(771,446,101,'1.34.3',unistr('«Направление поворота». На Т-образном перекрестке или на развилке дороги\u000d\u000a              направления движения. направления объезда ремонтируемого участка дороги.'),'2025-11-06 21:14:33','2025-11-06 21:14:33','1.34.3');
INSERT INTO road_sign_translations VALUES(772,447,100,'2.1',unistr('"Main road". a road on which commuters are unregulated\u000d\u000a              the advantage of crossing intersections is given.'),'2025-11-06 21:14:34','2025-11-06 21:14:34','2.1');
INSERT INTO road_sign_translations VALUES(773,447,101,'2.1',unistr('«Главная дорога». дорога, на которой пассажиры не регулируются\u000d\u000a              дается преимущество пересечения перекрестков.'),'2025-11-06 21:14:34','2025-11-06 21:14:34','2.1');
INSERT INTO road_sign_translations VALUES(774,448,100,'2.2','"End of the main road".','2025-11-06 21:14:35','2025-11-06 21:14:35','2.2');
INSERT INTO road_sign_translations VALUES(775,448,101,'2.2','«Конец главной дороги».','2025-11-06 21:14:35','2025-11-06 21:14:35','2.2');
INSERT INTO road_sign_translations VALUES(776,449,100,'2.3.1','"Intersection with secondary road".','2025-11-06 21:14:36','2025-11-06 21:14:36','2.3.1');
INSERT INTO road_sign_translations VALUES(777,449,101,'2.3.1','«Пересечение со второстепенной дорогой».','2025-11-06 21:14:36','2025-11-06 21:14:36','2.3.1');
INSERT INTO road_sign_translations VALUES(778,450,100,'2.3.2',unistr('"Next to the secondary road". 2.3.2, 2.3.4, 2.3.6: adjacent\u000d\u000a              from the right, 2.3.3, 2.3.5, 2.3.7 - adjacent from the left.'),'2025-11-06 21:14:37','2025-11-06 21:14:37','2.3.2');
INSERT INTO road_sign_translations VALUES(779,450,101,'2.3.2',unistr('«Рядом с второстепенной дорогой». 2.3.2, 2.3.4, 2.3.6: соседние\u000d\u000a              справа, 2.3.3, 2.3.5, 2.3.7 - примыкающие слева.'),'2025-11-06 21:14:37','2025-11-06 21:14:37','2.3.2');
INSERT INTO road_sign_translations VALUES(780,451,100,'2.4',unistr('"Give way." the driver must yield to the crosswalk, and\u000d\u000a              8.13: if there is a "Direction of the main road" sign, main\u000d\u000a              vehicles traveling on the road.'),'2025-11-06 21:14:41','2025-11-06 21:14:41','2.4');
INSERT INTO road_sign_translations VALUES(781,451,101,'2.4',unistr('"Уступи дорогу." водитель должен уступить дорогу пешеходному переходу, и\u000d\u000a              8.13: при наличии знака «Направление главной дороги» главная\u000d\u000a              транспортные средства, едущие по дороге.'),'2025-11-06 21:14:41','2025-11-06 21:14:41','2.4');
INSERT INTO road_sign_translations VALUES(782,452,100,'2.5',unistr('"Traffic without stopping is prohibited." it is forbidden to drive without\u000d\u000a              Before the "Stop" line (in its absence, before the edge of the crossing lane)\u000d\u000a              to stand The driver must give way to the road crossing, and 8.13 "Main\u000d\u000a              in the presence of the "direction of the road" sign, traveling along the main road\u000d\u000a              vehicles. If the 2.5 sign is placed from the railway line or\u000d\u000a              before the quarantine checkpoint, then the driver must stop before the "Stop" line, and that\u000d\u000a              in case of absence, before the sign.'),'2025-11-06 21:14:42','2025-11-06 21:14:42','2.5');
INSERT INTO road_sign_translations VALUES(783,452,101,'2.5',unistr('«Движение без остановок запрещено». запрещено ездить без\u000d\u000a              До линии «Стоп» (при ее отсутствии – до края полосы пересечения)\u000d\u000a              стоять Водитель обязан уступить дорогу переходу дороги, а 8.13 "Главное\u000d\u000a              при наличии знака «направление дороги» движение по главной дороге\u000d\u000a              транспортные средства. Если знак 2,5 установлен со стороны железнодорожной линии или\u000d\u000a              до карантинного пункта пропуска, то водитель должен остановиться перед линией «Стоп», и это\u000d\u000a              в случае отсутствия – перед знаком.'),'2025-11-06 21:14:42','2025-11-06 21:14:42','2.5');
INSERT INTO road_sign_translations VALUES(784,453,100,'2.6',unistr('"Oncoming traffic advantage". access is denied\u000d\u000a              a narrow stretch of road if it could make oncoming traffic difficult. The driver\u000d\u000a              must give way to vehicles approaching the narrow section from the opposite side\u000d\u000a              funds.'),'2025-11-06 21:14:43','2025-11-06 21:14:43','2.6');
INSERT INTO road_sign_translations VALUES(785,453,101,'2.6',unistr('«Преимущество встречного движения». доступ запрещен\u000d\u000a              узкий участок дороги, если это может затруднить встречное движение. Водитель\u000d\u000a              должен уступить дорогу транспортным средствам, приближающимся к узкому участку с противоположной стороны\u000d\u000a              средства.'),'2025-11-06 21:14:43','2025-11-06 21:14:43','2.6');
INSERT INTO road_sign_translations VALUES(786,454,100,'2.7',unistr('"Advantage over oncoming traffic". narrow road\u000d\u000a              while driving, the driver has an advantage over the oncoming vehicles\u000d\u000a              towards.'),'2025-11-06 21:14:44','2025-11-06 21:14:44','2.7');
INSERT INTO road_sign_translations VALUES(787,454,101,'2.7',unistr('«Преимущество перед встречным транспортом». узкая дорога\u000d\u000a              во время движения водитель имеет преимущество перед встречными транспортными средствами\u000d\u000a              навстречу.'),'2025-11-06 21:14:44','2025-11-06 21:14:44','2.7');
INSERT INTO road_sign_translations VALUES(788,455,100,'3.1',unistr('"Entry is prohibited". the entry of vehicles is prohibited\u000d\u000a              direction.'),'2025-11-06 21:14:46','2025-11-06 21:14:46','3.1');
INSERT INTO road_sign_translations VALUES(789,455,101,'3.1',unistr('«Вход запрещен». въезд транспортных средств запрещен\u000d\u000a              направление.'),'2025-11-06 21:14:46','2025-11-06 21:14:46','3.1');
INSERT INTO road_sign_translations VALUES(790,456,100,'3.2',unistr('"Traffic is prohibited". prohibited to all vehicles\u000d\u000a              traffic.'),'2025-11-06 21:14:47','2025-11-06 21:14:47','3.2');
INSERT INTO road_sign_translations VALUES(791,456,101,'3.2',unistr('«Движение запрещено». запрещен для всех транспортных средств\u000d\u000a              трафик.'),'2025-11-06 21:14:47','2025-11-06 21:14:47','3.2');
INSERT INTO road_sign_translations VALUES(792,457,100,'3.3','"The movement of mechanical vehicles is prohibited."','2025-11-06 21:14:48','2025-11-06 21:14:48','3.3');
INSERT INTO road_sign_translations VALUES(793,457,101,'3.3','«Движение механических транспортных средств запрещено».','2025-11-06 21:14:48','2025-11-06 21:14:48','3.3');
INSERT INTO road_sign_translations VALUES(794,458,100,'3.4',unistr('"The traffic of trucks is prohibited." prohibited 3.5\u000d\u000a              more than a ton (if the mass is not indicated on the sign) or greater than that indicated on the sign\u000d\u000a              trucks and vehicles with the maximum permissible mass\u000d\u000a              traffic of vehicles, as well as tractors and self-propelled vehicles;'),'2025-11-06 21:14:50','2025-11-06 21:14:50','3.4');
INSERT INTO road_sign_translations VALUES(795,458,101,'3.4',unistr('«Движение грузовых автомобилей запрещено». запрещено 3.5\u000d\u000a              более тонны (если масса не указана на знаке) или больше указанной на знаке\u000d\u000a              грузовые и транспортные средства с максимально допустимой массой\u000d\u000a              движение транспортных средств, а также тракторов и самоходных машин;'),'2025-11-06 21:14:50','2025-11-06 21:14:50','3.4');
INSERT INTO road_sign_translations VALUES(796,459,100,'3.5','"Motorcycle traffic is prohibited."','2025-11-06 21:14:50','2025-11-06 21:14:50','3.5');
INSERT INTO road_sign_translations VALUES(797,459,101,'3.5','«Движение мотоциклов запрещено».','2025-11-06 21:14:50','2025-11-06 21:14:50','3.5');
INSERT INTO road_sign_translations VALUES(798,460,100,'3.6',unistr('"The traffic of tractors is prohibited". tractors and\u000d\u000a              the traffic of self-propelled vehicles.'),'2025-11-06 21:14:51','2025-11-06 21:14:51','3.6');
INSERT INTO road_sign_translations VALUES(799,460,101,'3.6',unistr('«Движение тракторов запрещено». тракторы и\u000d\u000a              движение самоходных транспортных средств.'),'2025-11-06 21:14:51','2025-11-06 21:14:51','3.6');
INSERT INTO road_sign_translations VALUES(800,461,100,'3.7',unistr('"Traffic with a trailer is prohibited." prohibited with any type of attachment\u000d\u000a              traffic of trucks and tractors, as well as mechanical\u000d\u000a              vehicle towing.'),'2025-11-06 21:14:52','2025-11-06 21:14:52','3.7');
INSERT INTO road_sign_translations VALUES(801,461,101,'3.7',unistr('«Движение с прицепом запрещено». запрещено с любым типом вложения\u000d\u000a              движение грузовых автомобилей и тракторов, а также механического\u000d\u000a              буксировка автомобиля.'),'2025-11-06 21:14:52','2025-11-06 21:14:52','3.7');
INSERT INTO road_sign_translations VALUES(802,462,100,'3.8',unistr('"The traffic of carts is prohibited". no wheelbarrows\u000d\u000a              (sleds), horse or pack animal traffic and cattle driving;'),'2025-11-06 21:14:53','2025-11-06 21:14:53','3.8');
INSERT INTO road_sign_translations VALUES(803,462,101,'3.8',unistr('«Движение телег запрещено». никаких тачек\u000d\u000a              (сани), перевозка лошадей или вьючных животных и перегон скота;'),'2025-11-06 21:14:53','2025-11-06 21:14:53','3.8');
INSERT INTO road_sign_translations VALUES(804,463,100,'3.9',unistr('"Bicycle traffic is prohibited." prohibited by mopeds and\u000d\u000a              bicycle traffic.'),'2025-11-06 21:14:54','2025-11-06 21:14:54','3.9');
INSERT INTO road_sign_translations VALUES(805,463,101,'3.9',unistr('«Движение велосипедов запрещено». запрещено мопедам и\u000d\u000a              велосипедное движение.'),'2025-11-06 21:14:54','2025-11-06 21:14:54','3.9');
INSERT INTO road_sign_translations VALUES(806,464,100,'3.10','"The movement of pedestrians is prohibited."','2025-11-06 21:14:55','2025-11-06 21:14:55','3.10');
INSERT INTO road_sign_translations VALUES(807,464,101,'3.10','«Движение пешеходов запрещено».','2025-11-06 21:14:55','2025-11-06 21:14:55','3.10');
INSERT INTO road_sign_translations VALUES(808,465,100,'3.11',unistr('"Mass limitation". it is prohibited for those vehicles (ie\u000d\u000a              (including motor trains) traffic, the total actual mass of which is significantly greater\u000d\u000a              from the above.'),'2025-11-06 21:14:56','2025-11-06 21:14:56','3.11');
INSERT INTO road_sign_translations VALUES(809,465,101,'3.11',unistr('«Ограничение массы». это запрещено для этих транспортных средств (т.е.\u000d\u000a              (включая автопоезда) движение, общая фактическая масса которого значительно больше\u000d\u000a              из вышесказанного.'),'2025-11-06 21:14:56','2025-11-06 21:14:56','3.11');
INSERT INTO road_sign_translations VALUES(810,466,100,'3.12',unistr('"Limitation of axle load". it is forbidden to transport it\u000d\u000a              the traffic of means whose load on any axis is greater than the sign\u000d\u000a              from the mentioned.'),'2025-11-06 21:14:58','2025-11-06 21:14:58','3.12');
INSERT INTO road_sign_translations VALUES(811,466,101,'3.12',unistr('«Ограничение нагрузки на ось». его запрещено перевозить\u000d\u000a              движение средств, нагрузка которых на любую ось больше знака\u000d\u000a              из упомянутого.'),'2025-11-06 21:14:58','2025-11-06 21:14:58','3.12');
INSERT INTO road_sign_translations VALUES(812,467,100,'3.13',unistr('"Height restriction". It is prohibited for vehicles\u000d\u000a              vehicles whose curb height (with or without load) exceeds the mark\u000d\u000a              from the above.'),'2025-11-06 21:14:59','2025-11-06 21:14:59','3.13');
INSERT INTO road_sign_translations VALUES(813,467,101,'3.13',unistr('«Ограничение по высоте». Запрещено для транспортных средств\u000d\u000a              транспортные средства, высота бордюра которых (с грузом или без) превышает отметку\u000d\u000a              из вышесказанного.'),'2025-11-06 21:14:59','2025-11-06 21:14:59','3.13');
INSERT INTO road_sign_translations VALUES(814,468,100,'3.14',unistr('"Width limitation". It is prohibited for vehicles\u000d\u000a              traffic whose curb width (with or without load) exceeds the mark\u000d\u000a              from the above.'),'2025-11-06 21:15:00','2025-11-06 21:15:00','3.14');
INSERT INTO road_sign_translations VALUES(815,468,101,'3.14',unistr('«Ограничение ширины». Запрещено для транспортных средств\u000d\u000a              движение, ширина бордюра которого (с грузом или без) превышает отметку\u000d\u000a              из вышесказанного.'),'2025-11-06 21:15:00','2025-11-06 21:15:00','3.14');
INSERT INTO road_sign_translations VALUES(816,469,100,'3.15',unistr('"Length limitation". it is prohibited for those vehicles (ie\u000d\u000a              (including: motor trains) traffic, the gauge length of which (with cargo or\u000d\u000a              without load) is more than indicated on the sign.'),'2025-11-06 21:15:02','2025-11-06 21:15:02','3.15');
INSERT INTO road_sign_translations VALUES(817,469,101,'3.15',unistr('«Ограничение длины». это запрещено для этих транспортных средств (т.е.\u000d\u000a              (в том числе: автопоездов) движение, колея которого (с грузом или\u000d\u000a              без нагрузки) больше, чем указано на знаке.'),'2025-11-06 21:15:02','2025-11-06 21:15:02','3.15');
INSERT INTO road_sign_translations VALUES(818,470,100,'3.16',unistr('"Minimum interspace restriction". transport is prohibited\u000d\u000a              traffic of means, if the distance between them is less than indicated on the sign;'),'2025-11-06 21:15:04','2025-11-06 21:15:04','3.16');
INSERT INTO road_sign_translations VALUES(819,470,101,'3.16',unistr('«Минимальное ограничение межпространства». транспорт запрещен\u000d\u000a              движение транспортных средств, если расстояние между ними меньше указанного на знаке;'),'2025-11-06 21:15:04','2025-11-06 21:15:04','3.16');
INSERT INTO road_sign_translations VALUES(820,471,100,'3.17.1','"Customs point". it is forbidden to pass by the customs point without stopping.','2025-11-06 21:15:05','2025-11-06 21:15:05','3.17.1');
INSERT INTO road_sign_translations VALUES(821,471,101,'3.17.1','«Таможенный пункт». запрещено проезжать мимо таможенного пункта без остановки.','2025-11-06 21:15:05','2025-11-06 21:15:05','3.17.1');
INSERT INTO road_sign_translations VALUES(822,472,100,'3.17.2',unistr('"Danger". Prohibited from all vehicles further\u000d\u000a              traffic accident, fire, accident and other danger\u000d\u000a              in connection with, except for the police, emergency medical assistance, rescue and\u000d\u000a              vehicles of other services arriving for the purpose of eliminating the danger,\u000d\u000a              the traffic can be continued only after obtaining permission.'),'2025-11-06 21:15:07','2025-11-06 21:15:07','3.17.2');
INSERT INTO road_sign_translations VALUES(823,472,101,'3.17.2',unistr('"Опасность". Запрещено движение всех транспортных средств далее\u000d\u000a              дорожно-транспортное происшествие, пожар, авария и другая опасность\u000d\u000a              в связи, за исключением полиции, с неотложной медицинской помощью, спасательными и\u000d\u000a              транспортные средства других служб, прибывающие с целью устранения опасности,\u000d\u000a              движение может быть продолжено только после получения разрешения.'),'2025-11-06 21:15:07','2025-11-06 21:15:07','3.17.2');
INSERT INTO road_sign_translations VALUES(824,473,100,'3.17.3','"Control point". passing through the checkpoint without stopping is prohibited.','2025-11-06 21:15:08','2025-11-06 21:15:08','3.17.3');
INSERT INTO road_sign_translations VALUES(825,473,101,'3.17.3','«Контрольная точка». Проезд через КПП без остановки запрещен.','2025-11-06 21:15:08','2025-11-06 21:15:08','3.17.3');
INSERT INTO road_sign_translations VALUES(826,474,100,'3.18.1','"Right turn is prohibited".','2025-11-06 21:15:09','2025-11-06 21:15:09','3.18.1');
INSERT INTO road_sign_translations VALUES(827,474,101,'3.18.1','«Поворот направо запрещен».','2025-11-06 21:15:09','2025-11-06 21:15:09','3.18.1');
INSERT INTO road_sign_translations VALUES(828,475,100,'3.18.2','"Left turn is prohibited".','2025-11-06 21:15:11','2025-11-06 21:15:11','3.18.2');
INSERT INTO road_sign_translations VALUES(829,475,101,'3.18.2','«Поворот налево запрещен».','2025-11-06 21:15:11','2025-11-06 21:15:11','3.18.2');
INSERT INTO road_sign_translations VALUES(830,476,100,'3.19','"Return is prohibited".','2025-11-06 21:15:12','2025-11-06 21:15:12','3.19');
INSERT INTO road_sign_translations VALUES(831,476,101,'3.19','«Возврат запрещен».','2025-11-06 21:15:12','2025-11-06 21:15:12','3.19');
INSERT INTO road_sign_translations VALUES(832,477,100,'3.20',unistr('"Running is prohibited". prohibited by all types of vehicles\u000d\u000a              overtaking performance. It is allowed to overtake slow-moving vehicles,\u000d\u000a              wheelbarrows, two-wheeled motorcycles, mopeds and bicycles without sidecars;'),'2025-11-06 21:15:13','2025-11-06 21:15:13','3.20');
INSERT INTO road_sign_translations VALUES(833,477,101,'3.20',unistr('«Бег запрещен». запрещено для всех типов транспортных средств\u000d\u000a              обгонная производительность. Разрешается обгон тихоходных транспортных средств,\u000d\u000a              тачки, двухколесные мотоциклы, мопеды и велосипеды без коляски;'),'2025-11-06 21:15:13','2025-11-06 21:15:13','3.20');
INSERT INTO road_sign_translations VALUES(834,478,100,'3.21','"The end of the no-run zone".','2025-11-06 21:15:15','2025-11-06 21:15:15','3.21');
INSERT INTO road_sign_translations VALUES(835,478,101,'3.21','«Конец запретной зоны».','2025-11-06 21:15:15','2025-11-06 21:15:15','3.21');
INSERT INTO road_sign_translations VALUES(836,479,100,'3.22',unistr('"Overtaking by trucks is prohibited." all types of transport\u000d\u000a              Overtaking by vehicles is prohibited, except for motorcycles, light passenger vehicles\u000d\u000a              cars, buses and maximum permissible weight up to 3.5 tons\u000d\u000a              with trucks.'),'2025-11-06 21:15:17','2025-11-06 21:15:17','3.22');
INSERT INTO road_sign_translations VALUES(837,479,101,'3.22',unistr('«Обгон грузовиков запрещен». все виды транспорта\u000d\u000a              Обгон транспортными средствами запрещен, за исключением мотоциклов, легковых автомобилей.\u000d\u000a              легковые автомобили, автобусы и максимально допустимая масса до 3,5 тонн.\u000d\u000a              с грузовиками.'),'2025-11-06 21:15:17','2025-11-06 21:15:17','3.22');
INSERT INTO road_sign_translations VALUES(838,480,100,'3.23','"The end of the overtaking prohibition zone with trucks".','2025-11-06 21:15:17','2025-11-06 21:15:17','3.23');
INSERT INTO road_sign_translations VALUES(839,480,101,'3.23','«Конец зоны запрета обгона грузовиков».','2025-11-06 21:15:17','2025-11-06 21:15:17','3.23');
INSERT INTO road_sign_translations VALUES(840,481,100,'3.24',unistr('"Maximum speed limit". is prohibited from what is indicated on the sign\u000d\u000a              driving at high speed (km/h).'),'2025-11-06 21:15:18','2025-11-06 21:15:18','3.24');
INSERT INTO road_sign_translations VALUES(841,481,101,'3.24',unistr('«Максимальная скорость». запрещено то, что указано на знаке\u000d\u000a              езда на высокой скорости (км/ч).'),'2025-11-06 21:15:18','2025-11-06 21:15:18','3.24');
INSERT INTO road_sign_translations VALUES(842,482,100,'3.25','"End of the maximum speed limit zone".','2025-11-06 21:15:19','2025-11-06 21:15:19','3.25');
INSERT INTO road_sign_translations VALUES(843,482,101,'3.25','«Конец зоны ограничения максимальной скорости».','2025-11-06 21:15:19','2025-11-06 21:15:19','3.25');
INSERT INTO road_sign_translations VALUES(844,483,100,'3.26',unistr('"Honking is prohibited." it is forbidden to use voice\u000d\u000a              from signals, except when it is given for a traffic accident\u000d\u000a              to prevent'),'2025-11-06 21:15:21','2025-11-06 21:15:21','3.26');
INSERT INTO road_sign_translations VALUES(845,483,101,'3.26',unistr('«Гудеть запрещено». запрещено использовать голос\u000d\u000a              от сигналов, за исключением случаев, когда он подается при дорожно-транспортном происшествии\u000d\u000a              предотвратить'),'2025-11-06 21:15:21','2025-11-06 21:15:21','3.26');
INSERT INTO road_sign_translations VALUES(846,484,100,'3.27',unistr('"Stopping is prohibited". parking of vehicles is prohibited\u000d\u000a              parking.'),'2025-11-06 21:15:22','2025-11-06 21:15:22','3.27');
INSERT INTO road_sign_translations VALUES(847,484,101,'3.27',unistr('«Остановка запрещена». парковка транспортных средств запрещена\u000d\u000a              парковка.'),'2025-11-06 21:15:22','2025-11-06 21:15:22','3.27');
INSERT INTO road_sign_translations VALUES(848,485,100,'3.28','"Parking is prohibited". parking of vehicles is prohibited.','2025-11-06 21:15:23','2025-11-06 21:15:23','3.28');
INSERT INTO road_sign_translations VALUES(849,485,101,'3.28','«Стоянка запрещена». стоянка транспортных средств запрещена.','2025-11-06 21:15:23','2025-11-06 21:15:23','3.28');
INSERT INTO road_sign_translations VALUES(850,486,100,'3.29','"Parking is prohibited on odd days of the month."','2025-11-06 21:15:24','2025-11-06 21:15:24','3.29');
INSERT INTO road_sign_translations VALUES(851,486,101,'3.29','«Парковка запрещена в нечетные дни месяца».','2025-11-06 21:15:24','2025-11-06 21:15:24','3.29');
INSERT INTO road_sign_translations VALUES(852,487,100,'3.30',unistr('"Parking is prohibited on even days of the month." 3.29 and 3.30 of signs\u000d\u000a              in case of simultaneous application, vehicles from one side of the road to the other\u000d\u000a              are moved around 19.00 - 21.00.'),'2025-11-06 21:15:25','2025-11-06 21:15:25','3.30');
INSERT INTO road_sign_translations VALUES(853,487,101,'3.30',unistr('«Стоянка запрещена в четные дни месяца». 3.29 и 3.30 знаков\u000d\u000a              в случае одновременного применения транспортные средства с одной стороны дороги на другую\u000d\u000a              переносятся с 19.00 до 21.00.'),'2025-11-06 21:15:25','2025-11-06 21:15:25','3.30');
INSERT INTO road_sign_translations VALUES(854,488,100,'3.31',unistr('"End of all restrictions zone". notes 3.16, 3.20, 3.22, 3.24 and\u000d\u000a              3.26 - 3.30 simultaneous end of influence zones of some signs.'),'2025-11-06 21:15:26','2025-11-06 21:15:26','3.31');
INSERT INTO road_sign_translations VALUES(855,488,101,'3.31',unistr('«Конец зоны всех ограничений». примечания 3.16, 3.20, 3.22, 3.24 и\u000d\u000a              3.26 - 3.30 одновременное окончание зон влияния некоторых знаков.'),'2025-11-06 21:15:26','2025-11-06 21:15:26','3.31');
INSERT INTO road_sign_translations VALUES(856,489,100,'3.32',unistr('"Traffic of vehicles with dangerous goods is prohibited".\u000d\u000a              it is prohibited to drive vehicles that are equipped\u000d\u000a              "Dangerous cargo" recognition mark.'),'2025-11-06 21:15:27','2025-11-06 21:15:27','3.32');
INSERT INTO road_sign_translations VALUES(857,489,101,'3.32',unistr('«Движение транспортных средств с опасными грузами запрещено».\u000d\u000a              запрещается управлять транспортными средствами, оборудованными\u000d\u000a              Знак опознавания «Опасный груз».'),'2025-11-06 21:15:27','2025-11-06 21:15:27','3.32');
INSERT INTO road_sign_translations VALUES(858,490,100,'3.33',unistr('"Traffic of vehicles with explosive and flammable cargoes\u000d\u000a              is prohibited". traffic of vehicles which\u000d\u000a              are equipped with the "Dangerous Cargo" identification mark and are intended for 1, 2.2 - 2.4, 3.1, 3.2\u000d\u000a              and for transporting dangerous goods of classes 5.2 (according to the standard);'),'2025-11-06 21:15:29','2025-11-06 21:15:29','3.33');
INSERT INTO road_sign_translations VALUES(859,490,101,'3.33',unistr('«Движение транспортных средств с взрывоопасными и легковоспламеняющимися грузами.\u000d\u000a              запрещено». движение транспортных средств, которые\u000d\u000a              имеют опознавательный знак «Опасный груз» и предназначены для 1, 2.2 – 2.4, 3.1, 3.2.\u000d\u000a              и для перевозки опасных грузов классов 5.2 (по стандарту);'),'2025-11-06 21:15:29','2025-11-06 21:15:29','3.33');
INSERT INTO road_sign_translations VALUES(860,491,100,'4.1.1','"Traffic is straight".','2025-11-06 21:15:30','2025-11-06 21:15:30','4.1.1');
INSERT INTO road_sign_translations VALUES(861,491,101,'4.1.1','«Движение прямое».','2025-11-06 21:15:30','2025-11-06 21:15:30','4.1.1');
INSERT INTO road_sign_translations VALUES(862,492,100,'4.1.2','"Traffic to the right".','2025-11-06 21:15:32','2025-11-06 21:15:32','4.1.2');
INSERT INTO road_sign_translations VALUES(863,492,101,'4.1.2','«Движение правостороннее».','2025-11-06 21:15:32','2025-11-06 21:15:32','4.1.2');
INSERT INTO road_sign_translations VALUES(864,493,100,'4.1.3','"Traffic to the left".','2025-11-06 21:15:33','2025-11-06 21:15:33','4.1.3');
INSERT INTO road_sign_translations VALUES(865,493,101,'4.1.3','«Левое движение».','2025-11-06 21:15:33','2025-11-06 21:15:33','4.1.3');
INSERT INTO road_sign_translations VALUES(866,494,100,'4.1.4','"Traffic straight or to the right".','2025-11-06 21:15:34','2025-11-06 21:15:34','4.1.4');
INSERT INTO road_sign_translations VALUES(867,494,101,'4.1.4','«Движение прямо или направо».','2025-11-06 21:15:34','2025-11-06 21:15:34','4.1.4');
INSERT INTO road_sign_translations VALUES(868,495,100,'4.1.5','"Traffic going straight or to the left".','2025-11-06 21:15:36','2025-11-06 21:15:36','4.1.5');
INSERT INTO road_sign_translations VALUES(869,495,101,'4.1.5','«Движение прямо или налево».','2025-11-06 21:15:36','2025-11-06 21:15:36','4.1.5');
INSERT INTO road_sign_translations VALUES(870,496,100,'4.1.6',unistr('"Traffic to the right or to the left". only traffic is allowed\u000d\u000a              in the directions indicated by the arrows on the signs.'),'2025-11-06 21:15:36','2025-11-06 21:15:36','4.1.6');
INSERT INTO road_sign_translations VALUES(871,496,101,'4.1.6',unistr('«Движение правостороннее или левостороннее». разрешен только трафик\u000d\u000a              в направлениях, указанных стрелками на знаках.'),'2025-11-06 21:15:36','2025-11-06 21:15:36','4.1.6');
INSERT INTO road_sign_translations VALUES(872,497,100,'4.2.1','"Bypassing the ban on the right".','2025-11-06 21:15:38','2025-11-06 21:15:38','4.2.1');
INSERT INTO road_sign_translations VALUES(873,497,101,'4.2.1','«Обход запрета справа».','2025-11-06 21:15:38','2025-11-06 21:15:38','4.2.1');
INSERT INTO road_sign_translations VALUES(874,498,100,'4.2.2',unistr('"Bypassing the ban from the left". overtaking is allowed only by pointing the arrow\u000d\u000a              given by'),'2025-11-06 21:15:39','2025-11-06 21:15:39','4.2.2');
INSERT INTO road_sign_translations VALUES(875,498,101,'4.2.2',unistr('«Обход запрета слева». обгон разрешен только при наведении стрелки\u000d\u000a              данный'),'2025-11-06 21:15:39','2025-11-06 21:15:39','4.2.2');
INSERT INTO road_sign_translations VALUES(876,499,100,'4.2.3',unistr('"Bypassing the ban from the right or left". overtaking is allowed as right,\u000d\u000a              also from the left side.'),'2025-11-06 21:15:40','2025-11-06 21:15:40','4.2.3');
INSERT INTO road_sign_translations VALUES(877,499,101,'4.2.3',unistr('«Обход запрета справа или слева». обгон разрешен по закону,\u000d\u000a              также с левой стороны.'),'2025-11-06 21:15:40','2025-11-06 21:15:40','4.2.3');
INSERT INTO road_sign_translations VALUES(878,500,100,'4.3',unistr('"Roundabout". traffic is allowed with arrows\u000d\u000a              in the direction shown.'),'2025-11-06 21:15:41','2025-11-06 21:15:41','4.3');
INSERT INTO road_sign_translations VALUES(879,500,101,'4.3',unistr('«Карусель». движение разрешено со стрелками\u000d\u000a              в указанном направлении.'),'2025-11-06 21:15:41','2025-11-06 21:15:41','4.3');
INSERT INTO road_sign_translations VALUES(880,501,100,'4.4',unistr('"Bicycle path". only mopeds and\u000d\u000a              with bicycles. In the absence of a sidewalk or footpath, on a bike path\u000d\u000a              Pedestrians can also travel.'),'2025-11-06 21:15:42','2025-11-06 21:15:42','4.4');
INSERT INTO road_sign_translations VALUES(881,501,101,'4.4',unistr('«Велодорожка». только мопеды и\u000d\u000a              с велосипедами. При отсутствии тротуара или пешеходной дорожки на велосипедной дорожке\u000d\u000a              Пешеходы также могут путешествовать.'),'2025-11-06 21:15:42','2025-11-06 21:15:42','4.4');
INSERT INTO road_sign_translations VALUES(882,502,100,'4.5','"Pedestrian path". only pedestrian movement is allowed.','2025-11-06 21:15:43','2025-11-06 21:15:43','4.5');
INSERT INTO road_sign_translations VALUES(883,502,101,'4.5','«Пешеходная дорожка». разрешено только пешеходное движение.','2025-11-06 21:15:43','2025-11-06 21:15:43','4.5');
INSERT INTO road_sign_translations VALUES(884,503,100,'4.6',unistr('"Minimum speed limit". only marked traffic is allowed\u000d\u000a              (km/h) or higher speed.'),'2025-11-06 21:15:44','2025-11-06 21:15:44','4.6');
INSERT INTO road_sign_translations VALUES(885,503,101,'4.6',unistr('"Минимальный предел скорости". разрешен только маркированный трафик\u000d\u000a              (км/ч) или более высокую скорость.'),'2025-11-06 21:15:44','2025-11-06 21:15:44','4.6');
INSERT INTO road_sign_translations VALUES(886,504,100,'4.7','"End of the minimum speed limit zone".','2025-11-06 21:15:45','2025-11-06 21:15:45','4.7');
INSERT INTO road_sign_translations VALUES(887,504,101,'4.7','«Конец зоны ограничения минимальной скорости».','2025-11-06 21:15:45','2025-11-06 21:15:45','4.7');
INSERT INTO road_sign_translations VALUES(888,505,100,'4.8.1','"Traffic direction of vehicles with dangerous goods". Traffic of vehicles equipped with "Dangerous cargo" recognition signs is allowed only in the direction indicated by the arrow on the sign: 4.8.1: straight, 4.8.2: to the right, 4.8.3: to the left.','2025-11-06 21:15:47','2025-11-06 21:15:47','4.8.1');
INSERT INTO road_sign_translations VALUES(889,505,101,'4.8.1','«Направление движения транспортных средств с опасными грузами». Движение транспортных средств, оборудованных знаками опознавательного знака «Опасный груз», разрешается только в направлении, указанном стрелкой на знаке: 4.8.1: прямо, 4.8.2: направо, 4.8.3: налево.','2025-11-06 21:15:47','2025-11-06 21:15:47','4.8.1');
INSERT INTO road_sign_translations VALUES(890,506,100,'5.1',unistr('"Highway". a road where rules apply - highways\u000d\u000a              traffic order requirements.'),'2025-11-06 21:15:48','2025-11-06 21:15:48','5.1');
INSERT INTO road_sign_translations VALUES(891,506,101,'5.1',unistr('«Шоссе». дорога, где действуют правила - шоссе\u000d\u000a              требования к порядку движения.'),'2025-11-06 21:15:48','2025-11-06 21:15:48','5.1');
INSERT INTO road_sign_translations VALUES(892,507,100,'5.2','"End of the highway".','2025-11-06 21:15:48','2025-11-06 21:15:48','5.2');
INSERT INTO road_sign_translations VALUES(893,507,101,'5.2','«Конец шоссе».','2025-11-06 21:15:48','2025-11-06 21:15:48','5.2');
INSERT INTO road_sign_translations VALUES(894,508,100,'5.3',unistr('"Road for automobiles". motorcycles are also allowed\u000d\u000a              traffic.'),'2025-11-06 21:15:50','2025-11-06 21:15:50','5.3');
INSERT INTO road_sign_translations VALUES(895,508,101,'5.3',unistr('«Дорога для автомобилей». мотоциклы также разрешены\u000d\u000a              трафик.'),'2025-11-06 21:15:50','2025-11-06 21:15:50','5.3');
INSERT INTO road_sign_translations VALUES(896,509,100,'5.4','"End of the road for cars".','2025-11-06 21:15:51','2025-11-06 21:15:51','5.4');
INSERT INTO road_sign_translations VALUES(897,509,101,'5.4','«Конец дороги для автомобилей».','2025-11-06 21:15:51','2025-11-06 21:15:51','5.4');
INSERT INTO road_sign_translations VALUES(898,510,100,'5.5',unistr('"One-way road". road or carriageway on which\u000d\u000a              vehicular traffic is carried out on the entire width\u000d\u000a              direction.'),'2025-11-06 21:15:53','2025-11-06 21:15:53','5.5');
INSERT INTO road_sign_translations VALUES(899,510,101,'5.5',unistr('«Дорога с односторонним движением». дорога или проезжая часть, на которой\u000d\u000a              движение автотранспорта осуществляется по всей ширине\u000d\u000a              направление.'),'2025-11-06 21:15:53','2025-11-06 21:15:53','5.5');
INSERT INTO road_sign_translations VALUES(900,511,100,'5.6','"End of the road with one-way traffic".','2025-11-06 21:15:54','2025-11-06 21:15:54','5.6');
INSERT INTO road_sign_translations VALUES(901,511,101,'5.6','«Конец дороги с односторонним движением».','2025-11-06 21:15:54','2025-11-06 21:15:54','5.6');
INSERT INTO road_sign_translations VALUES(902,512,100,'5.7.1',unistr('"Exit to a one-way road". exit to\u000d\u000a              one-way road or carriageway.'),'2025-11-06 21:15:55','2025-11-06 21:15:55','5.7.1');
INSERT INTO road_sign_translations VALUES(903,512,101,'5.7.1',unistr('«Выход на дорогу с односторонним движением». выход в\u000d\u000a              дорога с односторонним движением или проезжая часть.'),'2025-11-06 21:15:55','2025-11-06 21:15:55','5.7.1');
INSERT INTO road_sign_translations VALUES(904,513,100,'5.8',unistr('"Transition traffic". the beginning of the part of the road where one or\u000d\u000a              the direction of traffic in several lanes can be changed oppositely;'),'2025-11-06 21:15:56','2025-11-06 21:15:56','5.8');
INSERT INTO road_sign_translations VALUES(905,513,101,'5.8',unistr('«Переходный трафик». начало части дороги, где находится один или\u000d\u000a              направление движения в нескольких полосах можно изменить встречно;'),'2025-11-06 21:15:56','2025-11-06 21:15:56','5.8');
INSERT INTO road_sign_translations VALUES(906,514,100,'5.9','"End of shift traffic".','2025-11-06 21:15:57','2025-11-06 21:15:57','5.9');
INSERT INTO road_sign_translations VALUES(907,514,101,'5.9','«Конец смены».','2025-11-06 21:15:57','2025-11-06 21:15:57','5.9');
INSERT INTO road_sign_translations VALUES(908,515,100,'5.10','"Exit to the turnpike road".','2025-11-06 21:15:58','2025-11-06 21:15:58','5.10');
INSERT INTO road_sign_translations VALUES(909,515,101,'5.10','«Выход на магистраль».','2025-11-06 21:15:58','2025-11-06 21:15:58','5.10');
INSERT INTO road_sign_translations VALUES(910,516,100,'5.11',unistr('"Road with a lane for vehicles of general use".\u000d\u000a              against the flow of traffic, vehicles of general use\u000d\u000a              a road with a special dedicated lane for traffic.'),'2025-11-06 21:16:00','2025-11-06 21:16:00','5.11');
INSERT INTO road_sign_translations VALUES(911,516,101,'5.11',unistr('«Дорога с полосой для транспортных средств общего пользования».\u000d\u000a              против потока транспорта, транспортные средства общего пользования\u000d\u000a              дорога со специальной выделенной полосой для движения транспорта.'),'2025-11-06 21:16:00','2025-11-06 21:16:00','5.11');
INSERT INTO road_sign_translations VALUES(912,517,100,'5.12',unistr('"On the road with a lane for general use vehicles\u000d\u000a              that''s it."'),'2025-11-06 21:16:01','2025-11-06 21:16:01','5.12');
INSERT INTO road_sign_translations VALUES(913,517,101,'5.12',unistr('«На дороге с полосой для транспортных средств общего пользования\u000d\u000a              вот и все».'),'2025-11-06 21:16:01','2025-11-06 21:16:01','5.12');
INSERT INTO road_sign_translations VALUES(914,518,100,'5.13.1',unistr('"Exit to vehicles of general use\u000d\u000a              road with one lane".'),'2025-11-06 21:16:03','2025-11-06 21:16:03','5.13.1');
INSERT INTO road_sign_translations VALUES(915,518,101,'5.13.1',unistr('«Выход к транспортным средствам общего пользования\u000d\u000a              дорога с одной полосой».'),'2025-11-06 21:16:03','2025-11-06 21:16:03','5.13.1');
INSERT INTO road_sign_translations VALUES(916,519,100,'5.14',unistr('"Zone for vehicles of general use". traffic\u000d\u000a              with the flow, for general use vehicles only\u000d\u000a              belt The effect of that token extends to the zone it is placed on.\u000d\u000a              The effect of the sign placed to the right of the road extends to the right lane.'),'2025-11-06 21:16:04','2025-11-06 21:16:04','5.14');
INSERT INTO road_sign_translations VALUES(917,519,101,'5.14',unistr('«Зона для транспортных средств общего пользования». трафик\u000d\u000a              с потоком, только для автомобилей общего пользования\u000d\u000a              пояс Эффект этого жетона распространяется на зону, в которой он находится.\u000d\u000a              Действие знака, размещенного справа от дороги, распространяется и на правую полосу движения.'),'2025-11-06 21:16:04','2025-11-06 21:16:04','5.14');
INSERT INTO road_sign_translations VALUES(918,520,100,'5.15.1',unistr('"Traffic directions in zones". number of lanes and traffic\u000d\u000a              allowed directions in each of them;'),'2025-11-06 21:16:04','2025-11-06 21:16:04','5.15.1');
INSERT INTO road_sign_translations VALUES(919,520,101,'5.15.1',unistr('«Направления движения в зонах». количество полос и трафик\u000d\u000a              разрешенные направления в каждом из них;'),'2025-11-06 21:16:04','2025-11-06 21:16:04','5.15.1');
INSERT INTO road_sign_translations VALUES(920,521,100,'5.15.2',unistr('"Traffic directions in the lane". traffic allowed\u000d\u000a              directions by belt.\u000d\u000a              Signs 5.15.1 and 5.15.2 Permitting Left Turns from the Left Side Lane\u000d\u000a                are also the return from that zone. The operation of signs 5.15.1 and 5.15.2 is not\u000d\u000a                applies to vehicles in general use. Before the intersection\u000d\u000a                The influence zone of the installed signs 5.8.1 and "5.15.2" extends to the entire intersection\u000d\u000a                on, unless other signs 5.15.1 or 5.8.2 placed there do not indicate otherwise\u000d\u000a                gives'),'2025-11-06 21:16:05','2025-11-06 21:16:05','5.15.2');
INSERT INTO road_sign_translations VALUES(921,521,101,'5.15.2',unistr('«Направления движения по полосе». трафик разрешен\u000d\u000a              направления по поясу.\u000d\u000a              Знаки 5.15.1 и 5.15.2, разрешающие поворот налево с левой полосы движения\u000d\u000a                также являются возвращением из этой зоны. Действие знаков 5.15.1 и 5.15.2 не является\u000d\u000a                применяется к транспортным средствам общего пользования. Перед перекрёстком\u000d\u000a                Зона влияния установленных знаков 5.8.1 и «5.15.2» распространяется на весь перекресток.\u000d\u000a                включен, если иные знаки 5.15.1 или 5.8.2, расположенные там, не означают иного\u000d\u000a                дает'),'2025-11-06 21:16:05','2025-11-06 21:16:05','5.15.2');
INSERT INTO road_sign_translations VALUES(922,522,100,'5.15.3',unistr('"Beginning of the zone". the start of a braking zone or an additional zone on an uphill.\u000d\u000a              If this sign placed before the additional zone shows 4.6: "Minimum\u000d\u000a              speed limit" sign, then the drivers of those vehicles that\u000d\u000a              cannot continue traffic in the main lane, at least as shown on the sign\u000d\u000a              speed, should be rearranged in an additional lane.'),'2025-11-06 21:16:07','2025-11-06 21:16:07','5.15.3');
INSERT INTO road_sign_translations VALUES(923,522,101,'5.15.3',unistr('«Начало зоны». начало зоны торможения или дополнительной зоны на подъеме.\u000d\u000a              Если на этом знаке, установленном перед дополнительной зоной, указано 4.6: «Минимум\u000d\u000a              знак ограничения скорости», то водители тех транспортных средств, которые\u000d\u000a              не может продолжать движение по главной полосе, по крайней мере, так, как показано на знаке\u000d\u000a              скорости, надо переставить в дополнительную полосу.'),'2025-11-06 21:16:07','2025-11-06 21:16:07','5.15.3');
INSERT INTO road_sign_translations VALUES(924,523,100,'5.15.4',unistr('"Beginning of the zone". three-lane for traffic in the given direction\u000d\u000a              the beginning of the middle lane section of the road. If the sign 5.15.4 depicts any species\u000d\u000a              a sign prohibiting vehicle traffic, then those vehicles\u000d\u000a              traffic in the respective lanes is prohibited.'),'2025-11-06 21:16:08','2025-11-06 21:16:08','5.15.4');
INSERT INTO road_sign_translations VALUES(925,523,101,'5.15.4',unistr('«Начало зоны». трехполосный для движения в заданном направлении\u000d\u000a              начало среднего полосного участка дороги. Если на знаке 5.15.4 изображен какой-либо вид\u000d\u000a              знак, запрещающий движение транспортных средств, то эти транспортные средства\u000d\u000a              движение по соответствующим полосам запрещено.'),'2025-11-06 21:16:08','2025-11-06 21:16:08','5.15.4');
INSERT INTO road_sign_translations VALUES(926,524,100,'5.15.5','"End of the zone". the end of a wandering zone or an additional zone on the rise;','2025-11-06 21:16:09','2025-11-06 21:16:09','5.15.5');
INSERT INTO road_sign_translations VALUES(927,524,101,'5.15.5','«Конец зоны». конец зоны блуждания или дополнительная зона на подъеме;','2025-11-06 21:16:09','2025-11-06 21:16:09','5.15.5');
INSERT INTO road_sign_translations VALUES(928,525,100,'5.15.6',unistr('"End of the zone". three-lane for traffic in the given direction\u000d\u000a              the end of the middle lane section of the road.'),'2025-11-06 21:16:10','2025-11-06 21:16:10','5.15.6');
INSERT INTO road_sign_translations VALUES(929,525,101,'5.15.6',unistr('«Конец зоны». трехполосный для движения в заданном направлении\u000d\u000a              конец средней полосы дороги.'),'2025-11-06 21:16:10','2025-11-06 21:16:10','5.15.6');
INSERT INTO road_sign_translations VALUES(930,526,100,'5.15.7',unistr('"Traffic direction in lanes". if depicted on the sign 5.15.7\u000d\u000a              a sign prohibiting the traffic of any vehicle, then that vehicle\u000d\u000a              traffic is prohibited in the indicated zone. 5.15.7 sign with the corresponding number of arrows\u000d\u000a              can be applied to roads with four or more lanes;'),'2025-11-06 21:16:11','2025-11-06 21:16:11','5.15.7');
INSERT INTO road_sign_translations VALUES(931,526,101,'5.15.7',unistr('«Направление движения по полосам». если изображено на знаке 5.15.7\u000d\u000a              знак, запрещающий движение любого транспортного средства, то это транспортное средство\u000d\u000a              движение в указанной зоне запрещено. 5.15.7 знак с соответствующим количеством стрелок.\u000d\u000a              может применяться на дорогах с четырьмя и более полосами движения;'),'2025-11-06 21:16:11','2025-11-06 21:16:11','5.15.7');
INSERT INTO road_sign_translations VALUES(932,527,100,'5.15.8',unistr('"Number of zones". shows the number of traffic lanes and by lanes\u000d\u000a              traffic patterns. The driver must follow the signs shown on the arrows\u000d\u000a              requirements.'),'2025-11-06 21:16:13','2025-11-06 21:16:13','5.15.8');
INSERT INTO road_sign_translations VALUES(933,527,101,'5.15.8',unistr('«Количество зон». показывает количество полос движения и по полосам\u000d\u000a              модели трафика. Водитель должен следовать указателям, указанным на стрелках.\u000d\u000a              требования.'),'2025-11-06 21:16:13','2025-11-06 21:16:13','5.15.8');
INSERT INTO road_sign_translations VALUES(934,528,100,'5.16','"Bus and (or) trolley bus stop".','2025-11-06 21:16:14','2025-11-06 21:16:14','5.16');
INSERT INTO road_sign_translations VALUES(935,528,101,'5.16','«Автобусная и (или) троллейбусная остановка».','2025-11-06 21:16:14','2025-11-06 21:16:14','5.16');
INSERT INTO road_sign_translations VALUES(936,529,100,'5.17','"Tram Stop Place".','2025-11-06 21:16:15','2025-11-06 21:16:15','5.17');
INSERT INTO road_sign_translations VALUES(937,529,101,'5.17','«Место трамвайной остановки».','2025-11-06 21:16:15','2025-11-06 21:16:15','5.17');
INSERT INTO road_sign_translations VALUES(938,530,100,'5.18','"Parking place for light passenger taxis".','2025-11-06 21:16:16','2025-11-06 21:16:16','5.18');
INSERT INTO road_sign_translations VALUES(939,530,101,'5.18','«Стоянка для легковых пассажирских такси».','2025-11-06 21:16:16','2025-11-06 21:16:16','5.18');
INSERT INTO road_sign_translations VALUES(940,531,100,'5.19.1',unistr('"Pedestrian crossing". at the crossing point 1.14.1 - 1.14.2\u000d\u000a              in the absence of markings, the sign 5.19.1 is placed to the left of the road, at the crossing\u000d\u000a              far, and the sign 5.19.2 - to the right of the road, near the nearest border of the crossing.'),'2025-11-06 21:16:17','2025-11-06 21:16:17','5.19.1');
INSERT INTO road_sign_translations VALUES(941,531,101,'5.19.1',unistr('"Пешеходный переход". на пересечении 1.14.1 - 1.14.2\u000d\u000a              при отсутствии разметки знак 5.19.1 ставится слева от дороги, у перехода\u000d\u000a              далеко, а знак 5.19.2 – справа от дороги, возле ближайшей границы перехода.'),'2025-11-06 21:16:17','2025-11-06 21:16:17','5.19.1');
INSERT INTO road_sign_translations VALUES(942,532,100,'5.20',unistr('"Artificial unevenness". indicates an artificial unevenness\u000d\u000a              the borders. The sign is placed on the approach of the vehicle to the artificial unevenness\u000d\u000a              on the nearest border of the direction.'),'2025-11-06 21:16:18','2025-11-06 21:16:18','5.20');
INSERT INTO road_sign_translations VALUES(943,532,101,'5.20',unistr('«Искусственная неровность». указывает на искусственную неровность\u000d\u000a              границы. Знак размещается при подъезде транспортного средства к искусственной неровности.\u000d\u000a              на ближайшей границе направления.'),'2025-11-06 21:16:18','2025-11-06 21:16:18','5.20');
INSERT INTO road_sign_translations VALUES(944,533,100,'5.21',unistr('"Residential zone". the area where the rules apply - in the residential zone\u000d\u000a              traffic order requirements.'),'2025-11-06 21:16:20','2025-11-06 21:16:20','5.21');
INSERT INTO road_sign_translations VALUES(945,533,101,'5.21',unistr('«Жилая зона». зона действия правил - в жилой зоне\u000d\u000a              требования к порядку движения.'),'2025-11-06 21:16:20','2025-11-06 21:16:20','5.21');
INSERT INTO road_sign_translations VALUES(946,534,100,'5.22','"The end of the residential zone".','2025-11-06 21:16:20','2025-11-06 21:16:20','5.22');
INSERT INTO road_sign_translations VALUES(947,534,101,'5.22','«Конец жилой зоны».','2025-11-06 21:16:20','2025-11-06 21:16:20','5.22');
INSERT INTO road_sign_translations VALUES(948,535,100,'5.23.1','"Beginning of settlement". the beginning of the settlement, where the requirements of the rules defining the order of traffic in the settlements apply;','2025-11-06 21:16:22','2025-11-06 21:16:22','5.23.1');
INSERT INTO road_sign_translations VALUES(949,535,101,'5.23.1','«Начало урегулирования». начало населенного пункта, где применяются требования правил, определяющих порядок движения транспорта в населенных пунктах;','2025-11-06 21:16:22','2025-11-06 21:16:22','5.23.1');
INSERT INTO road_sign_translations VALUES(950,536,100,'5.24.1','"End of the settlement". the place from which the requirements of the rules defining the order of traffic in settlements lose their force on the given road;','2025-11-06 21:16:23','2025-11-06 21:16:23','5.24.1');
INSERT INTO road_sign_translations VALUES(951,536,101,'5.24.1','«Конец поселения». место, с которого на данной дороге теряют силу требования правил, определяющих порядок движения в населенных пунктах;','2025-11-06 21:16:23','2025-11-06 21:16:23','5.24.1');
INSERT INTO road_sign_translations VALUES(952,537,100,'5.25',unistr('"Beginning of settlement". the name and beginning of the settlement where the data\u000d\u000a              on the road there are no rules defining the order of traffic in settlements\u000d\u000a              requirements.'),'2025-11-06 21:16:24','2025-11-06 21:16:24','5.25');
INSERT INTO road_sign_translations VALUES(953,537,101,'5.25',unistr('«Начало урегулирования». название и начало населенного пункта, где данные\u000d\u000a              на дороге отсутствуют правила, определяющие порядок движения в населенных пунктах\u000d\u000a              требования.'),'2025-11-06 21:16:24','2025-11-06 21:16:24','5.25');
INSERT INTO road_sign_translations VALUES(954,538,100,'5.26','"End of the settlement". 5.25 the end of the settlement indicated by the sign.','2025-11-06 21:16:25','2025-11-06 21:16:25','5.26');
INSERT INTO road_sign_translations VALUES(955,538,101,'5.26','«Конец поселения». 5.25 Окончание населенного пункта обозначено знаком.','2025-11-06 21:16:25','2025-11-06 21:16:25','5.26');
INSERT INTO road_sign_translations VALUES(956,539,100,'5.27',unistr('"Parking restricted zone". location where parking begins\u000d\u000a              prohibited area (road section).'),'2025-11-06 21:16:27','2025-11-06 21:16:27','5.27');
INSERT INTO road_sign_translations VALUES(957,539,101,'5.27',unistr('«Зона ограничения парковки». место, где начинается парковка\u000d\u000a              запретная зона (участок дороги).'),'2025-11-06 21:16:27','2025-11-06 21:16:27','5.27');
INSERT INTO road_sign_translations VALUES(958,540,100,'5.28','"End of the zone with parking restrictions".','2025-11-06 21:16:28','2025-11-06 21:16:28','5.28');
INSERT INTO road_sign_translations VALUES(959,540,101,'5.28','«Конец зоны с ограничением парковки».','2025-11-06 21:16:28','2025-11-06 21:16:28','5.28');
INSERT INTO road_sign_translations VALUES(960,541,100,'5.29',unistr('"Regulated parking zone". place starting from allowed and\u000d\u000a              The parking area regulated with the help of signs and markings (on the road\u000d\u000a              section).'),'2025-11-06 21:16:29','2025-11-06 21:16:29','5.29');
INSERT INTO road_sign_translations VALUES(961,541,101,'5.29',unistr('«Регулируемая парковочная зона». место, начиная с разрешенного и\u000d\u000a              Зона парковки регулируется с помощью знаков и разметки (на проезжей части\u000d\u000a              раздел).'),'2025-11-06 21:16:29','2025-11-06 21:16:29','5.29');
INSERT INTO road_sign_translations VALUES(962,542,100,'5.30','"End of regulated parking zone".','2025-11-06 21:16:31','2025-11-06 21:16:31','5.30');
INSERT INTO road_sign_translations VALUES(963,542,101,'5.30','«Конец зоны регулируемой парковки».','2025-11-06 21:16:31','2025-11-06 21:16:31','5.30');
INSERT INTO road_sign_translations VALUES(964,543,100,'5.31',unistr('"Maximum speed limit zone". starting place\u000d\u000a              the area with maximum speed limit (road section);'),'2025-11-06 21:16:32','2025-11-06 21:16:32','5.31');
INSERT INTO road_sign_translations VALUES(965,543,101,'5.31',unistr('«Зона ограничения максимальной скорости». стартовое место\u000d\u000a              зона с ограничением максимальной скорости (участок дороги);'),'2025-11-06 21:16:32','2025-11-06 21:16:32','5.31');
INSERT INTO road_sign_translations VALUES(966,544,100,'5.32','"End of zone with maximum speed limit".','2025-11-06 21:16:34','2025-11-06 21:16:34','5.32');
INSERT INTO road_sign_translations VALUES(967,544,101,'5.32','«Конец зоны с ограничением максимальной скорости».','2025-11-06 21:16:34','2025-11-06 21:16:34','5.32');
INSERT INTO road_sign_translations VALUES(968,545,100,'5.33',unistr('"Pedestrian lane". a place where only pedestrian traffic begins\u000d\u000a              the area allowed for (road section).'),'2025-11-06 21:16:35','2025-11-06 21:16:35','5.33');
INSERT INTO road_sign_translations VALUES(969,545,101,'5.33',unistr('«Пешеходный переулок». место, где начинается только пешеходное движение\u000d\u000a              разрешенная территория (участок дороги).'),'2025-11-06 21:16:35','2025-11-06 21:16:35','5.33');
INSERT INTO road_sign_translations VALUES(970,546,100,'5.34','"End of the pedestrian zone."','2025-11-06 21:16:35','2025-11-06 21:16:35','5.34');
INSERT INTO road_sign_translations VALUES(971,546,101,'5.34','«Конец пешеходной зоны».','2025-11-06 21:16:35','2025-11-06 21:16:35','5.34');
INSERT INTO road_sign_translations VALUES(972,547,100,'6.1',unistr('"General maximum speed limit". defined by the rules\u000d\u000a              General maximum speed limit.'),'2025-11-06 21:16:37','2025-11-06 21:16:37','6.1');
INSERT INTO road_sign_translations VALUES(973,547,101,'6.1',unistr('«Общий предел максимальной скорости». определяется правилами\u000d\u000a              Общее ограничение максимальной скорости.'),'2025-11-06 21:16:37','2025-11-06 21:16:37','6.1');
INSERT INTO road_sign_translations VALUES(974,548,100,'6.2',unistr('"Recommended speed". to travel on a given section of the road\u000d\u000a              preferred speed.\u000d\u000a              The zone of influence of the sign extends to the nearest intersection, however, if the sign\u000d\u000a                applied together with a warning sign, the zone of influence is determined to be dangerous\u000d\u000a                along the length of the section.'),'2025-11-06 21:16:38','2025-11-06 21:16:38','6.2');
INSERT INTO road_sign_translations VALUES(975,548,101,'6.2',unistr('«Рекомендуемая скорость». ехать по заданному участку дороги\u000d\u000a              предпочтительная скорость.\u000d\u000a              Зона действия знака распространяется до ближайшего перекрестка, однако, если знак\u000d\u000a                применяется вместе с предупреждающим знаком, зона воздействия определяется как опасная\u000d\u000a                по длине сечения.'),'2025-11-06 21:16:38','2025-11-06 21:16:38','6.2');
INSERT INTO road_sign_translations VALUES(976,549,100,'6.3.1','"Place of return". turning left is prohibited.','2025-11-06 21:16:39','2025-11-06 21:16:39','6.3.1');
INSERT INTO road_sign_translations VALUES(977,549,101,'6.3.1','«Место возвращения». поворот налево запрещен.','2025-11-06 21:16:39','2025-11-06 21:16:39','6.3.1');
INSERT INTO road_sign_translations VALUES(978,550,100,'6.3.2',unistr('"Return zone". the length of the zone for the return. Left turn\u000d\u000a              is prohibited.'),'2025-11-06 21:16:41','2025-11-06 21:16:41','6.3.2');
INSERT INTO road_sign_translations VALUES(979,550,101,'6.3.2',unistr('«Возвратная зона». длина зоны возврата. Левый поворот\u000d\u000a              запрещено.'),'2025-11-06 21:16:41','2025-11-06 21:16:41','6.3.2');
INSERT INTO road_sign_translations VALUES(980,551,100,'6.4','"Parking place".','2025-11-06 21:16:42','2025-11-06 21:16:42','6.4');
INSERT INTO road_sign_translations VALUES(981,551,101,'6.4','«Место для парковки».','2025-11-06 21:16:42','2025-11-06 21:16:42','6.4');
INSERT INTO road_sign_translations VALUES(982,552,100,'6.5','"Emergency stop zone". emergency stop zone on a steep descent.','2025-11-06 21:16:43','2025-11-06 21:16:43','6.5');
INSERT INTO road_sign_translations VALUES(983,552,101,'6.5','«Зона аварийной остановки». зона аварийной остановки на крутом спуске.','2025-11-06 21:16:43','2025-11-06 21:16:43','6.5');
INSERT INTO road_sign_translations VALUES(984,553,100,'6.6','"Underground pedestrian passage".','2025-11-06 21:16:44','2025-11-06 21:16:44','6.6');
INSERT INTO road_sign_translations VALUES(985,553,101,'6.6','«Подземный пешеходный переход».','2025-11-06 21:16:44','2025-11-06 21:16:44','6.6');
INSERT INTO road_sign_translations VALUES(986,554,100,'6.7','"Overground pedestrian crossing".','2025-11-06 21:16:47','2025-11-06 21:16:47','6.7');
INSERT INTO road_sign_translations VALUES(987,554,101,'6.7','«Наземный пешеходный переход».','2025-11-06 21:16:47','2025-11-06 21:16:47','6.7');
INSERT INTO road_sign_translations VALUES(988,555,100,'6.8.1','"Dead end". a road without a through passage.','2025-11-06 21:16:48','2025-11-06 21:16:48','6.8.1');
INSERT INTO road_sign_translations VALUES(989,555,101,'6.8.1','"Тупик". дорога без сквозного проезда.','2025-11-06 21:16:48','2025-11-06 21:16:48','6.8.1');
INSERT INTO road_sign_translations VALUES(990,556,100,'6.9.1','6.9.1. "Indicator of directions", 6.9.2. "Preliminary direction indicator". driving directions to the settlements and other objects indicated on the sign. These signs may display the image of the 6.14.1 sign, highway, airport logos and other icons. 6.9.1 images of other signs informing about traffic features may be depicted on the sign. 6.9.1 The distance from the place of installation of the sign to the intersection or the beginning of the braking zone is indicated in the lower part of the sign. The sign 6.9.1 is also used to give information about the direction of bypassing the road section equipped with any of the prohibiting signs 3.11 - 3.15;','2025-11-06 21:16:50','2025-11-06 21:16:50','6.9.1');
INSERT INTO road_sign_translations VALUES(991,556,101,'6.9.1','6.9.1. «Индикатор направлений», 6.9.2. «Предварительный указатель направления». схемы проезда к населенным пунктам и другим объектам, указанным на знаке. На этих знаках может отображаться изображение знака 6.14.1, логотипов шоссе, аэропорта и других значков. 6.9.1 На знаке могут быть изображены изображения других знаков, информирующих об особенностях дорожного движения. 6.9.1 Расстояние от места установки знака до перекрестка или начала зоны торможения указывается в нижней части знака. Знак 6.9.1 применяется также для указания направления объезда участка дороги, оборудованного любым из запрещающих знаков 3.11 – 3.15;','2025-11-06 21:16:50','2025-11-06 21:16:50','6.9.1');
INSERT INTO road_sign_translations VALUES(992,557,100,'6.9.3',unistr('"Traffic Scheme". in case of prohibition of certain maneuvers at intersections\u000d\u000a              traffic route or traffic clearance at complex intersections\u000d\u000a              directions.'),'2025-11-06 21:16:52','2025-11-06 21:16:52','6.9.3');
INSERT INTO road_sign_translations VALUES(993,557,101,'6.9.3',unistr('«Схема дорожного движения». в случае запрета определенных маневров на перекрестках\u000d\u000a              маршрут движения или разрешение дорожного движения на сложных перекрестках\u000d\u000a              направления.'),'2025-11-06 21:16:52','2025-11-06 21:16:52','6.9.3');
INSERT INTO road_sign_translations VALUES(994,558,100,'6.10.1',unistr('6.10.1. "Indicator of directions", 6.10.2. "Right\u000d\u000a              indicator". driving directions to waypoints. Signs may indicate\u000d\u000a              the distances to those objects (km), depicted on the highway,\u000d\u000a              airport logos and other icons;'),'2025-11-06 21:16:53','2025-11-06 21:16:53','6.10.1');
INSERT INTO road_sign_translations VALUES(995,558,101,'6.10.1',unistr('6.10.1. «Индикатор направлений», 6.10.2. «Правильно\u000d\u000a              индикатор». маршруты проезда к путевым точкам. Знаки могут указывать\u000d\u000a              расстояния до тех объектов (км), изображенных на трассе,\u000d\u000a              логотипы аэропортов и другие значки;'),'2025-11-06 21:16:53','2025-11-06 21:16:53','6.10.1');
INSERT INTO road_sign_translations VALUES(996,559,100,'6.11',unistr('"Name of object". apart from settlements, the name of another object (river, lake,\u000d\u000a              mountain pass, landmark, etc.).'),'2025-11-06 21:16:55','2025-11-06 21:16:55','6.11');
INSERT INTO road_sign_translations VALUES(997,559,101,'6.11',unistr('«Название объекта». кроме населенных пунктов, название другого объекта (реки, озера,\u000d\u000a              горный перевал, ориентир и т. д.).'),'2025-11-06 21:16:55','2025-11-06 21:16:55','6.11');
INSERT INTO road_sign_translations VALUES(998,560,100,'6.12',unistr('"Indicator of distances". until there are settlements on the route\u000d\u000a              distance (km).'),'2025-11-06 21:16:57','2025-11-06 21:16:57','6.12');
INSERT INTO road_sign_translations VALUES(999,560,101,'6.12',unistr('«Индикатор расстояний». пока на маршруте не появятся населенные пункты\u000d\u000a              расстояние (км).'),'2025-11-06 21:16:57','2025-11-06 21:16:57','6.12');
INSERT INTO road_sign_translations VALUES(1000,561,100,'6.13',unistr('"Kilometer sign". the distance to the start or end of the road\u000d\u000a              (km):'),'2025-11-06 21:16:59','2025-11-06 21:16:59','6.13');
INSERT INTO road_sign_translations VALUES(1001,561,101,'6.13',unistr('«Километровый знак». расстояние до начала или конца дороги\u000d\u000a              (км):'),'2025-11-06 21:16:59','2025-11-06 21:16:59','6.13');
INSERT INTO road_sign_translations VALUES(1002,562,100,'6.14.1',unistr('"Route number". 6.14.1: on the road (route)\u000d\u000a              assigned number, 6.14.2 - road (route) number and direction;'),'2025-11-06 21:17:00','2025-11-06 21:17:00','6.14.1');
INSERT INTO road_sign_translations VALUES(1003,562,101,'6.14.1',unistr('«Номер маршрута». 6.14.1: в дороге (маршруте)\u000d\u000a              присвоенный номер, 6.14.2 – номер дороги (маршрута) и направление;'),'2025-11-06 21:17:00','2025-11-06 21:17:00','6.14.1');
INSERT INTO road_sign_translations VALUES(1004,563,100,'6.15.1',unistr('"Traffic direction for trucks".\u000d\u000a              recommended for trucks, tractors and self-propelled vehicles\u000d\u000a              the direction of traffic if their traffic is in either direction at the intersection\u000d\u000a              it is forbidden.'),'2025-11-06 21:17:02','2025-11-06 21:17:02','6.15.1');
INSERT INTO road_sign_translations VALUES(1005,563,101,'6.15.1',unistr('«Направление движения грузовых автомобилей».\u000d\u000a              рекомендуется для грузовых автомобилей, тракторов и самоходных машин.\u000d\u000a              направление движения, если на перекрестке движение идет в любом направлении\u000d\u000a              это запрещено.'),'2025-11-06 21:17:02','2025-11-06 21:17:02','6.15.1');
INSERT INTO road_sign_translations VALUES(1006,564,100,'6.16',unistr('"Stop line". in case of traffic light (regulator) prohibiting signal\u000d\u000a              vehicle parking place.'),'2025-11-06 21:17:03','2025-11-06 21:17:03','6.16');
INSERT INTO road_sign_translations VALUES(1007,564,101,'6.16',unistr('«Стоп-линия». в случае запрещающего сигнала светофора (регулятора)\u000d\u000a              место для стоянки автотранспорта.'),'2025-11-06 21:17:03','2025-11-06 21:17:03','6.16');
INSERT INTO road_sign_translations VALUES(1008,565,100,'6.17',unistr('"Transfer scheme". section of the road temporarily closed to traffic\u000d\u000a              bypass route.'),'2025-11-06 21:17:03','2025-11-06 21:17:03','6.17');
INSERT INTO road_sign_translations VALUES(1009,565,101,'6.17',unistr('«Схема трансфера». участок дороги временно закрыт для движения\u000d\u000a              обходной путь.'),'2025-11-06 21:17:03','2025-11-06 21:17:03','6.17');
INSERT INTO road_sign_translations VALUES(1010,566,100,'6.18.1',unistr('"Transfer direction". temporarily closed to traffic\u000d\u000a              direction of bypassing the road section.'),'2025-11-06 21:17:05','2025-11-06 21:17:05','6.18.1');
INSERT INTO road_sign_translations VALUES(1011,566,101,'6.18.1',unistr('«Направление трансфера». временно закрыто для движения\u000d\u000a              направление обхода участка дороги.'),'2025-11-06 21:17:05','2025-11-06 21:17:05','6.18.1');
INSERT INTO road_sign_translations VALUES(1012,567,100,'6.19.1',unistr('"Preliminary indicator of rerouting to another lane".\u000d\u000a              bypassing the part of the roadway closed to traffic with the dividing line\u000d\u000a              or direction of traffic to return to the right-hand lane.'),'2025-11-06 21:17:06','2025-11-06 21:17:06','6.19.1');
INSERT INTO road_sign_translations VALUES(1013,567,101,'6.19.1',unistr('«Предварительный индикатор перенаправления на другую полосу».\u000d\u000a              обход закрытой для движения части проезжей части с разделительной линией\u000d\u000a              или направление движения, чтобы вернуться на правую полосу.'),'2025-11-06 21:17:06','2025-11-06 21:17:06','6.19.1');
INSERT INTO road_sign_translations VALUES(1014,568,100,'6.20.1',unistr('"Emergency exit". in the tunnel shows the place where\u000d\u000a              where is the emergency exit?'),'2025-11-06 21:17:07','2025-11-06 21:17:07','6.20.1');
INSERT INTO road_sign_translations VALUES(1015,568,101,'6.20.1',unistr('"Запасный выход". в тоннеле показано место, где\u000d\u000a              где аварийный выход?'),'2025-11-06 21:17:07','2025-11-06 21:17:07','6.20.1');
INSERT INTO road_sign_translations VALUES(1016,569,100,'6.21.1',unistr('"Direction of movement to the emergency exit". shows\u000d\u000a              the direction to the emergency exit and the distance to the emergency exit.'),'2025-11-06 21:17:08','2025-11-06 21:17:08','6.21.1');
INSERT INTO road_sign_translations VALUES(1017,569,101,'6.21.1',unistr('«Направление движения к запасному выходу». шоу\u000d\u000a              направление к запасному выходу и расстояние до запасного выхода.'),'2025-11-06 21:17:08','2025-11-06 21:17:08','6.21.1');
INSERT INTO road_sign_translations VALUES(1018,570,100,'7.1','"First medical aid point".','2025-11-06 21:17:09','2025-11-06 21:17:09','7.1');
INSERT INTO road_sign_translations VALUES(1019,570,101,'7.1','«Пункт первой медицинской помощи».','2025-11-06 21:17:09','2025-11-06 21:17:09','7.1');
INSERT INTO road_sign_translations VALUES(1020,571,100,'7.2','"Hospital".','2025-11-06 21:17:10','2025-11-06 21:17:10','7.2');
INSERT INTO road_sign_translations VALUES(1021,571,101,'7.2','«Больница».','2025-11-06 21:17:10','2025-11-06 21:17:10','7.2');
INSERT INTO road_sign_translations VALUES(1022,572,100,'7.3','"Car filling station".','2025-11-06 21:17:11','2025-11-06 21:17:11','7.3');
INSERT INTO road_sign_translations VALUES(1023,572,101,'7.3','«Автозаправочная станция».','2025-11-06 21:17:11','2025-11-06 21:17:11','7.3');
INSERT INTO road_sign_translations VALUES(1024,573,100,'7.4','"Technical maintenance of cars".','2025-11-06 21:17:12','2025-11-06 21:17:12','7.4');
INSERT INTO road_sign_translations VALUES(1025,573,101,'7.4','«Техническое обслуживание автомобилей».','2025-11-06 21:17:12','2025-11-06 21:17:12','7.4');
INSERT INTO road_sign_translations VALUES(1026,574,100,'7.5','"Car wash".','2025-11-06 21:17:13','2025-11-06 21:17:13','7.5');
INSERT INTO road_sign_translations VALUES(1027,574,101,'7.5','«Автомойка».','2025-11-06 21:17:13','2025-11-06 21:17:13','7.5');
INSERT INTO road_sign_translations VALUES(1028,575,100,'7.6','"Telephone".','2025-11-06 21:17:14','2025-11-06 21:17:14','7.6');
INSERT INTO road_sign_translations VALUES(1029,575,101,'7.6','«Телефон».','2025-11-06 21:17:14','2025-11-06 21:17:14','7.6');
INSERT INTO road_sign_translations VALUES(1030,576,100,'7.7','"Food point".','2025-11-06 21:17:14','2025-11-06 21:17:14','7.7');
INSERT INTO road_sign_translations VALUES(1031,576,101,'7.7','«Пищевая точка».','2025-11-06 21:17:14','2025-11-06 21:17:14','7.7');
INSERT INTO road_sign_translations VALUES(1032,577,100,'7.8','"Drinking water".','2025-11-06 21:17:15','2025-11-06 21:17:15','7.8');
INSERT INTO road_sign_translations VALUES(1033,577,101,'7.8','«Питьевая вода».','2025-11-06 21:17:15','2025-11-06 21:17:15','7.8');
INSERT INTO road_sign_translations VALUES(1034,578,100,'7.9','"Hotel or motel".','2025-11-06 21:17:16','2025-11-06 21:17:16','7.9');
INSERT INTO road_sign_translations VALUES(1035,578,101,'7.9','«Отель или мотель».','2025-11-06 21:17:16','2025-11-06 21:17:16','7.9');
INSERT INTO road_sign_translations VALUES(1036,579,100,'7.10','"Hangrvan".','2025-11-06 21:17:17','2025-11-06 21:17:17','7.10');
INSERT INTO road_sign_translations VALUES(1037,579,101,'7.10','«Хангрван».','2025-11-06 21:17:17','2025-11-06 21:17:17','7.10');
INSERT INTO road_sign_translations VALUES(1038,580,100,'7.11','"Rest place".','2025-11-06 21:17:18','2025-11-06 21:17:18','7.11');
INSERT INTO road_sign_translations VALUES(1039,580,101,'7.11','«Место отдыха».','2025-11-06 21:17:18','2025-11-06 21:17:18','7.11');
INSERT INTO road_sign_translations VALUES(1040,581,100,'7.12','"Traffic police checkpoint of the traffic service".','2025-11-06 21:17:19','2025-11-06 21:17:19','7.12');
INSERT INTO road_sign_translations VALUES(1041,581,101,'7.12','«КПП ГИБДД ГИБДД».','2025-11-06 21:17:19','2025-11-06 21:17:19','7.12');
INSERT INTO road_sign_translations VALUES(1042,582,100,'7.13','"Police".','2025-11-06 21:17:20','2025-11-06 21:17:20','7.13');
INSERT INTO road_sign_translations VALUES(1043,582,101,'7.13','"Полиция".','2025-11-06 21:17:20','2025-11-06 21:17:20','7.13');
INSERT INTO road_sign_translations VALUES(1044,583,100,'7.14','"Control point of international automobile transportation".','2025-11-06 21:17:20','2025-11-06 21:17:20','7.14');
INSERT INTO road_sign_translations VALUES(1045,583,101,'7.14','«Пункт управления международными автомобильными перевозками».','2025-11-06 21:17:20','2025-11-06 21:17:20','7.14');
INSERT INTO road_sign_translations VALUES(1046,584,100,'7.15',unistr('"Traffic information radio station\u000d\u000a              zone of action". section of the road where the sign is carried out\u000d\u000a              reception of frequency reports.'),'2025-11-06 21:17:21','2025-11-06 21:17:21','7.15');
INSERT INTO road_sign_translations VALUES(1047,584,101,'7.15',unistr('«Радиостанция дорожной информации»\u000d\u000a              зона действия». участок дороги, на котором установлен знак\u000d\u000a              прием частотных сводок.'),'2025-11-06 21:17:21','2025-11-06 21:17:21','7.15');
INSERT INTO road_sign_translations VALUES(1048,585,100,'7.16',unistr('"Radio communication zone with emergency services". part of the road where\u000d\u000a              there is a radio communication system with emergency services, indicated on the sign\u000d\u000a              with civil frequency.'),'2025-11-06 21:17:23','2025-11-06 21:17:23','7.16');
INSERT INTO road_sign_translations VALUES(1049,585,101,'7.16',unistr('«Зона радиосвязи с экстренными службами». часть дороги, где\u000d\u000a              имеется система радиосвязи с экстренными службами, указанная на знаке\u000d\u000a              с гражданской частотой.'),'2025-11-06 21:17:23','2025-11-06 21:17:23','7.16');
INSERT INTO road_sign_translations VALUES(1050,586,100,'7.17','"Swimming pool or beach".','2025-11-06 21:17:24','2025-11-06 21:17:24','7.17');
INSERT INTO road_sign_translations VALUES(1051,586,101,'7.17','«Бассейн или пляж».','2025-11-06 21:17:24','2025-11-06 21:17:24','7.17');
INSERT INTO road_sign_translations VALUES(1052,587,100,'7.18','"Toilet".','2025-11-06 21:17:25','2025-11-06 21:17:25','7.18');
INSERT INTO road_sign_translations VALUES(1053,587,101,'7.18','"Туалет".','2025-11-06 21:17:25','2025-11-06 21:17:25','7.18');
INSERT INTO road_sign_translations VALUES(1054,588,100,'7.19',unistr('"Emergency phone". shows the place where the operative is located\u000d\u000a              phone number to contact services.'),'2025-11-06 21:17:27','2025-11-06 21:17:27','7.19');
INSERT INTO road_sign_translations VALUES(1055,588,101,'7.19',unistr('«Телефон экстренной помощи». показывает место, где находится оперативник\u000d\u000a              номер телефона для связи со службами.'),'2025-11-06 21:17:27','2025-11-06 21:17:27','7.19');
INSERT INTO road_sign_translations VALUES(1056,589,100,'7.20','"Fire extinguisher". shows where the fire extinguisher is located.','2025-11-06 21:17:28','2025-11-06 21:17:28','7.20');
INSERT INTO road_sign_translations VALUES(1057,589,101,'7.20','"Огнетушитель". показывает, где находится огнетушитель.','2025-11-06 21:17:28','2025-11-06 21:17:28','7.20');
INSERT INTO road_sign_translations VALUES(1058,590,100,'8.1.1',unistr('"Distance to the object". points in the direction of travel from the sign\u000d\u000a              before the start of the dangerous section, at the place or in front of the appropriate restriction\u000d\u000a              the distance to a certain object (place).'),'2025-11-06 21:17:30','2025-11-06 21:17:30','8.1.1');
INSERT INTO road_sign_translations VALUES(1059,590,101,'8.1.1',unistr('«Расстояние до объекта». указывает направление движения от знака\u000d\u000a              перед началом опасного участка, на месте или перед соответствующим ограничением\u000d\u000a              расстояние до определенного объекта (места).'),'2025-11-06 21:17:30','2025-11-06 21:17:30','8.1.1');
INSERT INTO road_sign_translations VALUES(1060,591,100,'8.1.2',unistr('"Distance to the object". shows 2.4 from the "Give way" sign\u000d\u000a              the distance to the intersection when 2.5` is installed immediately before the intersection\u000d\u000a              "Traffic without stopping is prohibited" sign.'),'2025-11-06 21:17:31','2025-11-06 21:17:31','8.1.2');
INSERT INTO road_sign_translations VALUES(1061,591,101,'8.1.2',unistr('«Расстояние до объекта». показывает 2.4 от знака "Уступи дорогу"\u000d\u000a              расстояние до перекрестка при установке 2,5` непосредственно перед перекрестком\u000d\u000a              Знак «Движение без остановки запрещено».'),'2025-11-06 21:17:31','2025-11-06 21:17:31','8.1.2');
INSERT INTO road_sign_translations VALUES(1062,592,100,'8.1.3',unistr('"Distance to the object". shows the distance\u000d\u000a              to an off-road object.'),'2025-11-06 21:17:32','2025-11-06 21:17:32','8.1.3');
INSERT INTO road_sign_translations VALUES(1063,592,101,'8.1.3',unistr('«Расстояние до объекта». показывает расстояние\u000d\u000a              на объект бездорожья.'),'2025-11-06 21:17:32','2025-11-06 21:17:32','8.1.3');
INSERT INTO road_sign_translations VALUES(1064,593,100,'8.2.1',unistr('"Zone of influence". indicates a road equipped with warning signs\u000d\u000a              the length of the dangerous section or the zone of influence of prohibitory and informative signs;'),'2025-11-06 21:17:33','2025-11-06 21:17:33','8.2.1');
INSERT INTO road_sign_translations VALUES(1065,593,101,'8.2.1',unistr('«Зона влияния». указывает на дорогу, оборудованную предупреждающими знаками\u000d\u000a              протяженность опасного участка или зоны действия запрещающих и информативных знаков;'),'2025-11-06 21:17:33','2025-11-06 21:17:33','8.2.1');
INSERT INTO road_sign_translations VALUES(1066,594,100,'8.2.2',unistr('"Zone of influence". signs indicate and/or inform\u000d\u000a              are:\u000d\u000a              1) 8.2.2: 3.27: "Stopping is prohibited", 3.28: "Parking is prohibited", 3.29: "Parking\u000d\u000a                is prohibited on odd days of the month", 3.30: "Parking is prohibited on even days of the month"\u000d\u000a                the zone of influence of prohibitory signs.\u000d\u000a              2) 8.2.3: the end of the zone of influence of signs 3.27 - 3.30.\u000d\u000a              3) 8.2.4: 3.27 - 3.30 about being in the zone of influence.\u000d\u000a              4) the direction and zone of influence of signs 8.2.5, 7.2.6, 3.27 - 3.30, square,\u000d\u000a                prohibition of standing or parking along one side of the building facade and other places\u000d\u000a                case.'),'2025-11-06 21:17:34','2025-11-06 21:17:34','8.2.2');
INSERT INTO road_sign_translations VALUES(1067,594,101,'8.2.2',unistr('«Зона влияния». знаки указывают и/или информируют\u000d\u000a              являются:\u000d\u000a              1) 8.2.2:3.27: «Остановка запрещена», 3.28: «Стоянка запрещена», 3.29: «Стоянка\u000d\u000a                запрещена в нечетные дни месяца", 3.30: "Стоянка запрещена в четные дни месяца"\u000d\u000a                зона действия запрещающих знаков.\u000d\u000a              2) 8.2.3: окончание зоны влияния знаков 3.27 – 3.30.\u000d\u000a              3) 8.2.4:3.27 - 3.30 о нахождении в зоне влияния.\u000d\u000a              4) направление и зона влияния знаков 8.2.5, 7.2.6, 3.27 – 3.30, квадрат,\u000d\u000a                запрет стоять или парковаться вдоль одной стороны фасада здания и в других местах\u000d\u000a                случай.'),'2025-11-06 21:17:34','2025-11-06 21:17:34','8.2.2');
INSERT INTO road_sign_translations VALUES(1068,595,100,'8.3.1',unistr('"Directions of influence". are shown before the intersection\u000d\u000a              directions of impact of posted signs or traffic directions - to\u000d\u000a              the objects immediately near the road.'),'2025-11-06 21:17:35','2025-11-06 21:17:35','8.3.1');
INSERT INTO road_sign_translations VALUES(1069,595,101,'8.3.1',unistr('«Направления воздействия». показаны перед перекрёстком\u000d\u000a              направления воздействия вывешенных знаков или направлений движения -\u000d\u000a              объекты непосредственно возле дороги.'),'2025-11-06 21:17:35','2025-11-06 21:17:35','8.3.1');
INSERT INTO road_sign_translations VALUES(1070,596,100,'8.4.1',unistr('"Type of vehicle". is a demonstration\u000d\u000a              gives the type of vehicle to which the sign applies. This\u000d\u000a              The effect of signs used with signs extends to:\u000d\u000a              1) 8.4.1: a truck with a permissible maximum weight of more than 3.5 tons,\u000d\u000a                including also on vehicles operated with a trailer,\u000d\u000a              2) 8.4.3 - light passenger car, as well as up to 3.5 tons permissible maximum\u000d\u000a                on heavy goods vehicles,\u000d\u000a              3) 8.4.8: on vehicles equipped with the "Dangerous cargo" recognition sign.'),'2025-11-06 21:17:37','2025-11-06 21:17:37','8.4.1');
INSERT INTO road_sign_translations VALUES(1071,596,101,'8.4.1',unistr('«Тип транспортного средства». это демонстрация\u000d\u000a              указывает тип транспортного средства, к которому относится этот знак. Это\u000d\u000a              Действие знаков, используемых со знаками, распространяется на:\u000d\u000a              1) 8.4.1: грузовой автомобиль с разрешенной максимальной массой более 3,5 тонн,\u000d\u000a                в том числе и на транспортных средствах, эксплуатируемых с прицепом,\u000d\u000a              2) 8.4.3 – легковой легковой автомобиль, а также разрешенная максимальная масса до 3,5 тонн.\u000d\u000a                на грузовых автомобилях,\u000d\u000a              3) 8.4.8: на транспортных средствах, оборудованных знаком «Опасный груз».'),'2025-11-06 21:17:37','2025-11-06 21:17:37','8.4.1');
INSERT INTO road_sign_translations VALUES(1072,597,100,'8.5.1',unistr('8.5.1. "Saturdays, Sundays and holidays", 8.5.2. "Working days", 8.5.3. "Of the week\u000d\u000a                days". signs inform about the days of the week during which\u000d\u000a                the sign works.'),'2025-11-06 21:17:39','2025-11-06 21:17:39','8.5.1');
INSERT INTO road_sign_translations VALUES(1073,597,101,'8.5.1',unistr('8.5.1. «Суббота, воскресенье и праздничные дни», 8.5.2. «Рабочие дни», 8.5.3. «Из недели\u000d\u000a                дни». таблички сообщают о днях недели, в течение которых\u000d\u000a                знак работает.'),'2025-11-06 21:17:39','2025-11-06 21:17:39','8.5.1');
INSERT INTO road_sign_translations VALUES(1074,598,100,'8.5.4',unistr('8.5.4, 8.5.5 - 8.5.7. "Duration of operation". 8.5.4 sign informs the day\u000d\u000a              the hours, and the signs 8.5.5 - 8.5.7 - also the days of the week during which\u000d\u000a              the sign works.'),'2025-11-06 21:17:41','2025-11-06 21:17:41','8.5.4');
INSERT INTO road_sign_translations VALUES(1075,598,101,'8.5.4',unistr('8.5.4, 8.5.5 – 8.5.7. «Продолжительность эксплуатации». 8.5.4 знак информирует день\u000d\u000a              часы, и знаки 8.5.5 - 8.5.7 - а также дни недели, в течение которых\u000d\u000a              знак работает.'),'2025-11-06 21:17:41','2025-11-06 21:17:41','8.5.4');
INSERT INTO road_sign_translations VALUES(1076,599,100,'8.6.1',unistr('"The manner of stopping the vehicle for parking\u000d\u000a              places". show the ways of stopping vehicles:\u000d\u000a              1) 8.6.1 - on the carriageway, along the length of the pavement - for all vehicles\u000d\u000a                for\u000d\u000a              2) 8.6.2 - 8.6.9: in the curbside parking place for light passenger cars and\u000d\u000a                for motorcycles.'),'2025-11-06 21:17:43','2025-11-06 21:17:43','8.6.1');
INSERT INTO road_sign_translations VALUES(1077,599,101,'8.6.1',unistr('«Способ остановки транспортного средства для стоянки\u000d\u000a              места». показать способы остановки транспортных средств:\u000d\u000a              1) 8.6.1 - на проезжей части, по длине тротуара - для всех транспортных средств\u000d\u000a                для\u000d\u000a              2) 8.6.2 – 8.6.9: на тротуарной стоянке легковых автомобилей и\u000d\u000a                для мотоциклов.'),'2025-11-06 21:17:43','2025-11-06 21:17:43','8.6.1');
INSERT INTO road_sign_translations VALUES(1078,600,100,'8.7',unistr('"Parking with the engine not running". indicates that 6.4 "Parking place"\u000d\u000a              Parking of vehicles is allowed in the parking place equipped with a sign\u000d\u000a              only with the engine not running.'),'2025-11-06 21:17:44','2025-11-06 21:17:44','8.7');
INSERT INTO road_sign_translations VALUES(1079,600,101,'8.7',unistr('«Парковка с неработающим двигателем». указывает, что 6.4 «Место парковки»\u000d\u000a              Парковка транспортных средств разрешается на стоянке, оборудованной знаком.\u000d\u000a              только при неработающем двигателе.'),'2025-11-06 21:17:45','2025-11-06 21:17:45','8.7');
INSERT INTO road_sign_translations VALUES(1080,601,100,'8.8',unistr('"Paid services". informs that the services provided\u000d\u000a              are paid.'),'2025-11-06 21:17:46','2025-11-06 21:17:46','8.8');
INSERT INTO road_sign_translations VALUES(1081,601,101,'8.8',unistr('«Платные услуги». сообщает, что оказанные услуги\u000d\u000a              платятся.'),'2025-11-06 21:17:46','2025-11-06 21:17:46','8.8');
INSERT INTO road_sign_translations VALUES(1082,602,100,'8.9',unistr('"Parking duration limit". informs 6.4: "Parking place"\u000d\u000a              maximum stay of a vehicle in a parking place equipped with a sign\u000d\u000a              about the duration.'),'2025-11-06 21:17:47','2025-11-06 21:17:47','8.9');
INSERT INTO road_sign_translations VALUES(1083,602,101,'8.9',unistr('«Ограничение продолжительности парковки». сообщает 6.4: «Место парковки»\u000d\u000a              максимальное пребывание транспортного средства на стоянке, оборудованной знаком\u000d\u000a              о продолжительности.'),'2025-11-06 21:17:47','2025-11-06 21:17:47','8.9');
INSERT INTO road_sign_translations VALUES(1084,603,100,'8.10',unistr('"Car inspection place". informs that 6.4 "Parking place" or\u000d\u000a              7.11: Vehicle inspection is available in the square equipped with the "Rest Place" sign\u000d\u000a              a hole or other facility intended for'),'2025-11-06 21:17:48','2025-11-06 21:17:48','8.10');
INSERT INTO road_sign_translations VALUES(1085,603,101,'8.10',unistr('«Место техосмотра». сообщает, что 6.4 «Место парковки» или\u000d\u000a              7.11: Осмотр автомобиля осуществляется на площади, оборудованной знаком «Место отдыха».\u000d\u000a              яма или другое сооружение, предназначенное для'),'2025-11-06 21:17:48','2025-11-06 21:17:48','8.10');
INSERT INTO road_sign_translations VALUES(1086,604,100,'8.11',unistr('"Limitation of the maximum permissible mass". informs to sign\u000d\u000a              the effect only applies to vehicles that are allowed\u000d\u000a              the maximum mass is greater than that indicated on the label;'),'2025-11-06 21:17:50','2025-11-06 21:17:50','8.11');
INSERT INTO road_sign_translations VALUES(1087,604,101,'8.11',unistr('«Ограничение максимально допустимой массы». сообщает подписать\u000d\u000a              эффект распространяется только на транспортные средства, которым разрешено\u000d\u000a              максимальная масса больше указанной на этикетке;'),'2025-11-06 21:17:50','2025-11-06 21:17:50','8.11');
INSERT INTO road_sign_translations VALUES(1088,605,100,'8.12',unistr('"Dangerous bed". warns that repair work is being carried out\u000d\u000a              because it is dangerous to enter the bed. 1.25 "Road\u000d\u000a              works" with the sign.'),'2025-11-06 21:17:52','2025-11-06 21:17:52','8.12');
INSERT INTO road_sign_translations VALUES(1089,605,101,'8.12',unistr('«Опасная кровать». предупреждает о том, что ведутся ремонтные работы\u000d\u000a              потому что опасно заходить в кровать. 1,25 "Дорога\u000d\u000a              работает» со знаком.'),'2025-11-06 21:17:52','2025-11-06 21:17:52','8.12');
INSERT INTO road_sign_translations VALUES(1090,606,100,'8.13',unistr('"Direction of the main road". shows the main road\u000d\u000a              the direction at the intersection.'),'2025-11-06 21:17:52','2025-11-06 21:17:52','8.13');
INSERT INTO road_sign_translations VALUES(1091,606,101,'8.13',unistr('«Направление главной дороги». показывает главную дорогу\u000d\u000a              направление на перекрёстке.'),'2025-11-06 21:17:52','2025-11-06 21:17:52','8.13');
INSERT INTO road_sign_translations VALUES(1092,607,100,'8.14',unistr('"Traffic lane". indicates the traffic lane on which\u000d\u000a              the effect of a sign or traffic light is extended;'),'2025-11-06 21:17:54','2025-11-06 21:17:54','8.14');
INSERT INTO road_sign_translations VALUES(1093,607,101,'8.14',unistr('«Транспортная полоса». указывает полосу движения, на которой\u000d\u000a              продлевается эффект знака или светофора;'),'2025-11-06 21:17:54','2025-11-06 21:17:54','8.14');
INSERT INTO road_sign_translations VALUES(1094,608,100,'8.15',unistr('"Blind pedestrians". informs that the pedestrian crossing is used\u000d\u000a              the blind. 1.22, 5.19.1 and 5.19.2 apply to "Pedestrian crossing" signs and\u000d\u000a              with traffic lights.'),'2025-11-06 21:17:57','2025-11-06 21:17:57','8.15');
INSERT INTO road_sign_translations VALUES(1095,608,101,'8.15',unistr('«Слепые пешеходы». сообщает, что пешеходный переход используется\u000d\u000a              слепой. 1.22, 5.19.1 и 5.19.2 распространяются на знаки «Пешеходный переход» и\u000d\u000a              со светофорами.'),'2025-11-06 21:17:57','2025-11-06 21:17:57','8.15');
INSERT INTO road_sign_translations VALUES(1096,609,100,'8.16',unistr('"Wet coating". informs that the effect of the sign only works\u000d\u000a              during the period during which the pavement is wet;'),'2025-11-06 21:17:58','2025-11-06 21:17:58','8.16');
INSERT INTO road_sign_translations VALUES(1097,609,101,'8.16',unistr('«Мокрое покрытие». сообщает, что эффект знака работает только\u000d\u000a              в период, когда дорожное покрытие влажное;'),'2025-11-06 21:17:58','2025-11-06 21:17:58','8.16');
INSERT INTO road_sign_translations VALUES(1098,610,100,'8.17',unistr('"Disabled people". informs that 6.4 - Effect of "Parking place" sign\u000d\u000a              applies only to motorcycles and motor vehicles equipped with\u000d\u000a              With the "Disabled" recognition sign.'),'2025-11-06 21:17:59','2025-11-06 21:17:59','8.17');
INSERT INTO road_sign_translations VALUES(1099,610,101,'8.17',unistr('«Инвалиды». сообщает, что 6.4 - Действие знака «Место для парковки»\u000d\u000a              распространяется только на мотоциклы и автомобили, оснащенные\u000d\u000a              С опознавательным знаком «Инвалид».'),'2025-11-06 21:17:59','2025-11-06 21:17:59','8.17');
INSERT INTO road_sign_translations VALUES(1100,611,100,'8.18',unistr('"Except for the disabled". informs that the effect of the mark does not extend\u000d\u000a              On motorcycles and cars equipped with the "Disabled" recognition sign.'),'2025-11-06 21:18:00','2025-11-06 21:18:00','8.18');
INSERT INTO road_sign_translations VALUES(1101,611,101,'8.18',unistr('«Кроме инвалидов». сообщает, что действие отметки не распространяется\u000d\u000a              На мотоциклах и автомобилях, оборудованных знаком «Инвалид».'),'2025-11-06 21:18:00','2025-11-06 21:18:00','8.18');
INSERT INTO road_sign_translations VALUES(1102,612,100,'8.19',unistr('"Dangerous cargo class". indicates the dangerous goods class(es)\u000d\u000a              number according to the standard.\u000d\u000a              3.32 "Traffic of vehicles with dangerous goods" applies\u000d\u000a                is prohibited" and 4.8.1 - 4.8.3: "Vehicles with dangerous goods\u000d\u000a                with traffic direction" signs.'),'2025-11-06 21:18:01','2025-11-06 21:18:01','8.19');
INSERT INTO road_sign_translations VALUES(1103,612,101,'8.19',unistr('«Класс опасного груза». указывает класс(ы) опасного груза\u000d\u000a              номер по стандарту.\u000d\u000a              3.32 «Движение транспортных средств с опасными грузами» применяется.\u000d\u000a                запрещено» и 4.8.1 – 4.8.3: «Транспортные средства с опасными грузами\u000d\u000a                с указанием направления движения».'),'2025-11-06 21:18:01','2025-11-06 21:18:01','8.19');
INSERT INTO road_sign_translations VALUES(1104,613,100,'8.20.1',unistr('"Vehicle stroller type". 3.12 mark apply\u000d\u000a              with and indicates the number of axles of the vehicle being approached, each of which\u000d\u000a              the mass indicated on the number sign is considered to be marginally permissible.'),'2025-11-06 21:18:02','2025-11-06 21:18:02','8.20.1');
INSERT INTO road_sign_translations VALUES(1105,613,101,'8.20.1',unistr('«Тип автомобильной коляски». 3.12 отметка применяется\u000d\u000a              с и указывает количество осей подъезжающего транспортного средства, каждая из которых\u000d\u000a              масса, указанная на цифровом знаке, считается предельно допустимой.'),'2025-11-06 21:18:02','2025-11-06 21:18:02','8.20.1');
INSERT INTO road_sign_translations VALUES(1106,614,100,'8.21.1',unistr('"General use vehicle\u000d\u000a              type". Used with 6.4 sign and shows metro stations, bus\u000d\u000a              (trolley) or parking of vehicles near tram stops\u000d\u000a              the squares intended for'),'2025-11-06 21:18:03','2025-11-06 21:18:03','8.21.1');
INSERT INTO road_sign_translations VALUES(1107,614,101,'8.21.1',unistr('«Автомобиль общего назначения\u000d\u000a              тип». Используется со знаком 6.4 и показывает станции метро, автобус.\u000d\u000a              (троллейбус) или парковка транспортных средств возле трамвайных остановок\u000d\u000a              квадраты, предназначенные для'),'2025-11-06 21:18:03','2025-11-06 21:18:03','8.21.1');
INSERT INTO road_sign_translations VALUES(1108,615,100,'8.22.1',unistr('"Obstacle". apply with symbols 4.2.1 - 4.2.3 and\u000d\u000a              shows the obstacle and the direction to avoid it.\u000d\u000a              Tables are placed directly below the symbols with which they apply.\u000d\u000a                If the signs are placed above the carriageway, curb or sidewalk, then 8.2.2 -\u000d\u000a                Signs 8.2.4 and 8.13 may be placed next to the sign.'),'2025-11-06 21:18:04','2025-11-06 21:18:04','8.22.1');
INSERT INTO road_sign_translations VALUES(1109,615,101,'8.22.1',unistr('"Препятствие". применять с символами 4.2.1 – 4.2.3 и\u000d\u000a              показывает препятствие и направление, как его избежать.\u000d\u000a              Таблицы размещаются непосредственно под символами, с которыми они применяются.\u000d\u000a                Если знаки расположены над проезжей частью, бордюром или тротуаром, то 8.2.2 -\u000d\u000a                Рядом со знаком могут размещаться знаки 8.2.4 и 8.13.'),'2025-11-06 21:18:04','2025-11-06 21:18:04','8.22.1');
INSERT INTO road_sign_translations VALUES(1110,616,100,'1.4.2','"Approach to the railway line". additional warning about approaching the railway line outside the settlements;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.2');
