INSERT INTO road_sign_translations VALUES(1112,617,100,'1.4.3','"Approach to the railway line". additional warning about approaching the railway line outside the settlements;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.3');
INSERT INTO road_sign_translations VALUES(1113,617,101,'1.4.3','«Подход к железнодорожной линии». дополнительное предупреждение о приближении к железнодорожной линии за пределами населенных пунктов;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.3');
INSERT INTO road_sign_translations VALUES(1114,618,100,'1.4.4','"Approach to the railway line". additional warning about approaching the railway line outside the settlements;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.4');
INSERT INTO road_sign_translations VALUES(1115,618,101,'1.4.4','«Подход к железнодорожной линии». дополнительное предупреждение о приближении к железнодорожной линии за пределами населенных пунктов;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.4');
INSERT INTO road_sign_translations VALUES(1116,619,100,'1.4.5','"Approach to the railway line". additional warning about approaching the railway line outside the settlements;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.5');
INSERT INTO road_sign_translations VALUES(1117,619,101,'1.4.5','«Подход к железнодорожной линии». дополнительное предупреждение о приближении к железнодорожной линии за пределами населенных пунктов;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.5');
INSERT INTO road_sign_translations VALUES(1118,620,100,'1.4.6','"Approach to the railway line". additional warning about approaching the railway line outside the settlements;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.6');
INSERT INTO road_sign_translations VALUES(1119,620,101,'1.4.6','«Подход к железнодорожной линии». дополнительное предупреждение о приближении к железнодорожной линии за пределами населенных пунктов;','2025-11-06 21:18:05','2025-11-06 21:18:05','1.4.6');
INSERT INTO road_sign_translations VALUES(1120,621,100,unistr('1.11.2\u0009'),'"Dangerous turn". curvature of the road with a small radius or limited visibility: 1.11.1 - to the right, 1.11.2 - to the left;','2025-11-06 21:18:06','2025-11-06 21:18:06','1.11.2');
INSERT INTO road_sign_translations VALUES(1121,621,101,unistr('1.11.2\u0009'),'«Опасный поворот». кривизна дороги малого радиуса или ограниченной видимости: 1.11.1 – вправо, 1.11.2 – влево;','2025-11-06 21:18:06','2025-11-06 21:18:06','1.11.2');
INSERT INTO road_sign_translations VALUES(1122,622,100,unistr('1.12.2\u0009'),'"Dangerous turns". road section with dangerous turns: 1.12.1: the first turn to the right, 1.12.2: the first turn to the left;','2025-11-06 21:18:07','2025-11-06 21:18:07','1.12.2');
INSERT INTO road_sign_translations VALUES(1123,622,101,unistr('1.12.2\u0009'),'«Опасные повороты». участок дороги с опасными поворотами: 1.12.1: первый поворот направо, 1.12.2: первый поворот налево;','2025-11-06 21:18:07','2025-11-06 21:18:07','1.12.2');
INSERT INTO road_sign_translations VALUES(1124,623,100,'1.20.2','"Narrowing of the road". 1.20.1: narrowing on both sides, 1.20.2: on the right, 1.20.3: on the left.','2025-11-06 21:18:08','2025-11-06 21:18:08','1.20.2');
INSERT INTO road_sign_translations VALUES(1125,623,101,'1.20.2','«Сужение дороги». 1.20.1: сужение с обеих сторон, 1.20.2: справа, 1.20.3: слева.','2025-11-06 21:18:08','2025-11-06 21:18:08','1.20.2');
INSERT INTO road_sign_translations VALUES(1126,624,100,'1.20.3','"Narrowing of the road". 1.20.1: narrowing on both sides, 1.20.2: on the right, 1.20.3: on the left.','2025-11-06 21:18:09','2025-11-06 21:18:09','1.20.3');
INSERT INTO road_sign_translations VALUES(1127,624,101,'1.20.3','«Сужение дороги». 1.20.1: сужение с обеих сторон, 1.20.2: справа, 1.20.3: слева.','2025-11-06 21:18:09','2025-11-06 21:18:09','1.20.3');
INSERT INTO road_sign_translations VALUES(1128,625,100,'1.34.2','"Turn direction". direction of traffic on a curve with a small radius of the road with limited visibility; direction of bypassing the part of the road under repair.','2025-11-06 21:18:10','2025-11-06 21:18:10','1.34.2');
INSERT INTO road_sign_translations VALUES(1129,625,101,'1.34.2','«Направление поворота». направление движения на повороте с небольшим радиусом дороги при ограниченной видимости; направление обхода ремонтируемого участка дороги.','2025-11-06 21:18:10','2025-11-06 21:18:10','1.34.2');
INSERT INTO road_sign_translations VALUES(1130,626,100,'1.34.1','"Turn direction". direction of traffic on a curve with a small radius of the road with limited visibility; direction of bypassing the part of the road under repair.','2025-11-06 21:18:10','2025-11-06 21:18:10','1.34.1');
INSERT INTO road_sign_translations VALUES(1131,626,101,'1.34.1','«Направление поворота». направление движения на повороте с небольшим радиусом дороги при ограниченной видимости; направление обхода ремонтируемого участка дороги.','2025-11-06 21:18:10','2025-11-06 21:18:10','1.34.1');
INSERT INTO road_sign_translations VALUES(1132,627,100,'2.3.3','"Next to the secondary road". 2.3.2, 2.3.4, 2.3.6: knitting from the right, 2.3.3, 2.3.5, 2.3.7: knitting from the left.','2025-11-06 21:18:11','2025-11-06 21:18:11','2.3.3');
INSERT INTO road_sign_translations VALUES(1133,627,101,'2.3.3','«Рядом с второстепенной дорогой». 2.3.2, 2.3.4, 2.3.6: вязать справа, 2.3.3, 2.3.5, 2.3.7: вязать слева.','2025-11-06 21:18:11','2025-11-06 21:18:11','2.3.3');
INSERT INTO road_sign_translations VALUES(1134,628,100,'2.3.4','"Next to the secondary road". 2.3.2, 2.3.4, 2.3.6: knitting from the right, 2.3.3, 2.3.5, 2.3.7: knitting from the left.','2025-11-06 21:18:11','2025-11-06 21:18:11','2.3.4');
INSERT INTO road_sign_translations VALUES(1135,628,101,'2.3.4','«Рядом с второстепенной дорогой». 2.3.2, 2.3.4, 2.3.6: вязать справа, 2.3.3, 2.3.5, 2.3.7: вязать слева.','2025-11-06 21:18:11','2025-11-06 21:18:11','2.3.4');
INSERT INTO road_sign_translations VALUES(1136,629,100,'2.3.5','"Next to the secondary road". 2.3.2, 2.3.4, 2.3.6: knitting from the right, 2.3.3, 2.3.5, 2.3.7: knitting from the left.','2025-11-06 21:18:11','2025-11-06 21:18:11','2.3.5');
INSERT INTO road_sign_translations VALUES(1137,629,101,'2.3.5','«Рядом с второстепенной дорогой». 2.3.2, 2.3.4, 2.3.6: вязать справа, 2.3.3, 2.3.5, 2.3.7: вязать слева.','2025-11-06 21:18:11','2025-11-06 21:18:11','2.3.5');
INSERT INTO road_sign_translations VALUES(1138,630,100,'2.3.6','"Next to the secondary road". 2.3.2, 2.3.4, 2.3.6: knitting from the right, 2.3.3, 2.3.5, 2.3.7: knitting from the left.','2025-11-06 21:18:12','2025-11-06 21:18:12','2.3.6');
INSERT INTO road_sign_translations VALUES(1139,630,101,'2.3.6','«Рядом с второстепенной дорогой». 2.3.2, 2.3.4, 2.3.6: вязать справа, 2.3.3, 2.3.5, 2.3.7: вязать слева.','2025-11-06 21:18:12','2025-11-06 21:18:12','2.3.6');
INSERT INTO road_sign_translations VALUES(1140,631,100,'2.3.7','"Next to the secondary road". 2.3.2, 2.3.4, 2.3.6: knitting from the right, 2.3.3, 2.3.5, 2.3.7: knitting from the left.','2025-11-06 21:18:12','2025-11-06 21:18:12','2.3.7');
INSERT INTO road_sign_translations VALUES(1141,631,101,'2.3.7','«Рядом с второстепенной дорогой». 2.3.2, 2.3.4, 2.3.6: вязать справа, 2.3.3, 2.3.5, 2.3.7: вязать слева.','2025-11-06 21:18:12','2025-11-06 21:18:12','2.3.7');
INSERT INTO road_sign_translations VALUES(1142,632,100,'4.8.2','"Traffic direction of vehicles with dangerous goods". Traffic of vehicles equipped with "Dangerous cargo" recognition signs is allowed only in the direction indicated by the arrow on the sign: 4.8.1: straight, 4.8.2: to the right, 4.8.3: to the left.','2025-11-06 21:18:12','2025-11-06 21:18:12','4.8.2');
INSERT INTO road_sign_translations VALUES(1143,632,101,'4.8.2','«Направление движения транспортных средств с опасными грузами». Движение транспортных средств, оборудованных знаками опознавательного знака «Опасный груз», разрешается только в направлении, указанном стрелкой на знаке: 4.8.1: прямо, 4.8.2: направо, 4.8.3: налево.','2025-11-06 21:18:12','2025-11-06 21:18:12','4.8.2');
INSERT INTO road_sign_translations VALUES(1144,633,100,'4.8.3','"Traffic direction of vehicles with dangerous goods". Traffic of vehicles equipped with "Dangerous cargo" recognition signs is allowed only in the direction indicated by the arrow on the sign: 4.8.1: straight, 4.8.2: to the right, 4.8.3: to the left.','2025-11-06 21:18:12','2025-11-06 21:18:12','4.8.3');
INSERT INTO road_sign_translations VALUES(1145,633,101,'4.8.3','«Направление движения транспортных средств с опасными грузами». Движение транспортных средств, оборудованных знаками опознавательного знака «Опасный груз», разрешается только в направлении, указанном стрелкой на знаке: 4.8.1: прямо, 4.8.2: направо, 4.8.3: налево.','2025-11-06 21:18:12','2025-11-06 21:18:12','4.8.3');
INSERT INTO road_sign_translations VALUES(1146,634,100,'5.23.2','"Beginning of settlement". the beginning of the settlement, where the requirements of the rules defining the order of traffic in the settlements apply;','2025-11-06 21:18:12','2025-11-06 21:18:12','5.23.2');
INSERT INTO road_sign_translations VALUES(1147,634,101,'5.23.2','«Начало урегулирования». начало населенного пункта, где применяются требования правил, определяющих порядок движения транспорта в населенных пунктах;','2025-11-06 21:18:12','2025-11-06 21:18:12','5.23.2');
INSERT INTO road_sign_translations VALUES(1148,635,100,'5.24.2','"End of the settlement". the place from which the requirements of the rules defining the order of traffic in settlements lose their force on the given road;','2025-11-06 21:18:12','2025-11-06 21:18:12','5.24.2');
INSERT INTO road_sign_translations VALUES(1149,635,101,'5.24.2','«Конец поселения». место, с которого на данной дороге теряют силу требования правил, определяющих порядок движения в населенных пунктах;','2025-11-06 21:18:12','2025-11-06 21:18:12','5.24.2');
INSERT INTO road_sign_translations VALUES(1150,636,100,'6.8.2','"Dead end". a road without a through passage.','2025-11-06 21:18:12','2025-11-06 21:18:12','6.8.2');
INSERT INTO road_sign_translations VALUES(1151,636,101,'6.8.2','"Тупик". дорога без сквозного проезда.','2025-11-06 21:18:12','2025-11-06 21:18:12','6.8.2');
INSERT INTO road_sign_translations VALUES(1152,637,100,'6.8.3','"Dead end". a road without a through passage.','2025-11-06 21:18:13','2025-11-06 21:18:13','6.8.3');
INSERT INTO road_sign_translations VALUES(1153,637,101,'6.8.3','"Тупик". дорога без сквозного проезда.','2025-11-06 21:18:13','2025-11-06 21:18:13','6.8.3');
INSERT INTO road_sign_translations VALUES(1154,638,100,'6.9.2','6.9.1. "Indicator of directions", 6.9.2. "Preliminary direction indicator". driving directions to the settlements and other objects indicated on the sign. These signs may display the image of the 6.14.1 sign, highway, airport logos and other icons. 6.9.1 images of other signs informing about traffic features may be depicted on the sign. 6.9.1 The distance from the place of installation of the sign to the intersection or the beginning of the braking zone is indicated in the lower part of the sign. The sign 6.9.1 is also used to give information about the direction of bypassing the road section equipped with any of the prohibiting signs 3.11 - 3.15;','2025-11-06 21:18:13','2025-11-06 21:18:13','6.9.2');
INSERT INTO road_sign_translations VALUES(1155,638,101,'6.9.2','6.9.1. «Индикатор направлений», 6.9.2. «Предварительный указатель направления». схемы проезда к населенным пунктам и другим объектам, указанным на знаке. На этих знаках может отображаться изображение знака 6.14.1, логотипов шоссе, аэропорта и других значков. 6.9.1 На знаке могут быть изображены изображения других знаков, информирующих об особенностях дорожного движения. 6.9.1 Расстояние от места установки знака до перекрестка или начала зоны торможения указывается в нижней части знака. Знак 6.9.1 применяется также для указания направления объезда участка дороги, оборудованного любым из запрещающих знаков 3.11 – 3.15;','2025-11-06 21:18:13','2025-11-06 21:18:13','6.9.2');
INSERT INTO road_sign_translations VALUES(1156,639,100,'5.7.2',unistr('"Exit to a one-way road". exit to\u000d\u000a              one-way road or carriageway.'),'2025-11-06 21:18:13','2025-11-06 21:18:13','5.7.2');
INSERT INTO road_sign_translations VALUES(1157,639,101,'5.7.2',unistr('«Выход на дорогу с односторонним движением». выход в\u000d\u000a              дорога с односторонним движением или проезжая часть.'),'2025-11-06 21:18:13','2025-11-06 21:18:13','5.7.2');
INSERT INTO road_sign_translations VALUES(1158,640,100,'5.13.2',unistr('"Exit to vehicles of general use\u000d\u000a              road with one lane".'),'2025-11-06 21:18:13','2025-11-06 21:18:13','5.13.2');
INSERT INTO road_sign_translations VALUES(1159,640,101,'5.13.2',unistr('«Выход к транспортным средствам общего пользования\u000d\u000a              дорога с одной полосой».'),'2025-11-06 21:18:13','2025-11-06 21:18:13','5.13.2');
INSERT INTO road_sign_translations VALUES(1160,641,100,'5.19.2',unistr('"Pedestrian crossing". at the crossing point 1.14.1 - 1.14.2\u000d\u000a              in the absence of markings, the sign 5.19.1 is placed to the left of the road, at the crossing\u000d\u000a              far, and the sign 5.19.2 - to the right of the road, near the nearest border of the crossing.'),'2025-11-06 21:18:13','2025-11-06 21:18:13','5.19.2');
INSERT INTO road_sign_translations VALUES(1161,641,101,'5.19.2',unistr('"Пешеходный переход". на пересечении 1.14.1 - 1.14.2\u000d\u000a              при отсутствии разметки знак 5.19.1 ставится слева от дороги, у перехода\u000d\u000a              далеко, а знак 5.19.2 – справа от дороги, возле ближайшей границы перехода.'),'2025-11-06 21:18:13','2025-11-06 21:18:13','5.19.2');
INSERT INTO road_sign_translations VALUES(1162,642,100,'6.10.2',unistr('6.10.1. "Indicator of directions", 6.10.2. "Right\u000d\u000a              indicator". driving directions to waypoints. Signs may indicate\u000d\u000a              the distances to those objects (km), depicted on the highway,\u000d\u000a              airport logos and other icons;'),'2025-11-06 21:18:13','2025-11-06 21:18:13','6.10.2');
INSERT INTO road_sign_translations VALUES(1163,642,101,'6.10.2',unistr('6.10.1. «Индикатор направлений», 6.10.2. «Правильно\u000d\u000a              индикатор». маршруты проезда к путевым точкам. Знаки могут указывать\u000d\u000a              расстояния до тех объектов (км), изображенных на трассе,\u000d\u000a              логотипы аэропортов и другие значки;'),'2025-11-06 21:18:13','2025-11-06 21:18:13','6.10.2');
INSERT INTO road_sign_translations VALUES(1164,643,100,'6.14.2',unistr('"Route number". 6.14.1: on the road (route)\u000d\u000a              assigned number, 6.14.2 - road (route) number and direction;'),'2025-11-06 21:18:13','2025-11-06 21:18:13','6.14.2');
INSERT INTO road_sign_translations VALUES(1165,643,101,'6.14.2',unistr('«Номер маршрута». 6.14.1: в дороге (маршруте)\u000d\u000a              присвоенный номер, 6.14.2 – номер дороги (маршрута) и направление;'),'2025-11-06 21:18:13','2025-11-06 21:18:13','6.14.2');
INSERT INTO road_sign_translations VALUES(1166,644,100,'6.15.2',unistr('"Traffic direction for trucks".\u000d\u000a              recommended for trucks, tractors and self-propelled vehicles\u000d\u000a              the direction of traffic if their traffic is in either direction at the intersection\u000d\u000a              it is forbidden.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.15.2');
INSERT INTO road_sign_translations VALUES(1167,644,101,'6.15.2',unistr('«Направление движения грузовых автомобилей».\u000d\u000a              рекомендуется для грузовых автомобилей, тракторов и самоходных машин.\u000d\u000a              направление движения, если на перекрестке движение идет в любом направлении\u000d\u000a              это запрещено.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.15.2');
INSERT INTO road_sign_translations VALUES(1168,645,100,'6.15.3',unistr('"Traffic direction for trucks".\u000d\u000a              recommended for trucks, tractors and self-propelled vehicles\u000d\u000a              the direction of traffic if their traffic is in either direction at the intersection\u000d\u000a              it is forbidden.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.15.3');
INSERT INTO road_sign_translations VALUES(1169,645,101,'6.15.3',unistr('«Направление движения грузовых автомобилей».\u000d\u000a              рекомендуется для грузовых автомобилей, тракторов и самоходных машин.\u000d\u000a              направление движения, если на перекрестке движение идет в любом направлении\u000d\u000a              это запрещено.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.15.3');
INSERT INTO road_sign_translations VALUES(1170,646,100,'6.18.2',unistr('"Transfer direction". temporarily closed to traffic\u000d\u000a              direction of bypassing the road section.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.18.2');
INSERT INTO road_sign_translations VALUES(1171,646,101,'6.18.2',unistr('«Направление трансфера». временно закрыто для движения\u000d\u000a              направление обхода участка дороги.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.18.2');
INSERT INTO road_sign_translations VALUES(1172,647,100,'6.18.3',unistr('"Transfer direction". temporarily closed to traffic\u000d\u000a              direction of bypassing the road section.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.18.3');
INSERT INTO road_sign_translations VALUES(1173,647,101,'6.18.3',unistr('«Направление трансфера». временно закрыто для движения\u000d\u000a              направление обхода участка дороги.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.18.3');
INSERT INTO road_sign_translations VALUES(1174,648,100,'6.19.2',unistr('"Preliminary indicator of rerouting to another lane".\u000d\u000a              bypassing the part of the roadway closed to traffic with the dividing line\u000d\u000a              or direction of traffic to return to the right-hand lane.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.19.2');
INSERT INTO road_sign_translations VALUES(1175,648,101,'6.19.2',unistr('«Предварительный индикатор перенаправления на другую полосу».\u000d\u000a              обход закрытой для движения части проезжей части с разделительной линией\u000d\u000a              или направление движения, чтобы вернуться на правую полосу.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.19.2');
INSERT INTO road_sign_translations VALUES(1176,649,100,'6.20.2',unistr('"Emergency exit". in the tunnel shows the place where\u000d\u000a              where is the emergency exit?'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.20.2');
INSERT INTO road_sign_translations VALUES(1177,649,101,'6.20.2',unistr('"Запасный выход". в тоннеле показано место, где\u000d\u000a              где аварийный выход?'),'2025-11-06 21:18:14','2025-11-06 21:18:14','6.20.2');
INSERT INTO road_sign_translations VALUES(1178,650,100,'8.1.4',unistr('"Distance to the object". shows the distance\u000d\u000a              to an off-road object.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','8.1.4');
INSERT INTO road_sign_translations VALUES(1179,650,101,'8.1.4',unistr('«Расстояние до объекта». показывает расстояние\u000d\u000a              на объект бездорожья.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','8.1.4');
INSERT INTO road_sign_translations VALUES(1180,651,100,'8.2.3',unistr('"Zone of influence". signs indicate and/or inform\u000d\u000a              are:\u000d\u000a              1) 8.2.2: 3.27: "Stopping is prohibited", 3.28: "Parking is prohibited", 3.29: "Parking\u000d\u000a                is prohibited on odd days of the month", 3.30: "Parking is prohibited on even days of the month"\u000d\u000a                the zone of influence of prohibitory signs.\u000d\u000a              2) 8.2.3: the end of the zone of influence of signs 3.27 - 3.30.\u000d\u000a              3) 8.2.4: 3.27 - 3.30 about being in the zone of influence.\u000d\u000a              4) the direction and zone of influence of signs 8.2.5, 7.2.6, 3.27 - 3.30, square,\u000d\u000a                prohibition of standing or parking along one side of the building facade and other places\u000d\u000a                case.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','8.2.3');
INSERT INTO road_sign_translations VALUES(1181,651,101,'8.2.3',unistr('«Зона влияния». знаки указывают и/или информируют\u000d\u000a              являются:\u000d\u000a              1) 8.2.2:3.27: «Остановка запрещена», 3.28: «Стоянка запрещена», 3.29: «Стоянка\u000d\u000a                запрещена в нечетные дни месяца", 3.30: "Стоянка запрещена в четные дни месяца"\u000d\u000a                зона действия запрещающих знаков.\u000d\u000a              2) 8.2.3: окончание зоны влияния знаков 3.27 – 3.30.\u000d\u000a              3) 8.2.4:3.27 - 3.30 о нахождении в зоне влияния.\u000d\u000a              4) направление и зона влияния знаков 8.2.5, 7.2.6, 3.27 – 3.30, квадрат,\u000d\u000a                запрет стоять или парковаться вдоль одной стороны фасада здания и в других местах\u000d\u000a                случай.'),'2025-11-06 21:18:14','2025-11-06 21:18:14','8.2.3');
