INSERT INTO road_sign_translations VALUES(1188,655,100,'8.3.2',unistr('"Directions of influence". are shown before the intersection\u000d\u000a              directions of impact of posted signs or traffic directions - to\u000d\u000a              the objects immediately near the road.'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.3.2');
INSERT INTO road_sign_translations VALUES(1189,655,101,'8.3.2',unistr('«Направления воздействия». показаны перед перекрёстком\u000d\u000a              направления воздействия вывешенных знаков или направлений движения -\u000d\u000a              объекты непосредственно возле дороги.'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.3.2');
INSERT INTO road_sign_translations VALUES(1190,656,100,'8.3.3',unistr('"Directions of influence". are shown before the intersection\u000d\u000a              directions of impact of posted signs or traffic directions - to\u000d\u000a              the objects immediately near the road.'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.3.3');
INSERT INTO road_sign_translations VALUES(1191,656,101,'8.3.3',unistr('«Направления воздействия». показаны перед перекрёстком\u000d\u000a              направления воздействия вывешенных знаков или направлений движения -\u000d\u000a              объекты непосредственно возле дороги.'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.3.3');
INSERT INTO road_sign_translations VALUES(1192,657,100,'8.4.2',unistr('"Type of vehicle". is a demonstration\u000d\u000a              gives the type of vehicle to which the sign applies. This\u000d\u000a              The effect of signs used with signs extends to:\u000d\u000a              1) 8.4.1: a truck with a permissible maximum weight of more than 3.5 tons,\u000d\u000a                including also on vehicles operated with a trailer,\u000d\u000a              2) 8.4.3 - light passenger car, as well as up to 3.5 tons permissible maximum\u000d\u000a                on heavy goods vehicles,\u000d\u000a              3) 8.4.8: on vehicles equipped with the "Dangerous cargo" recognition sign.'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.4.2');
INSERT INTO road_sign_translations VALUES(1193,657,101,'8.4.2',unistr('«Тип транспортного средства». это демонстрация\u000d\u000a              указывает тип транспортного средства, к которому относится этот знак. Это\u000d\u000a              Действие знаков, используемых со знаками, распространяется на:\u000d\u000a              1) 8.4.1: грузовой автомобиль с разрешенной максимальной массой более 3,5 тонн,\u000d\u000a                в том числе и на транспортных средствах, эксплуатируемых с прицепом,\u000d\u000a              2) 8.4.3 – легковой легковой автомобиль, а также разрешенная максимальная масса до 3,5 тонн.\u000d\u000a                на грузовых автомобилях,\u000d\u000a              3) 8.4.8: на транспортных средствах, оборудованных знаком «Опасный груз».'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.4.2');
INSERT INTO road_sign_translations VALUES(1194,658,100,'8.4.3',unistr('"Type of vehicle". is a demonstration\u000d\u000a              gives the type of vehicle to which the sign applies. This\u000d\u000a              The effect of signs used with signs extends to:\u000d\u000a              1) 8.4.1: a truck with a permissible maximum weight of more than 3.5 tons,\u000d\u000a                including also on vehicles operated with a trailer,\u000d\u000a              2) 8.4.3 - light passenger car, as well as up to 3.5 tons permissible maximum\u000d\u000a                on heavy goods vehicles,\u000d\u000a              3) 8.4.8: on vehicles equipped with the "Dangerous cargo" recognition sign.'),'2025-11-06 21:18:15','2025-11-06 21:18:15','8.4.3');
