INSERT INTO road_sign_translations VALUES(1206,664,100,'8.5.2',unistr('8.5.1. "Saturdays, Sundays and holidays", 8.5.2. "Working days", 8.5.3. "Of the week\u000d\u000a                days". signs inform about the days of the week during which\u000d\u000a                the sign works.'),'2025-11-06 21:18:16','2025-11-06 21:18:16','8.5.2');
