INSERT INTO road_sign_translations VALUES(1232,677,100,'8.20.2',unistr('"Vehicle stroller type". 3.12 mark apply\u000d\u000a              with and indicates the number of axles of the vehicle being approached, each of which\u000d\u000a              the mass indicated on the number sign is considered to be marginally permissible.'),'2025-11-06 21:18:18','2025-11-06 21:18:18','8.20.2');
INSERT INTO road_sign_translations VALUES(1233,677,101,'8.20.2',unistr('«Тип автомобильной коляски». 3.12 отметка применяется\u000d\u000a              с и указывает количество осей подъезжающего транспортного средства, каждая из которых\u000d\u000a              масса, указанная на цифровом знаке, считается предельно допустимой.'),'2025-11-06 21:18:18','2025-11-06 21:18:18','8.20.2');
INSERT INTO road_sign_translations VALUES(1234,678,100,'8.22.2',unistr('"Obstacle". apply with symbols 4.2.1 - 4.2.3 and\u000d\u000a              shows the obstacle and the direction to avoid it.\u000d\u000a              Tables are placed directly below the symbols with which they apply.\u000d\u000a                If the signs are placed above the carriageway, curb or sidewalk, then 8.2.2 -\u000d\u000a                Signs 8.2.4 and 8.13 may be placed next to the sign.'),'2025-11-06 21:18:18','2025-11-06 21:18:18','8.22.2');
INSERT INTO road_sign_translations VALUES(1235,678,101,'8.22.2',unistr('"Препятствие". применять с символами 4.2.1 – 4.2.3 и\u000d\u000a              показывает препятствие и направление, как его избежать.\u000d\u000a              Таблицы размещаются непосредственно под символами, с которыми они применяются.\u000d\u000a                Если знаки расположены над проезжей частью, бордюром или тротуаром, то 8.2.2 -\u000d\u000a                Рядом со знаком могут размещаться знаки 8.2.4 и 8.13.'),'2025-11-06 21:18:18','2025-11-06 21:18:18','8.22.2');
INSERT INTO road_sign_translations VALUES(1236,679,100,'8.22.3',unistr('"Obstacle". apply with symbols 4.2.1 - 4.2.3 and\u000d\u000a              shows the obstacle and the direction to avoid it.\u000d\u000a              Tables are placed directly below the symbols with which they apply.\u000d\u000a                If the signs are placed above the carriageway, curb or sidewalk, then 8.2.2 -\u000d\u000a                Signs 8.2.4 and 8.13 may be placed next to the sign.'),'2025-11-06 21:18:18','2025-11-06 21:18:18','8.22.3');
INSERT INTO road_sign_translations VALUES(1237,679,101,'8.22.3',unistr('"Препятствие". применять с символами 4.2.1 – 4.2.3 и\u000d\u000a              показывает препятствие и направление, как его избежать.\u000d\u000a              Таблицы размещаются непосредственно под символами, с которыми они применяются.\u000d\u000a                Если знаки расположены над проезжей частью, бордюром или тротуаром, то 8.2.2 -\u000d\u000a                Рядом со знаком могут размещаться знаки 8.2.4 и 8.13.'),'2025-11-06 21:18:18','2025-11-06 21:18:18','8.22.3');
