INSERT INTO road_sign_translations VALUES('1264','692','102','«Խաչմերուկի տարածք»','Նշանակում է մոտեցում խաչմերուկին, որի հատվածը նշված է 1.26 գծանշմամբ, և որտեղ արգելվում է մուտք գործել, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կհարկադրի կանգ առնել` խոչընդոտ ստեղծելով հատող ճանապարհով լայնական ուղղությամբ տրանսպորտային միջոցների երթևեկության համար, բացառությամբ սույն Կանոններով սահմանված՝ աջ կամ ձախ շրջադարձ կատարելու դեպքերի: 1.35 նշանը տեղադրվում է խաչմերուկի սահմանին: Եթե բարդ խաչմերուկներում հնարավոր չէ ճանապարհային նշանը տեղադրել խաչմերուկի սահմանին, ապա այն տեղադրում են խաչմերուկի սահմանից ոչ ավել, քան 30 մ հեռավորության վրա:','2026-03-16 22:36:23','2026-03-16 22:36:23','1.35');
INSERT INTO exploitation_translations VALUES(1,1,102,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝\u000a    </p>\u000a    <ol class="list-decimal pl-5 space-y-3 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            ճանապարհային կամ վահանակային (ստենդային) փորձարկումների ժամանակ չեն պահպանվում բանվորական\u000a            արգելակային համակարգի արդյունավետության ստանդարտով սահմանված նորմերը:\u000a        </li>\u000a        <li>\u000a            խախտված է հիդրավլիկ արգելակային հաղորդակի հերմետիկությունը:\u000a        </li>\u000a        <li>\u000a            չի գործում պնևմատիկ կամ պնևմահիդրավլիկ արգելակային հաղորդակի ճնշաչափը:\u000a        </li>\u000a        <li>\u000a            կայանման արգելակային համակարգն ստանդարտով սահմանված թեքության վրա չի ապահովում անշարժ վիճակ:\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(2,1,101,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Эксплуатация транспортного средства запрещается, если:\u000a    </p>\u000a    <ol class="list-decimal pl-5 space-y-3 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            при дорожных или стендовых испытаниях не выполняются нормы эффективности рабочей тормозной системы,\u000a            установленные стандартом;\u000a        </li>\u000a        <li>\u000a            нарушена герметичность гидравлического привода тормозной системы;\u000a        </li>\u000a        <li>\u000a            не работает манометр пневматического или пневмогидравлического привода тормозной системы;\u000a        </li>\u000a        <li>\u000a            стояночная тормозная система не обеспечивает неподвижное состояние транспортного средства\u000a            на уклоне, установленном стандартом.\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(3,2,102,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            ղեկային կառավարման համակարգի գումարային խաղացքը գերազանցում է հետևյալ ցուցանիշները՝\u000a            <div class="mt-2 space-y-1">\u000a                <p>ա. 10 աստիճան՝ թեթև մարդատար ավտոմոբիլների և դրանց բազայի վրա պատրաստված բեռնատար ավտոմոբիլների և ավտոբուսների մոտ,</p>\u000a                <p>բ. 20 աստիճան՝ ավտոբուսների մոտ,</p>\u000a                <p>գ. 25 աստիճան՝ բեռնատար ավտոմոբիլների մոտ:</p>\u000a            </div>\u000a        </li>\u000a\u000a        <li>\u000a            առկա են մանրամասերի (դետալներ) ու հանգույցների կառուցվածքով չնախատեսված տեղաշարժեր կամ\u000a            պարուրակային միացումները ձգված կամ սահմանված ձևով սևեռված չեն, անսարք է ղեկասյունակի դիրքի\u000a            սևեռիչ սարքավորումը:\u000a        </li>\u000a\u000a        <li>\u000a            անսարք է կամ բացակայում է կառուցվածքով նախատեսված ղեկային կառավարման ուժեղարարը կամ\u000a            մոտոցիկլների ղեկային հանդարտիչը:\u000a        </li>\u000a\u000a        <li>\u000a            ղեկային կառավարման համակարգն աջակողմյան տեղաբաշխմամբ է:\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(4,2,101,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Эксплуатация транспортного средства запрещается, если:\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            суммарный люфт рулевого управления превышает следующие значения:\u000a            <div class="mt-2 space-y-1">\u000a                <p>а. 10° — у легковых автомобилей и грузовых автомобилей и автобусов, изготовленных на их базе;</p>\u000a                <p>б. 20° — у автобусов;</p>\u000a                <p>в. 25° — у грузовых автомобилей.</p>\u000a            </div>\u000a        </li>\u000a\u000a        <li>\u000a            имеются не предусмотренные конструкцией перемещения деталей и узлов либо резьбовые соединения\u000a            не затянуты или не закреплены надлежащим образом, неисправно устройство фиксации положения\u000a            рулевой колонки;\u000a        </li>\u000a\u000a        <li>\u000a            неисправен или отсутствует предусмотренный конструкцией усилитель рулевого управления либо\u000a            демпфер руля мотоцикла;\u000a        </li>\u000a\u000a        <li>\u000a            рулевое управление имеет правостороннее расположение.\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(5,3,102,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            արտաքին լուսային սարքերի թիվը, տեսակը, գույնը, դասավորվածությունը և աշխատանքի ռեժիմը չեն\u000a            համապատասխանում տրանսպորտային միջոցի կառուցվածքի և ստանդարտներով պահանջներին (արտադրությունից\u000a            հանված տրանսպորտային միջոցների վրա թույլատրվում է այլ մակնիշների և մոդելների տրանսպորտային\u000a            միջոցների արտաքին լուսային սարքերի տեղադրում).\u000a        </li>\u000a\u000a        <li>\u000a            լապտերների կարգավորումը չի համապատասխանում ստանդարտի պահանջներին:\u000a        </li>\u000a\u000a        <li>\u000a            սահմանված ռեժիմով չեն աշխատում կամ կեղտոտված են արտաքին լուսային սարքերը և\u000a            լուսանդրադարձիչները:\u000a        </li>\u000a\u000a        <li>\u000a            լուսային սարքերի վրա բացակայում են լամպերը կամ ցրիչները, կամ օգտագործվում են տվյալ\u000a            լուսային սարքի տեսակին չհամապատասխանող ցրիչներ կամ լամպեր:\u000a        </li>\u000a\u000a        <li>\u000a            առկայծող փարոսիկների տեղակայումը, ամրացման ձևերը և լուսային ազդանշանի տեսանելիությունը չեն\u000a            համապատասխանում ստանդարտի պահանջներին:\u000a        </li>\u000a\u000a        <li>\u000a            տրանսպորտային միջոցի վրա տեղադրված են՝\u000a            <div class="mt-2 space-y-1">\u000a                <p>\u000a                    ա. առջևի մասում՝ ցանկացած գույնի լույսերով հակամառախուղային լապտերներ, շրջադարձի ցուցիչներ\u000a                    և այլ լուսային սարքեր, բացի սպիտակ, դեղին կամ նարնջագույն գույների լույսերից, ցանկացած գույնի\u000a                    լուսաանդրադարձնող հարմարանքներ, բացի սպիտակ գույնից,\u000a                </p>\u000a                <p>\u000a                    բ. հետևի մասում՝ ցանկացած գույնի լույսերով հետընթացի և հաշվառման համարանիշի լուսավորման\u000a                    լապտերիկներ, բացի սպիտակ գույնի լույսերից, ցանկացած գույնի լույսերով այլ լուսային սարքեր,\u000a                    բացի կարմիր, դեղին կամ նարնջագույն գույնի լույսերից, ցանկացած գույնի լուսաանդրադարձնող\u000a                    հարմարանքներ, բացի կարմիր գույնից:\u000a                </p>\u000a            </div>\u000a            <p class="mt-2 text-xs text-gray-600">\u000a                Սույն ենթակետի պահանջները չեն տարածվում տրանսպորտային միջոցների վրա տեղադրված հաշվառման\u000a                համարանիշերի, տարբերիչ և ճանաչման նշանների վրա:\u000a            </p>\u000a        </li>\u000a\u000a        <li>\u000a            հետին հակամառախուղային լապտերիկները միացված են տրանսպորտային միջոցի արգելակումն ազդարարող\u000a            լուսային սարքերին:\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(6,3,101,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Эксплуатация транспортного средства запрещается, если:\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            количество, тип, цвет, расположение и режим работы внешних световых приборов\u000a            не соответствуют конструкции транспортного средства и требованиям стандартов\u000a            (на транспортных средствах, снятых с производства, допускается установка внешних\u000a            световых приборов от транспортных средств других марок и моделей);\u000a        </li>\u000a\u000a        <li>\u000a            регулировка фар не соответствует требованиям стандарта;\u000a        </li>\u000a\u000a        <li>\u000a            внешние световые приборы и световозвращатели не работают в установленном режиме\u000a            или загрязнены;\u000a        </li>\u000a\u000a        <li>\u000a            на световых приборах отсутствуют лампы или рассеиватели либо используются\u000a            рассеиватели или лампы, не соответствующие данному типу светового прибора;\u000a        </li>\u000a\u000a        <li>\u000a            расположение, способы крепления и видимость светового сигнала проблесковых маячков\u000a            не соответствуют требованиям стандарта;\u000a        </li>\u000a\u000a        <li>\u000a            на транспортном средстве установлены:\u000a            <div class="mt-2 space-y-1">\u000a                <p>\u000a                    а. спереди — противотуманные фары, указатели поворота и другие световые приборы\u000a                    с любым цветом света, кроме белого, жёлтого или оранжевого, а также\u000a                    световозвращающие устройства любого цвета, кроме белого;\u000a                </p>\u000a                <p>\u000a                    б. сзади — фонари освещения заднего хода и регистрационного знака любого цвета,\u000a                    кроме белого, а также другие световые приборы любого цвета, кроме красного,\u000a                    жёлтого или оранжевого, и световозвращающие устройства любого цвета,\u000a                    кроме красного.\u000a                </p>\u000a            </div>\u000a            <p class="mt-2 text-xs text-gray-600">\u000a                Требования настоящего подпункта не распространяются на регистрационные знаки,\u000a                отличительные и опознавательные знаки, установленные на транспортных средствах.\u000a            </p>\u000a        </li>\u000a\u000a        <li>\u000a            задние противотуманные фонари подключены к световым приборам, сигнализирующим\u000a            о торможении транспортного средства.\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(7,4,102,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրությունը պակաս է`\u000a            <div class="mt-2 space-y-1">\u000a                <p>ա. 2,0 մմ` ավտոբուսների համար,</p>\u000a                <p>բ. 1,6 մմ` թեթև մարդատար ավտոմոբիլների համար,</p>\u000a                <p>գ. 1,0 մմ` բեռնատար ավտոմոբիլների համար,</p>\u000a                <p>դ. 0,8 մմ` մոտոցիկլների և մոպեդների համար։</p>\u000a            </div>\u000a            <p class="mt-2 text-xs text-gray-600">\u000a                Կցորդների դողերի պահպանաշերտի նախշանկարի մնացորդային բարձրության նորմերը սահմանվում են\u000a                որպես քարշակ ծառայող ավտոմոբիլների դողերի նորմերին համապատասխան:\u000a            </p>\u000a        </li>\u000a\u000a        <li>\u000a            դողերն ունեն հենքը (կորդը) մերկացնող տեղային վնասվածքներ (անցքեր, կտրվածքներ, ճեղքվածքներ),\u000a            ինչպես նաև հիմնակմախքի շերտաբաժանում, պահպանաշերտի և կողերի շերտատում:\u000a        </li>\u000a\u000a        <li>\u000a            անվահեցի կամ անվասկավառակի վրա առկա են ճաքեր, կամ բացակայում է դրանց ամրացման\u000a            հեղույսներից (մանեկներից) թեկուզ մեկը կամ առկա են դրանց ամրացման անցքերի ձևի և չափերի\u000a            տեսանելի խախտումներ:\u000a        </li>\u000a\u000a        <li>\u000a            դողերը չափերով կամ թույլատրելի բեռնվածությամբ չեն համապատասխանում տրանսպորտային միջոցի տվյալ\u000a            մոդելին:\u000a        </li>\u000a\u000a        <li>\u000a            տրանսպորտային միջոցի նույն սռնու վրա տեղադրված են տարբեր չափերի, տարբեր կառուցվածքների,\u000a            տարբեր մոդելների, պահպանաշերտի տարբեր նախշանկարներով, բութակավորված և չբութակավորված,\u000a            ցրտադիմացկուն և ոչ ցրտադիմացկուն, նոր և վերականգնված դողեր:\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(8,4,101,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Эксплуатация транспортного средства запрещается, если:\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            остаточная глубина рисунка протектора шин составляет менее:\u000a            <div class="mt-2 space-y-1">\u000a                <p>а. 2,0 мм — для автобусов;</p>\u000a                <p>б. 1,6 мм — для легковых автомобилей;</p>\u000a                <p>в. 1,0 мм — для грузовых автомобилей;</p>\u000a                <p>г. 0,8 мм — для мотоциклов и мопедов.</p>\u000a            </div>\u000a            <p class="mt-2 text-xs text-gray-600">\u000a                Нормы остаточной глубины рисунка протектора шин прицепов устанавливаются такими же,\u000a                как для тягачей.\u000a            </p>\u000a        </li>\u000a\u000a        <li>\u000a            шины имеют местные повреждения, обнажающие корд (проколы, порезы, разрывы),\u000a            а также расслоение каркаса, отслаивание протектора или боковин;\u000a        </li>\u000a\u000a        <li>\u000a            на ободе или диске колеса имеются трещины либо отсутствует хотя бы одна\u000a            из гаек (болтов) крепления или видны нарушения формы и размеров крепёжных отверстий;\u000a        </li>\u000a\u000a        <li>\u000a            размеры шин или допустимая нагрузка на них не соответствуют данному типу\u000a            транспортного средства;\u000a        </li>\u000a\u000a        <li>\u000a            на одной оси транспортного средства установлены шины различного размера,\u000a            конструкции, модели, с различным рисунком протектора, шипованные и нешипованные,\u000a            зимние и обычные, новые и восстановленные.\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(9,5,102,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-3 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            արտածվող գազերում վնասակար նյութերի պարունակությունը կամ դրանց ծխայնությունը գերազանցում են\u000a            Հայաստանի Հանրապետության օրենսդրությամբ սահմանված նորմերը:\u000a        </li>\u000a        <li>\u000a            խախտված է սնման համակարգի հերմետիկությունը:\u000a        </li>\u000a        <li>\u000a            անսարք է բանած գազերի արտածման համակարգը:\u000a        </li>\u000a        <li>\u000a            խախտված է հենատուփի (կարտեր) օդափոխության համակարգի հերմետիկությունը:\u000a        </li>\u000a        <li>\u000a            արտաքին աղմուկի թույլատրելի մակարդակը գերազանցում է ստանդարտով սահմանված նորմերը:\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(10,5,101,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Эксплуатация транспортного средства запрещается, если:\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-3 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            содержание вредных веществ или дымность отработавших газов превышают нормы,\u000a            установленные законодательством Республики Армения;\u000a        </li>\u000a        <li>\u000a            нарушена герметичность системы питания;\u000a        </li>\u000a        <li>\u000a            неисправна система выпуска отработавших газов;\u000a        </li>\u000a        <li>\u000a            нарушена герметичность системы вентиляции картера;\u000a        </li>\u000a        <li>\u000a            уровень внешнего шума превышает нормы, установленные стандартом.\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(11,6,102,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Տրանսպորտային միջոցների շահագործումն արգելվում է, եթե՝\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            ապակեմաքրիչները չեն աշխատում սահմանված ռեժիմով, կամ չեն աշխատում տրանսպորտային միջոցի\u000a            կառուցվածքով նախատեսված ապակեողողիչները:\u000a        </li>\u000a\u000a        <li>\u000a            հետին տեսանելիության հայելիների քանակը, դասավորվածությունը և դասը չեն համապատասխանում\u000a            ստանդարտի պահանջներին, բացակայում են տրանսպորտային միջոցի կառուցվածքով նախատեսված ապակիները:\u000a        </li>\u000a\u000a        <li>\u000a            չի աշխատում ձայնային ազդանշանի սարքը կամ այն, կամ տրվող ազդանշանը չեն համապատասխանում\u000a            ստանդարտին:\u000a        </li>\u000a\u000a        <li>\u000a            տեղադրված են երթևեկության մասնակիցներին վնասվածքներ հասցնելու վտանգ պարունակող կամ վարորդի\u000a            նստատեղից նրա տեսադաշտը սահմանափակող իրեր կամ առարկաներ:\u000a        </li>\u000a\u000a        <li>\u000a            տրանսպորտային միջոցի՝\u000a            <div class="mt-2 space-y-1">\u000a                <p>\u000a                    ա. ապակիների (այդ թվում՝ արտաքին թաղանթապատում ունեցող հետևի դիտապակու կամ հետևի\u000a                    կողային ապակիների) լուսաթափանցելիությունը չի համապատասխանում Հայաստանի Հանրապետության\u000a                    օրենսդրությամբ սահմանված չափերին,\u000a                </p>\u000a                <p>\u000a                    բ. առջևի դիտապակին կամ առջևի կողային ապակիները վարագուրապատված են,\u000a                </p>\u000a                <p>\u000a                    գ. հետևի դիտապակին կամ հետևի կողային ապակիները վարագուրապատված են և բացակայում են հետին\u000a                    տեսանելիության 2 կողային հայելիները:\u000a                </p>\u000a            </div>\u000a        </li>\u000a\u000a        <li>\u000a            չեն աշխատում տրանսպորտային միջոցների կառուցվածքով նախատեսված` թափքի կամ խցիկի դռների կամ\u000a            շարժիչի ծածկոցի փականները, ցիստեռնների բկանցքների և բեռնատար հարթակների կողերի փականները,\u000a            վառելիքի բաքերի խցանները, վարորդի նստատեղի դիրքը կարգավորող մեխանիզմը, ավտոբուսի դռների\u000a            վթարային բացիչները և կանգառ կատարելու պահանջի ազդանշանը, ավտոբուսի սրահի ներքին լուսավորության\u000a            սարքերը, վթարային ելքերը և դրանք գործողության մեջ դնող հարմարանքները, դռների կառավարման\u000a            հաղորդակը, արագաչափը, պտուտագրիչը, հակաառևանգման և ապակիների տաքացման ու փչահարման սարքերը:\u000a        </li>\u000a\u000a        <li>\u000a            բացակայում են կառուցվածքով նախատեսված հետին պաշտպանիչ հարմարանքը, ցեխապաշտպան գոգնոցները և\u000a            ցայտապաշտպանիչները:\u000a        </li>\u000a\u000a        <li>\u000a            անսարք են քարշակի կամ կցորդային մասի քարշակցման կամ հենակցման հարմարանքները, ինչպես նաև բացակայում\u000a            կամ անսարք են կառուցվածքով նախատեսված ապահովիչ մետաղաճոպանները (շղթաներ): Մոտոցիկլի և կողային\u000a            կցորդի շրջանակների միացումներում առկա է խաղացք:\u000a        </li>\u000a\u000a        <li>\u000a            բացակայում են`\u000a            <div class="mt-2 space-y-1">\u000a                <p>\u000a                    ա. բժշկական դեղատուփը, կրակմարիչը, վթարային կանգառի նշանը (թարթող կարմիր լապտերիկ)` ավտոբուսներում,\u000a                    թեթև մարդատար և բեռնատար ավտոմոբիլներում ու անվավոր տրակտորներում,\u000a                </p>\u000a                <p>\u000a                    բ. երկուսից ոչ պակաս հակագլորման հենակներ` համապատասխանաբար 3,5 տոննա և 5 տոննայից ավելի\u000a                    թույլատրելի առավելագույն զանգված ունեցող բեռնատար ավտոմոբիլներում և ավտոբուսներում,\u000a                </p>\u000a                <p>\u000a                    գ. բժշկական դեղատուփը, վթարային կանգառի նշանը (թարթող կարմիր լապտերիկ)` կողային կցորդով\u000a                    մոտոցիկլներում:\u000a                </p>\u000a            </div>\u000a            <p class="mt-2 text-xs text-gray-600">\u000a                Ավտոբուսում պետք է լինի առնվազն երկու կրակմարիչ, մեկը` վարորդի խցիկում, մյուսը` սրահում, իսկ\u000a                մնացած նշված տրանսպորտային միջոցներում` դյուրահաս տեղերում: Բժշկական դեղատուփում պարունակվող\u000a                պարտադիր դեղերի և բժշկական պարագաների ցանկը հաստատում է Հայաստանի Հանրապետության\u000a                առողջապահության նախարարը:\u000a            </p>\u000a        </li>\u000a\u000a        <li>\u000a            տրանսպորտային միջոցները, բացառությամբ սահմանված կարգով նախատեսված դեպքերի, կահավորված են\u000a            առկայծող փարոսիկներով և (կամ) հատուկ ձայնային ազդանշաններ արձակող սարքավորումներով, կամ դրանց\u000a            թափքերի վրա պատկերված են գունագծապատկերներ և գրառումներ (տրանսպորտային միջոցների\u000a            գունագծապատկերներին և դրանց վրա տեղադրվող առկայծող փարոսիկներին ու հատուկ ձայնային ազդանշաններին\u000a            ներկայացվող պահանջները սահմանվում են ստանդարտով, իսկ այն տրանսպորտային միջոցների ցանկը, որոնք\u000a            կարող են կահավորվել դրանցով, սահմանում է Հայաստանի Հանրապետության կառավարությունը):\u000a        </li>\u000a\u000a        <li>\u000a            բացակայում են կամ չեն աշխատում տրանսպորտային միջոցի կառուցվածքով նախատեսված նստատեղերի գլխակալները\u000a            կամ անվտանգության ամրագոտիները, կամ անվտանգության ամրագոտիների ժապավենի վրա առկա են տեսանելի\u000a            պատռվածքներ:\u000a        </li>\u000a\u000a        <li>\u000a            մոտոցիկլների և մոպեդների վրա բացակայում են կառուցվածքով նախատեսված ոտնատեղերը, թամբի վրայի ուղևորի\u000a            համար լայնակի բռնատեղը, իսկ մոտոցիկլների վրա` նաև անվտանգության աղեղները:\u000a        </li>\u000a\u000a        <li>\u000a            չեն աշխատում պահեստային անիվի բռնիչը, բարձրացման-իջեցման մեխանիզմը կամ կարապիկը:\u000a        </li>\u000a\u000a        <li>\u000a            կիսակցորդի վրա բացակայում են կամ անսարք են հենարանային սարքավորումը, հենակների տրանսպորտային\u000a            վիճակի սևեռիչը, հենակների բարձրացման-իջեցման մեխանիզմը:\u000a        </li>\u000a\u000a        <li>\u000a            խախտված է շարժիչի, փոխանցման տուփի, պտույտափոխանցիչի, հետին կամրջակի, կցորդման, ակումուլյատորային\u000a            մարտկոցի, օդի հովացման և լավորակման համակարգի և տրանսպորտային միջոցի վրա լրացուցիչ տեղադրված\u000a            հիդրավլիկ սարքավորումների միացումների կամ կիպարարների հերմետիկությունը:\u000a        </li>\u000a\u000a        <li>\u000a            գազաբալոնային սնման համակարգով կահավորված ավտոմոբիլների գազաբալոնների արտաքին մակերեսին նշված\u000a            տեխնիկական պարամետրերը չեն համապատասխանում տեխնիկական անձնագրում նշված տվյալներին, բացակայում են\u000a            վերջին և պլանավորված փորձարկումների ամսաթվերը:\u000a        </li>\u000a\u000a        <li>\u000a            առանց տրանսպորտային միջոցի հաշվառումն իրականացնող մարմնի թույլտվության` տրանսպորտային միջոցի\u000a            կառուցվածքում կատարված են փոփոխություններ (վերասարքավորումներ):\u000a        </li>\u000a\u000a        <li>\u000a            հաշվառման համարանիշերը կամ դրանց տեղակայման (ամրացման) ձևը չեն համապատասխանում օրենսդրության կամ\u000a            ստանդարտների պահանջներին:\u000a        </li>\u000a\u000a        <li>\u000a            մեխանիկական տրանսպորտային միջոցը, որով իրականացվում է գործնական վարման ուսուցումը, չունի համապատասխան\u000a            ճանաչման նշան կամ կահավորված չէ հետին դիտման լրացուցիչ հայելիով (սովորեցնողի համար) կամ կցորդման\u000a            (բացառությամբ ավտոմատ փոխհաղորդակով (տրանսմիսիայով) տրանսպորտային միջոցների) և արգելակման լրացուցիչ\u000a            ոտնակներով:\u000a        </li>\u000a\u000a        <li>\u000a            անսարք է հեծանիվի ղեկը, արգելակը կամ ձայնային ազդանշանի սարքը, կամ այն առջևից կահավորված չէ սպիտակ\u000a            գույնի լուսանդրադարձիչով և լապտերով կամ լապտերիկով (օրվա մութ ժամանակ և անբավարար տեսանելիության\u000a            պայմաններում երթևեկելու համար), հետևից` կարմիր գույնի լուսանդրադարձիչով կամ լապտերիկով, իսկ կողերից`\u000a            նարնջագույն կամ կարմիր գույնի լուսանդրադարձիչներով:\u000a        </li>\u000a\u000a        <li>\u000a            լծասայլը չունի կառուցվածքով նախատեսված կայանման սարքին արգելակ կամ հակագլորման հենակներ, առջևից\u000a            կահավորված չէ երկու սպիտակ գույնի լուսանդրադարձիչով կամ լապտերով (օրվա մութ ժամանակ և անբավարար\u000a            տեսանելիության պայմաններում երթևեկելու համար), իսկ հետևից` երկու կարմիր գույնի լուսանդրադարձիչով կամ\u000a            լապտերով:\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO exploitation_translations VALUES(12,6,101,unistr('<div class="rounded-xl border border-gray-200 bg-white p-4 md:p-5 space-y-4">\u000a    <p class="font-semibold text-gray-900">\u000a        Эксплуатация транспортного средства запрещается, если:\u000a    </p>\u000a\u000a    <ol class="list-decimal pl-5 space-y-4 text-sm leading-relaxed text-gray-800">\u000a        <li>\u000a            стеклоочистители не работают в установленном режиме либо не работают предусмотренные\u000a            конструкцией стеклоомыватели;\u000a        </li>\u000a\u000a        <li>\u000a            количество, расположение и класс зеркал заднего вида не соответствуют требованиям стандарта\u000a            либо отсутствует предусмотренное конструкцией остекление транспортного средства;\u000a        </li>\u000a\u000a        <li>\u000a            не работает звуковой сигнал или он, либо подаваемый сигнал, не соответствует стандарту;\u000a        </li>\u000a\u000a        <li>\u000a            установлены предметы или устройства, создающие опасность травмирования участников\u000a            дорожного движения либо ограничивающие обзор с места водителя;\u000a        </li>\u000a\u000a        <li>\u000a            у транспортного средства:\u000a            <div class="mt-2 space-y-1">\u000a                <p>\u000a                    а. светопропускание стёкол (в том числе заднего стекла и задних боковых стёкол\u000a                    с наружной плёнкой) не соответствует нормам, установленным законодательством\u000a                    Республики Армения,\u000a                </p>\u000a                <p>\u000a                    б. ветровое стекло или передние боковые стёкла закрыты шторками,\u000a                </p>\u000a                <p>\u000a                    в. заднее стекло или задние боковые стёкла закрыты шторками и при этом отсутствуют\u000a                    оба наружных зеркала заднего вида.\u000a                </p>\u000a            </div>\u000a        </li>\u000a\u000a        <li>\u000a            не работают предусмотренные конструкцией: замки дверей кузова или кабины, замок капота,\u000a            заглушки горловин цистерн и борта грузовой платформы, пробки топливных баков, механизм\u000a            регулировки положения сиденья водителя, аварийные приводы дверей автобуса и сигнал\u000a            «остановка по требованию», внутреннее освещение салона автобуса, аварийные выходы\u000a            и приводы их открывания, приводы управления дверями, спидометр, тахограф,\u000a            противоугонное устройство, устройства обогрева и обдува стёкол;\u000a        </li>\u000a\u000a        <li>\u000a            отсутствуют предусмотренные конструкцией заднее защитное устройство, грязезащитные\u000a            фартуки и брызговики;\u000a        </li>\u000a\u000a        <li>\u000a            неисправны элементы сцепного или опорного устройства тягача или прицепа, а также\u000a            отсутствуют или неисправны предусмотренные конструкцией страховочные цепи (тросы);\u000a            в соединениях рам мотоцикла и бокового прицепа имеется люфт;\u000a        </li>\u000a\u000a        <li>\u000a            отсутствуют:\u000a            <div class="mt-2 space-y-1">\u000a                <p>\u000a                    а. аптечка, огнетушитель, знак аварийной остановки (мигающий красный фонарь) —\u000a                    в автобусах, легковых и грузовых автомобилях и колесных тракторах;\u000a                </p>\u000a                <p>\u000a                    б. не менее двух противооткатных упоров — в грузовых автомобилях и автобусах\u000a                    с разрешённой максимальной массой соответственно более 3,5 т и более 5 т;\u000a                </p>\u000a                <p>\u000a                    в. аптечка и знак аварийной остановки (мигающий красный фонарь) — на мотоциклах\u000a                    с боковым прицепом.\u000a                </p>\u000a            </div>\u000a            <p class="mt-2 text-xs text-gray-600">\u000a                В автобусе должно быть не менее двух огнетушителей: один — в кабине водителя,\u000a                другой — в салоне. В остальных указанных транспортных средствах огнетушитель и аптечка\u000a                должны находиться в легкодоступных местах. Перечень обязательных лекарственных средств\u000a                и медицинских изделий аптечки утверждается министром здравоохранения Республики Армения.\u000a            </p>\u000a        </li>\u000a\u000a        <li>\u000a            транспортные средства, за исключением случаев, предусмотренных установленным порядком,\u000a            оснащены проблесковыми маячками и (или) специальными звуковыми сигналами либо на их кузовах\u000a            нанесены специальные цветографические схемы и надписи (требования к цветографическим схемам,\u000a            проблесковым маячкам и специальным звуковым сигналам устанавливаются стандартом, а перечень\u000a            транспортных средств, которые могут быть ими оснащены, утверждается Правительством\u000a            Республики Армения);\u000a        </li>\u000a\u000a        <li>\u000a            отсутствуют или не работают предусмотренные конструкцией подголовники сидений либо ремни\u000a            безопасности, либо на лентах ремней безопасности имеются видимые надрывы;\u000a        </li>\u000a\u000a        <li>\u000a            на мотоциклах и мопедах отсутствуют предусмотренные конструкцией подножки, поперечная\u000a            рукоятка для пассажира на седле, а на мотоциклах также защитные дуги;\u000a        </li>\u000a\u000a        <li>\u000a            не работают держатель запасного колеса, механизм его подъёма и опускания или домкрат;\u000a        </li>\u000a\u000a        <li>\u000a            на полуприцепе отсутствует или неисправно опорное устройство, фиксаторы транспортного\u000a            положения опор и механизм подъёма и опускания опор;\u000a        </li>\u000a\u000a        <li>\u000a            нарушена герметичность соединений или уплотнений двигателя, коробки передач,\u000a            раздаточной коробки, заднего моста, сцепления, аккумуляторной батареи, систем охлаждения\u000a            и кондиционирования воздуха и дополнительных гидравлических устройств, установленных\u000a            на транспортном средстве;\u000a        </li>\u000a\u000a        <li>\u000a            у автомобилей с газобаллонной системой питания указанные на наружной поверхности баллонов\u000a            технические параметры не соответствуют данным, указанным в техническом паспорте, либо\u000a            отсутствуют даты последнего и планируемого испытаний;\u000a        </li>\u000a\u000a        <li>\u000a            без разрешения органа, осуществляющего государственную регистрацию транспортных средств,\u000a            в конструкцию транспортного средства внесены изменения (переоборудование);\u000a        </li>\u000a\u000a        <li>\u000a            регистрационные знаки или способ их установки (крепления) не соответствуют требованиям\u000a            законодательства или стандартов;\u000a        </li>\u000a\u000a        <li>\u000a            механическое транспортное средство, на котором осуществляется обучение вождению, не имеет\u000a            соответствующего опознавательного знака либо не оборудовано дополнительным зеркалом заднего\u000a            вида (для инструктора) и дополнительными педалями сцепления (кроме транспортных средств\u000a            с автоматической трансмиссией) и тормоза;\u000a        </li>\u000a\u000a        <li>\u000a            у велосипеда неисправны руль, тормоз или звуковой сигнал либо он не оборудован спереди\u000a            белым световозвращателем и фонарём (для движения в тёмное время суток и в условиях\u000a            недостаточной видимости), сзади — красным световозвращателем или фонарём, а сбоку —\u000a            оранжевыми или красными световозвращателями;\u000a        </li>\u000a\u000a        <li>\u000a            гужевой повозке не хватает предусмотренного конструкцией стояночного устройства (тормоза)\u000a            или противооткатных упоров, спереди она не оборудована двумя белыми световозвращателями\u000a            или фонарями (для движения в тёмное время суток и в условиях недостаточной видимости),\u000a            а сзади — двумя красными световозвращателями или фонарями.\u000a        </li>\u000a    </ol>\u000a</div>'),'2025-11-18 16:14:29','2025-11-18 16:14:29');
INSERT INTO group_translations VALUES(1,1,102,'Խումբ 1','Մանևրում, դասավորվածություն երթևեկելի մասում, երթևեկության առավելություն','2025-05-03 22:29:09','2025-05-03 22:29:09');
INSERT INTO group_translations VALUES(2,2,102,'Խումբ 2','ՀՀ օրենք «Ճանապարհային երթևեկության անվտանգության ապահովման մասին»:','2025-05-03 22:29:09','2025-05-03 22:29:09');
INSERT INTO group_translations VALUES(3,3,102,'Խումբ 3','Տրանսպորտային միջոցների շահագործումն արգելող անսարքությունները և պայմանները:','2025-05-03 22:29:09','2025-05-03 22:29:09');
INSERT INTO group_translations VALUES(4,4,102,'Խումբ 4','Ճանապարհային նշաններ և ճանապարհային գծանշումներ:','2025-05-03 22:29:09','2025-05-03 22:29:09');
INSERT INTO group_translations VALUES(5,5,102,'Խումբ 5','Խաչմերուկ (նշաններով, առանց նշանների)','2025-05-03 22:29:09','2025-05-05 22:48:54');
INSERT INTO group_translations VALUES(6,6,102,'Խումբ 6','Խաչմերուկ (կարգավորող, լուսացույց):','2025-05-03 22:29:09','2025-05-05 22:49:10');
INSERT INTO group_translations VALUES(7,7,102,'Խումբ 7','Ճանապարհային գծանշում, կանգառ, կայանում:','2025-05-03 22:29:09','2025-05-05 22:49:28');
INSERT INTO group_translations VALUES(8,8,102,'Խումբ 8','Արագություն, քարշակում, մարդկանց և բեռների փոխադրում:','2025-05-03 22:29:09','2025-05-05 22:49:54');
INSERT INTO group_translations VALUES(9,9,102,'Խումբ 9','Նախազգուշացնող ազդանշաններ, հատուկ ազդանշաններ, վազանց.','2025-05-03 22:29:09','2025-05-05 22:50:38');
INSERT INTO group_translations VALUES(10,10,102,'Խումբ 10','Երթևեկության մասնակիցների կյանքի անվտանգության և պատահարների դեպքում առաջին օգնության և ինքնօգնության քայլերի վերաբերյալ:','2025-05-03 22:29:09','2025-05-05 22:50:42');
INSERT INTO group_translations VALUES(11,1,101,'Группа 1','Маневренность, выравнивание дороги, преимущество в движении.','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(12,2,101,'Группа 2','Закон РА \"Об обеспечении безопасности дорожного движения\".','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(13,3,101,'Группа 3','Неисправности и условия, запрещающие эксплуатацию транспортных средств.','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(14,4,101,'Группа 4','Дорожные знаки и дорожная разметка.','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(15,5,101,'Группа 5','Перекресток (со знаками, без знаков).','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(16,6,101,'Группа 6','Перекресток (регулятор, светофор).','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(17,7,101,'Группа 7','Дорожная разметка, остановка, станция.','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(18,8,101,'Группа 8','Скорость, буксировка, перевозка людей и грузов.','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(19,9,101,'Группа 9','Предупреждающие сигналы, специальные сигналы, обгон.','2025-11-06 21:18:29','2025-11-06 21:18:29');
INSERT INTO group_translations VALUES(20,10,101,'Группа 10','О безопасности жизнедеятельности участников дорожного движения и мерах первой помощи и самопомощи при ДТП.','2025-11-06 21:18:29','2025-11-06 21:18:29');
