INSERT INTO pdd_chapter_translations VALUES(106,106,102,'I. ԸՆԴՀԱՆՈՒՐ ԴՐՈՒՅԹՆԵՐ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(107,107,102,'II. ԼՈՒՍԱՑՈՒՅՑԻ ԵՎ ԿԱՐԳԱՎՈՐՈՂԻ ԱԶԴԱՆՇԱՆՆԵՐԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(108,108,102,'III. ՎԹԱՐԱՅԻՆ ԱԶԴԱՆՇԱՆԻ ԵՎ "ՎԹԱՐԱՅԻՆ ԿԱՆԳԱՌ" ՃԱՆԱՉՄԱՆ ՆՇԱՆԻ ԿԻՐԱՌՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(109,109,102,'IV. ՀԱՏՈՒԿ ԱԶԴԱՆՇԱՆՆԵՐԻ ԿԻՐԱՌՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(110,110,102,'V. ԵՐԹԵՎԵԿՈՒԹՅԱՆ ՍԿԻԶԲԸ ԵՎ ՄԱՆԵՎՐՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(111,111,102,'VI. ՏՐԱՆՍՊՈՐՏԱՅԻՆ ՄԻՋՈՑՆԵՐԻ ԴԱՍԱՎՈՐՈՒԹՅՈՒՆԸ ԵՐԹԵՎԵԿԵԼԻ ՄԱՍՈՒՄ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(112,112,102,'VII. ԵՐԹԵՎԵԿՈՒԹՅԱՆ ԱՐԱԳՈՒԹՅՈՒՆԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(113,113,102,'VIII. ՎԱԶԱՆՑԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(114,114,102,'IX. ԿԱՆԳԱՌԸ ԵՎ ԿԱՅԱՆՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(115,115,102,'X. ԽԱՉՄԵՐՈՒԿՆԵՐԻ ԱՆՑՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(116,116,102,'XI. ՀԵՏԻՈՏՆԱՅԻՆ ԱՆՑՈՒՄՆԵՐԻ ՀԱՏՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(117,117,102,'XII. ԵՐԹԵՎԵԿՈՒԹՅՈՒՆԸ ԵՐԿԱԹՈՒՂԱՅԻՆ ԳԾԱՆՑՆԵՐՈՎ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(118,118,102,'XIII. ԵՐԹԵՎԵԿՈՒԹՅՈՒՆՆ ԱՎՏՈՄԱՅՐՈՒՂԻՆԵՐՈՎ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(119,119,102,'XIV. ԵՐԹԵՎԵԿՈՒԹՅՈՒՆԸ ԲՆԱԿԵԼԻ ԳՈՏԻՆԵՐՈՒՄ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(120,120,102,'XV. ԸՆԴՀԱՆՈՒՐ ՕԳՏԱԳՈՐԾՄԱՆ ՏՐԱՆՍՊՈՐՏԱՅԻՆ ՄԻՋՈՑՆԵՐԻ ԵՐԹԵՎԵԿՈՒԹՅԱՆ ԱՌԱՎԵԼՈՒԹՅՈՒՆԸ ԵՎ ԴՐԱՆՑ ԿԱՆԳԱՌԻ ԿԵՏԵՐԻ ԱՆՑՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(121,121,102,'XVI. ԱՐՏԱՔԻՆ ԼՈՒՍԱՅԻՆ ՍԱՐՔԵՐԻ ԵՎ ՁԱՅՆԱՅԻՆ ԱԶԴԱՆՇԱՆԻ ԿԻՐԱՌՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(122,122,102,'XVII. ՄԵԽԱՆԻԿԱԿԱՆ ՏՐԱՆՍՊՈՐՏԱՅԻՆ ՄԻՋՈՑՆԵՐԻ ՔԱՐՇԱԿՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(123,123,102,'XVIII. ՈՒՍՈՒՄՆԱԿԱՆ ՎԱՐՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(124,124,102,'XIX. ՄԱՐԴԿԱՆՑ ՓՈԽԱԴՐՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(125,125,102,'XX. ԲԵՌՆԵՐԻ ՓՈԽԱԴՐՈՒՄԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
INSERT INTO pdd_chapter_translations VALUES(126,126,102,'XXI. ՃԱՆԱՊԱՐՀԱՅԻՆ ՆՇԱՆՆԵՐԸ, ՃԱՆԱՊԱՐՀԱՅԻՆ ԳԾԱՆՇՈՒՄԸ ԵՎ ԴՐԱՆՑ ԲՆՈՒԹԱԳՐԵՐԸ, ՏՐԱՆՍՊՈՐՏԱՅԻՆ ՄԻՋՈՑԻ ՃԱՆԱՉՄԱՆ ՆՇԱՆՆԵՐԸ','2025-05-04 22:28:59','2025-05-04 22:28:59');
