INSERT INTO question_translations VALUES(5560,5557,102,'Նշաններից ո՞րն է կոչվում «Արգելքի շրջանցումը ձախից»։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5561,5558,102,'Թույլատրվու՞մ է արդյոք ավտոբուսի վարորդին մուտք գործել խաչմերուկ տվյալ  իրադրությունում։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5562,5559,102,'Նշված դեպքում ո՞ր գոտուց պետք է կատարվի աջ շրջադարձը։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5563,5560,102,'Խաչմերուկում կազմակերպված է շրջանաձև երթևեկություն։ Երթևեկելի մասը, որով մոտենում  եք խաչմերուկին, ունի երթևեկության երկու գոտի։ Խաչմերուկ մուտք գործելիս` շրջադարձ կատարելու համար ո՞ր գոտին եք պարտավոր զբաղեցնել՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5564,5561,102,'Թույլատրվու՞մ է արդյոք մուտք գործել բակ նշված տեղից։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5565,5562,102,'Երկկողմ երթևեկությամբ գծանշված ճանապարհներին, երեք գոտու առկայության դեպքում  (բացառությամբ երթևեկության դարձափոխային կարգավորմամբ ճանապարհների), որոնցից միջինն օգտագործվում է երկու ուղղություններով երթևեկության համար, ձախ եզրային գոտի մուտք գործելը՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5566,5563,102,'Ո՞ր  պատասխանում  է  ճիշտ  նշված  երթևեկության թույլատրելի  ուղղությունը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5567,5564,102,'Ո՞ր ուղղությամբ է արգելվում երթևեկությունը՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5568,5565,102,'Հետադարձն  արգելվում  է՝','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5569,5566,102,'Թույլատրվու՞մ է  արդյոք  դեղին ավտոբուսի  վարորդին  մուտք գործել  խաչմերուկ։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5570,5567,102,'Ո՞ր պատասխանում  է  ճիշտ  նշված  երթևեկության թույլատրելի  ուղղությունը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5571,5568,102,'Հետադարձն արգելվում է, եթե ճանապարհի թեկուզ և մեկ ուղղությամբ տեսանելիությունը պակաս է՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5572,5569,102,'Դուք երթևեկում եք երեք գոտի ունեցող երկկողմ երթևեկությամբ ճանապարհով։ Ո՞ր դեպքում է  թույլատրվում  մուտք գործել միջին գոտի։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5573,5570,102,'Ո՞ր ուղղությամբ է թույլատրվում բեռնատար ավտոմոբիլի երթևեկությունը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5574,5571,102,'Ո՞ր նկարում է  վարորդը ճիշտ կատարում մանևրը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5575,5572,102,'Ո՞ր տրանսպորտային միջոցի վարորդն է ճիշտ կատարում հետադարձը։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5576,5573,102,'Ճանապարհային նշանների, գծանշման և բաժանարար  գոտու բացակայության  դեպքում վարորդները երկկողմ  երթևեկությամբ ճանապարհների  երթևեկելի  մասում  գտնվող ճանապարհային կառույցների տարրերը պետք  է  շրջանցեն՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5577,5574,102,'Ո՞ր  ուղղությամբ է արգելվում երթևեկությունը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5578,5575,102,'Ո՞ր  տրանսպորտային  միջոցի  վարորդն  է  խախտում կանոնները  շրջադարձ  կատարելիս՝  արգելակման  գոտի ունեցող  ճանապարհին։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5579,5576,102,'Թույլատրվու՞մ է արդյոք տվյալ իրադրությունում կարմիր ավտոմոբիլի վարորդին  շարունակել  երթևեկությունը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5580,5577,102,'Երեք գոտի ունեցող երկկողմ երթևեկությամբ ճանապարհի վրա Ձեզ  անհրաժեշտ  է կատարել  ձախ շրջադարձ։  Ո՞ր գոտուց կկատարեք  տվյալ մանևրը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5581,5578,102,'Թույլատրվու՞մ  է  արդյոք  կարմիր  ավտոմոբիլի  վարորդին երթևեկել  տրամվայի  գծերով։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5582,5579,102,'Հետադարձն  արգելվում  է՝','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5583,5580,102,'Ո՞ր  ուղղություններով  է  թույլատրվում  երթևեկությունը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5584,5581,102,'Ո՞ր  տրանսպորտային  միջոցների  վարորդներն  են  խախտել ճանապարհային  նշանի պահանջները։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5585,5582,102,'Համընթաց ուղղությամբ երթևեկող տրանսպորտային միջոցների միաժամանակյա վերադասավորման դեպքում ճանապարհը պետք է զիջի՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5586,5583,102,'Ո՞ր տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթևեկության  իրավունք։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5587,5584,102,'Պարտավո՞ր է արդյոք սահմանված երթուղով երթևեկող ավտոբուսի վարորդը նշված իրադրությունում  զիջել ճանապարհը։','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5588,5585,102,'Եթե համապատասխան  նշաններով  կահավորված  երկայնական թեքությամբ ճանապարհահատվածներում  հանդիպակաց երթևեկությունը  դժվարացած  է, ապա ճանապարհը  պետք  է զիջել՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5589,5586,102,'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։','2025-05-18 20:17:11','2025-05-18 20:17:11');
INSERT INTO question_translations VALUES(5590,5587,102,'Երթևեկության առավելություն ունի՝','2025-05-18 20:17:11','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5591,5588,102,'Պարտավո՞ր են արդյոք տրանսպորտային միջոցների վարորդները   բնակավայրերում  ճանապարհը  զիջել կահավորված և նշված կանգառի կետերի տարածքից երթևեկությունը սկսող ընդհանուր օգտագործման տրանսպորտային միջոցներին։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5592,5589,102,'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5593,5590,102,'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5594,5591,102,'Ո՞ր տրանսպորտային  միջոցի վարորդը պետք է զիջի ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5595,5592,102,'Նշե՛ք  խաչմերուկի  անցման  հերթականությունը`','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5596,5593,102,'Հանդիպակաց  երթևեկության  դեպքում  կտրուկ  վայրէջքի  վրա անհրաժեշտ  է  ճանապարհը զիջել՝','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5597,5594,102,'Բնակավայրերում միևնույն ուղղությամբ երթևեկության 3 և ավելի գոտիների առկայության դեպքում ձախ եզրային գոտի զբաղեցնել  թույլատրվու՞մ է արդյոք  ընդհանուր օգտագործման տրանսպորտային միջոցներին։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5598,5595,102,'Բոլոր ճանապարհներին միևնույն ուղղությամբ երթևեկության 3 և ավելի գոտիների առկայության դեպքում ձախ եզրային գոտի զբաղեցնել  թույլատրվու՞մ է արդյոք ընդհանուր օգտագործման տրանսպորտային միջոցներին։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5599,5596,102,'Ինչպե՞ս պետք է վարվի երթուղային ավտոբուսի վարորդը տվյալ իրավիճակում։','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5600,5597,102,'Տվյալ իրադրությունում սպիտակ թեթև մարդատար ավտոմոբիլի վարորդը`','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5601,5598,102,'Ո՞ր տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթևեկության իրավունք։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5602,5599,102,'Ո՞ր տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթևեկության իրավունք տվյալ իրավիճակում։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5603,5600,102,'Խաչմերուկում որտեղ կազմակերպված է շրջանաձև երթևեկություն, պարտավո՞ր է արդյոք ավտոբուսի վարորդը զիջել ճանապարհը բեռնատար ավտոմոբիլին։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5604,5601,102,'Երթևեկությունն ուղիղ շարունակող ավտոբուսի վարորդը պարտավո՞ր է արդյոք զիջել ճանապարհը բեռնատար ավտոմոբիլին։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5605,5602,102,'Եթե մտադիր եք  շարունակել երթևեկությունն ուղիղ, ո՞ր տրանսպորտային միջոցին  պետք է զիջեք ճանապարհը։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5606,5603,102,'Եթե մտադիր եք  շարունակել երթևեկությունն ուղիղ, ու՞մ պետք է զիջեք ճանապարհը։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5607,5604,102,'Տվյալ իրադրությունում  պարտավո՞ր է մոտոցիկլի վարորդը զիջել ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5608,5605,102,'Տվյալ իրադրությունում ունե՞ք արդյոք նշված մանևրի իրավունք։','2025-05-18 20:17:12','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5609,5606,102,'Դուք շարունակում եք երթևեկությունն ուղիղ, ո՞ր տրանսպորտային  միջոցին   պետք է զիջեք  ճանապարհը։','2025-05-18 20:17:12','2025-05-19 18:25:40');
