INSERT INTO question_translations VALUES(5615,5612,102,'Եթե մտադիր եք խաչմերուկում կատարել ձախ շրջադարձ, ո՞ր տրանսպորտային միջոցին պետք է զիջեք ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
