INSERT INTO question_translations VALUES(5617,5614,102,'Եթե մտադիր եք խաչմերուկում կատարել հետադարձ, ո՞ր տրանսպորտային միջոցին պետք է զիջեք ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5618,5615,102,'Եթե մտադիր եք կատարել ձախ շրջադարձ, ո՞ր տրանսպորտային միջոցին պետք է զիջեք ճանապարհը։','2025-05-18 20:17:12','2025-05-18 20:17:12');
