INSERT INTO question_translations VALUES(5665,5662,102,'Թույլատրվո՞ւմ է թեթև մարդատարի վարորդին սկսել շարժումը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5666,5663,102,'Ո՞ր տարբերակում է թույլատրված հետընթացը','2025-05-18 20:17:12','2025-05-18 20:17:12');
