INSERT INTO question_translations VALUES(5673,5670,102,'Զիջել ճանապարհը բեռնատարի վարորդին','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5674,5671,102,'Ո՞ր հետագծով է թույլատրված հետադարձը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5675,5672,102,'Ո՞ր հետագծով է թույլատրված հետադարձը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5676,5673,102,'Ճանապարհը պետք է զիջի','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5677,5674,102,'Թույլատրվո՞ւմ է պատահմամբ անցած խաչմերուկում հետընթաց վարմամբ շտկել և շարունակել երթևեկությունը մեզ անհրաժեշտ ուղղությամբ','2025-05-18 20:17:12','2025-05-18 20:17:12');
