INSERT INTO question_translations VALUES(5680,5677,102,'Վերադասավորվելով հարևան գոտի այս իրավիճակում','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5681,5678,102,'Ո՞ր հետագծով է թույլատրված հետադարձը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5682,5679,102,'Ո՞ր հետագծով է թույլատրված ձախ շրջադարձը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5683,5680,102,'Այս իրավիճակում թո՞ւյլատրվում է հետընթացով մոտենալ ուղևորին','2025-05-18 20:17:12','2025-05-18 20:17:12');
