INSERT INTO question_translations VALUES(5687,5684,102,'Հետընթացով մոտենալ ուղևորին այս իրավիճակում','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5688,5685,102,'Ո՞ր վարորդն է խախտում երթևեկության կանոնները դուրս գալով շրջանաձև երթևեկությամբ խաչմերուկից','2025-05-18 20:17:12','2025-05-18 20:17:12');
