INSERT INTO question_translations VALUES(5691,5688,102,'Պարտավոր եք արդյո՞ք միացնել աջ շրջադարձի ցուցիչ այս խաչմերուկում','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5692,5689,102,'Մերձակա տարածք մուտք գործելիս վարորդը պետք է ճանապարհը զիջի','2025-05-18 20:17:12','2025-05-18 20:17:12');
