INSERT INTO question_translations VALUES(5694,5691,102,'Հետադարձ կատարել նշանից հետո թույլատրվում է','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5695,5692,102,'Ազդանշան տալը երթևեկության մյուս մասնակիցների նկատմամբ առավելություն','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5696,5693,102,'Նշված հետագծով աջ շրջադարձը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5697,5694,102,'Բեռնատարից առաջ անցնելուց հետո ո՞ր գոտով կարող եք շարունակել երթևեկությունը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5698,5695,102,'Հետադարձը նշված վայրում','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5699,5696,102,'Առաջնահերթ երթևեկության իրավունք ունի','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5700,5697,102,'Միաժամանակ վերադասավորվելիս ո՞ր տրանսպորտային միջոցի վարորդը ունի առաջնահերթ երթևեկության իրավունք','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5701,5698,102,'Թույլատրվո՞ւմ է հետընթացով մոտենալ ուղևորին','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5702,5699,102,'Աջ բակ մուտք գոծելու դեպքում պարտավոր ենք զիջել','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5703,5700,102,'Այս վերելքի ուղղությամբ շարժվելիս հետադարձ թույլատրվում է, եթե','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5704,5701,102,'Ո՞ր տրանսպորտային միջոցի վարորդը պետք է զիջի ճանապարհը','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5705,5702,102,'Թույլատրվում է հետադարձն այս վայրում','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5706,5703,102,'Թույլատրվո՞ւմ է անցնել կամուրջը, եթե դա չի խոչընդոտում մոտոցիկլի վարորդին','2025-05-18 20:17:12','2025-05-18 20:17:12');
INSERT INTO question_translations VALUES(5707,5704,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն ուղևոր է համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5708,5705,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ  օրենքի  համաձայն՝ «A» կարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական  կարող է տրվել՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5709,5706,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «BE» կարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5710,5707,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն`  ճանապարհի երթևեկելի  մաս է համարվում`','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5711,5708,102,'Պարտավո՞ր  է արդյոք  վարել  սովորողն  ուսումնական  վարման ժամանակ  ամրակապվել  անվտանգության  գոտիներով։','2025-05-18 20:17:13','2025-05-18 20:17:13');
INSERT INTO question_translations VALUES(5712,5709,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «D» կարգի  և «D1» ենթակարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5713,5710,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»   ՀՀ   օրենքի  համաձայն՝  հետիոտն  է  համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5714,5711,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի գործնական վարման սկզբնական ուսուցումը  իրականացվում է՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5715,5712,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն` մերձակա  տարածքից ելքը դեպի ճանապարհ համարվու՞մ  է  արդյոք խաչմերուկ։','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5716,5713,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «B», «C» և «D»  կարգերի տրանսպորտային  միջոցներ  վարելու իրավունքի վկայական ունեցող անձանց թույլատրվում է դրանք վարել նաև կցորդներով, եթե  կցորդի թույլատրելի առավելագույն զանգվածը չի գերազանցում','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5717,5714,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ օրենքի համաձայն՝ երթևեկելի մասով հեծանվորդներին  արգելվում է երթևեկել՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5718,5715,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ «B» և «C» կարգերի տրանսպորտային  միջոցներ  վարելու  իրավունքի վկայական կարող է տրվել՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5719,5716,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»    ՀՀ   օրենքի   համաձայն՝  մոպեդ  է  համարվում ՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5720,5717,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն՝  հարկադրված կանգառ է համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5721,5718,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ անբավարար տեսանելիություն  է համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5722,5719,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն՝ կանգառ է համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5723,5720,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման  մասին»  ՀՀ   օրենքի  համաձայն՝ ընդհանուր օգտագործման  տրանսպորտային  միջոց  է  համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5724,5721,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝  հետիոտներին  են հավասարեցվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5725,5722,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝  կցորդ  (կիսակցորդ)  է համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5726,5723,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն՝  Հայաստանի Հանրապետության ճանապարհներին սահմանվում է՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5727,5724,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝  կայանում է համարվում՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5728,5725,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝  ՀՀ զինված ուժեր և այլ զորքեր զորակոչված անձանց  «D»  կարգի և «D1» ենթակարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել՝','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5729,5726,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ օրենքի համաձայն՝ տրանսպորտա յին  միջոցի ձեռք բերման օրվանից ի՞նչ ժամկետում այն պետք  է  ներկայացվի պետական գրանցման՝  Ճանապարհային  ոստիկանության մարմիններ։','2025-05-18 20:17:13','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5730,5727,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման  մասին»  ՀՀ  օրենքի համաձայն՝ ճանապարհային երթևեկությանը   մասնակցող  տրանսպորտային միջոցը տեխնիկապես  սարքին  վիճակում  պահպանելու  համար պատասխանատվություն կրում է՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5731,5728,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման  մասին»  ՀՀ  օրենքի  համաձայն՝  երթևեկությունը սկսելուց  առաջ  տրանսպորտային  միջոցի  վարորդը պարտավոր  է  ստուգել՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5732,5729,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի վարորդը պարտավոր է օժանդակելու նպատակով  տրամադրել տրանսպորտային միջոցը՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5733,5730,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային  միջոցի վարորդը պարտավոր է  ճանապարհատրանսպորտային պատահարին առընչություն ունենալու դեպքում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5734,5731,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն՝ մեխանիկական տրանսպորտային միջոցի վարորդը պարտավոր է իր մոտ ունենալ՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5735,5732,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման  մասին»  ՀՀ  օրենքի համաձայն՝  երթևեկության գոտի  է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5736,5733,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ թույլատրելի առավելագույն զանգված  է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5737,5734,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»   ՀՀ  օրենքի  համաձայն՝ կարգավորող  է  համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5738,5735,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ տրանսպորտային  միջոց  վարել սովորեցնողը՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5739,5736,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝  վթարային  իրադրություն  է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5740,5737,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»   ՀՀ   օրենքի  համաձայն՝  օրվա մութ  ժամանակ  է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5741,5738,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ ավտոբուս  է  համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5742,5739,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ թեթև  մարդատար  ավտոմոբիլ է  համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5743,5740,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ  օրենքի համաձայն՝ հետիոտներին են հավասարեցվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5744,5741,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ տրանսպորտային միջոցներ վարելու իրավունքը ծագում է՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5745,5742,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»   ՀՀ  օրենքի  համաձայն՝  «A»  և  «B»  կարգերի տրանսպորտային միջոցներ վարելու միջազգային վարորդական վկայականները  կարող են տրվել՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5746,5743,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ   օրենքի  համաձայն՝  «C»   կարգի տրանսպորտային միջոցներ վարելու միջազգայի ն վարորդական վկայական կարող է տրվել՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5747,5744,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն՝ ազգային վարորդական  վկայականները  տրվում  են՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5748,5745,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման  մասին»   ՀՀ   օրենքի  համաձայն`  միջազգային վարորդական  վկայականները  տրվում են՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5749,5746,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման  մասին»  ՀՀ  օրենքի համաձայն՝  Ճանապարհային ոստիկանության  ստորաբաժանումներում (բացառությամբ «AM» ենթակարգի տրանսպորտային միջոցի վարորդի թեկնածուի) վարորդի  թեկնածուն կարող  է  մասնակցել  գործնական քննության, եթե լրացել է նրա','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5750,5747,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի  համաձայն՝ կանգառ է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5751,5748,102,'«Ճանապարհային  երթևեկության  անվտանգության ապահովման  մասին»  ՀՀ   օրենքի  համաձայն՝ ընդհանուր օգտագործման  տրանսպորտային  միջոց  է  համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5752,5749,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ տրանսպորտային միջոցի թույլատրելի առավելագույն  զանգված  է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5753,5750,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝ «B», «C»,  «D»  կարգերի և «C1», «D1» ենթակարգերի տրանսպորտային  միջոցներ  վարե լու իրավունքի վկայական ունեցող անձանց թույլատրվում է դրանք վարել նաև կցորդներով, եթե  կցորդի առավելագույն թույլատրելի զանգված է։','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5754,5751,102,'«Ճանապարհային  երթևեկության անվտանգության ապահովման մասին»  ՀՀ  օրենքի համաձայն՝ ընդհանուր օգտագործման տրանսպորտային միջոցի կանգառի կետ է համարվում՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5755,5752,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝   «D»  կարգի և «D1» ենթակարգի տրանսպորտային միջոցներ վարելու իրավունքի վկայական կարող է տրվել այն անձանց, ովքեր ունեն`','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5756,5753,102,'«Ճանապարհային երթևեկության անվտանգության ապահովման մասին» ՀՀ օրենքի համաձայն՝  «D»,  «DE»   կարգերի,  «D1» և «D1E»  ենթակարգերի տրանսպորտային միջոցներ վարելու միջազգային վարորդական իրավունքի վկայական կարող է տրվել՝','2025-05-18 20:17:14','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5757,5754,102,'Հողային ծածկույթով ճանապարհից դուրս գալով ասֆալտբետոնե ծածկույթ ունեցող ճանապարհ','2025-05-18 20:17:14','2025-05-18 20:17:14');
