INSERT INTO question_translations VALUES(5877,5874,102,'Ի՞նչ  է  ցույց  տալիս  այս  նշանի  տակ  տեղադրված  ցուցանակը՝','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5878,5875,102,'Այս  ճանապարհային  նշանը նախազգուշացնում է, որ  առջևում՝','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5879,5876,102,'Նշաններից ո՞րն է ցույց տալիս տրանսպորտային միջոցների կանգառն ու կայանելն արգելող ճանապարհային  նշանների ազդման գոտին։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5880,5877,102,'Հետևյալ նշաններից ո՞րն է ցույց տալիս նախազգուշացնող նշանների ազդեցության` ճանապարհի վտանգավոր  հատվածի երկարությունը։','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5881,5878,102,'Այս ճանապարհային նշանը ցույց է տալիս՝','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5882,5879,102,'Նշաններից ո՞րն է կոչվում «Հյուրանոց» կամ «Մոթել»։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5883,5880,102,'Այսպիսի   ճանաչման  նշանով  կահավորվում  են  այն ավտոմոբիլները, որոնք՝','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5884,5881,102,'Նշաններից ո՞րն է ցույց տալիս 50 կմ/ժ առավելագույն արագության սահմանափակման գոտու վերջը։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5885,5882,102,'Ինչի՞ մասին են զգուշացնում այս նշանը և ցուցանակը։','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5886,5883,102,'Այսպիսի ճանաչման նշանով են կահավորվում այն տրանսպորտային միջոցները,  որոնք՝','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5887,5884,102,'Նշաններից ո՞րն է  վերացնում նախկին բոլոր սահմանափակումները։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5888,5885,102,'Ո՞ր դեպքում է վարորդը ճիշտ կատարել այս նշանի պահանջները։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5889,5886,102,'Տեղադրվածներից ո՞րն է  կիրառվում որպես ավտոգնացքի ճանաչման նշան։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5890,5887,102,'Ո՞ր նշանն է  պարտադրում զիջել ճանապարհը հատվող ճանապարհով երթևեկող տրանսպորտային միջոցներին։','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5891,5888,102,'Հետևյալ նշաններից  (ցուցանակներից) ո՞րն է  ցույց  տալիս տրանսպորտային  միջոցի կանգնեցման  ձևը կայանման տեղերում։','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5892,5889,102,'Թույլատրվու՞մ  է  արդյոք  ուղևորներ նստեցնելու համար  կանգ առնել այս նշանով նշված գոտու վրա։','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5893,5890,102,'Այս ճանապարհային նշանի առկայության դեպքում՝','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5894,5891,102,'Նշաններից  ո՞րն  է  կոչվում    «Հատում  հեծանվային  արահետի հետ»։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5895,5892,102,'Նշաններից ո՞րն  է  ցույց  տալիս  երթևեկության ուղղությունները   T-աձև  խաչմերուկում։','2025-05-18 20:17:24','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5896,5893,102,'Այս  ճանապարհային  նշանը ցույց է տալիս՝','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5897,5894,102,'Ո՞ ր  նշանի ազդեցությունը չի տարածվում ընդհանուր օգտագործման տրանսպորտային միջոցների վրա։','2025-05-18 20:17:24','2025-05-18 20:17:24');
INSERT INTO question_translations VALUES(5898,5895,102,'Ո՞ր տրանսպորտային  միջոցների երթևեկությունն  է թույլատրվում այս նշանի ազդեցության ճանապարհներին։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5899,5896,102,'Այս ճանապարհային նշաններից ո՞րը չի համարվում արգելող։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5900,5897,102,'Ի՞նչ է նշանակում այս ճանաչման նշանը։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5901,5898,102,'Նշաններից ո՞րն է կոչվում  «Միակողմ երթևեկությամբ ճանապարհի վերջ»։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5902,5899,102,'Նշաններից ո՞րն է պարտադրում զիջել ճանապարհը  հատվող ճանապարհով ընթացող տրանսպորտային  միջոցներին։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5903,5900,102,'Հետևյալ նշանները ցույց են տալիս՝','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5904,5901,102,'Այս նշաններից  ո՞րն է համարվում տրանսպորտային  միջոցի ճանաչման նշան։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5905,5902,102,'Ո՞ր տրանսպորտային միջոցի երթևեկությունն է արգելում այս ճանապարհային  նշանը։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5906,5903,102,'Նշաններից  ո՞րն  է  ցույց  տալիս  արգելքի շրջանցումն  աջից կամ  ձախից։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5907,5904,102,'Նշաններից ո՞րն է տեղադրվում  տրանսպորտային միջոցների առջևի և ետևի կողմերում` երեխաների կազմակերպված խմբեր տեղափոխելիս։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5908,5905,102,'Ի՞նչ  են ցույց տալիս նշված ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5909,5906,102,'Ի՞նչ են ցույց տալիս նշված ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5910,5907,102,'Ո՞ր նշանների ազդեցությունն է գործում միայն այն ժամանակահատվածում, որի ընթացքում երթևեկելի մասի ծածկույթը խոնավ է։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5911,5908,102,'Ինչպե՞ս պետք է  վարվի վարորդը տվյալ իրադրությունում։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5912,5909,102,'Ի՞նչ  են ցույց տալիս նշված ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5913,5910,102,'Ո՞ր ուղղությամբ է  թույլատրվում վարորդին երթևեկել։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5914,5911,102,'Ի՞նչ  են  ցույց տալիս նշված ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5915,5912,102,'Ո՞ր ճանապարհային նշանն է արգելում հետադարձը։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5916,5913,102,'Ի՞նչ  են ցույց տալիս նշված ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5917,5914,102,'Ի՞նչպես պիտի  վարվի վարորդն այն դեպքում, երբ խաչմերուկից առաջ տեղադրված է հետևյալ ճանապարհային նշանը։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5918,5915,102,'Ո՞ր ճանապարհային նշանների ազդեցությունը չի տարածվում ընդհանուր օգտագործման  տրանսպորտային միջոցների  վրա։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5919,5916,102,'Հետևյալ ճանապարհային  նշանը ցույց է տալիս`','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5920,5917,102,'Տվյալ իրադրությունում պարտավո՞ր է վարորդը  ճանապարհը զիջել բեռնատար ավտոմոբիլին։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5921,5918,102,'Ի՞նչ  են ցույց տալիս հետևյալ ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5922,5919,102,'Ի՞նչ են ցույց տալիս հետևյալ ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5923,5920,102,'Ի՞նչ  է ցույց տալիս հետևյալ ճանապարհային նշանը։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5924,5921,102,'Ո՞ր ճանապարհային նշանն է պարտադրում վարորդին երթևեկել միայն դեպի ձախ կամ դեպի աջ։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5925,5922,102,'Ի՞նչ  են ցույց  տալիս հետևյալ ճանապարհային նշանները։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5926,5923,102,'Տվյալ ճանապարհային նշանների ազդեցությունը տարածվում է`','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5927,5924,102,'Տվյալ իրադրությունում ո՞ր հետագծով է թույլատրվում արգելքի շրջանցումը։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5928,5925,102,'Ինչպե՞ս պետք է վարվի վարորդը տվյալ իրավիճակում։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5929,5926,102,'Ի՞նչպես պետք է  վարվի վարորդը, եթե խաչմերուկում մտադիր է կատարել աջ շրջադարձ։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5930,5927,102,'Տվյալ իրադրությունում նշանից 200 մ հեռավորության վրա վարորդն ունի՞ արդյոք հետադարձի իրավունք։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5931,5928,102,'Տվյալ դեպքում պարտավո՞ր է  վարորդը կանգ առնել կարգավորողի կողմից նշված տեղում։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5932,5929,102,'Ինչպե՞ս պետք է վարվի վարորդը տվյալ իրավիճակում։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5933,5930,102,'Ի՞նչ  է  ցույց տալիս երթևեկելի մասում արված գծանշումը։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5934,5931,102,'Ո՞ ր ուղղությամբ է թույլատրվում թեթև մարդատար ավտոմոբիլի երթևեկությունը։','2025-05-18 20:17:25','2025-05-19 18:25:40');
INSERT INTO question_translations VALUES(5935,5932,102,'Ինչպե՞ս պետք է  վարվի վարորդը տվյալ իրադրությունում։','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5936,5933,102,'Ստորև ներկայացվող ճանապարհային նշաններից ո՞րն է արգելում մուտք գործել խաչմերուկի տարածք, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, բացառությամբ աջ կամ ձախ շրջադարձ կատարելու դեպքերի','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5937,5934,102,'Ի՞նչ առավելագույն հեռավորության վրա է տեղադրվում բարդ խաչմերուկներում «խաչմերուկի տարածք» ճանապարհային նշանը, եթե այն հնարավոր չէ տեղադրել խաչմերուկի սահմանին :','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5938,5935,102,'Ինչի՞ մասին է զգուշացնում հետևյալ ճանապարհային նշանը:','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5939,5936,102,'Ի՞նչ է ցույց տալիս հետևյալ ճանապարհային գծանշումը:','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5940,5937,102,'Ստորև ներկայացված ճանապարհային գծանշումներից ո՞րն է ցույց տալիս խաչմերուկի հատվածը, որտեղ արգելվում է մուտք գործել, եթե առջևում՝ երթևեկության ուղղությամբ առաջացել է խցանում, որը վարորդին կհարկադրի կանգ առնել:','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5941,5938,102,'Հետադարձ կատարել նշված գոտուց','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5942,5939,102,'Ո՞ր հետագծով է թույլատրվում հետադարձ կատարել','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5943,5940,102,'Ո՞ր հետագծով է թույլատրվում հետադարձ կատարել','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5944,5941,102,'Ո՞ր հետագծով է թույլատրվում հետադարձ կատարելը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5945,5942,102,'Պարտավոր եք արդյո՞ք կանգ առնել «Կանգ-գծի» առջև','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5946,5943,102,'Երթևեկությունը թույլատրվում է','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5947,5944,102,'Այս իրավիճակում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5948,5945,102,'Այս նշաններից հետո 3.5 տոննայից ոչ ավել թույլատրելի առավելագույն զանգվածով բեռնատարի վարորդին երթևեկության առավելագույն արագությունը սահմանված է','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5949,5946,102,'Ի՞նչն է արգելված այս ճանապարհային նշանով','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5950,5947,102,'Որտե՞ղ է անհրաժեշտ կանգ առնել նշանի պահանջը կատարելիս','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5951,5948,102,'Ո՞ր նշանն է արագության սահմանափակում մտցնում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5952,5949,102,'Նշաններից ո՞րի ազդեցությունն է տարածվում միայն այն գոտում, որի վրա կախված է','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5953,5950,102,'Կայանել նշված վայրում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5954,5951,102,'Խախտել է արդյո՞ք կայանման կանոնները բեռնատարի վարորդը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5955,5952,102,'Ո՞ր ուղղությամբ է թույլատրված երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5956,5953,102,'Ի՞նչ է ցույց տալիս լրացուցիչ տեղեկատվության ցուցանակը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5957,5954,102,'Կանգառ կատարել նշված վայրում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5958,5955,102,'Ո՞ր նշանների ազդեցությունն է տարածվում շարժման ուղղությամբ մինչև մոտակա խաչմերուկը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5959,5956,102,'Այս նշաններով ի՞նչ արագության ռեժիմ է սահմանված ճանապարհին','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5960,5957,102,'Նշաններից, որն է արգելում ձախ շրջադարձ կատարել','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5961,5958,102,'Թույլատրվո՞ւմ է վարորդին կատարել ձախ շրջադարձ','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5962,5959,102,'Նշանները տեղեկացնում են այն մասին, որ','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5963,5960,102,'Ո՞ր հետագծերով է թույլատրված երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5964,5961,102,'Նշաններից ո՞րն է արգելում երթևեկությունը 40կմ/ժ-ից պակաս արագությամբ','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5965,5962,102,'Նշաններից ո՞րի դեպքում պետք է զիջեք ճանապարհը հանդիպակաց երթևեկողին նեղ հատվածում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5966,5963,102,'Ո՞ր ուղղությամբ կարող եք շարունակել երթևեկությունն այս խաչմերուկում, եթե վարում եք 3.5 տոննա թույլատրելի առավելագույն զանգվածով բեռնատար ավտոմեքենա','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5967,5964,102,'Թո՞ւյլատրվում է աջ շրջադարձ դեպի հողային ծածկույթով ճանապարհը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5968,5965,102,'Թույլատրվո՞ւմ է ուղևոր նստեցնելու նպատակով կանգառ կատարել նշված վայրում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5969,5966,102,'Ո՞ր նշանով է նշվում հետիոտնային արահետը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5970,5967,102,'Այս ճանապարհային նշանը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5971,5968,102,'Ինչպե՞ս կվարվեք, եթե անհրաժեշտ է շարժման ուղղությունը փոխել հակառակի','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5972,5969,102,'Կայանումը նշված վայրում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5973,5970,102,'Այս ցուցանակի դեպքում իր հետ օգտագործված նշանի ազդեցությունը տարածվում է','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5974,5971,102,'Այս ճանապարհային նշանը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5975,5972,102,'Նշված գոտուց ո՞ր ուղղություններով է թույլատրված երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5976,5973,102,'Այս խաչմերուկում նշվածներից ո՞ր ուղղություններով կարող եք շարունակել երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5977,5974,102,'Այս ճանապարհային նշանը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5978,5975,102,'Ցուցանակներից որոնք են, իրենց հետ տեղակայված նշանի ազդման գոտին ցույց տալիս','2025-05-18 20:17:25','2025-05-18 20:17:25');
