INSERT INTO question_translations VALUES(5980,5977,102,'Ո՞ր դեպքում է նշանի ազդեցությունն սկսվում անմիջապես տեղակայման վայրից','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5981,5978,102,'Ո՞ր հետագծով է թույլատրվում շարունակել երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5982,5979,102,'Ի՞նչի մասին է նախազգուշացնում ճանապարհային նշանը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5983,5980,102,'Նշաններից որի՞ ազդման գոտում չեն գործում բնակավայրում երթևեկության կանոնները','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5984,5981,102,'Թեթև մարդատարի վարորդին ո՞ր ուղղությամբ է թույլատրվում երթևեկել այս իրավիճակում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5985,5982,102,'Բեռնաթափել ավտոմոբիլը այս ճանապարհային նշանի ազդման գոտում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5986,5983,102,'Նշաններից ո՞րն է արգելում հետադարձը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5987,5984,102,'Թույլատրվո՞ւմ է նշված բակ մուտք գործել','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5988,5985,102,'Այս իրադրությունում կանգառ կատարել ուղևոր նստեցնելու նպատակով','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5989,5986,102,'Ո՞ր նշաններից հետո է առանց թույլտվության երթևեկությունն արգելվում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5990,5987,102,'Այս դեպքում նվազագույնը որքա՞ն հետո կարող է հանդիպել հավասարազոր խաչմերուկը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5991,5988,102,'Սլաքներով նշվածներից ո՞ր ուղղությամբ կարելի է շարունակել քարշակումը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5992,5989,102,'Ո՞րտեղից են սկսում գործել բնակավայրով երթևեկության կանոնները','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5993,5990,102,'Այս ճանապարհային նշանը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5994,5991,102,'Այս նշանները պարտադրում են պահպանել առջևից ընթացողից հեռավորությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5995,5992,102,'Նշված գոտուց ո՞ր ուղղությամբ կարող եք շարունակել երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5996,5993,102,'Այս նշանները նախազգուշացնում են','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5997,5994,102,'Թույլատրվո՞ւմ է կայանումը նշված վայրում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5998,5995,102,'Նշաններից ո՞րն է 5 տոննա զանգված ունեցող բեռնատարի վարորդին պարտադրում աջ շրջադարձ կատարել խաչմերուկում','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(5999,5996,102,'Ի՞նչ ուղղությամբ կարող եք շարունակել երթևեկությունը նշված խաչմերուկում, եթե վարում եք 3 տոննա թույլատրելի առավելագույն զանգվածով բեռնատար','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(6000,5997,102,'Նշաններից որով է կահավորվում արհեստական անհարթությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(6001,5998,102,'Ո՞ր հետագծով կարող եք շարունակել երթևեկությունը','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(6002,5999,102,'Չկարգավորվող խաչմերուկում ո՞ր նշաններն են առավելություն տալիս վարորդին հատվող ճանապարհով երթևեկողների նկատմամբ','2025-05-18 20:17:25','2025-05-18 20:17:25');
INSERT INTO question_translations VALUES(6003,6000,102,'Թույլատրվո՞ւմ է վազանց կատարել այս իրավիճակում','2025-05-18 20:17:26','2025-05-18 20:17:26');
INSERT INTO question_translations VALUES(6004,6001,102,'Խախտել է արդյո՞ք բեռնատարի վարորդը կայանման կանոնները','2025-05-18 20:17:26','2025-05-18 20:17:26');
INSERT INTO question_translations VALUES(6005,6002,102,'Ո՞ր հետագծով է թույլատրված հետադարձ կատարելը','2025-05-18 20:17:26','2025-05-18 20:17:26');
INSERT INTO question_translations VALUES(6006,6003,102,'Ամսվա կենտ օրերին կարելի է՞ կայանել նշված վայրում','2025-05-18 20:17:26','2025-05-18 20:17:26');
INSERT INTO question_translations VALUES(6007,6004,102,'Ո՞ր նշաններով է նշվում այն հատվածը, որտեղ վարորդները պետք է զիջեն երթևեկելի մասը հատող հետիոտներին','2025-05-18 20:17:26','2025-05-18 20:17:26');
INSERT INTO question_translations VALUES(6008,6005,102,'Նշաններից ո՞րն է նախազգուշացնում հանդիպակաց երթևեկությամբ ճանապարհի սկզբին մոտենալու մասին','2025-05-18 20:17:26','2025-05-18 20:17:26');
INSERT INTO question_translations VALUES(6009,6006,102,'Թո՞ւյլատրվում է մոտենալ աշխատանքի վայրին այս նշանների ազդման գոտում','2025-05-18 20:17:26','2025-05-18 20:17:26');
