INSERT INTO question_translations VALUES(6254,6251,102,'Երթևեկությունը թույլատրվում է','2025-05-18 20:17:39','2025-05-18 20:17:39');
INSERT INTO question_translations VALUES(6255,6252,102,'Երթևեկությունը թույլատրվում է','2025-05-18 20:17:39','2025-05-18 20:17:39');
INSERT INTO question_translations VALUES(6256,6253,102,'Լուսացույցի կանաչ ազդանշանին պատկերված սլաքները տեղեկացնում են','2025-05-18 20:17:39','2025-05-18 20:17:39');
