INSERT INTO question_translations VALUES(6267,6264,102,'Թույլատրվու՞մ  է  արդյոք  ավտոմոբիլի  կայանումը նշված տեղում։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6268,6265,102,'Երկաթուղային գծանցներից ի՞նչ հեռավորության վրա է արգելվում  տրանսպորտային  միջոցների  կայանումը։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6269,6266,102,'Թույլատրվու՞մ է արդյոք տվյալ դեպքում կանգ առնել  ուղևոր իջեցնելու համար։','2025-05-18 20:17:46','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6270,6267,102,'Վարորդներից ո՞րն է պարտավոր կանգ առնել։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6271,6268,102,'Տվյալ ճանապարհային գծանշումը թույլատրում է երթևեկել`','2025-05-18 20:17:46','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6272,6269,102,'Ո՞ր տրանսպորտային միջոցներին է թույլատրվում  կայանել տվյալ ճանապարհային նշանի  ազդեցության գոտում։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6273,6270,102,'Ի՞նչ է նշանակում տվյալ ճանապարհային գծանշումը։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6274,6271,102,'Ի՞նչ է  ցույց տալիս հորիզոնական գծանշման դեղին  հոծ գիծը։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6275,6272,102,'Թույլատրվու՞մ է  արդյոք  վարորդին հատել տրանսպորտային միջոցների կայանման տեղերի սահմանները նշող  գծանշման հոծ գիծը։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6276,6273,102,'Սլաքներով  նշված  ո՞ր  ուղղություններով  է  թույլատրվում երթևեկությունը։','2025-05-18 20:17:46','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6277,6274,102,'Ի՞նչ  է  ցույց  տալիս  այս  գծանշումը։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6278,6275,102,'Քանի՞ գոտի ունի ճանապարհը, որտեղ հանդիպակաց ուղղությունների տրանսպորտային հոսքերը  բաժանվում  են կրկնակի  հոծ  գծերով։','2025-05-18 20:17:46','2025-05-18 20:17:46');
INSERT INTO question_translations VALUES(6279,6276,102,'Ի՞նչ են նախազգուշացնում երթևեկելի մասի վրա գծանշված սլաքները։','2025-05-18 20:17:46','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6280,6277,102,'Գծանշման այս  գծերից  ո՞րն  է  օգտագործվում  դարձափոխային երթևեկությամբ գոտիները նշելու համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6281,6278,102,'Որտե՞ղ է  գծվում  կանգառը և կայանումն արգելող  տեղերը  նշող դեղին  հոծ գիծը։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6282,6279,102,'Ճանապարհային նշաններից որի՞ հետ կարող է կիրառվել  դեղին գույնի ընդհատվող գծանշումը։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6283,6280,102,'Ո՞ր տրանսպորտային միջոցներին է թույլատրվում  երթևեկել երթևեկելի մասի  աջ գոտիով։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6284,6281,102,'Այս ճանապարհային գծանշումն ունի հետևյալ նշանակությունը։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6285,6282,102,'Այս հորիզոնական ճանապարհային գծանշումը ցույց է տալիս՝','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6286,6283,102,'Թույլատրվու՞մ է արդյոք  մուտք գործել սպիտակ լայն  գծերով գծանշված ուղղորդ կղզյակ։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6287,6284,102,'Ինչպե՞ս պետք է վարվի վարորդը՝ մոտենալով խաչմերուկին՝ «Կանգ - գիծ»  գծանշման  և լուսացույցի  կանաչ ազդանշանի պայմաններում։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6288,6285,102,'Ի՞նչ է ցույց տալիս այս գծանշումը։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6289,6286,102,'Վարորդը որտե՞ղ  պետք է կանգնեցնի տրանսպորտային  միջոցն այս  գծանշման  առկայության դեպքում։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6290,6287,102,'Ի՞նչ է նշանակում այս գծանշումը։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6291,6288,102,'Թույլատրվու՞մ է արդյոք նշված վայրում հետադարձ  կատարել։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6292,6289,102,'Թույլատրվու՞մ է արդյոք  տվյալ գծանշման առկայության դեպքում զբոսաշրջության երթուղով երթևեկող  ավտոբուսի  վարորդին մուտք  գործել  «A»   գծանշումով  գոտի։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6293,6290,102,'Ի՞նչ  է  ցույց  տալիս  ընդհատվող  լայն  գծի  տեսքով  գծանշումը։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6294,6291,102,'Ո՞ր ավտոմոբիլին է թույլատրվում կանգառ կատարել այս նշանների ազդման գոտում։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6295,6292,102,'Ո՞ր նկարում է վարորդը ճիշտ կատարել կանգառ` ուղևորներ իջեցնելու համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6296,6293,102,'Որպես գնացքի կանգառի ազդանշան  ծառայում է՝','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6297,6294,102,'Բնակավայրերում,  յուրաքանչյուր  ուղղությամբ  մեկ  երթևեկելի գոտի  ունեցող  և  մեջտեղում  տրամվայի  գծեր չունեցող ճանապարհների ձախ  կողմում կանգառն ու կայանումը՝','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6298,6295,102,'«Կանգ-գծից»  կամ  «Երթևեկությունն  առանց  կանգառի արգելվում  է»  նշանից  ի՞նչ հեռավարության  վրա  պետք  է կանգնեցվի  տրանսպորտային  միջոցը՝  մոտեցող  գնացքին ճանապարհը  զիջելու  համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6299,6296,102,'Թույլատրվու՞մ է արդյոք կանգառը նշված տեղում։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6300,6297,102,'Թույլատրվու՞մ է արդյոք  ավտոմոբիլի կանգառն այս  վայրում։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6301,6298,102,'Ո՞ր  տրանսպորտային  միջոցի  վարորդն  է  խախտել  կայանման կանոնները։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6302,6299,102,'Որտե՞ղ է թույլատրվում երկարատև  հանգստի, գիշերակացի և այլ նպատակներով կայանելը բնակավայրերից դուրս։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6303,6300,102,'Կանգառն արգելվում է, եթե հոծ  գծի և կանգնած տրանսպորտային միջոցի միջև տարածությունը կազմում է`','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6304,6301,102,'Եթե երկաթուղային գծանցով երթևեկությունը արգելված է  և բացակայում են  լուսացույցը,  ճանապարհային նշանները, գծանշումն ու ուղեփակոցը, ապա վարորդը պետք է  կանգնի՝','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6305,6302,102,'Ի՞նչ հեռավորության վրա է արգելվում տրանսպորտային միջոցների կայանումը երկաթուղային  գծանցներից՝','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6306,6303,102,'Ո՞ր պատասխանում են  ճիշտ թվարկած կանգառի կանոնները խախտած վարորդները։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6307,6304,102,'Ո՞ր տրանսպորտային միջոցների վարորդներն են սխալ  կանգառ կատարել ուղևորներ իջեցնելու համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6308,6305,102,'Եթե երկաթուղային գծանցով երթևեկությունն արգելված է  և բացակայում  են լուսացույցը,  ճանապարհային նշաններն ու գծանշումը, ապա վարորդը պետք է կանգնի՝','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6309,6306,102,'Թույլատրվու՞մ է զբոսաշրջային ավտոբուսին երթևեկել «A» գծանշումով գոտիով։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6310,6307,102,'Ի՞նչ է նշանակում երթևեկելի մասի գոտում  գծանշված «A» տառը։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6311,6308,102,'Տրանսպորտային միջոցին թույլատրվու՞մ է կանգնել նշված տեղում ուղևորներ իջեցնելու համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6312,6309,102,'Թույլատրվու՞մ է շարունակել երթևեկությունը սլաքով նշված ուղղությամբ։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6313,6310,102,'Այսպիսի ուղղաձիգ գծանշմամբ  նշվում են`','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6314,6311,102,'Ինչպե՞ս պետք է վարվի թեթև  մարդատար ավտոմոբիլի վարորդը, եթե ավտոբուսի վարորդը սկսել է արգելակել։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6315,6312,102,'Ավտոբուսի վարորդը կատարել է կանգառ ուղևորներ նստեցնելու նպատակով։ Թեթև մարդատար ավտոմոբիլը երթևեկում է  70 կմ/ժ արագությամբ։ Ո՞ր տրանսպորտային միջոցի վարո րդն է խախտում ճանապարհային երթևեկության  կանոնների պահանջները։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6316,6313,102,'Թվարկվածներից ո՞ր դեպքում կարող է ավտոբուսի  վարորդն անցնել երկկողմ  երթևեկության եռագոտի ճանապարհի մեջտեղի գոտի, որը օգտագործվում է երկու ուղղությամբ երթևեկության համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6317,6314,102,'Որտե՞ղ պետք է կանգ առնի վարորդը տվյալ իրավիճակում։','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6318,6315,102,'Ավտոբուսը կանգ է  առել հետիոտնին զիջելու համար։ Թեթև մարդատար ավտոմոբիլի վարորդը  տվյալ իրադրությունում խախտու՞մ  է ճանապարհային  երթևեկության կանոնների պահանջները։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6319,6316,102,'Թույլատրվու՞մ է կանոնավոր ուղևորափոխադրումներ իրականացնող ավտոբուսի վարորդին ուղևորներ նստեցնելու նպատակով կանգառ կատարել նշված վայրում։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6320,6317,102,'Զբոսաշրջային ավտոբուսի վարորդը երկարատև հանգստի նպատակով իրավունք ունի՞ կանգ առնել  նշված վայրում։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6321,6318,102,'Դեպի ձախ երթևեկությունը շարունակելու համար որտե՞ղ  պետք է կանգ առնի ավտոբուսի վարորդը ճանապարհը  թեթև մարդատար ավտոմոբիլին զիջելու համար։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6322,6319,102,'Տվյալ իրավիճակում որտե՞ղ պետք է կանգ առնել։','2025-05-18 20:17:47','2025-05-18 20:17:47');
