INSERT INTO question_translations VALUES(6324,6321,102,'Նշված ճանապարհային նշանների ազդման գոտում թույլատրվու՞մ է կանգառ կատարել, ուղևորներ նստեցնելու նպատակով։','2025-05-18 20:17:47','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6325,6322,102,'Ո՞ր տրանսպորտային  միջոցների համար է առանձնացված  «A» տառով գծանշված  գոտին։','2025-05-18 20:17:47','2025-05-18 20:17:47');
