INSERT INTO question_translations VALUES(6384,6381,102,'Երբ նարնջագույն և սպիտակ գծանշումները իրար հակասում են, վարորդները','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6385,6382,102,'Ո՞ր վարորդին է կանգառ կատարելու դեպքում թույլատրված հատել հոծ գծանշումը','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6386,6383,102,'Թույլատրվո՞ւմ է կանգառ կատարել նշված վայրում','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6387,6384,102,'Այս գծանշումը','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6388,6385,102,'Ի՞նչ է արգելում այս գծանշումը','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6389,6386,102,'Այս գծանշումը նշանակում է','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6390,6387,102,'Գրառումը երթևեկելի մասում ցույց է տալիս','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6391,6388,102,'Ո՞ր կողմից կարելի է շրջանցել արգելքը','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6392,6389,102,'Ո՞ր տրանսպորտային միջոցները կարող են երթևեկել այս ճանապարհի աջ եզրային գոտիով','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6393,6390,102,'Թո՞ւյլատրվում է կայանել նշված վայրում','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6394,6391,102,'Ընդհատվող գծանշման գծիկների մեծացումը հայտնում է','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6395,6392,102,'Նշված իրավիճակում ուղիղ երթևեկելն','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6396,6393,102,'Քան՞ի երթևեկության գոտի ունի այս ճանապարհը','2025-05-18 20:17:47','2025-05-18 20:17:47');
INSERT INTO question_translations VALUES(6397,6394,102,'Ի՞նչ առավելագույն արագությամբ է  թույլատրվում թեթև մարդատար ավտոմոբիլների երթևեկությունը ճանապարհներին` բնակավայրերից դուրս։','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6398,6395,102,'Կահավորված թափքում մարդ փոխադրող բեռնատար ավտոմոբիլների  երթևեկությունը  թույլատրվում  է ոչ  ավելի քան`','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6399,6396,102,'Այս նախազգուշացնող նշանը բնակավայրերից դուրս, մինչև վտանգավոր հատվածի սկիզբը ի՞նչ հեռավորության վրա է տեղադրվում։','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6400,6397,102,'Երեխաների կազմակերպված խմբեր փոխադրող տրանսպորտային միջոցների երթևեկությունը թույլատրվում է՝','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6401,6398,102,'Տրանսպորտային միջոցների երթևեկությունը բնակավայրերում թույլատրվում է՝','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6402,6399,102,'Ո՞ր ուղղությամբ է թույլատրվում երթևեկությունը։','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6403,6400,102,'Միջքաղաքային ավտոբուսների երթևեկությունը բնակավայրերից դուրս թույլատրվում է՝','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6404,6401,102,'Ի՞նչ արագությամբ է թույլատրվում երթևեկել  3.5 տ ոչ  ավելի թույլատրելի  առավելագույն զանգված ունեցող  բեռնատար ավտոմոբիլներով՝ բնակավայրերից դուրս։','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6405,6402,102,'Թույլատրվու՞մ է արդյոք մերձքաղաքային, միջմարզային և միջքաղաքային ավտոբուսների  վարորդներին   բնակավայրերում գերազանցել  60  կմ/ժ  արագությունը։','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6406,6403,102,'Թույլատրվու՞մ  է  արդյոք  միջքաղաքային  ավտոբուսի  վարորդին բնակավայրերից  դուրս  գերազանցել 70 կմ/ժ  արագությունը։','2025-05-18 20:17:49','2025-05-18 20:17:49');
INSERT INTO question_translations VALUES(6407,6404,102,'Քարշակման  ժամանակ վթարային լուսային ազդանշանի բացակայության կամ անսարքության դեպքում, «Վթարային կանգառ» նշանը տեղադրվում է՝','2025-05-18 20:17:49','2025-05-18 20:17:49');
INSERT INTO question_translations VALUES(6408,6405,102,'Կոշտ կցիչով քարշակման ժամանակ  տրանսպորտային միջոցների միջև հեռավորությունը չպետք է գերազանցի՝','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6409,6406,102,'Թույլատրվու՞մ է արդյոք կոշտ կամ ճկուն կցիչով քարշակման ժամանակ  մարդկանց փոխադրումը  բեռնատար  ավտոմոբիլի թափքում՝','2025-05-18 20:17:49','2025-05-18 20:17:49');
INSERT INTO question_translations VALUES(6410,6407,102,'Կոշտ կամ ճկուն կցիչով քարշակման ժամանակ նշվածներից ո՞ր դեպքում է թույլատրվում  մարդկանց փոխադրումը քարշակվող ավտոմոբիլում։','2025-05-18 20:17:49','2025-05-18 20:17:49');
INSERT INTO question_translations VALUES(6411,6408,102,'Ի՞նչ  առավելագույն  արագությամբ  է  թույլատրվում երթևեկությունը՝ մեխանիկական տրանսպորտային  միջոցներով քարշակում կատարելիս։','2025-05-18 20:17:49','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6412,6409,102,'Քարշակումը մերկասառույցի պայմաններում արգելվո ւմ է՝','2025-05-18 20:17:49','2025-05-18 20:17:49');
INSERT INTO question_translations VALUES(6413,6410,102,'Ինչպիսի՞  առավելագույն  արագությամբ  կարող  է  իրականացվել քարշակումը  տվյալ պայմաններում։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6414,6411,102,'Թույլատրվու՞մ է արդյոք  ճկուն կամ կոշտ կցիչով քարշակման դեպքում մարդկանց փոխադրումը քարշակվող մեխանիկական տրանսպորտային միջոցում։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6415,6412,102,'Քարշակումը մերկասառույցի պայմաններում՝','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6416,6413,102,'Ինչպիսի՞ առավելագույն  արագությամբ է թույլատրվում տրանսպորտային միջոցների քարշակումը  ճկուն  կցիչով։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6417,6414,102,'Ո՞ր դեպքում է արգելվում քարշակումը։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6418,6415,102,'Բնակավայրերից դուրս մեխանիկական տրանսպորտային միջոցներ քարշակելիս  երթևեկության արագությունը  չպետք է գերազանցի՝','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6419,6416,102,'Թույլատրվու՞մ է արդյոք մոտոցիկլների քարշակումը։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6420,6417,102,'Քարշարկման ժամանակ տրանսպորտային միջոցների միջև ի՞նչ հեռավորություն  պետք է ապահովի ճկուն կցիչը։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6421,6418,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրվում կցորդ քարշակող  թեթև մարդատար  ավտոմոբիլների երթևեկությունն ավտոմայրուղիներով երթևեկելիս։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6422,6419,102,'Կոշտ կցիչով քարշակման ժամանակ հեռավորությունը տրանսպորտային միջոցների միջև պետք է լինի ոչ ավելի՝','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6423,6420,102,'Մեխանիկական տրանսպորտային միջոցների մասնակի բեռնումով   քարշակման   ժամանակ   ուղևորների  փոխադրում թույլատրվում է՝','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6424,6421,102,'Թույլատրվու՞մ է արդյոք քարշակել կողային կցորդով մոտոցիկլները։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6425,6422,102,'Ի՞նչ  առավելագույն  արագությամբ  է  թույլատրվում երթևեկությունը  ճկուն  կցիչով քարշակելիս։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6426,6423,102,'Տրանսպորտային միջոցի վրա բեռը տեղաբաշխվում և անհրաժեշտության դեպքում  նաև ամրացվում է այնպես, որպեսզի`','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6427,6424,102,'Թեթև  մարդատար ավտոմոբիլի առջևի նստատեղին, եթե այն կահավորված չէ երեխաներին պահող հարմարանքով, թույլատրվում է փոխադրել երեխաներ, եթե լրացել է նրանց՝','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6428,6425,102,'Թույլատրվու՞մ  է արդյոք  մարդկանց  փոխադրումը  բեռնատար կցորդում։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6429,6426,102,'Թույլատրվու՞մ է արդյոք մինչև 12 տարեկան երեխաների փոխադրումը մոտոցիկլի հետևի նստատեղին։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6430,6427,102,'Թույլատրվու՞մ  է  արդյոք  երթևեկության  ժամանակ  մարդկանց գտնվելը  բեռնատար ավտոմոբիլի  թափքում,  եթե  այն կահավորված  չէ  մարդկանց  փոխադրելու  համար։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6431,6428,102,'Մարդկանց փոխադրումը բեռնատար կցորդում՝','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6432,6429,102,'Կոշտ կամ ճկուն կցիչով քարշակման ժամանակ թույլատրվու՞մ է արդյոք  մարդկանց փոխադրումը քարշակվող ավտոբուսում։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6433,6430,102,'Ավտոբուսի քարշակումը մերկասառույցի պայմաններում արգելվում է՝','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6434,6431,102,'Թույլատրվու՞մ է արդյոք  ճկուն կամ կոշտ կցիչով քարշակման դեպքում մարդկանց փոխադրումը քարշակվող մեխանիկական տրանսպորտային միջոցում։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6435,6432,102,'Մարդկանց  փոխադրումն արգելվում է, եթե`','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6436,6433,102,'Ավտոբուսով երեխաների կազմակերպված խմբեր փոխադրելիս սրահում պետք է գտնվի առնվազն`','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6437,6434,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրվում երթևեկել միջմարզային և միջքաղաքային ուղևորափոխադրումներ իրականացնող ավտոբուսներին` բնակավայրերից դուրս բոլոր ճանապարհներին։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6438,6435,102,'Թույլատրվու՞մ է  արդյոք ավտոբուսներին բնակավայրերից դուրս երթևեկել  70 կմ/ժ  արագությամբ։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6439,6436,102,'Միջքաղաքային  փոխադրումներ իրականացնող ավտոբուսների երթևեկությունը բնակավայրերում թույլատրվում է ոչ ավելի քան`','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6440,6437,102,'Ի՞նչ առավելագույն  արագությամբ է թույլատրվում միջքաղաքային փոխադրումներ իրականացնող ավտոբուսների երթևեկությունը բնակավայրերից դուրս`','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6441,6438,102,'Ի՞նչ առավելագույն  արագությամբ է թույլատրվում ավտոբուսների երթևեկությունը «Բնակելի գոտի» և «Բնակելի գոտու վերջը» նշաններով կահավորված տարածքներում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6442,6439,102,'Թույլատրվու՞մ է արդյոք  կոշտ  կամ ճկուն կցիչով քարշակման ժամանակ մարդկանց փոխադրումը քարշակվող ավտոբուսում։','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6443,6440,102,'Կահավորված թափքում մարդկանց փոխադրելու  դեպքում բեռնատար ավտոմոբիլի վարորդը պարտավոր է երթևեկել ոչ ավելի քան`','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6444,6441,102,'Թույլատրվու՞մ է արդյոք ուղևորների փոխադրումը քարշակող ավտոբուսում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6445,6442,102,'Այս նշանի առկայության դեպքում ի՞նչ  առավելագույն արագությամբ  երթևեկելու իրավունք ունեն միջքաղաքային ավտոբուսների վարորդները։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6446,6443,102,'Ի՞նչ առավելագույն արագությամբ  կարող է երթևեկել քարշակող ավտոբուսի վարորդը տվյալ իրավիճակում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6447,6444,102,'Ի՞նչ առավելագույն արագությամբ  կարող է երթևեկել միջքաղաքային ավտոբուսի վարորդը  տվյալ իրավիճակում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6448,6445,102,'Ի՞նչ արագությամբ  կարող է շարունակել երթևեկությունը ավտոբուսի վարորդը  տվյալ ճանապարհային նշանով նշված գոտում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6449,6446,102,'Այս նշանով կահավորված ճանապարհներին միջքաղաքային ավտոբուսների վարորդներն իրավունք  ունեն երթևեկելու ոչ ավելի քան`','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6450,6447,102,'Այս նշանով կահավորված ճանապարհներին միջքաղաքային ավտոբուսների վարորդներն իրավունք  ունեն երթևեկելու ոչ ավել քան`','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6451,6448,102,'Թույլատրվու՞մ է ուղևորների փոխադրումը ավտոբուսի սրահում տվյալ իրավիճակում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6452,6449,102,'Կոշտ կամ ճկուն կցիչով քարշակման ժամանակ թույլատրվու՞մ է արդյոք ուղևորների փոխադրումը քարշակվող ավտոբուսում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6453,6450,102,'Քարշակման ժամանակ քարշակվող  տրանսպորտային միջոցի վրա պետք է  միացված լինեն`','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6454,6451,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրվում  միջքաղաքային ավտոբուսների երթևեկությունն  ավտոմայրուղիներով։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6455,6452,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրվում ավտոբուսի երթևեկությունը այս ճանապարհային նշանի ազդեցության ճանապարհահատվածներում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6456,6453,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրվում  միջքաղաքային ավտոբուսների երթևեկությունն  ավտոմայրուղիներով։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6457,6454,102,'Ի՞նչ արագությամբ  է  թույլատրվում  տրանսպորտային միջոցների երթևեկությունը «Բնակելի գոտի» և «Բնակելի գոտու վերջ» ճանապարհային  նշանների ազդեցության տարածքներում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6458,6455,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրվում թեթև մարդատար ավտոմոբիլների երթևեկությունը այս ճանապարհային նշանի ազդեցության ճանապարհահատվածներում։','2025-05-18 20:17:50','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6459,6456,102,'Ի՞նչ առավելագույն արագությամբ է թույլատրված երթևեկությունը 3,5 տոննայից ոչ ավել թույլատրելի առավելագույն զանգվածով բեռնատարի վարորդին նշված նշանների ազդման գոտում','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6460,6457,102,'Մեխանիկական տրանսպորտային միջոց քարշակելիս այս ճանապարհի ո՞ր գոտով կարող եք շարունակել երթևեկությ ունը','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6461,6458,102,'Ի՞նչ պայմաններ պետք է հաշվի առնի վարորդը սահմանված արագությունը չգերազանցող արագությունը ընտրելիս','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6462,6459,102,'Ի՞նչ արագություն պետք է ընտրի վարորդը թույլատրելի առավելագույնի սահմաններում','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6463,6460,102,'Վարորդին արգելվում է`','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6464,6461,102,'Ո՞ր նշանն է արագության սահմանափակում մտցնում','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6465,6462,102,'Վարորդին արգելվում է','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6466,6463,102,'Խաչմերուկին մոտենալիս վարորդը տրանսպորտային միջոցը պետք է վարի այնպիսի արագությամբ, որ','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6467,6464,102,'Բարձրացնել արագությունը վարորդին արգելվում է, եթե','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6468,6465,102,'Վարորդը պարտավոր է իջեցնել արագությունը','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6469,6466,102,'Տրանսպորտային միջոցի կողքից` եզրաչափային լույսի արտաքին եզրից 0,5 մ դուրս ցցվելու դեպքում բեռը պետք է արդյո՞ք նշվի օրվա լուսավոր ժամերին «Մեծ եզրաչափերով բեռ» ճանաչման նշանով, իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, նաև` առջևից սպիտակ, իսկ հետևից` կարմիր գույնի լապտերիկներով կամ լուսանդրադարձիչով:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6470,6467,102,'Բեռնատարով, որի վարորդը ունի B և C կարգերի տրանսպորտային միջոցներ վարելու իրավունքի վկայական պահպանելով բեռնատարներով մարդ փոխադրելու կանոնները թույլատրվում է փոխադրել մինչև','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6471,6468,102,'Արգելվում է մինչև 12 տարեկան երեխաներին փոխադրել','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6472,6469,102,'Տրանսպորտային միջոցի հետևի եզրաչափից 1.2 մ դուրս ցցված բեռը պետք է արդյո՞ք նշվի օրվա լուսավոր ժամերին  «Մեծ եզրաչափերով բեռ» ճանաչման նշանով, իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, նաև` առջևից սպիտակ, իսկ հետևից` կարմիր գույնի լապտերիկներով կամ լուսանդրադարձիչով','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6473,6470,102,'Բեռի փոխադրումն արգելվում է, եթե այն`','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6474,6471,102,'Եթե բեռի վիճակն ու դասավորությունը հնարավորություն չեն տալիս կատարել դրա փոխադրումը կանոնների պահանջներին համապատասխան, ապա վարորդը պետք է','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6475,6472,102,'Տրանսպորտային միջոցի հետևի եզրաչափից 0.6մ դուրս ցցված բեռը պետք է արդյո՞ք նշվի օրվա լուսավոր ժամերին «Մեծ եզրաչափերով բեռ» ճանաչման նշանով, իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, նաև` առջևից սպիտակ, իսկ հետևից` կարմիր գույնի լապտերիկներով կամ լուսանդրադարձիչով','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6476,6473,102,'Տրանսպորտային միջոցի կողքից` եզրաչափային լույսի արտաքին եզրից 0,3 մ դուրս ցցվելու դեպքում բեռը պետք է արդյո՞ք նշվի օրվա լուսավոր ժամերին «Մեծ եզրաչափերով բեռ» ճանաչման նշանով, իսկ օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում, նաև` առջևից սպիտակ, իսկ հետևից` կարմիր գույնի լապտերիկներով կամ լուսանդրադարձիչով:','2025-05-18 20:17:50','2025-05-18 20:17:50');
INSERT INTO question_translations VALUES(6477,6474,102,'Կարմիր գույնի առկայծող փարոսիկ  միացրած, կանգնած վիճակում գտնվող տրանսպորտային միջոցին մոտենալիս` տվյալ ուղղությամբ  երթևեկող  ընդհանուր օգտագործման տրանսպորտային միջոցների վարորդները պետք է`','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6478,6475,102,'Կապույտ գույնի առկայծող փարոսիկ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոց մոտենալու դեպքում   ընդհանուր օգտագործման տրանսպորտային միջոցների վարորդները պետք է՝','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6479,6476,102,'Ընդհանուր օգտագործման տրանսպորտային միջոցների վարորդների կողմից ձայնային ազդանշանները կարող են կիրառվել`','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6480,6477,102,'Օրվա մութ ժամանակ ճանապարհի չլուսավորված հատվածներում  սահմանված  երթուղով երթևեկող ավտոբուսի վրա պետք է միացված լինի՝','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6481,6478,102,'Պարտադի՞ր է արդյոք օրվա լուսավոր ժամերին լապտերների մոտակա լույսը միացված լինի  հատուկ առանձնացված գոտիով, հիմնական հոսքին հանդիպակաց երթևեկող ընդհանուր օգտագործման տրանսպորտային միջոցների վրա։','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6482,6479,102,'Ո՞ր  դեպքում  կանոնները  չեն  պարտադրում  տալ նախազգուշացնող ազդանշան։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6483,6480,102,'Վերադասավորումից առաջ նախազգուշացնող ազդանշանը պետք է տրվի՝','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6484,6481,102,'Մանևրը կատարելուց առաջ նախազգուշացնող ազդանշանը պետք է տրվի՝','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6485,6482,102,'Վարորդի կողմից ձեռքով տրվող  նախազգուշացնող  ազդանշանը դադարեցվում է`','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6486,6483,102,'Ո՞ր դեպքում վարորդը պետք է տա նախազգուշացնող ազդանշան՝ կանգառ  կատարելուց առաջ։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6487,6484,102,'Ձայնային ազդանշանների կրկնողությամբ ընդհանուր  տագնապի ինչպիսի՞ ազդանշան է վարորդը պարտավոր  տալ  երկաթուղային գծանցի  վրա  հարկադրական  կանգառ կատարելու դե պքում։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6488,6485,102,'Շրջադարձի լուսային ցուցիչի բացակայության կամ անսարքության դեպքում ձեռքով տրվող նախազգուշացնող ազդանշանը դադարեցվում է՝','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6489,6486,102,'Երկաթուղային  գծանցի  վրա  տրվող  ընդհանուր  տագնապի ազդանշան  է  հանդիսանում ձայնային  ազդանշանների  հետևյալ համակցությունը՝','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6490,6487,102,'Ո՞ր  նկարում  է  վարորդը  տալիս  ձախ  շրջադարձի  ազդանշան։','2025-05-18 20:17:54','2025-05-18 20:17:54');
INSERT INTO question_translations VALUES(6491,6488,102,'Կարմիր գույնի առկայծող փարոսիկ  միացրած, կանգնած վիճակում գտնվող տրանսպորտային միջոցին մոտենալիս` տվյալ ուղղությամբ  երթևեկող  տրանսպորտային միջոցների վարորդները պետք է`','2025-05-18 20:17:54','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6492,6489,102,'Տրանսպորտային միջոցների վրա ի՞նչ նպատակով են տեղադրված նարնջագույն կամ դեղին գույնի առկայծող փարոսիկներ։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6493,6490,102,'Կապույտ գույնի առկայծող փարոսիկ և հատուկ ձայնային ազդանշան միացրած տրանսպորտային միջոց մոտենալու դեպքում  վարորդները պետք է՝','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6495,6492,102,'Կապույտ և կարմիր գույների առկայծող փարոսիկներ և  հատուկ ձայնային  ազդանշան միացրած  տրանսպորտային միջոց մոտենալու դեպքում վարորդները պետք է՝','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6496,6493,102,'Ո՞ր  տրանսպորտային միջոցի վարորդն ունի առաջնահերթ երթևեկության իրավունք։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6497,6494,102,'Սև  ավտոմոբիլը  խաչմերուկը  կանցնի՝','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6498,6495,102,'Ո՞ր  տրանսպորտային  միջոցի  վարորդը  պետք  է  զիջի ճանապարհը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6499,6496,102,'Կապույտ ավտոմոբիլը խաչմերուկը կանցնի՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6500,6497,102,'Տալի՞ս  է արդյոք  երթևեկության  առավելություն տրանսպորտային  միջոցի  վրա  միացված  դեղին գույնի (նարնջագույն)  առկայծող  փարոսիկը։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6501,6498,102,'Լուսնասպիտակ գույնի առկայծող փարոսիկները միացրած տրանսպորտային միջոցի  վարորդը  տալիս  է  հատուկ ձայնային ազդանշան, որպեսզի՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6502,6499,102,'Կապույտ  գույնի  առկայծող  փարոսիկով  կահավորված տրանսպորտային  միջոցի  վարորդը երթևեկության  մյուս մասնակիցների  նկատմամբ  առավելություն  ունի,  եթե՝','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6503,6500,102,'Ի՞նչ տարածության վրա է  արգելվում վազանցը մինչև երկաթուղային գծանցը։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6504,6501,102,'Թույլատրվու՞մ  է  արդյոք  խաչմերուկում  կատարել տրանսպորտային  միջոցների   վազանց` հատվողի նկատմամբ գլխավոր համարվող ճանապարհի վրա։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6505,6502,102,'Թույլատրվու՞մ է արդյոք թեթև մարդատար ավտոմոբիլի վարորդին վազանց կատարել նշված իրադրությունում։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6506,6503,102,'Վազանցն արգելվում է՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6507,6504,102,'Վազանցն արգելվում է՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6508,6505,102,'Թույլատրվու՞մ է արդյոք վազանցել ավտոգնացքը տվյալ իրադրությունում, եթե դրա արագությունը  չի  գերազանցում  30 կմ/ժ։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6509,6506,102,'Թույլատրվու՞մ է արդյոք կանաչ ավտոմոբիլի վարորդին վազանց կատարել։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6510,6507,102,'Թույլատրվու՞մ է արդյոք կարմիր ավտոմոբիլի վարորդին  վազանց կատարել  տվյալ իրադրությունում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6511,6508,102,'Թույլատրվու՞մ է արդյոք նշված տեղում վազանցել  ավտոբուսը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6512,6509,102,'Տրանսպորտային  միջոցների  վազանց  նշանակում  է՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6513,6510,102,'Օրվա մութ ժամանակ և անբավարար տեսանելիության պայմաններում` անկախ ճանապարհի  լուսավորվածությունից, երթևեկող  մեխանիկական  տրանսպորտային միջոցների վրա պետք է միացված լինեն`','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6514,6511,102,'Ո՞ր դեպքում օրվա լուսավոր ժամանակ մոտոցիկլի վրա պետք է միացված լինի լապտերների մոտակա լույսը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6515,6512,102,'Առաջնահերթ ի՞նչ պետք է ձեռնարկի վարորդը հանդիպակաց երթևեկող տրանսպորտային միջոցի լապտերների լույսից շլանալու դեպքում։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6516,6513,102,'Ձայնային ազդանշանները կարող են կիրառվել միայն՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6517,6514,102,'Օրվա մութ ժամանակ ճանապարհի չլուսավորված հատվածներում երթևեկող մեխանիկական տրանսպորտային միջոցի վրա պետք է միացված լինի՝','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6518,6515,102,'Հետին հակամառախուղային լապտերիկները կարող են օգտագործվել՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6519,6516,102,'Հանդիպակաց  երթևեկող  տրանսպորտային  միջոցից  ի՞նչ հեռավորության վրա լապտերների հեռահար լույսը  պետք է փոխարկվի մոտակայի։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6520,6517,102,'Լապտեր-լուսարձակ  թույլատրվում  է  օգտագործել՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6521,6518,102,'Այս նախազգուշացնող նշանը բնակավայրերում, մինչև վտանգավոր հատվածի սկիզբը ի՞նչ հեռավորության վրա է տեղադրվում։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6522,6519,102,'Թույլատրվու՞մ է արդյոք երկաթուղային գծանցով փոխադրել գյուղատնտեսական, ճանապարհային, շինարարական և այլ մեքենաներ ու մեխանիզմներ։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6523,6520,102,'Որտե՞ղ  է  թույլատրվում  հատել  երկաթուղային  գծերը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6524,6521,102,'Թույլատրվու՞մ է արդյոք ծառայողական առաջադրանք կատարելիս ինքնակամ բացել կամ շրջանցել  ուղեփակոցը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6525,6522,102,'Թույլատրվու՞մ է արդյոք երկաթուղայհն գծանցով փոխադրել գյուղատնտեսական, ճանապարհային, շինարարական և այլ մեքենաներ ու մեխանիզմներ։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6526,6523,102,'Ինչո՞վ  պետք  է  ղեկավարվի  վարորդը  երկաթուղային  գծանցին մոտենալիս։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6527,6524,102,'Թույլատրվու՞մ  է  արդյոք   հետիոտներին   տեղաշարժվել «Ավտոմայրուղի» նշանով կահավորված ճանապարհով։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6528,6525,102,'Տրանսպորտային միջոցներով, որոնց արագությունը տեխնիկական բնութագրերից կամ վիճակից ելնելով  չի գերազանցում  40  կմ/ժ,  ավտոմայրուղիներով  երթևեկել՝','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6529,6526,102,'Տրանսպորտային  միջոցի  վրա  վթարային  լուսային  ազդանշանը պետք  է  միացված  լինի՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6530,6527,102,'Տրանսպորտային միջոցի վրա վթարային լուսային  ազդանշանը պետք է միացված լինի՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6531,6528,102,'Տրանսպորտային  միջոցից ի՞նչ հեռավորության վրա է տեղադրվում «Վթարային կանգառ» նշանը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6532,6529,102,'Տրանսպորտային միջոցի վրա վթարային լուսային ազդանշանը պետք է միացված լինի՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6533,6530,102,'Տրանսպորտային  միջոցի  վրա  վթարային  լուսային  ազդանշանը պետք  է  միացված  լինի`','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6534,6531,102,'Կառուցապատված տարածքներում, որտեղ մուտք ու ելքը նշված են «Բնակելի գոտի»  և «Բնակելի գոտու վերջ»  ճանապարհային նշաններով, չի արգելվում`','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6535,6532,102,'Խաչմերուկը համարվում է կարգավորվող, եթե երթևեկության հերթականությունը որոշվում է`','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6536,6533,102,'Առանց ծածկույթի հողային ճանապարհի վրա, անմիջապես խաչմերուկից առաջ, ծածկույթով հատվածի առկայությունն արդյոք այդ ճանապարհը դարձնու՞մ է հատվողին հավասարազոր։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6537,6534,102,'Ո՞ր նկարում են պատկերված երթևեկության թույլատրելի ուղղությունները։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6538,6535,102,'Եթե լուսացույցի ազդանշանների նշանակությունները  հակասում են առավելության նշանների պահանջներին, ապա վարորդները պետք է ղեկավարվեն՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6539,6536,102,'Թույլատրվու՞մ է արդյոք վարորդին շարունակել երթևեկությունը լուսացույցի դեղին ազդանշանը միանալու կամ  կարգավորողը ձեռքը բարձրացնելու դեպքում։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6540,6537,102,'Կարգավորողն  ազդանշան  տալիս  է  սուլիչով՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6541,6538,102,'Թույլատրվու՞մ  է  արդյոք  տվյալ  իրադրությունում ավտոգնացքին անցնել  կամուրջի վրայով։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6542,6539,102,'Ո՞ր  դեպքում  կանոնները  չեն  պարտադրում  ավտոբուսի վարորդին տալ  նախազգուշացնող ազդանշան։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6543,6540,102,'Վերադասավորումից առաջ  ավտոբուսի վարորդը նախազգուշացնող ազդանշան  պետք է տա՝','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6544,6541,102,'Ձայնային ազդանշանների կրկնողությամբ ընդհանուր  տագնապի ինչպիսի՞ ազդանշան է ավտոբուսի վարորդը պարտավոր  տալ երկաթուղային  գծանցի  վրա  հարկադրական  կանգառ կատարելու դեպքում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6545,6542,102,'Միջքաղաքային  ավտոբուսի վարորդն իրավունք ունի՞ վազանցելու մոտոցիկլին, որը երթևեկում է 70 կմ/ժ արագությամբ։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6546,6543,102,'Կարելի՞ է  նշված հետագծով  երթևեկելու համար ձեռքով տալ նախազգուշացնող ազդանշան։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6547,6544,102,'Պարտավո՞ր է վարորդը   միացնել շրջադարձի ցուցիչը` բնակելի գոտում երթևեկությունը սկսելուց առաջ։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6548,6545,102,'Պարեկային ծառայության ավտոմոբիլի վարորդը երթևեկության այլ մասնակիցների նկատմամբ  առավելություն ստանալու համար պետք է միացնի`','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6549,6546,102,'Պարտավո՞ր է ավտոբուսի վարորդը ճանապարհը զիջել «Շտապ օգնության» ավտոմոբիլին, եթե միացրած չեն կապույտ գույնի առկայծող փարոսիկը և հատուկ ձայնային ազդանշանը։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6550,6547,102,'Վազանցն արգելվում է`','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6551,6548,102,'Ինչի՞ մասին  է տեղեկացնում թեթև մարդատար ավտոմոբիլի վարորդի կողմից ձեռքով տրված ազդանշանը։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6552,6549,102,'Վթարային լուսային ազդանշանը միացվում է`','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6553,6550,102,'Ինչի՞ մասին  է տեղեկացնում մոտոցիկլի  վարորդի կողմից ձեռքով տրված ազդանշանը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6554,6551,102,'Ինչի՞ մասին  է տեղեկացնում թեթև մարդատար ավտոմոբիլի վարորդի կողմից ձեռքով տրված ազդանշանը։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6555,6552,102,'Ինչի՞ մասին  է տեղեկացնում թեթև մարդատար ավտոմոբիլի վարորդի կողմից ձեռքով տրված ազդանշանը։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6556,6553,102,'Պարտավո՞ր է արդյոք վարորդը միացնել շրջադարձի ցուցիչը տվյալ դեպքում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6557,6554,102,'Օրվա լուսավոր ժամերին երեխաների կազմակերպված խմբեր տեղափոխելու ժամանակ պետք է  միացված  լինեն  ավտոբուսի`','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6558,6555,102,'Թույլատրվու՞մ է բեռնատար ավտոմոբիլի վարորդին վազանցել ավտոբուսին, որը երթևեկում է 60 կմ/ժ արագությամբ։','2025-05-18 20:17:55','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6559,6556,102,'Թույլատրվու՞մ է վազանց կատարել տվյալ իրավիճակում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6560,6557,102,'Թույլատրվու՞մ է արդյոք մուտք գործել երկաթուղային գծանց տվյալ իրավիճակում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6561,6558,102,'Թույլատրվու՞մ է արդյոք մուտք գործել երկաթուղային գծանց տվյալ իրավիճակում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6562,6559,102,'Ինչպե՞ս պետք է գործել տվյալ իրադրությունում։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6563,6560,102,'Տվյալ իրավիճակում թույլատրվու՞մ է անցնել երկաթուղային գծանցը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6564,6561,102,'Տվյալ իրավիճակում թույլատրվու՞մ է անցնել երկաթուղային գծանցը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6565,6562,102,'Տվյալ իրավիճակում որտե՞ղ կարելի է սկսել վազանցը։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6566,6563,102,'Տվյալ իրավիճակում թույլատրվու՞մ է  վազանց կատարել։','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6567,6564,102,'Ի՞նչ մանևր է կատարում թեթև մարդատարի վարորդը','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6568,6565,102,'Թույլատրվում է արդյո՞ք վազանցել մոտոցիկլին','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6569,6566,102,'Ո՞ր դեպքում է թույլատրվում հանդիպակաց երթևեկության գոտով վազանց կատարել յուրաքանչյուր ուղղությամբ մեկ գոտի ունեցող ճանապարհներին','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6570,6567,102,'Թույլատրվում է արդյո՞ք վազանց կատարել նշված իրավիճակում:','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6571,6568,102,'Թույլատրվո՞ւմ է վազանցել բեռնատարին:','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6572,6569,102,'Ի՞նչ է պահանջվում վազանցվող տրանսպորտային միջոցի վարորդից','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6573,6570,102,'Թույլատրվո՞ւմ է այս իրավիճակում վազանց կատարել','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6574,6571,102,'Թույլատրվո՞ւմ է բեռնատարի վարորդին վազանցել տրակտորին, եթե թույլատրելի առավելագույն զանգվածը 3 տոննա է:','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6575,6572,102,'Եթե հանդիպակաց երթևեկությունը դժվար է այս իրավիճակում, ապա ճանապարհը պետք է զիջի','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6576,6573,102,'Հետիոտնային անցման վրա վազանցն','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6577,6574,102,'Ո՞ր հետագծով է թույլատրվում վազանց կատարել','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6578,6575,102,'Ի՞նչ է ցույց տալիս ճանապարհային նշանը','2025-05-18 20:17:55','2025-05-18 20:17:55');
INSERT INTO question_translations VALUES(6579,6576,102,'Վարորդը միացնել շրջադարձի լուսային ցուցիչն այս իրավիճակում','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6580,6577,102,'Վարորդի դեպի վեր պարզած ձեռքով տեղեկացնում է','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6581,6578,102,'Ազդանշան տալը երթևեկության մյուս մասնակիցների նկատմամբ առավելություն','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6582,6579,102,'Ի՞նչի մասին է տեղեկացնում մոտոցիկլի վարորդը','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6583,6580,102,'Ձախ շրջադարձ կատարելիս այս իրավիճակում ազդանշան տալը','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6584,6581,102,'Վազանց կատարելիս ձախ շրջադարձի լուսային ցուցիչը անջատել պարտավոր ենք','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6585,6582,102,'Հետադարձն այս խաչմերուկում կատարելիս ո՞ր շրջադարձի ցուցիչը պետք է միացնենք','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6586,6583,102,'Պարտավոր եք արդյո՞ք նշված իրադրությունում տալ ազդանշան լուսային ցուցիչով','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6587,6584,102,'Ի՞նչի մասին է տեղեկացնում մոտոցիկլի վարորդը','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6588,6585,102,'Լուսային ցուցիչով տրված մանևրի մասին ազդանշանը պետք է դադարեցվի','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6589,6586,102,'Լուսային ցուցիչով ազդանշան տալ նշված իրավիճակում','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6590,6587,102,'Ո՞ր վարորդն է աջ շրջադարձի ազդանշան տալիս','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6591,6588,102,'Կայանատեղիներում կամ ավտոլցակայաններում մանևրելիս ազդանշան տալ լուսային ցուցիչով','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6592,6589,102,'Այս իրավիճակում ի՞նչ կարող է նշանակել վարորդի դուրս պարզած ձեռքը','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6593,6590,102,'Ի՞նչ ազդանշաններ պետք է տաք նշված հետագծով հետադարձը կատարելիս','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6594,6591,102,'Եթե անմիջապես խաչմերուկից հետո մտադրվել եք կանգառ կատարել երթևեկության մասնակիցներին շփոթության մեջ չգցելու նպատակով, երբ պետք է միացնեք աջ շրջադարձի լուսային ցուցիչը','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6595,6592,102,'Վազանցն ավարտող մեքենայի վարորդը ունի արդյո՞ք առավելություն համընթաց գոտի վերադասավորվելիս, տվյալ գոտով երթևեկող վարորդի նկատմամբ','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6596,6593,102,'Մերձակա տարածքից դուրս եկող հատուկ ձայնային և լուսային ազդանշաններ միացրած վարորդին զիջել','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6597,6594,102,'Խաչմերուկն ուղիղ անցնելիս պարտավոր ենք արդյո՞ք զիջել ճանապարհը միացված դեղին առկայծող փարոսիկներով բեռնատարի վարորդին','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6598,6595,102,'Զիջել ճանապարհը պարտավոր ենք','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6599,6596,102,'Զիջել ճանապարհը պարտավոր ենք','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6600,6597,102,'Այս իրադրությունում','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6601,6598,102,'Զիջել պարտավոր ենք','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6602,6599,102,'Ձախ շրջադարձ կատարելիս','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6603,6600,102,'Գլխի վնասվածքի դեպքում տուժածին օգնություն ցուցաբերելիս պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6604,6601,102,'Ավտովթարի ժամանակ հետևյալ տուժածներից որի՞ն օգնություն կցուցաբերեք առաջին հերթին։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6605,6602,102,'Քթից արյունահոսության դեպքում տուժածին օգնություն ցուցաբերելիս պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6606,6603,102,'Մեքենան վարելու ընթացքում վարորդը հանկարծակի սկսում է գանգատվել կրծքավանդակի ճնշող ուժեղ ցավերից և շնչառության դժվարացումից։ Ի՞նչ է պետք անել։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6607,6604,102,'Ի՞նչ օգնություն է պետք ցուցաբերել տուժածին ցնցումային նոպայի դեպքում։','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6608,6605,102,'Ի՞նչ պետք է  անել այրվածքի դեպքում օգնություն ցուցաբերելիս։','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6609,6606,102,'Վթարի հետևանքով հետիոտն ընկել է  և վնասել ձեռքը։ Նախաբազկի վրա կա մեծ վերք (մոտ 5 սմ երկարությամբ), որից միալար մուգ գույնի արյուն է հոսում։ Ի՞նչ է պետք անել արյունահոսությունը դադարեցնելու նպատակով։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6610,6607,102,'Վերջույթների փափուկ հյուսվածքների փակ վնասվածքների դեպքում առաջին ժամերին օգնություն ցուցաբերելիս պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6611,6608,102,'Վարորդը կքանստած երկար ժամանակ փոխում էր ավտոմեքենայի անիվը։ Կտրուկ վեր կենալով` նա բռնում է գլուխը և հանկարծ կորցնելով գիտակցությունը, ընկնում։ Ի՞նչ է պետք անել։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6612,6609,102,'Ի՞նչ  է պետք  անել, եթե հնարավոր չէ ապահովել դեպքի վայրի անվտանգությունը։','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6613,6610,102,'Դուք տեսնում եք ընկած մարդու և նկատում նրա սրունքից դուրս  ցցված ոսկորը  և  արյուն։ Եթե դեպքի վայրն անվտանգ է, ի՞նչ պետք է անել առաջին հերթին։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6614,6611,102,'Երբ տուժածը ունի վերջույթի բաց կոտրվածք, ապա օգնություն ցուցաբերելիս անհրաժեշտ է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6615,6612,102,'Կրծքավանդակի վնասվածքի դեպքում պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6616,6613,102,'Տուժածի որովայնի վրա բաց վնասվածքից օրգանների արտընկման դեպքում պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6617,6614,102,'Անգիտակից վիճակում գտնվող և շնչառություն ունեցող տուժածին պետք է.','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6618,6615,102,'Ուժեղ արյունահոսության դեպքում պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6619,6616,102,'Ավտովթարի դեպքում առաջին հերթին պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6620,6617,102,'Եթե տուժածի վերքի մեջ օտար մարմին կա, ապա օգնություն ցուցաբերելիս պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6621,6618,102,'Հանգիստ վիճակում չափահաս մարդու անոթազարկը կազմում է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6622,6619,102,'Հանգիստ վիճակում չափահաս մարդու շնչառությունը կազմում է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6623,6620,102,'Վթարի դեպքում ավտոմեքենայից տուժածին պետք է տեղափոխել, եթե.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6624,6621,102,'Որովայնային ներքին արյունահոսության կասկածի դեպքում օգնություն ցուցաբերելիս պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6625,6622,102,'Դուք հարևանի ավտոտնակից լսում եք մեքենայի շարժիչի ձայնը և, բացելով դուռը, տեսնում եք գետին ընկած հարևանին։ Ի՞նչ է պետք անել առաջին հերթին։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6626,6623,102,'Անգիտակից վիճակում գտնվող տուժածին հայտնաբերելուց հետո առաջին հերթին պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6627,6624,102,'Վերջույթներում արյան շրջանառությունը ստուգելու համար վիրակապից ներքև սեղմում և բաց եք թողնում տուժածի վնասված վերջույթի եղունգը։ Դուք որոշում եք, որ արյան շրջանառությունը վերջույթում խանգարված է, եթե.','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6628,6625,102,'Շաքարախտով հիվանդ ձեր ընկերն իրեն վատառողջ է զգում և չի հիշում, թե վերջին անգամ երբ է ինսուլին ընդունել։ Ի՞նչ է պետք անել այդ դեպքում առաջին հերթին։','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6629,6626,102,'Առավել վտանգավոր արյունահոսության նշան է, եթե.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6630,6627,102,'Մեքենան բախվել է սյանը և էլեկտրական հաղորդալարն ընկած է մեքենայի կողքն անգիտակից վիճակում պառկած տուժածի վրա։ Օգնություն ցուցաբերելիս առաջին հերթին պետք է.','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6631,6628,102,'Առաջին օգնություն ցուցաբերելիս վարակումից պաշտպանվելու համար պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6632,6629,102,'Բրոնխիալ ասթմայով տուժածին նոպայի դեպքում պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6633,6630,102,'Որովայնի վնասվածքով տուժածին պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6634,6631,102,'Ուշագնացության դեպքում տուժածին պետք է.','2025-05-18 20:17:56','2025-05-18 20:17:56');
INSERT INTO question_translations VALUES(6635,6632,102,'Ցածր թափքով մեքենայի չափահաս հետիոտնին, որի հասակը կազմում է 1 մ 55 սմ և ավելի, բախման դեպքում նրա մոտ առավել հավանական վնասվածքներն են.','2025-05-18 20:17:56','2025-05-19 18:25:41');
INSERT INTO question_translations VALUES(6636,6633,102,'Ցածր թափքով մեքենայի 3-5 տարեկան երեխային բախման դեպքում նրա մոտ առավել հավանական վնասվածքներն են.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6637,6634,102,'Եթե հաղորդալարն ընկած է մեքենայի վրա, ապա պետք է.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6638,6635,102,'Քիչ վտանգավոր վերքերի մշակման ժամանակ պետք է.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6639,6636,102,'Վտանգավոր վերքերի մշակման ժամանակ պետք է.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6640,6637,102,'Վթարի դեպքում շտապօգնության կանչի համար ի՞նչ տեղեկատվություն պետք է տրամադրվի օպերատորին.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6641,6638,102,'Ի՞նչ օպտիմալ դիրք պետք է տրվի գիտակցությունը պահպանված տուժածին` ողնաշարի վնասվածք կասկածի դեպքում.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6642,6639,102,'Ինչպե՞ս իրականացնել առաջին օգնությունը ցրտահարության և գերսառեցման դեպքում.','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6643,6640,102,'Ինչպիսի՞ առաջին օգնություն պետք է ցուցաբերել գլխի մազածածկ մասի վերքի առկայությամբ գանգուղեղային վնասվածքի դեպքում:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6644,6641,102,'Գիտակցության կորստի ժամանակ` շնչառության և արյան շրջանառության առկայության դեպքում, առաջին օգնություն ցուցաբերելու նպատակով Ի՞նչ դիրքով պառկեցնել տուժածին:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6645,6642,102,'Որքա՞ն ժամանակ կարող է կապված մնալ արյունահոսությունը դադարեցնող լարանը:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6646,6643,102,'Ինչպե՞ս որոշել գիտակցությունը կորցրած տուժածի մոտ շնչառության առկայությունը:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6647,6644,102,'Որո՞նք են խոշոր զարկերակից արյունահոսության նշանները և ինչի՞ց է սկսվում առաջին օգնությունը խոշոր զարկերակային արյունահոսության ժամանակ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6648,6645,102,'Արդյո՞ք թույլատրվում է տուժածին դեղեր տալ առաջին բուժօգնություն ցուցաբերելու ժամանակ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6649,6646,102,'Ինչպե՞ս դադարեցնել արյունահոսությունը երակների և ոչ խոշոր զարկերակների վնասվածքի դեպքում:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6650,6647,102,'Որո՞նք են առաջին բուժօգնության նախնական քայլերը` վթարի հետևանքով առաջացած վնասվածքների դեպքում:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6651,6648,102,'Ինչպե՞ս է առաջին օգնություն իրականացվում վերջույթների կոտրվածքների դեպքում, եթե չկան շինաներ և այն պատրաստելու համար ձեռքի տակ եղած միջոցներ','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6652,6649,102,'Ո՞ր դեպքերում պետք է տուժածը դուրս հանվի ավտոմեքենայի խցիկից','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6653,6650,102,'Ո՞րն է առաջին օգնությունը մակերեսային ջերմային այրվածքի (մաշկի կարմրություն, այտուցվածություն, այրվածքի տեղում թափանցիկ հեղուկով  լցված բշտիկների առաջացում, ուժեղ ցավ) ժամանակ:','2025-05-18 20:17:57','2025-05-18 20:17:57');
INSERT INTO question_translations VALUES(6654,6491,102,'Կապույտ ավտոմոբիլը խաչմերուկը կանցնի՝','2025-05-24 07:15:23','2025-05-24 07:15:23');
INSERT INTO question_translations VALUES(6655,5557,101,'Который из знаков означает \"Объезд препятствия слева\"?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6656,5558,101,'Разрешается ли водителю автобуса въехать на перекресток в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6657,5559,101,'Из какой полосы следует выполнять поворот направо в указанной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6658,5560,101,'На перекрестке организовано круговое движение. Проезжая часть, по которой Вы подъезжаете к перекрестку имеет две полосы движения. Какую полосу Вы обязаны занять для поворота при въезде на перекресток?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6659,5561,101,'Разрешается ли повернуть во двор из указанного места?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6660,5562,101,'На дорогах с двусторонним движением, имеющих три полосы, обозначенные разметкой, из которых средняя используется для движения в обоих направлениях (за исключением дорог с реверсивным регулированием движения) въехать на крайнюю левую полосу:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6661,5563,101,'В каком ответе правильно указано разрешенное направление движения?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6662,5564,101,'В каком направлении запрещено движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6663,5565,101,'Разворот запрещается:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6664,5566,101,'Разрешается ли водителю желтого автобуса въехать на перекресток?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6665,5567,101,'В каком ответе правильно указано разрешенное направление движения?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6666,5568,101,'Разворот запрещается, если видимость дороги хотя бы в одном направлении менее:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6667,5569,101,'Вы движетесь по дороге с двусторонним движением, имеющей три полосы. В каком случае разрешается въезжать на среднюю полосу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6668,5570,101,'В каком направлении разрешается движение грузового автомобиля?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6669,5571,101,'На каком рисунке водитель правильно выполняет маневр?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6670,5572,101,'Водитель какого транспортного средства правильно выполняет разворот?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6671,5573,101,'На дорогах с двусторонним движением при отсутствии дорожных знаков, разметки и разделительной полосы водители должны объезжать элементы дорожных сооружений, находящихся на проезжей части дорог:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6672,5574,101,'В каком направлении запрещено движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6673,5575,101,'Водитель какого транспортного средства нарушает правила поворота с дороги, на которой есть полоса торможения?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6674,5576,101,'Разрешается ли водителю красного автомобиля в данной ситуации продолжить движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6675,5577,101,'На дороге с двусторонним движением, имеющей три полосы, Вам необходимо совершить левый поворот. С какой полосы Вы совершите данный маневр?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6676,5578,101,'Разрешается ли водителю красного автомобиля двигаться по трамвайным путям?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6677,5579,101,'Разворот запрещается:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6678,5580,101,'В каких направлениях разрешается движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6679,5581,101,'Водители каких транспортных средств нарушили требования дорожного знака?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6680,5582,101,'При одновременном перестроении транспортных средств, движущихся попутно, дорогу должен уступить:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6681,5583,101,'Водитель какого транспортного средства имеет право на первоочередное движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6682,5584,101,'Обязан ли водитель автобуса, движущегося по установленному маршруту, уступать дорогу в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6683,5585,101,'Если встречный разъезд на уклонах, обозначенных соответствующими знаками, затруднен, необходимо уступить дорогу:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6684,5586,101,'Водитель какого транспортного средства должен уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6685,5587,101,'Преимущество в движении имеет:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6686,5588,101,'Обязаны ли водители транспортных средств в населенных пунктах уступать дорогу транспортным средствам общего пользования, начинающим движение от оборудованной территории обозначенного места остановки?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6687,5589,101,'Водитель какого транспортного средства должен уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6688,5590,101,'Водитель какого транспортного средства должен уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6689,5591,101,'Водитель какого транспортного средства должен уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6690,5592,101,'Укажите очередность проезда перекрестка:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6691,5593,101,'При встречном разъезде на крутом спуске необходимо уступить дорогу:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6692,5594,101,'Разрешается ли транспортным средствам общего пользования в населенных пунктах на дорогах, имеющих три полосы и более для движения в одном направлении, выезжать на крайнюю левую полосу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6693,5595,101,'Разрешается ли транспортным средствам общего пользования на всех дорогах, имеющих три полосы и более для движения в одном направлении, выезжать на крайнюю левую полосу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6694,5596,101,'Как должен поступить водитель маршрутного автобуса в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6695,5597,101,'В данной ситуации водитель белого легкового автомобиля:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6696,5598,101,'Водитель какого транспортного средства имеет право право на первоочередное движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6697,5599,101,'Водитель какого транспортного средства имеет право право на первоочередное движение в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6698,5600,101,'Обязан ли водитель автобуса уступить дорогу грузовому автомобилю на перекрестке, где организовано кольцевое движение?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6699,5601,101,'Обязан ли водитель автобуса, продолжающего движение прямо, уступить дорогу грузовому автомобилю?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6700,5602,101,'Если Вы намерены продолжить движение прямо, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6701,5603,101,'Если Вы намерены продолжить движение прямо, кому Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6702,5604,101,'В данной ситуации обязан ли водитель мотоцикла уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6703,5605,101,'В данной ситуации имеете ли Вы право на указанный маневр?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6704,5606,101,'Вы продолжаете движение прямо, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6705,5607,101,'Вы продолжаете движение прямо, обязаны ли Вы уступить дорогу легковому автомобилю?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6706,5608,101,'Вы начинаете движение с обочины, обязаны ли Вы уступить дорогу легковому автомобилю, выполняющему разворот?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6707,5609,101,'Вы продолжаете движение прямо, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6708,5610,101,'Если Вы намерены совершить левый поворот, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6709,5611,101,'Если Вы намерены произвести разворот на перекрестке, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6710,5612,101,'Если Вы намерены совершить левый поворот на перекрестке, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6711,5613,101,'Если Вы намерены совершить левый поворот на перекрестке, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6712,5614,101,'Если Вы намерены выполнить разворот на перекрестке, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6713,5615,101,'Если Вы намерены выполнить поворот налево, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6714,5616,101,'Если Вы намерены выполнить поворот направо, обязаны ли Вы уступить дорогу легковому автомобилю?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6715,5617,101,'Если Вы намерены выполнить поворот направо, какому транспортному средству Вы должны уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6716,5618,101,'Обязаны ли мы в данной ситуации уступить дорогу водителю автомобиля, приближающегося с противоположной стороны?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6717,5619,101,'В данной ситуации Вы обязаны:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6718,5620,101,'В данной ситуации:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6719,5621,101,'В этой ситуации:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6720,5622,101,'В данной ситуации при движении прямо разрешается:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6721,5623,101,'По какой траектории разрешено приближаться к пешеходу, ожидающему у обочины?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6722,5624,101,'Выйдя на дорогу, в данной ситуации мы обязаны уступить:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6723,5625,101,'В данной ситуации уступить дорогу обязан:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6724,5626,101,'По какой траектории разрешен разворот?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6725,5627,101,'В какой из изображенных на рисунке ситуаций водитель синего автомобиля имеет право на первоочередное движение по отношению к другим водителям?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6726,5628,101,'Разворот в указанном месте:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6727,5629,101,'По какой траектории разрешен поворот направо?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6728,5630,101,'Водитель какого транспортного средства должен уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6729,5631,101,'По какой траектории разрешено выполнить разворот?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6730,5632,101,'С этой полосы в каком направлении может продолжить движение водитель легкового автомобиля?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6731,5633,101,'При выполнении правого поворота на прилегающую справа дорогу необходимо:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6732,5634,101,'При въезде в левый двор кому следует уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6733,5635,101,'Разворот на данном перекрестке:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6734,5636,101,'Обязан ли водитель легкового автомобиля уступить дорогу водителю автокрана, перестраивающегося на его полосу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6735,5637,101,'Разрешается ли разворот в данном месте?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6736,5638,101,'Обязан ли водитель легкового автомобиля пересториться на крайнюю правую полосу после завершения обгона?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6737,5639,101,'На какой траекторией разрешен поворот налево?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6738,5640,101,'В тех случаях, когда полосы движения транспортных средств пересекаются, а последовательность проезда не установлена правилами, дорогу должен уступитьт тот водитель,','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6739,5641,101,'Какой водитель должен уступить дорогу?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6740,5642,101,'Разворот в указанном месте:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6741,5643,101,'На какой траекторией разрешен поворот налево?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6742,5644,101,'Водитель легкового автомобиля:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6743,5645,101,'На какой траекторией разрешен поворот направо?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6744,5646,101,'На какой траекторией разрешен разворот?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6745,5647,101,'Обязан ли водитель перестроиться на правую полосу и только после этого выполнить поворот направо в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6746,5648,101,'Разрешается ли разворот при нахождении в пределах моста?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6747,5649,101,'Въезд на перекресток с указанной полосы:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6748,5650,101,'Разрешен ли разворот в указанном месте?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6749,5651,101,'Водитель, двигающийся без перестроения, уступить дорогу водителю, перестраивающемуся с правой стороны:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6750,5652,101,'Разворот в данном месте:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6751,5653,101,'Повороты налево разрешены','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6752,5654,101,'При одновременном начале движения с парковки обязаны ли Вы уступить дорогу впереди находящемуся водителю?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6753,5655,101,'По какой траектории водитель имеет право выполнить левый поворот в данной ситуации?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6754,5656,101,'Разрешается ли на перекрестке разворот с применением заднего хода?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6755,5657,101,'Разрешается ли водителю выполнить поворот направо в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6756,5658,101,'При остановке в данной ситуации какой световой указатель должен включить водитель?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6757,5659,101,'По каким траекториям разрешено движение?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6758,5660,101,'По причине отсутствия видимости, при движении задним ходом водитель должен:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6759,5661,101,'В данной ситуации выполнение разворота с использованием въезда во двор задним ходом:','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6760,5662,101,'Разрешается ли водителю легкового автомобиля начать движение?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6761,5663,101,'В каком варианте разрешено движение задним ходом?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6762,5664,101,'В данной ситуации разрешается ли водителю движение по трамвайным путям?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6763,5665,101,'Обязан ли водитель в данной ситуации при выполнении поворота налево подать сигнал световым указателем?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6764,5666,101,' Разрешен левый поворот','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6765,5667,101,'Разрешается ли водителю легкового автомобиля подъехать задним ходом к пассажиру, стоящему на мосту?','2025-11-06 21:40:29','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6766,5668,101,'Разрешается ли разворот в данной ситуации?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6767,5669,101,'Какое правило нарушает водитель, въезжая во двор?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6768,5670,101,'Уступить дорогу водителю грузового автомобиля:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6769,5671,101,'На какой траекторией разрешен разворот?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6770,5672,101,'На какой траекторией разрешен разворот?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6771,5673,101,'Дорогу должен уступить:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6772,5674,101,'Если мы случайно проехали перекрёсток, разрешено ли в этой ситуации использовать задний ход, чтобы затем продолжить движение в необходимом нам направлении?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6773,5675,101,'С этой полосы продолжить движение разрешается:','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6774,5676,101,'В данной ситуации разрешается ли въезд в правый двор, выполнив разворот?','2025-11-06 21:40:29','2025-11-06 21:40:29');
INSERT INTO question_translations VALUES(6775,5677,101,'При перестроении на соседнюю полосу в данной ситуации:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6776,5678,101,'На какой траекторией разрешен разворот?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6777,5679,101,'На какой траекторией разрешен поворот налево?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6778,5680,101,'В данной ситуации разрешается ли подъехать задним ходом к пассажиру?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6779,5681,101,'Как Вы должны поступить при левом повороте и развороте вне перекрестка?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6780,5682,101,'Разрешено ли движение задним ходом в данной ситуации?','2025-11-06 21:40:30','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6781,5683,101,'Начиная движение, обязаны ли Вы уступить дорогу водителю, выполняющему разворот?','2025-11-06 21:40:30','2025-11-06 21:40:30');
