INSERT INTO question_translations VALUES(6952,5854,101,'Разрешается ли заезжать на полосу, обозначенную этим знаком, при выполнении правого поворота?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6953,5855,101,'Этот дорожный знак обозначает:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6954,5856,101,'Какой из указанных знаков запрещает движение с дистанцией, меньшей указанной на знаке?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6955,5857,101,'На каком расстоянии до начала опасного участка дороги устанавливаются эти знаки в населенных пунктах?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6956,5858,101,'Этот дорожный знак:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6957,5859,101,'Какой из указанных знаков обязывает уступить дорогу встречным транспортным средствам, въезжающим на узкий участок дороги или подъезжающим к нему?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6958,5860,101,'Какой из указанных знаков предупреждает о приближении к перекрестку равнозначных дорог?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6959,5861,101,'Какой из указанных знаков устанавливается непосредственно перед пересечением проезжих частей?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6960,5862,101,'Эти знаки разрешают движение:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6961,5863,101,'Какой из указанных знаков предоставляет водителю преимущество по отношению к встречным транспортным средствам?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6962,5864,101,'Что означает табличка, установленная под знаком?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6963,5865,101,'Что означают следующие знаки?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6964,5866,101,'Какой знак запрещает стоянку по четным числам месяца?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6965,5867,101,'Этот дорожный знак:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6966,5868,101,'Какой из следующих знаков обязывает уступить дорогу встречным транспортным средствам?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6967,5869,101,'Этот знак называется:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6968,5870,101,'Какой из знаков обязывает уступить дорогу транспортным средствам, движущимся по пересекаемой дороге?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6969,5871,101,'Разрешается ли водителю автобуса выполнить обгон в зоне действия этого знака?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6970,5872,101,'Какой из следующих знаков разрешает движение только с указанной (км/ч) или большей скоростью?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6971,5873,101,'Какой из знаков указывает участок дороги с односторонним движением?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6972,5874,101,'Что указывает табличка, установленная под знаком?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6973,5875,101,'Этот дорожный знак предупреждает, что впереди:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6974,5876,101,'Какой из знаков указывает зону действия дорожных знаков, запрещающих остановку и стоянку транспортных средств?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6975,5877,101,'Какой из следующих знаков указывает протяженность опасного участка дороги, обозначенного предупреждающими знаками?','2025-11-06 21:40:30','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(6976,5878,101,'Этот дорожный знак обозначает:','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6977,5879,101,'Какой из знаков обозначает \"Гостиницу\" или \"Мотель\"?','2025-11-06 21:40:30','2025-11-06 21:40:30');
INSERT INTO question_translations VALUES(6978,5880,101,'Таким опознавательным знаком обозначаются автомобили, которые:','2025-11-06 21:40:30','2025-11-06 21:40:30');
