INSERT INTO question_translations VALUES(7038,5940,101,'В какой полосе разрешено разворот?','2025-11-06 21:40:31','2025-11-06 21:40:31');
INSERT INTO question_translations VALUES(7039,5941,101,'В какой полосе разрешено разворот?','2025-11-06 21:40:31','2025-11-06 21:40:31');
