INSERT INTO question_translations VALUES(7043,5945,101,'После этого знака для водителя грузового автомобиля с разрешенной максимальной массой не более 3.5 тонн установлена максимальная скорость движения:','2025-11-06 21:40:31','2025-11-06 21:40:31');
