INSERT INTO question_translations VALUES(7333,6235,101,'Вы намерены выполнить поворот налево. Кому Вы обязаны уступить дорогу?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7334,6236,101,'При выполнении поворота налево:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7335,6237,101,'Обязаны ли мы в данной ситуации уступить водителю грузового автомобиля?','2025-11-06 21:40:32','2025-11-06 21:40:32');
