INSERT INTO question_translations VALUES(7337,6239,101,'В каком случае Вы можете проехать перекресток, не уступая другим участникам дорожного движения?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7338,6240,101,'При выполнении поворота направо следует:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7339,6241,101,'При выполнении поворота направо:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7340,6242,101,'После включения разрешающего сигнала светофора мы можем въехать на перекресток:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7341,6243,101,'После включения зеленого сигнала мы обязаны:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7342,6244,101,'Обязаны ли Вы уступить дорогу автобусу?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7343,6245,101,'При выполнении разворота в данной ситуации уступить дорогу другому водителю:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7344,6246,101,'С этого положения в каком направлении водитель может продолжить движение?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7345,6247,101,'Какой водитель может продолжить движение?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7346,6248,101,'Проезжать переезд:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7347,6249,101,'Где следует остановиться, подчиняясь сигналу светофора?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7348,6250,101,'Выполнение поворота налево разрешается:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7349,6251,101,'Движение разрешается:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7350,6252,101,'Движение разрешается:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7351,6253,101,'Стрелки, изображенные на зеленом сигнале светофора, информируют:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7352,6254,101,'Разрешен ли обгон грузового автомобиля?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7353,6255,101,'В каком направлении водитель может продолжить движение в данной ситуации?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7354,6256,101,'Въезжать на полосу реверсивного движения в данной ситуации','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7355,6257,101,'С указанной полосы прямое движение','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7356,6258,101,'Движение разрешается:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7357,6259,101,'В данной ситуации движение:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7358,6260,101,'Каким транспортным средствам разрешена стоянка?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7359,6261,101,'Стоянка запрещена:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7360,6262,101,'Разрешается ли высадка пассажиров в месте, где нанесена по верху бордюра сплошная желтая линия в сочетании со знаком \"Остановка запрещена\"?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7361,6263,101,'Действует ли запрещающий знак на той части дороги, где совершил остановку водитель?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7362,6264,101,'Разрешается ли стоянка автомобиля в указанном месте?','2025-11-06 21:40:32','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7363,6265,101,'На каком расстоянии от железнодорожных переездов запрещена стоянка транспортных средств?','2025-11-06 21:40:32','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7364,6266,101,'Разрешается ли в данной ситуации остановиться для высадки пассажира?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7365,6267,101,'Кто из водителей должен остановиться?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7366,6268,101,'Данная дорожная разметка разрешает движение:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7367,6269,101,'Каким транспортным средствам разрешена стоянка в зоне действия показанного дорожного знака?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7368,6270,101,'Что обозначает данная дорожная разметка?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7369,6271,101,'Что показывает сплошная желтая линия горизонтальной разметки?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7370,6272,101,'Разрешается ли водителю пересекать сплошную линию разметки, обозначающую границы стояночных мест транспортных средств?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7371,6273,101,'По какому из обозначенных стрелками пути разрешено движение?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7372,6274,101,'Что обозначает данная разметка?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7373,6275,101,'Сколько полос имеет дорога, где транспортные потоки противоположных направлений разделяются двойными сплошными линиями?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7374,6276,101,'О чем предупреждают разметки в виде стрелок на проезжей части?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7375,6277,101,'Какая из линий разметки используется для обозначения полос, на которых осуществляется реверсивное движение?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7376,6278,101,'Где наносится сплошная желтая линия, обозначающая места, запрещающие остановку и стоянку?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7377,6279,101,'С каким дорожным знаком может быть применена разметка в виде желтой прерывистой линии?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7378,6280,101,'Каким транспортным средствам разрешено движение по правой полосе проезжей части?','2025-11-06 21:40:32','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7379,6281,101,'Эта дорожная разметка имеет следующее значение:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7380,6282,101,'Эта горизонтальная дорожная разметка показывает:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7381,6283,101,'Разрешается ли заезжать на направляющий островок, размеченный широкими белыми линиями?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7382,6284,101,'Как должен поступить водитель, приблизившись к перекрестку, перед которым нанесена \"Стоп-линия\" и включен зеленый сигнал светофора?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7383,6285,101,'Что показывает эта разметка?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7384,6286,101,'Где водитель должен остановить транспортное средство при наличии этой разметки?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7385,6287,101,'Что показывает эта разметка?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7386,6288,101,'Разрешается ли в указанном месте произвести разворот?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7387,6289,101,'Разрешается ли водителю туристического автобуса заезжать на полосу \"А\" при наличии данной разметки?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7388,6290,101,'Что показывает разметка в виде широкой прерывистой линии?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7389,6291,101,'Какому автомобилю разрешается остановка в зоне действия этих знаков?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7390,6292,101,'На каком рисунке водитель правильно выполнил остановку для высадки пассажиров?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7391,6293,101,'Сигналом остановки поезда служит:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7392,6294,101,'В населенных пунктах, на дорогах с одной полосой движения в каждом направлении, при отсутствии трамвайных путей посередине, остановка и стоянка на левой стороне дороги:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7393,6295,101,'На каком расстоянии от \"Стоп-линии\" или знака \"Движение без остановки запрещено\" должно быть остановлено транспортное средство для пропуска приближающегося поезда?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7394,6296,101,'Разрешается ли остановка в указанном месте?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7395,6297,101,'Разрешается ли остановка автомобиля в данном месте?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7396,6298,101,'Водитель какого транспортного средства нарушил правила стоянки?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7397,6299,101,'Где разрешается длительная стоянка вне населенных пунктов для отдыха, ночлега и в других целях?','2025-11-06 21:40:32','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7398,6300,101,'Остановка запрещается, если расстояние между сплошной линией разметки и остановившимся транспортным средством составляет:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7399,6301,101,'Если движение через железнодорожный переезд запрещено и отсутствуют светофор, дорожные знаки, разметка и шлагбаум, то водитель должен остановиться:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7400,6302,101,'На каком расстоянии от железнодорожного переезда запрещается стоянка транспортных средств?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7401,6303,101,'В каком ответе правильно перечислены водители, нарушившие, правила остановки?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7402,6304,101,'Водители каких транспортных средств выполнили неправильную остановку для высадки пассажиров?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7403,6305,101,'Если движение через железнодорожный переезд запрещено и отсутствуют светофор, дорожные знаки, разметка и шлагбаум, то водитель должен остановиться:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7404,6306,101,'Разрешается ли туристическому автобусу двигаться по полосе \"А\"?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7405,6307,101,'Что обозначает буква \"А\", нанесенная на полосе проезжей части?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7406,6308,101,'Разрешается ли транспортному средству остановиться в указанном месте для высадки пассажиров?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7407,6309,101,'Разрешается ли продолжить движение по указанному стрелкой направлению?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7408,6310,101,'Такой вертикальной разметкой обозначаются:','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7409,6311,101,'Как должен поступить водитель легкового автомобиля, если водитель автобуса начал тормозить?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7410,6312,101,'Водитель автобуса совершил остановку для посадки пассажиров. Легковой автомобиль движется со скоростью 70 км/ч. Водитель какого транспортного средства нарушает требования правил дорожного движения?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7411,6313,101,'В каком из перечисленных случаев водитель автобуса может занять среднюю полосу на трехполосной дороге двустороннего движения, которая используется для движения в обоих направлениях.','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7412,6314,101,'Где должен остановиться водитель в данной ситуации?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7413,6315,101,'Автобус остановился, чтобы уступить дорогу пешеходу. Нарушает ли водитель легкового автомобиля требования правил дорожного движения в данной ситуации?','2025-11-06 21:40:32','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7414,6316,101,'Разрешается ли водителю автобуса, совершающего регулярные пассажирские перевозки, останавливаться в указанном месте с целью посадки пассажиров?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7415,6317,101,'Имеет ли водитель туристического автобуса право на стоянку в указанном месте с целью длительного отдыха?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7416,6318,101,'Для продолжения движения налево где должен остановиться водитель автобуса, чтобы уступить дорогу легковому автомобилю?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7417,6319,101,'Где необходимо остановиться в данной ситуации?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7418,6320,101,'Каким транспортным средствам разрешается совершать остановку в зоне действия данного знака?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7419,6321,101,'В зоне действия указанных дорожных знаков разрешается ли совершать остановку с целью посадки пассажиров?','2025-11-06 21:40:32','2025-11-06 21:40:32');
INSERT INTO question_translations VALUES(7420,6322,101,'Для каких транспортных средств выделена полоса движения, обозначенная буквой \"А\"?','2025-11-06 21:40:32','2025-11-06 21:40:32');
