INSERT INTO question_translations VALUES(7608,6510,101,'В темное время суток и в условиях недостаточной видимости, независимо от освещения дороги, на движущемся механическом транспортном средстве должны быть включены:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7609,6511,101,'В каком случае в светлое время суток на мотоцикле должен быть включен ближний свет фар?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7610,6512,101,'Что должен предпринять водитель в первую очередь при ослеплении светом фар встречного автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7611,6513,101,'Звуковые сигналы могут применяться только:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7612,6514,101,'В темное время суток на механическом транспортном средстве, движущемся на неосвещенных участках дороги, должны быть включены:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7613,6515,101,'Задние противотуманные фонари могут использоваться:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7614,6516,101,'На каком расстоянии до встречного транспортного средства дальний свет фар должен быть переключен на ближний?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7615,6517,101,'Фарой-прожектором разрешается пользоваться:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7616,6518,101,'На каком расстоянии до начала опасного участка устанавливается этот предупреждающий знак в населенных пунктах?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7617,6519,101,'Разрешается ли провозить через железнодорожный переезд сельскохозяйственные, дорожные, строительные и другие машины и механизмы?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7618,6520,101,'Где разрешается пересекать железнодорожные линии?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7619,6521,101,'Разрешается ли при выполнении служебного задания самовольно открывать шлагбаум или объезжать его?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7620,6522,101,'Разрешается ли провозить через железнодорожный переезд сельскохозяйственные, дорожные, строительные и другие машины и механизмы?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7621,6523,101,'Чем должен руководствоваться водитель при приближении к железнодорожному переезду?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7622,6524,101,'Разрешается ли пешеходам передвигаться по дороге, обозначенной знаком \"Автомагистраль\"?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7623,6525,101,'Движение транспортных средств, скорость которых по технической характеристике или состоянию не превышает 40 км/ч, на автомагистралях:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7624,6526,101,'На транспортном средстве аварийная световая сигнализация должна быть включена:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7625,6527,101,'На транспортном средстве аварийная световая сигнализация должна быть включена:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7626,6528,101,'На каком расстоянии от транспортного средства устанавливают знак \"Аварийная остановка\"?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7627,6529,101,'На транспортном средстве аварийная световая сигнализация должна быть включена:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7628,6530,101,'На транспортном средстве аварийная световая сигнализация должна быть включена:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7629,6531,101,'На застроенных территориях, въезды на которые и выезды с которых обозначены дорожными знаками \"Жилая зона\" и \"Конец жилой зоны\", не запрещается:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7630,6532,101,'Перекресток считается регулируемым, если очередность движения на нем определяется:','2025-11-06 21:40:33','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7631,6533,101,'Если на грунтовой дороге непосредственно перед перекрестком имеется участок с покрытием, то делает ли это ее равной по значению с пересекаемой?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7632,6534,101,'На каком рисунке показаны разрешенные направления движения?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7633,6535,101,'Если значения сигналов светофора противоречат требованиям дорожных знаков приоритета, то водители должны руководствоваться:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7634,6536,101,'Разрешается ли водителю продолжать движение при включении желтого сигнала светофора или поднятии регулировщиком руки вверх?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7635,6537,101,'Регулировщик подает сигнал свистком','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7636,6538,101,'Разрешается ли в данной ситуации автопоезду проехать по мосту?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7637,6539,101,'В каком случае правила не обязывают водителя автобуса подать предупредительный сигнал?','2025-11-06 21:40:33','2026-03-10 23:54:53');
INSERT INTO question_translations VALUES(7638,6540,101,'Перед перестроением водитель автобуса должен подать предупредительный сигнал:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7639,6541,101,'Какие повторяющиеся звуковые сигналы общей тревоги обязан подавать водитель автобуса при вынужденной остановке на железнодорожном переезде?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7640,6542,101,'Имеет ли водитель междугороднего автобуса право выполнять обгон мотоцикла, который движется со скоростью 70 км/ч?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7641,6543,101,'Можно ли подавать предупреждающий сигнал рукой для движения по данной траектории?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7642,6544,101,'Обязан ли водитель включить указатель поворота перед началом движения в населенном пункте?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7643,6545,101,'Водитель автомобиля патрульной службы для приобретения преимущества перед другими участниками движения должен включить:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7644,6546,101,'Обязан ли водитель автобуса уступить дорогу автомобилю \"Скорой помощи\", если на нем не включен проблесковый маячок синего цвета и специальный звуковой сигнал?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7645,6547,101,'Обгон запрещается:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7646,6548,101,'О чем информирует сигнал, поданный рукой водителя легкового автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7647,6549,101,'Аварийный световой сигнал включается:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7648,6550,101,'О чем информирует сигнал, поданный рукой водителя мотоцикла?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7649,6551,101,'О чем информирует сигнал, поданный рукой водителя легкового автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7650,6552,101,'О чем информирует сигнал, поданный рукой водителя легкового автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7651,6553,101,'Обязан ли водитель включить указатель поворота в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7652,6554,101,'При организованной перевозке группы детей в светлое время суток на автобусе должны быть включены:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7653,6555,101,'Разрешается ли водителю грузового автомобиля обгонять автобус, который двигается со скоростью 60 км/ч?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7654,6556,101,'Разрешается ли выполнять обгон в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7655,6557,101,'Разрешается ли въезжать на железнодорожный переезд в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7656,6558,101,'Разрешается ли въезжать на железнодорожный переезд в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7657,6559,101,'Как необходимо действовать в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7658,6560,101,'Разрешается ли проехать железнодорожный переезд в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7659,6561,101,'Разрешается ли проехать железнодорожный переезд в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7660,6562,101,'В данной ситуации где можно начать обгон?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7661,6563,101,'Разрешен ли обгон в этой ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7662,6564,101,'Какой маневр выполняет водитель легкового автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7663,6565,101,'Разрешается ли обгонять мотоцикл?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7664,6566,101,'В каком случае разрешается на дорогах с одной полосой в каждом направлении выполнять обгон на полосе встречного движения?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7665,6567,101,'Разрешается ли обгон в указанной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7666,6568,101,'Разрешается ли обгон грузового автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7667,6569,101,'Что требуется от водителя обгоняемого транспортного средства?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7668,6570,101,'Разрешается ли выполнять обгон в данной ситуации?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7669,6571,101,'Разрешается ли водителю грузового автомобиля обгонять трактор, если разрешенная максимальная масса составляет 3 тонны?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7670,6572,101,'Если встречный разъезд затруднен в данной ситуации, то дорогу должен уступить:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7671,6573,101,'Обгон на пешеходном переходе:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7672,6574,101,'По какой полосе разрешен обгон?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7673,6575,101,'Что показывает данный дорожный знак?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7674,6576,101,'Водитель в этой ситуации включить световой указатель поворота:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7675,6577,101,'Поднятая вверх рука водителя информирует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7676,6578,101,'Подача сигнала преимущество по отношению к другим участникам движения:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7677,6579,101,'О чем информирует водитель мотоцикла?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7678,6580,101,'При выполнении поворота налево в данной ситуации подача сигнала:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7679,6581,101,'При выполнении обгона мы обязаны выключить световой указатель поворота:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7680,6582,101,'При выполнении разворота на этом перекрестке какой указатель поворота мы должны включить?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7681,6583,101,'Обязаны ли Вы в указанной ситуации подать сигнал световым указателем?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7682,6584,101,'О чем информирует водитель мотоцикла?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7683,6585,101,'Сигнал о маневре, поданный световым указателем, должен быть прекращен:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7684,6586,101,'Подача сигнала световым указателем в указанной ситуации:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7685,6587,101,'Какой водитель подает сигнал о повороте направо?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7686,6588,101,'При маневрировании на стоянках или АЗС подавать сигнал световым указателем:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7687,6589,101,'В данной ситуации что может обозначать вытянутая наружу рука водителя?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7688,6590,101,'Какие сигналы Вы должны подать при выполнении разворота по указанной траектории?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7689,6591,101,'Если Вы намерены остановиться непосредственно после перекрестка, когда Вы должны включить световой указатель поворота направо для того, чтобы не ввести в заблуждение участников движения?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7690,6592,101,'Имеет ли преимущество водитель завершающего обгон автомобиля по отношению к водителю, движущемуся по данной полосе, при перестроении на парралельную полосу?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7691,6593,101,'Водителю, выезжающему с окрестной территории, включившему специальные звуковые и световые сигналы, уступать:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7692,6594,101,'При проезде перекрестка прямо обязаны ли мы уступить дорогу водителю грузового автомобиля с включенными проблесковыми маячками желтого цвета?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7693,6595,101,'При повороте налево дорогу уступим:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7694,6596,101,'Мы обязаны уступить дорогу:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7695,6597,101,'В данной ситуации:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7696,6598,101,'Мы обязаны уступить:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7697,6599,101,'При выполнении поворота налево:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7698,6600,101,'При травме головы, оказывая помощь пострадавшему, необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7699,6601,101,'При автомобильной аварии какому из следующих пострадавших Вы окажете помощь в первую очередь?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7700,6602,101,'При кровотечении из носа, оказывая помощь пострадавшему, необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7701,6603,101,'Во время движения водитель внезапно начинает жаловаться на сильную давящую боль в грудной клетке и затрудненное дыхание. Как следует поступить?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7702,6604,101,'Какую помощь следует оказать пострадавшему при судорожном припадке?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7703,6605,101,'Как следует поступить, оказывая помощь при ожоге?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7704,6606,101,'В результате аварии пешеход упал и повредил руку. На предплечье имеется большая рана (около 5 см), из которой непрерывно вытекает кровь темного цвета. Что необходимо сделать для остановки кровотечения?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7705,6607,101,'Оказывая помощь при закрытых травмах мягких тканей конечностей, в первые часы следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7706,6608,101,'Водитель, сидя на корточках, продолжительное время заменял колесо автомобиля. Резко привстав, хватается за голову и, потеряв сознание, падает. Что следует делать?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7707,6609,101,'Как следует поступить, если невозможно обеспечить безопасность на месте происшествия?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7708,6610,101,'Вы видите лежащего на земле человека и замечаете торчащую из голена кость и кровь. Если место происшествия безопасно, что следует делать в первую очередь?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7709,6611,101,'Когда пострадавший имеет открытый перелом конечности, то при оказании помощи необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7710,6612,101,'При травме грудной клетки необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7711,6613,101,'При выпадении органов вследствие открытой травмы брюшной полости пострадавшего необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7712,6614,101,'Пострадавшего, находящегося в бессознательном состоянии при наличии дыхания, необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7713,6615,101,'При сильном кровотечении необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7714,6616,101,'При автомобильной аварии в первую очередь необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7715,6617,101,'Если в ране пострадавшего находится инородный предмет, то при оказании помощи необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7716,6618,101,'В состоянии покоя у взрослого человека пульс составляет:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7717,6619,101,'В состоянии покоя у взрослого человека частота дыхания составляет:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7718,6620,101,'При аварии пострадавшего из автомобиля следует вынести, если:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7719,6621,101,'При подозрении на внутреннее кровотечение в брюшной полости, при оказании помощи необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7720,6622,101,'Из соседского автогаража Вы слышите звук двигателя машины и, открыв дверь, видите лежащего на полу соседа. Что следует предпринять в первую очередь?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7721,6623,101,'При обнаружении пострадавшего в безсознательном состоянии в первую очередь необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7722,6624,101,'Для проверки кровообращения в конечностях пострадавшего Вы ниже повязки надавливаете и отпускаете ноготь на пальце травмированной конечности. Вы определяете, что кровообращение нарушено, если:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7723,6625,101,'Ваш приятель, больной сахарным диабетом, плохо себя чувствует и не помнит, когда в последний раз принимал инсулин. Что следует предпринять в первую очередь?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7724,6626,101,'Кровотечение считается наиболее опасным, если:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7725,6627,101,'Автомобиль столкнулся со столбом, и оборвавшийся электрический провод лежит на находящемся без сознания пострадавшем. При оказании помощи, в первую очередь следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7726,6628,101,'Для того, чтобы избежать заражения при оказании первой помощи следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7727,6629,101,'В случае приступа бронхиальной астмы у пострадавшего следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7728,6630,101,'Пострадавшего с травмой в брюшной полости следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7729,6631,101,'Если пострадавший находится в бессознательном состоянии, следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7730,6632,101,'При наезде автомобилем с низким кузовом на пешехода, имеющего рост 1 м 55 см. или более, наиболее возможны:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7731,6633,101,'При наезде автомобилем с низким кузовом на 3-5 летнего ребенка наиболее возможными травмами являются:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7732,6634,101,'Если электрический провод лежит на автомобиле, необходимо:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7733,6635,101,'При обработке менее опасных ран следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7734,6636,101,'При обработке опасных ран следует:','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7735,6637,101,'В случае аварии, какую информацию нужно предоставить оператору для вызова скорой помощи?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7736,6638,101,'Какое оптимальное положение следует занять пострадавшему в сознании при подозрении на травму позвоночника?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7737,6639,101,'Как оказать первую помощь при отморожении и переохлаждении?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7738,6640,101,'Какова первая помощь при черепно-мозговой травме, сопровождающейся ранением волосистой части головы?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7739,6641,101,'Как следует уложить пострадавшего при потере им сознания и наличии дыхания и кровообращения для оказания первой помощи?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7740,6642,101,'На какой срок может быть наложен кровоостанавливающий жгут?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7741,6643,101,'Как определить наличие дыхания у потерявшего сознание пострадавшего?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7742,6644,101,'Каковы признаки кровотечения из крупной артерии и с чего начинается первая помощь при повреждении крупной артерии?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7743,6645,101,'Разрешается ли давать пострадавшему лекарственные средства при оказании первой помощи?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7744,6646,101,'Как остановить кровотечение при ранении вены и некрупных артерий?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7745,6647,101,'Каковы первоначальные действия при оказании первой помощи в случае ранения, полученного в результате ДТП?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7746,6648,101,'Как оказывается первая помощь при переломах конечностей, если отсутствуют шины и подручные средства для их изготовления?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7747,6649,101,'В каких случаях пострадавшего следует извлекать из салона автомобиля?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7748,6650,101,'Какова первая помощь при наличии признаков поверхностного термического ожога (покраснение и отек кожи, образование на месте ожога пузырей, наполненных прозрачной жидкостью, сильная боль)?','2025-11-06 21:40:33','2025-11-06 21:40:33');
INSERT INTO question_translations VALUES(7931,6807,102,'Ի՞նչ է պատկերված առջևում գտնվող քառակուսու մեջ:','2025-11-12 19:51:05','2025-11-12 19:51:05');
